INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_contact_sheet-step_2.app', 'en', 'Step 2: Contact Sheet Workflow', 'Upload the fashion editorial and product image. Generate 8 distinct angle variations with product consistency from only 2 Nano Banana generations.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_contact_sheet-step_2.app', 'zh', '步骤 2：联系表工作流程', '上传时尚大片和产品图片。仅通过2次Nano Banana生成，生成8种具有产品一致性的不同角度变体。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_contact_sheet-step_2.app', 'zh-TW', '步驟 2：聯繫表工作流程', '上傳時尚大片和產品圖片。僅透過2次Nano Banana生成，生成8種具有產品一致性的不同角度變體。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_contact_sheet-step_2.app', 'ja', 'ステップ 2：コンタクトシートのワークフロー', 'ファッションエディトリアルと商品画像をアップロードしてください。わずか2回のNano Banana生成で、製品の一貫性を保った8種類の異なる角度バリエーションを生成します。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_contact_sheet-step_2.app', 'ko', '2단계: 연락처 시트 워크플로', '패션 에디토리얼과 제품 이미지를 업로드하세요. 단 2번의 Nano Banana 생성만으로 제품 일관성을 유지한 8가지 서로 다른 각도 변형을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_contact_sheet-step_2.app', 'es', 'Paso 2: Flujo de trabajo de la hoja de contacto', 'Sube el editorial de moda y la imagen del producto. Genera 8 variaciones de ángulo distintas con consistencia del producto a partir de solo 2 generaciones de Nano Banana.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_contact_sheet-step_2.app', 'fr', 'Étape 2 : Flux de travail de la feuille de contact', 'Téléchargez l''éditorial de mode et l''image du produit. Générez 8 variations d''angle distinctes avec cohérence produit à partir de seulement 2 générations Nano Banana.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_contact_sheet-step_2.app', 'ru', 'Шаг 2: Рабочий процесс контактного листа', 'Загрузите фэшн-редакционное изображение и изображение товара. Сгенерируйте 8 различных вариантов углов с сохранением консистенции товара всего за 2 поколения Nano Banana.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_contact_sheet-step_2.app', 'tr', 'Adım 2: İletişim Sayfası İş Akışı', 'Moda editoryalını ve ürün görselini yükleyin. Sadece 2 Nano Banana nesli ile ürün tutarlılığına sahip 8 farklı açı varyasyonu oluşturun.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_contact_sheet-step_2.app', 'ar', 'الخطوة 2: سير عمل ورقة الاتصال', 'قم بتحميل الصورة التحريرية للأزياء وصورة المنتج. قم بتوليد 8 اختلافات زاوية متميزة مع اتساق المنتج من جيلين فقط من Nano Banana.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_contact_sheet-step_2.app', 'pt-BR', 'Passo 2: Fluxo de trabalho da folha de contato', 'Faça upload do editorial de moda e da imagem do produto. Gere 8 variações de ângulo distintas com consistência do produto a partir de apenas 2 gerações do Nano Banana.', 0, NULL, '2026-04-19T13:33:43.914Z');
