INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-wan2_1_infinitetalk_music', 'zh-TW', '音訊驅動角色口型同步影片', '上傳角色圖像和音訊檔案。生成唇形同步影片，使角色的嘴部動作與提供的音軌匹配。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-wan2_1_infinitetalk_music', 'ja', 'オーディオ駆動キャラクターリップシンク動画', 'キャラクター画像とオーディオファイルをアップロードしてください。提供された音声トラックに合わせてキャラクターの口の動きが同期するリップシンク動画を生成します。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-wan2_1_infinitetalk_music', 'ko', '오디오 기반 캐릭터 립싱크 영상', '캐릭터 이미지와 오디오 파일을 업로드하세요. 제공된 오디오 트랙에 맞춰 캐릭터의 입 모양이 움직이는 립싱크 동영상을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-wan2_1_infinitetalk_music', 'es', 'Video de sincronización labial de personajes impulsado por audio', 'Sube una imagen de un personaje y un archivo de audio. Genera un video de sincronización labial donde los movimientos de la boca del personaje coincidan con la pista de audio proporcionada.', 0, NULL, '2026-04-19T13:33:43.914Z');
