INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-wan2_1_infinitetalk_music', 'ru', 'Видео с синхронизацией губ персонажа на основе аудио', 'Загрузите изображение персонажа и аудиофайл. Создайте видео с синхронизацией губ, где движения рта персонажа соответствуют предоставленной аудиодорожке.', 0, NULL, '2026-04-19T13:33:43.914Z');
