INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_character_portrait_relighting', 'zh', '人物肖像重新打光', '上传角色肖像，在保持角色一致性的同时创建多种电影级光照条件。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_character_portrait_relighting', 'zh-TW', '人物肖像重新打光', '上傳角色肖像，在保持角色一致性的同時創建多種電影級光照條件。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_character_portrait_relighting', 'ja', 'キャラクターポートレートの再照明', 'キャラクターの肖像をアップロードし、キャラクターの一貫性を保ちながら複数の映画的な照明条件を作成します。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_character_portrait_relighting', 'ko', '캐릭터 초상화 재조명', '캐릭터의 초상화를 업로드하고 캐릭터 일관성을 유지하면서 여러 시네마틱 조명 조건을 생성하세요.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_character_portrait_relighting', 'es', 'Reiluminación de Retratos de Personajes', 'Sube un retrato de tu personaje y crea múltiples condiciones de iluminación cinematográfica manteniendo la coherencia del personaje.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_character_portrait_relighting', 'fr', 'Rééclairage de Portraits de Personnages', 'Téléchargez un portrait de votre personnage et créez plusieurs conditions d''éclairage cinématographiques tout en préservant la cohérence du personnage.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_character_portrait_relighting', 'ru', 'Переосвещение Портретов Персонажей', 'Загрузите портрет вашего персонажа и создайте несколько кинематографических условий освещения, сохраняя при этом целостность персонажа.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_character_portrait_relighting', 'tr', 'Karakter Portresi Yeniden Aydınlatma', 'Karakterinizin bir portresini yükleyin ve karakter tutarlılığını korurken birden fazla sinematik aydınlatma koşulu oluşturun.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_character_portrait_relighting', 'ar', 'إعادة إضاءة صورة الشخصية', 'قم بتحميل صورة شخصية لشخصيتك وأنشئ ظروف إضاءة سينمائية متعددة مع الحفاظ على اتساق الشخصية.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_character_portrait_relighting', 'pt-BR', 'Reiluminação de Retrato de Personagem', 'Faça upload de um retrato do seu personagem e crie múltiplas condições de iluminação cinematográfica mantendo a consistência do personagem.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (10, 'template_horizontal_vertical_entension', 1, 9, 'Video Aspect Ratio Extension ', 'Extend any video to a custom aspect ratio. Convert vertical videos to horizontal format and vice versa. Includes an application mode for easy use.', 'image', 'webp', 'compareSlider', '["input/animated_man_framing.mp4","output/template_horizontal_vertical_entension.mp4"]', '["Video","Video Edit","Outpainting"]', '["Kling O3"]', '[{"provider":"Kling"}]', '["comfyui_essentials","comfyui_layerstyle","masquerade-nodes-comfyui"]', '[]', '{"inputs":[{"nodeId":247,"nodeType":"LoadVideo","file":"animated_man_framing.mp4","mediaType":"video"}],"outputs":[{"nodeId":270,"nodeType":"SaveVideo","file":"template_horizontal_vertical_entension.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-30', 0, 'active', 0, 0, 0, 0, 'shane', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_horizontal_vertical_entension', 'en', 'Video Aspect Ratio Extension ', 'Extend any video to a custom aspect ratio. Convert vertical videos to horizontal format and vice versa. Includes an application mode for easy use.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_horizontal_vertical_entension', 'zh', '视频宽高比扩展', '将任何视频扩展至自定义宽高比。将竖屏视频转换为横屏格式，反之亦然。包含应用程序模式，便于使用。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_horizontal_vertical_entension', 'zh-TW', '影片寬高比擴充功能', '將任何影片擴展至自訂寬高比。將豎屏影片轉換為橫屏格式，反之亦然。包含應用程式模式，便於使用。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_horizontal_vertical_entension', 'ja', 'ビデオアスペクト比拡張機能', '任意の動画をカスタムアスペクト比に拡張します。縦動画を横形式に変換し、その逆も可能です。簡単に使用できるアプリケーションモードを含みます。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_horizontal_vertical_entension', 'ko', '비디오 화면비 확장 프로그램', '모든 비디오를 사용자 정의 화면비로 확장합니다. 세로 비디오를 가로 형식으로 변환하거나 그 반대로 변환합니다. 쉬운 사용을 위한 애플리케이션 모드를 포함합니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_horizontal_vertical_entension', 'es', 'Extensión de Relación de Aspecto de Video', 'Extiende cualquier video a una relación de aspecto personalizada. Convierte videos verticales a formato horizontal y viceversa. Incluye un modo de aplicación para un uso fácil.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_horizontal_vertical_entension', 'fr', 'Extension de Rapport d''Aspect Vidéo', 'Étendez n''importe quelle vidéo à un rapport d''aspect personnalisé. Convertissez les vidéos verticales au format horizontal et vice versa. Inclut un mode application pour une utilisation facile.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_horizontal_vertical_entension', 'ru', 'Расширение соотношения сторон видео', 'Расширьте любое видео до пользовательского соотношения сторон. Преобразуйте вертикальные видео в горизонтальный формат и наоборот. Включает режим приложения для удобного использования.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_horizontal_vertical_entension', 'tr', 'Video En Boy Oranı Uzantısı', 'Herhangi bir videoyu özel en boy oranına genişletin. Dikey videoları yatay formata dönüştürün veya tam tersi. Kolay kullanım için bir uygulama modu içerir.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_horizontal_vertical_entension', 'ar', 'امتداد نسبة العرض إلى الارتفاع للفيديو', 'قم بتوسيع أي فيديو إلى نسبة عرض إلى ارتفاع مخصصة. قم بتحويل مقاطع الفيديو العمودية إلى تنسيق أفقي والعكس صحيح. يتضمن وضع التطبيق لسهولة الاستخدام.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_horizontal_vertical_entension', 'pt-BR', 'Extensão de Proporção de Tela de Vídeo', 'Estenda qualquer vídeo para uma proporção personalizada. Converta vídeos verticais para formato horizontal e vice-versa. Inclui um modo de aplicativo para fácil uso.', 0, NULL, '2026-04-19T13:33:43.914Z');
