INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_ltx2_3_style_transition', 'en', 'LTX-2.3 Style Transition ', 'Apply the ltx2.3-transition LoRA to create smooth style and scene transitions. This workflow uses a specialized model to blend visual elements.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_ltx2_3_style_transition', 'zh', 'LTX-2.3 风格过渡', '应用ltx2.3-transition LoRA以创建流畅的风格和场景过渡。此工作流程使用专用模型来融合视觉元素。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_ltx2_3_style_transition', 'zh-TW', 'LTX-2.3 風格過渡', '應用ltx2.3-transition LoRA以創建流暢的風格和場景過渡。此工作流程使用專用模型來融合視覺元素。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_ltx2_3_style_transition', 'ja', 'LTX-2.3 スタイル遷移', 'ltx2.3-transition LoRAを適用して、滑らかなスタイルとシーンの遷移を作成します。このワークフローは、視覚要素をブレンドするための専用モデルを使用します。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_ltx2_3_style_transition', 'ko', 'LTX-2.3 스타일 전환', 'ltx2.3-transition LoRA를 적용하여 부드러운 스타일 및 장면 전환을 생성합니다. 이 워크플로우는 시각적 요소를 혼합하는 특수 모델을 사용합니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_ltx2_3_style_transition', 'es', 'Transición de estilo LTX-2.3', 'Aplica el LoRA ltx2.3-transition para crear transiciones suaves de estilo y escena. Este flujo de trabajo utiliza un modelo especializado para fusionar elementos visuales.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_ltx2_3_style_transition', 'fr', 'Transition de style LTX-2.3', 'Appliquez le LoRA ltx2.3-transition pour créer des transitions de style et de scène fluides. Ce flux de travail utilise un modèle spécialisé pour fusionner les éléments visuels.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_ltx2_3_style_transition', 'ru', 'Стилевой переход LTX-2.3', 'Примените LoRA ltx2.3-transition для создания плавных переходов стиля и сцен. Этот рабочий процесс использует специализированную модель для смешивания визуальных элементов.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_ltx2_3_style_transition', 'tr', 'LTX-2.3 Stil Geçişi', 'Pürüzsüz stil ve sahne geçişleri oluşturmak için ltx2.3-transition LoRA''yı uygulayın. Bu iş akışı, görsel öğeleri harmanlamak için özel bir model kullanır.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_ltx2_3_style_transition', 'ar', 'الانتقال الأسلوبي LTX-2.3', 'طبق LoRA ltx2.3-transition لإنشاء انتقالات سلسة للأسلوب والمشهد. يستخدم سير العمل هذا نموذجًا متخصصًا لدمج العناصر المرئية.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_ltx2_3_style_transition', 'pt-BR', 'Transição de Estilo LTX-2.3', 'Aplique o LoRA ltx2.3-transition para criar transições suaves de estilo e cena. Este fluxo de trabalho usa um modelo especializado para mesclar elementos visuais.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (12, 'templates_graphic_design_recomposer', 1, 11, 'Graphic Design Recomposer', 'Upload a graphic design and select your desired aspect ratio. Generates and recomposes the graphic to fit the new aspect ratio.', 'image', 'webp', NULL, '["thumbnail/templates_graphic_design_recomposer.mp4"]', '["Layout Design"]', '["Nano Banana 2","Nano Banana Pro"]', '[{"provider":"Google"}]', '[]', '[]', '{"inputs":[{"nodeId":125,"nodeType":"LoadImage","file":"latent_space_clud.png","mediaType":"image"}],"outputs":[{"nodeId":131,"nodeType":"SaveImage","file":"templates_graphic_design_recomposer.png","mediaType":"image"}]}', NULL, NULL, '2026-03-30', 0, 'active', 0, 0, 0, 0, 'hellorob', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_graphic_design_recomposer', 'en', 'Graphic Design Recomposer', 'Upload a graphic design and select your desired aspect ratio. Generates and recomposes the graphic to fit the new aspect ratio.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_graphic_design_recomposer', 'zh', '图形设计重组器', '上传图形设计并选择所需宽高比。生成并重新构图以适应新的宽高比。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_graphic_design_recomposer', 'zh-TW', '圖形設計重組器', '上傳圖形設計並選擇所需寬高比。生成並重新構圖以適應新的寬高比。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_graphic_design_recomposer', 'ja', 'グラフィックデザインリコンポーザー', 'グラフィックデザインをアップロードし、希望のアスペクト比を選択してください。新しいアスペクト比に合わせてグラフィックを生成し再構成します。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_graphic_design_recomposer', 'ko', '그래픽 디자인 리컴포저', '그래픽 디자인을 업로드하고 원하는 화면비를 선택하세요. 새로운 화면비에 맞게 그래픽을 생성하고 재구성합니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_graphic_design_recomposer', 'es', 'Recomponedor de Diseño Gráfico', 'Sube un diseño gráfico y selecciona la relación de aspecto deseada. Genera y recompone el gráfico para ajustarse a la nueva relación de aspecto.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_graphic_design_recomposer', 'fr', 'Recomposeur de Design Graphique', 'Téléchargez un design graphique et sélectionnez le format d''image souhaité. Génère et recompose le graphique pour s''adapter au nouveau format.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_graphic_design_recomposer', 'ru', 'Рекомпоновщик графического дизайна', 'Загрузите графический дизайн и выберите желаемое соотношение сторон. Генерирует и перекомпоновывает графику для соответствия новому соотношению сторон.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_graphic_design_recomposer', 'tr', 'Grafik Tasarım Yeniden Düzenleyici', 'Bir grafik tasarımı yükleyin ve istediğiniz en-boy oranını seçin. Yeni en-boy oranına uyacak şekilde grafiği oluşturur ve yeniden düzenler.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_graphic_design_recomposer', 'ar', 'مُعاد تركيب التصميم الجرافيكي', 'قم بتحميل تصميم رسومي واختر نسبة العرض إلى الارتفاع المطلوبة. يقوم بإنشاء وإعادة تركيب الرسم ليتناسب مع نسبة العرض إلى الارتفاع الجديدة.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_graphic_design_recomposer', 'pt-BR', 'Recompositor de Design Gráfico', 'Faça upload de um design gráfico e selecione a proporção desejada. Gera e recompõe o gráfico para se ajustar à nova proporção.', 0, NULL, '2026-04-19T13:33:43.914Z');
