INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_image_speech_to_video', 'en', 'Generate UGC Video With Voice Clone', 'Upload an image to generate AI prompts and synthesize speech. Create a final video with accurate lip sync using Eleven Labs and LTX Video.', 0, NULL, '2026-04-19T13:33:43.914Z');
