INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_image_speech_to_video', 'zh-TW', '使用語音克隆生成UGC影片', '上傳圖像以生成AI提示並合成語音。使用Eleven Labs和LTX Video創建具有準確口型同步的最終影片。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_image_speech_to_video', 'ja', '音声クローンでUGC動画を生成', '画像をアップロードしてAIプロンプトを生成し、音声を合成します。Eleven LabsとLTX Videoを使用して正確なリップシンクの最終動画を作成します。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_image_speech_to_video', 'ko', '음성 복제로 UGC 동영상 생성', '이미지를 업로드하여 AI 프롬프트를 생성하고 음성을 합성합니다. Eleven Labs와 LTX Video를 사용하여 정확한 립싱크가 적용된 최종 동영상을 제작하세요.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_image_speech_to_video', 'es', 'Generar video UGC con clon de voz', 'Sube una imagen para generar indicaciones de IA y sintetizar voz. Crea un video final con sincronización labial precisa usando Eleven Labs y LTX Video.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_image_speech_to_video', 'fr', 'Générer une vidéo UGC avec clone vocal', 'Téléchargez une image pour générer des invites IA et synthétiser la parole. Créez une vidéo finale avec une synchronisation labiale précise en utilisant Eleven Labs et LTX Video.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_image_speech_to_video', 'ru', 'Создать UGC-видео с клоном голоса', 'Загрузите изображение для создания AI-подсказок и синтеза речи. Создайте итоговое видео с точной синхронизацией губ с помощью Eleven Labs и LTX Video.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_image_speech_to_video', 'tr', 'Ses Klonu ile UGC Videosu Oluştur', 'AI istemleri oluşturmak ve konuşma sentezlemek için bir görsel yükleyin. Eleven Labs ve LTX Video kullanarak doğru dudak senkronizasyonu ile son video oluşturun.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_image_speech_to_video', 'ar', 'إنشاء فيديو UGC باستخدام نسخ صوتي', 'قم بتحميل صورة لإنشاء مطالبات الذكاء الاصطناعي وتوليف الكلام. أنشئ فيديو نهائي بمزامنة دقيقة للشفاه باستخدام Eleven Labs وLTX Video.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_image_speech_to_video', 'pt-BR', 'Gerar vídeo UGC com clone de voz', 'Faça upload de uma imagem para gerar prompts de IA e sintetizar fala. Crie um vídeo final com sincronização labial precisa usando Eleven Labs e LTX Video.', 0, NULL, '2026-04-19T13:33:43.914Z');
