INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_split_stack_qwen_multi_wan22', 'en', '1 image input Split Stack - Qwen Multiangle + Wan 2.2', 'Upload 1 input image and generate 5 alternate angles to be used as start frames with Wan2.2. Each video is stacked horizontally in a final 9x16 video.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_split_stack_qwen_multi_wan22', 'zh', '1个图像输入分割堆栈 - Qwen多角度 + Wan 2.2', '上传1张输入图像，使用Wan2.2生成5个替代角度作为起始帧。每个视频在最终的9x16视频中水平堆叠。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_split_stack_qwen_multi_wan22', 'zh-TW', '1個圖像輸入分割堆疊 - Qwen多角度 + Wan 2.2', '上傳1張輸入圖像，使用Wan2.2生成5個替代角度作為起始幀。每個影片在最終的9x16影片中水平堆疊。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_split_stack_qwen_multi_wan22', 'ja', '1画像入力分割スタック - Qwenマルチアングル + Wan 2.2', '1枚の入力画像をアップロードし、Wan2.2を使用して5つの代替角度を生成し、開始フレームとして使用します。各ビデオは最終的な9x16ビデオで水平に積み重ねられます。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_split_stack_qwen_multi_wan22', 'ko', '1개 이미지 입력 분할 스택 - Qwen 멀티앵글 + Wan 2.2', '1개의 입력 이미지를 업로드하고 Wan2.2를 사용하여 시작 프레임으로 사용할 5개의 대체 각도를 생성합니다. 각 비디오는 최종 9x16 비디오에서 수평으로 쌓입니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_split_stack_qwen_multi_wan22', 'es', '1 entrada de imagen Pila dividida - Qwen Multiángulo + Wan 2.2', 'Sube 1 imagen de entrada y genera 5 ángulos alternativos para usar como fotogramas iniciales con Wan2.2. Cada video se apila horizontalmente en un video final de 9x16.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_split_stack_qwen_multi_wan22', 'fr', '1 entrée d''image Pile divisée - Qwen Multiangle + Wan 2.2', 'Téléchargez 1 image d''entrée et générez 5 angles alternatifs à utiliser comme images de départ avec Wan2.2. Chaque vidéo est empilée horizontalement dans une vidéo finale de 9x16.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_split_stack_qwen_multi_wan22', 'ru', '1 вход изображения Разделенный стек - Qwen Многоракурсный + Wan 2.2', 'Загрузите 1 входное изображение и сгенерируйте 5 альтернативных ракурсов для использования в качестве стартовых кадров с Wan2.2. Каждое видео расположено горизонтально в итоговом видео формата 9x16.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_split_stack_qwen_multi_wan22', 'tr', '1 görsel girişi Bölünmüş Yığın - Qwen Çok Açılı + Wan 2.2', '1 giriş görseli yükleyin ve Wan2.2 ile başlangıç kareleri olarak kullanılmak üzere 5 alternatif açı oluşturun. Her video, nihai 9x16 videoda yatay olarak istiflenir.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_split_stack_qwen_multi_wan22', 'ar', '1 مدخل صورة كومة مقسمة - Qwen متعدد الزوايا + Wan 2.2', 'قم بتحميل صورة إدخال واحدة وقم بتوليد 5 زوايا بديلة لاستخدامها كإطارات بداية مع Wan2.2. يتم ترتيب كل فيديو أفقيًا في فيديو نهائي بنسبة 9x16.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_split_stack_qwen_multi_wan22', 'pt-BR', '1 entrada de imagem Pilha Dividida - Qwen Multiângulo + Wan 2.2', 'Faça upload de 1 imagem de entrada e gere 5 ângulos alternativos para serem usados como quadros iniciais com o Wan2.2. Cada vídeo é empilhado horizontalmente em um vídeo final de 9x16.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (15, 'templates_purz_wan22_animate_auto_full_scene', 1, 14, 'Wan Animate 2.2 Character Replacement Workflow', 'Wan Animate 2.2 — Character & Scene Replacement - Uses Nano Banana 2 to generate a reference image from the first frame, then swaps the full scene. Optimized for human subjects.', 'image', 'webp', 'compareSlider', '["input/art_gallery_dancer.mp4","output/templates_purz_wan22_animate_auto_full_scene.mp4"]', '["Video"]', '["wan2.2 Animate"]', '[{"provider":["Google","WAN"]}]', '["ComfyUI-WanAnimatePreprocess","ComfyUI-segment-anything-2","comfyui-kjnodes"]', '[]', '{"inputs":[{"nodeId":301,"nodeType":"VHS_LoadVideo","file":"templates_purz_wan22_animate_auto_full_scene.mp4","mediaType":"video"}],"outputs":[{"nodeId":349,"nodeType":"SaveImage","file":"templates_purz_wan22_animate_auto_full_scene.png","mediaType":"image"},{"nodeId":19,"nodeType":"SaveVideo","file":"templates_purz_wan22_animate_auto_full_scene.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-21', 0, 'active', 28776280883, 28776280883, 0, 0, 'PurzBeats', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_wan22_animate_auto_full_scene', 'en', 'Wan Animate 2.2 Character Replacement Workflow', 'Wan Animate 2.2 — Character & Scene Replacement - Uses Nano Banana 2 to generate a reference image from the first frame, then swaps the full scene. Optimized for human subjects.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_wan22_animate_auto_full_scene', 'zh', 'Wan Animate 2.2 角色替换工作流程', 'Wan Animate 2.2 — 角色与场景替换 - 使用 Nano Banana 2 从第一帧生成参考图像，然后替换整个场景。针对人物主体优化。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_wan22_animate_auto_full_scene', 'zh-TW', 'Wan Animate 2.2 角色替換工作流程', 'Wan Animate 2.2 — 角色與場景替換 - 使用 Nano Banana 2 從第一幀生成參考圖像，然後替換整個場景。針對人物主體優化。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_wan22_animate_auto_full_scene', 'ja', 'Wan Animate 2.2 キャラクター置換ワークフロー', 'Wan Animate 2.2 — キャラクターとシーンの置き換え - Nano Banana 2 を使用して最初のフレームから参照画像を生成し、その後シーン全体を置き換えます。人物被写体に最適化されています。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_wan22_animate_auto_full_scene', 'ko', 'Wan Animate 2.2 캐릭터 교체 워크플로우', 'Wan Animate 2.2 — 캐릭터 및 장면 교체 - Nano Banana 2를 사용하여 첫 번째 프레임에서 참조 이미지를 생성한 후 전체 장면을 교체합니다. 인물 피사체에 최적화되었습니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_wan22_animate_auto_full_scene', 'es', 'Flujo de trabajo de reemplazo de personajes de Wan Animate 2.2', 'Wan Animate 2.2 — Reemplazo de Personaje y Escena - Utiliza Nano Banana 2 para generar una imagen de referencia desde el primer fotograma, luego reemplaza la escena completa. Optimizado para sujetos humanos.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_wan22_animate_auto_full_scene', 'fr', 'Flux de travail de remplacement de personnages Wan Animate 2.2', 'Wan Animate 2.2 — Remplacement de Personnage et de Scène - Utilise Nano Banana 2 pour générer une image de référence à partir de la première image, puis remplace la scène entière. Optimisé pour les sujets humains.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_wan22_animate_auto_full_scene', 'ru', 'Рабочий процесс замены персонажей Wan Animate 2.2', 'Wan Animate 2.2 — Замена Персонажа и Сцены - Использует Nano Banana 2 для создания эталонного изображения из первого кадра, затем заменяет всю сцену. Оптимизировано для человеческих объектов.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_wan22_animate_auto_full_scene', 'tr', 'Wan Animate 2.2 Karakter Değiştirme İş Akışı', 'Wan Animate 2.2 — Karakter ve Sahne Değiştirme - İlk kareden bir referans görüntüsü oluşturmak için Nano Banana 2 kullanır, ardından tüm sahneyi değiştirir. İnsan konular için optimize edilmiştir.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_wan22_animate_auto_full_scene', 'ar', 'سير عمل استبدال الشخصيات في Wan Animate 2.2', 'Wan Animate 2.2 — استبدال الشخصية والمشهد - يستخدم Nano Banana 2 لإنشاء صورة مرجعية من الإطار الأول، ثم يستبدل المشهد بالكامل. مُحسّن لموضوعات البشر.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_wan22_animate_auto_full_scene', 'pt-BR', 'Fluxo de trabalho de substituição de personagens do Wan Animate 2.2', 'Wan Animate 2.2 — Substituição de Personagem e Cena - Usa o Nano Banana 2 para gerar uma imagem de referência a partir do primeiro quadro, depois substitui a cena inteira. Otimizado para sujeitos humanos.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (16, 'templates_purz_image_glitch', 1, 15, 'Apply Glitch And Distortion Effects', 'Adds customizable glitch and tearing effects to images. Control distortion intensity, chromatic aberration, and pattern randomness. Outputs a stylistically distorted image.', 'image', 'webp', NULL, '["thumbnail/templates_purz_image_glitch.mp4"]', '["Image","Visual Effects"]', '["None"]', '[]', '["comfyui_fill-nodes"]', '[]', '{"inputs":[{"nodeId":2,"nodeType":"LoadImage","file":"comfy_cat.png","mediaType":"image"}],"outputs":[{"nodeId":3,"nodeType":"SaveImage","file":"templates_purz_image_glitch.png","mediaType":"image"}]}', NULL, NULL, '2026-03-19', 1, 'active', 0, 0, 0, 0, 'PurzBeats', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_image_glitch', 'en', 'Apply Glitch And Distortion Effects', 'Adds customizable glitch and tearing effects to images. Control distortion intensity, chromatic aberration, and pattern randomness. Outputs a stylistically distorted image.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_image_glitch', 'zh', '应用故障与失真效果', '为图像添加可自定义的故障和撕裂效果。控制失真强度、色差和图案随机性。输出具有风格化失真效果的图像。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_image_glitch', 'zh-TW', '應用故障與失真效果', '為圖像添加可自訂的故障和撕裂效果。控制失真強度、色差和圖案隨機性。輸出具有風格化失真效果的圖像。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_image_glitch', 'ja', 'グリッチと歪み効果を適用', '画像にカスタマイズ可能なグリッチやティアリング効果を追加します。歪みの強度、色収差、パターンのランダム性を制御します。スタイリッシュに歪んだ画像を出力します。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_image_glitch', 'ko', '글리치 및 왜곡 효과 적용', '이미지에 맞춤 설정 가능한 글리치 및 티어링 효과를 추가합니다. 왜곡 강도, 색수차, 패턴 무작위성을 제어합니다. 스타일리시하게 왜곡된 이미지를 출력합니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_image_glitch', 'es', 'Aplicar efectos de glitch y distorsión', 'Añade efectos de glitch y desgarro personalizables a las imágenes. Controla la intensidad de la distorsión, la aberración cromática y la aleatoriedad del patrón. Genera una imagen distorsionada con estilo.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_image_glitch', 'fr', 'Appliquer des effets de glitch et de distorsion', 'Ajoute des effets de glitch et de déchirure personnalisables aux images. Contrôlez l''intensité de la distorsion, l''aberration chromatique et l''aléatoire des motifs. Produit une image stylistiquement déformée.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_image_glitch', 'ru', 'Применить эффекты глитча и искажения', 'Добавляет настраиваемые эффекты глитча и разрывов к изображениям. Управляйте интенсивностью искажения, хроматической аберрацией и случайностью паттернов. Выводит стилистически искаженное изображение.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_image_glitch', 'tr', 'Glitch ve Bozulma Efektlerini Uygula', 'Görsellere özelleştirilebilir glitch ve yırtılma efektleri ekler. Bozulma yoğunluğunu, kromatik sapmayı ve desen rastgeleliğini kontrol edin. Stilistik olarak bozulmuş bir görsel çıktısı verir.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_image_glitch', 'ar', 'تطبيق تأثيرات الخلل والتشويه', 'يضيف تأثيرات عطل وتمزق قابلة للتخصيص للصور. تحكم في شدة التشويه، والانحراف اللوني، وعشوائية النمط. يُخرج صورة مشوهة بأسلوب مميز.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_image_glitch', 'pt-BR', 'Aplicar efeitos de glitch e distorção', 'Adiciona efeitos de glitch e rasgo personalizáveis às imagens. Controle a intensidade da distorção, a aberração cromática e a aleatoriedade do padrão. Gera uma imagem distorcida estilisticamente.', 0, NULL, '2026-04-19T13:33:43.914Z');
