INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_wan22_animate_auto_character_replace', 'en', 'Wan2.2 Animate: Automatic Character Replacement', 'Upload a video and a character image. Automatically replace the character in the video using the Wan2.2 Animate model.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_wan22_animate_auto_character_replace', 'zh', 'Wan2.2 Animate：自动角色替换', '上传视频和角色图像。使用Wan2.2 Animate模型自动替换视频中的角色。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_wan22_animate_auto_character_replace', 'zh-TW', 'Wan2.2 Animate：自動角色替換', '上傳影片和角色圖像。使用Wan2.2 Animate模型自動替換影片中的角色。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_wan22_animate_auto_character_replace', 'ja', 'Wan2.2 Animate：自動キャラクター置換', '動画とキャラクター画像をアップロードしてください。Wan2.2 Animateモデルを使用して動画内のキャラクターを自動的に置き換えます。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_wan22_animate_auto_character_replace', 'ko', 'Wan2.2 Animate: 자동 캐릭터 교체', '동영상과 캐릭터 이미지를 업로드하세요. Wan2.2 Animate 모델을 사용하여 동영상의 캐릭터를 자동으로 교체합니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_wan22_animate_auto_character_replace', 'es', 'Wan2.2 Animate: Reemplazo Automático de Personajes', 'Sube un video y una imagen de personaje. Reemplaza automáticamente al personaje en el video usando el modelo Wan2.2 Animate.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_wan22_animate_auto_character_replace', 'fr', 'Wan2.2 Animate : Remplacement Automatique de Personnages', 'Téléchargez une vidéo et une image de personnage. Remplacez automatiquement le personnage dans la vidéo à l''aide du modèle Wan2.2 Animate.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_wan22_animate_auto_character_replace', 'ru', 'Wan2.2 Animate: Автоматическая замена персонажей', 'Загрузите видео и изображение персонажа. Автоматически замените персонажа в видео с помощью модели Wan2.2 Animate.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_wan22_animate_auto_character_replace', 'tr', 'Wan2.2 Animate: Otomatik Karakter Değiştirme', 'Bir video ve bir karakter görseli yükleyin. Wan2.2 Animate modelini kullanarak videodaki karakteri otomatik olarak değiştirin.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_wan22_animate_auto_character_replace', 'ar', 'Wan2.2 Animate: استبدال الشخصيات التلقائي', 'قم بتحميل مقطع فيديو وصورة شخصية. استبدل الشخصية في الفيديو تلقائيًا باستخدام نموذج Wan2.2 Animate.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_wan22_animate_auto_character_replace', 'pt-BR', 'Wan2.2 Animate: Substituição Automática de Personagens', 'Faça upload de um vídeo e uma imagem de personagem. Substitua automaticamente o personagem no vídeo usando o modelo Wan2.2 Animate.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (18, 'template_product_placement', 1, 17, 'Product Placement', 'Swap products into a reference scene while preserving composition and lighting. Generates a final product image and an automatic video prompt for creating polished product videos.', 'image', 'webp', NULL, '[]', '["Video","Replacement","Product"]', '["Nano Banana 2","Gemini-3.1-Pro","Kling 3.0"]', '[{"provider":["Google","Kling"]}]', '[]', '[]', '{"inputs":[{"nodeId":1,"nodeType":"LoadImage","file":"product_1_product_placement.png","mediaType":"image"},{"nodeId":2,"nodeType":"LoadImage","file":"product_2_product_placement.png","mediaType":"image"},{"nodeId":3,"nodeType":"LoadImage","file":"product_3_product_placement.png","mediaType":"image"},{"nodeId":5,"nodeType":"LoadImage","file":"reference_image_product_placement.png","mediaType":"image"}],"outputs":[{"nodeId":10,"nodeType":"SaveVideo","file":"template_product_placement.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-30', 0, 'active', 0, 0, 0, 0, 'Julien | MJM', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_product_placement', 'en', 'Product Placement', 'Swap products into a reference scene while preserving composition and lighting. Generates a final product image and an automatic video prompt for creating polished product videos.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_product_placement', 'zh', '产品展示', '将产品替换到参考场景中，同时保持构图和光照。生成最终产品图像和自动视频提示，用于创建精美的产品视频。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_product_placement', 'zh-TW', '產品展示', '將產品替換到參考場景中，同時保持構圖和光照。生成最終產品圖像和自動影片提示，用於建立精美的產品影片。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_product_placement', 'ja', 'プロダクトプレイスメント', '構図と照明を維持しながら、参照シーンに製品を差し替えます。最終的な製品画像と、洗練された製品動画を作成するための自動ビデオプロンプトを生成します。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_product_placement', 'ko', '제품 배치', '구도와 조명을 유지하면서 참조 장면에 제품을 교체합니다. 최종 제품 이미지와 세련된 제품 동영상을 제작하기 위한 자동 비디오 프롬프트를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_product_placement', 'es', 'Colocación de Productos', 'Intercambia productos a una escena de referencia preservando la composición y la iluminación. Genera una imagen final del producto y un aviso de video automático para crear videos de producto pulidos.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_product_placement', 'fr', 'Placement de Produit', 'Échangez des produits dans une scène de référence tout en préservant la composition et l''éclairage. Génère une image produit finale et une invite vidéo automatique pour créer des vidéos produit soignées.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_product_placement', 'ru', 'Продуктовый Плейсмент', 'Заменяйте продукты в эталонной сцене с сохранением композиции и освещения. Создает итоговое изображение продукта и автоматическую видео-подсказку для создания качественных видеороликов о продукте.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_product_placement', 'tr', 'Ürün Yerleştirme', 'Kompozisyon ve ışıklandırmayı koruyarak ürünleri bir referans sahnesine takas edin. Son ürün görseli ve cilalı ürün videoları oluşturmak için otomatik bir video istemi oluşturur.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_product_placement', 'ar', 'تنسيق المنتج', 'تبادل المنتجات في مشهد مرجعي مع الحفاظ على التكوين والإضاءة. يُنشئ صورة منتج نهائية ومطالبة فيديو تلقائية لإنشاء مقاطع فيديو منتج مصقولة.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_product_placement', 'pt-BR', 'Posicionamento de Produto', 'Troque produtos para uma cena de referência preservando a composição e a iluminação. Gera uma imagem final do produto e um prompt de vídeo automático para criar vídeos de produto polidos.', 0, NULL, '2026-04-19T13:33:43.914Z');
