INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_qwen_image_illustration_lora', 'en', 'Qwen Image: Illustration LoRA', 'A t2v workflows for a style LoRA built on Qwen-Image. Produces images spanning cute anime character design, European bande dessinee, indie risograph prints, storybook watercolor, retro shoujo manga, and graphic novel illustration.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_qwen_image_illustration_lora', 'zh', 'Qwen Image：插画LoRA', '基于Qwen-Image构建的风格LoRA的t2v工作流。生成涵盖可爱动漫角色设计、欧洲连环漫画、独立孔版印刷、故事书水彩、复古少女漫画和图像小说插图的图像。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_qwen_image_illustration_lora', 'zh-TW', 'Qwen Image：插畫LoRA', '基於Qwen-Image構建的風格LoRA的t2v工作流。生成涵蓋可愛動漫角色設計、歐洲連環漫畫、獨立孔版印刷、故事書水彩、復古少女漫畫和圖像小說插圖的圖像。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_qwen_image_illustration_lora', 'ja', 'Qwen Image：イラストLoRA', 'Qwen-Image上に構築されたスタイルLoRAのt2vワークフロー。可愛いアニメキャラクターデザイン、欧州バンドデシネ、インディーリソグラフ印刷、絵本風水彩画、レトロ少女漫画、グラフィックノベルイラストにわたる画像を生成します。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_qwen_image_illustration_lora', 'ko', 'Qwen Image：일러스트 LoRA', 'Qwen-Image에 구축된 스타일 LoRA용 t2v 워크플로우입니다. 귀여운 애니메이션 캐릭터 디자인, 유럽 만화, 인디 리소그래프 인쇄, 동화책 수채화, 레트로 소녀 만화, 그래픽 노블 일러스트에 이르는 이미지를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_qwen_image_illustration_lora', 'es', 'Qwen Image: LoRA de ilustración', 'Un flujo de trabajo t2v para un LoRA de estilo construido sobre Qwen-Image. Produce imágenes que abarcan diseño de personajes de anime lindo, bande dessinee europea, impresiones risográficas independientes, acuarela de libro de cuentos, manga shoujo retro e ilustración de novela gráfica.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_qwen_image_illustration_lora', 'fr', 'Qwen Image : LoRA d''illustration', 'Un flux de travail t2v pour un LoRA de style construit sur Qwen-Image. Produit des images couvrant la conception de personnages d''anime mignons, la bande dessinée européenne, les impressions risographiques indépendantes, l''aquarelle de livre d''histoires, le manga shoujo rétro et l''illustration de roman graphique.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_qwen_image_illustration_lora', 'ru', 'Qwen Image: LoRA для иллюстраций', 't2v рабочий процесс для стилевого LoRA, построенного на Qwen-Image. Создает изображения, охватывающие милый дизайн аниме-персонажей, европейскую bande dessinee, независимую ризографическую печать, акварель для книг с картинками, ретро сёдзе-мангу и иллюстрации для графических романов.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_qwen_image_illustration_lora', 'tr', 'Qwen Image: İllüstrasyon LoRA', 'Qwen-Image üzerine inşa edilmiş bir stil LoRA için t2v iş akışı. Sevimli anime karakter tasarımı, Avrupa bande dessinee, bağımsız risograf baskılar, resimli kitap suluboya, retro shoujo manga ve grafik roman illüstrasyonunu kapsayan görüntüler üretir.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_qwen_image_illustration_lora', 'ar', 'Qwen Image: لوحة LoRA التوضيحية', 'سير عمل t2v لنمط LoRA مبني على Qwen-Image. ينتج صورًا تشمل تصميم شخصيات أنيمي لطيفة، ورسوم القصص المصورة الأوروبية، وطباعة ريزوغراف المستقلة، وألوان مائية لكتب القصص، ومانغا شوجو بأسلوب قديم، ورسوم الروايات المصورة.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_qwen_image_illustration_lora', 'pt-BR', 'Qwen Image: LoRA de Ilustração', 'Um fluxo de trabalho t2v para um LoRA de estilo construído no Qwen-Image. Produz imagens que abrangem design de personagens de anime fofos, bande dessinee europeia, impressões risográficas independentes, aquarela de livro de histórias, mangá shoujo retrô e ilustração de graphic novel.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (21, 'template_sugar_coated_gummy_style_qwen', 1, 20, 'Qwen Image: Gummy Animals LoRA', 'Apply a Qwen Image LoRA to transform any subject into a sour gummy candy-style character. Enter an animal name in the prompt to generate a stylized, edible-looking creature.', 'image', 'webp', NULL, '["output/template_sugar_coated_gummy_style_qwen.png"]', '["Image","LoRA"]', '["Qwen-Image"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":60,"nodeType":"SaveImage","file":"template_sugar_coated_gummy_style_qwen.png","mediaType":"image"}]}', NULL, NULL, '2026-03-30', 1, 'active', 30709016166, 30709016166, 0, 0, 'enigmatic_e', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sugar_coated_gummy_style_qwen', 'en', 'Qwen Image: Gummy Animals LoRA', 'Apply a Qwen Image LoRA to transform any subject into a sour gummy candy-style character. Enter an animal name in the prompt to generate a stylized, edible-looking creature.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sugar_coated_gummy_style_qwen', 'zh', 'Qwen Image：软糖动物LoRA', '应用Qwen图像LoRA，将任何主题转化为酸软糖风格的角色。在提示中输入动物名称，生成具有风格化、可食用外观的生物。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sugar_coated_gummy_style_qwen', 'zh-TW', 'Qwen Image：軟糖動物LoRA', '應用Qwen圖像LoRA，將任何主題轉化為酸軟糖風格的角色。在提示中輸入動物名稱，生成具有風格化、可食用外觀的生物。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sugar_coated_gummy_style_qwen', 'ja', 'Qwen Image：グミ動物LoRA', 'Qwen画像LoRAを適用して、あらゆる被写体を酸っぱいグミキャンディ風のキャラクターに変えます。プロンプトに動物の名前を入力すると、スタイライズされた食用に見える生き物が生成されます。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sugar_coated_gummy_style_qwen', 'ko', 'Qwen Image：젤리 동물 LoRA', 'Qwen 이미지 LoRA를 적용하여 모든 주제를 신맛 나는 구미 캔디 스타일의 캐릭터로 변환하세요. 프롬프트에 동물 이름을 입력하면 스타일화된, 먹을 수 있어 보이는 생물이 생성됩니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sugar_coated_gummy_style_qwen', 'es', 'Qwen Image: Gominolas Animales LoRA', 'Aplica un LoRA de imagen Qwen para transformar cualquier sujeto en un personaje con estilo de gominola ácida. Introduce un nombre de animal en el prompt para generar una criatura estilizada con apariencia comestible.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sugar_coated_gummy_style_qwen', 'fr', 'Qwen Image : Animaux en gélatine LoRA', 'Appliquez un LoRA d''image Qwen pour transformer n''importe quel sujet en un personnage de style bonbon gélifié acidulé. Entrez un nom d''animal dans l''invite pour générer une créature stylisée à l''apparence comestible.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sugar_coated_gummy_style_qwen', 'ru', 'Qwen Image: Желейные животные LoRA', 'Примените Qwen Image LoRA, чтобы превратить любой объект в персонажа в стиле кислой жевательной конфеты. Введите название животного в запросе, чтобы создать стилизованное существо, выглядящее съедобным.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sugar_coated_gummy_style_qwen', 'tr', 'Qwen Image: Sakızlı Hayvanlar LoRA', 'Herhangi bir konuyu ekşi sakızlı şeker tarzı bir karaktere dönüştürmek için bir Qwen Görüntü LoRA''sı uygulayın. Stilize, yenilebilir görünümlü bir yaratık oluşturmak için isteme bir hayvan adı girin.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sugar_coated_gummy_style_qwen', 'ar', 'Qwen Image: حيوانات جيلاتينية LoRA', 'طبق Qwen Image LoRA لتحويل أي موضوع إلى شخصية بأسلوب حلوى الجيلي الحامضة. أدخل اسم حيوان في المطالبة لإنشاء مخلوق مُصمم بمظهر صالح للأكل.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sugar_coated_gummy_style_qwen', 'pt-BR', 'Qwen Image: Animais de Goma LoRA', 'Aplique um LoRA de imagem Qwen para transformar qualquer assunto em um personagem no estilo de bala de goma azeda. Insira um nome de animal no prompt para gerar uma criatura estilizada com aparência comestível.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (22, 'tempate_eric_thumbnail_generator', 1, 21, 'YouTube Thumbnail Generator', 'Generate high-contrast, clickable YouTube thumbnails using Nano Banana Pro. Creates dramatic compositions with exaggerated subjects and bold color strategies for maximum engagement.', 'image', 'webp', NULL, '["output/ComfyUI_00223_.png"]', '["Image"]', '["Nano Banana Pro"]', '[{"provider":"Google"}]', '[]', '[]', '{"inputs":[{"nodeId":16,"nodeType":"LoadImage","file":"man_with_dog.png","mediaType":"image"}],"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"ComfyUI_00223_.png","mediaType":"image"}]}', NULL, NULL, '2026-03-21', 0, 'active', 0, 0, 0, 0, 'enigmatic_e', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_thumbnail_generator', 'en', 'YouTube Thumbnail Generator', 'Generate high-contrast, clickable YouTube thumbnails using Nano Banana Pro. Creates dramatic compositions with exaggerated subjects and bold color strategies for maximum engagement.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_thumbnail_generator', 'zh', 'YouTube 缩略图生成器', '使用Nano Banana Pro生成高对比度、可点击的YouTube缩略图。通过夸张的主体和鲜明的色彩策略创造戏剧性构图，实现最大参与度。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_thumbnail_generator', 'zh-TW', 'YouTube 縮圖產生器', '使用Nano Banana Pro生成高對比度、可點擊的YouTube縮圖。透過誇張的主體和鮮明的色彩策略創造戲劇性構圖，實現最大參與度。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_thumbnail_generator', 'ja', 'YouTube サムネイルジェネレーター', 'Nano Banana Proを使用して、高コントラストでクリック可能なYouTubeサムネイルを生成します。誇張された被写体と大胆な色彩戦略でドラマチックな構図を作り出し、最大限のエンゲージメントを実現します。', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_thumbnail_generator', 'ko', 'YouTube 썸네일 생성기', 'Nano Banana Pro를 사용하여 고대비, 클릭 가능한 YouTube 썸네일을 생성합니다. 과장된 주제와 대담한 색상 전략으로 극적인 구도를 만들어 최대 참여도를 달성합니다.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_thumbnail_generator', 'es', 'Generador de miniaturas de YouTube', 'Genera miniaturas de YouTube de alto contraste y clicables con Nano Banana Pro. Crea composiciones dramáticas con sujetos exagerados y estrategias de color audaces para maximizar la participación.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_thumbnail_generator', 'fr', 'Générateur de miniatures YouTube', 'Générez des miniatures YouTube à fort contraste et cliquables avec Nano Banana Pro. Créez des compositions dramatiques avec des sujets exagérés et des stratégies de couleurs audacieuses pour un engagement maximal.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_thumbnail_generator', 'ru', 'Генератор миниатюр YouTube', 'Создавайте высококонтрастные, кликабельные миниатюры для YouTube с помощью Nano Banana Pro. Создавайте драматичные композиции с преувеличенными объектами и смелыми цветовыми стратегиями для максимального вовлечения.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_thumbnail_generator', 'tr', 'YouTube Küçük Resim Oluşturucu', 'Nano Banana Pro ile yüksek kontrastlı, tıklanabilir YouTube küçük resimleri oluşturun. Abartılı konular ve cesur renk stratejileriyle dramatik kompozisyonlar yaratın ve maksimum etkileşim sağlayın.', 0, NULL, '2026-04-19T13:33:43.914Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_thumbnail_generator', 'ar', 'منشئ صور مصغرة لـ YouTube', 'أنشئ صورًا مصغرة قابلة للنقر وعالية التباين لـ YouTube باستخدام Nano Banana Pro. أنشئ تركيبات درامية بموضوعات مبالغ فيها واستراتيجيات ألوان جريئة لتحقيق أقصى قدر من التفاعل.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_thumbnail_generator', 'pt-BR', 'Gerador de Miniaturas do YouTube', 'Gere miniaturas do YouTube de alto contraste e clicáveis usando o Nano Banana Pro. Crie composições dramáticas com assuntos exagerados e estratégias de cores ousadas para o máximo de engajamento.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (23, 'templates_ohneis_i2v', 1, 22, 'Image to Video', 'This is the base workflow behind my viral Wes Anderson-style reel on Instagram.  It shows how to go from a simple prompt to a Wes Anderson-style image using a cinematic image model, then enhance it with Nanobanana to improve textures and details, and finally turn it into a video using the current best video model, Kling 3.0.', 'image', 'webp', 'compareSlider', '["thumbnail/templates_ohneis_i2v-1.png","thumbnail/templates_ohneis_i2v-2.png"]', '["Image to Video","Text to Image","Video"]', '["Kling 2.6","Nano Banana Pro","Z-Image-Turbo"]', '[{"provider":["Google","Kling"]}]', '[]', '[]', '{"outputs":[{"nodeId":66,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":63,"nodeType":"SaveVideo","file":"","mediaType":"video"},{"nodeId":9,"nodeType":"SaveImage","file":"","mediaType":"image"}]}', NULL, NULL, '2026-03-19', 0, 'active', 20723217203, 20723217203, 0, 0, 'ohneis652', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ohneis_i2v', 'en', 'Image to Video', 'This is the base workflow behind my viral Wes Anderson-style reel on Instagram.  It shows how to go from a simple prompt to a Wes Anderson-style image using a cinematic image model, then enhance it with Nanobanana to improve textures and details, and finally turn it into a video using the current best video model, Kling 3.0.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ohneis_i2v', 'zh', '图生视频', '这是我Instagram上爆火的韦斯·安德森风格短视频背后的基础工作流程。它展示了如何从一个简单的提示词开始，通过电影级图像模型生成韦斯·安德森风格的图像，接着用Nanobanana增强纹理与细节，最后利用当前最佳视频模型Kling 3.0将其转化为视频。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ohneis_i2v', 'zh-TW', '圖像轉影片', '這是我在Instagram上爆紅的魏斯·安德森風格短片的基礎工作流程。它展示了如何從簡單的提示開始，使用電影影像模型生成魏斯·安德森風格的圖像，接著用Nanobanana增強紋理和細節，最後利用當前最佳的影片模型Kling 3.0將其轉換為影片。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ohneis_i2v', 'ja', '画像から動画へ', 'これは、私のInstagramでバズったウェス・アンダーソン風リールの基本的なワークフローです。シンプルなプロンプトから、映画的な画像モデルを使ってウェス・アンダーソン風の画像を生成し、Nanobananaで質感やディテールを向上させ、最後に現在最高のビデオモデルであるKling 3.0を使って動画に変換するまでの流れを示しています。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ohneis_i2v', 'ko', '이미지를 동영상으로', '이것은 제 인스타그램에서 바이럴이 된 웨스 앤더슨 스타일 릴의 기본 워크플로입니다. 시네마틱 이미지 모델을 사용해 간단한 프롬프트에서 웨스 앤더슨 스타일 이미지로 나아가는 방법을 보여주고, 나노바나나로 텍스처와 디테일을 개선한 후, 현재 최고의 비디오 모델인 클링 3.0을 사용해 비디오로 전환하는 과정입니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ohneis_i2v', 'es', 'Imagen a video', 'Este es el flujo de trabajo base detrás de mi reel viral al estilo Wes Anderson en Instagram. Muestra cómo pasar de un simple prompt a una imagen al estilo Wes Anderson usando un modelo de imagen cinematográfica, luego mejorarla con Nanobanana para perfeccionar texturas y detalles, y finalmente convertirla en un video usando el mejor modelo de video actual, Kling 3.0.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ohneis_i2v', 'fr', 'Image en vidéo', 'Voici le processus de base derrière mon montage viral de style Wes Anderson sur Instagram. Il montre comment passer d''une simple instruction à une image de style Wes Anderson en utilisant un modèle d''image cinématographique, puis l''améliorer avec Nanobanana pour rehausser les textures et les détails, et enfin la transformer en vidéo en utilisant le meilleur modèle vidéo actuel, Kling 3.0.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ohneis_i2v', 'ru', 'Изображение в видео', 'Это базовая рабочая схема моего вирусного рила в стиле Уэса Андерсона для Instagram. Она показывает, как перейти от простого текстового запроса к изображению в стиле Уэса Андерсона с помощью кинематографической модели для генерации изображений, затем улучшить его с помощью Nanobanana для проработки текстур и деталей и, наконец, превратить в видео с использованием текущей лучшей модели для видео — Kling 3.0.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ohneis_i2v', 'tr', 'Görüntüden Videoya', 'Bu, Instagram''da viral olan Wes Anderson tarzı reel''imin arkasındaki temel iş akışıdır. Basit bir prompt''tan, sinematik bir görüntü modeli kullanarak Wes Anderson tarzı bir görüntüye nasıl ulaşılacağını, ardından dokuları ve detayları iyileştirmek için Nanobanana ile nasıl geliştirileceğini ve son olarak mevcut en iyi video modeli Kling 3.0 kullanarak bunu nasıl bir videoya dönüştüreceğinizi gösterir.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ohneis_i2v', 'ar', 'الصورة إلى فيديو', 'هذا هو سير العمل الأساسي وراء الفيديو الذي حقق انتشارًا واسعًا على إنستغرام بأسلوب ويس أندرسون. يوضح كيفية الانتقال من أمر نصي بسيط إلى صورة بأسلوب ويس أندرسون باستخدام نموذج صور سينمائي، ثم تحسينها باستخدام Nanobanana لتحسين القوام والتفاصيل، وأخيرًا تحويلها إلى فيديو باستخدام أفضل نموذج فيديو حاليًا، Kling 3.0.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ohneis_i2v', 'pt-BR', 'Imagem para Vídeo', 'Este é o fluxo de trabalho básico por trás do meu reel viral no estilo Wes Anderson no Instagram. Ele mostra como ir de um prompt simples a uma imagem no estilo Wes Anderson usando um modelo de imagem cinematográfica, depois aprimorá-la com o Nanobanana para melhorar texturas e detalhes e, finalmente, transformá-la em vídeo usando o atual melhor modelo de vídeo, o Kling 3.0.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (24, 'templates_doc_workbox_poster_recreator', 1, 23, 'Realistic Poster Redesign With Character Transformation', 'Transform uploaded images into realistic poster designs. Change character poses, faces, and clothing while maintaining artistic style and color schemes. Outputs a visually impactful poster with artistic typography.', 'image', 'webp', NULL, '["output/templates_doc_workbox_poster_recreator.png"]', '["Poster","Image Edit"]', '["Nano Banana Pro"]', '[{"provider":"Google"}]', '[]', '[]', '{"inputs":[{"nodeId":3,"nodeType":"LoadImage","file":"reference_poster.png","mediaType":"image"}],"outputs":[{"nodeId":4,"nodeType":"SaveImage","file":"templates_doc_workbox_poster_recreator.png","mediaType":"image"}]}', NULL, NULL, '2026-03-21', 0, 'active', 0, 0, 0, 0, 'Doc_workBox', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_poster_recreator', 'en', 'Realistic Poster Redesign With Character Transformation', 'Transform uploaded images into realistic poster designs. Change character poses, faces, and clothing while maintaining artistic style and color schemes. Outputs a visually impactful poster with artistic typography.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_poster_recreator', 'zh', '写实海报重设计，角色形象焕新', '将上传的图片转化为逼真的海报设计。在保持艺术风格和配色方案的同时，改变人物姿势、面部和服装。输出具有艺术字体、视觉冲击力强的海报。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_poster_recreator', 'zh-TW', '寫實海報重設計，角色形象煥新', '將上傳的圖片轉化為逼真的海報設計。在保持藝術風格和配色方案的同時，改變人物姿勢、面部和服裝。輸出具有藝術字體、視覺衝擊力強的海報。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_poster_recreator', 'ja', 'キャラクター変身を伴うリアルなポスターリデザイン', 'アップロードした画像をリアルなポスターデザインに変換します。芸術的なスタイルとカラースキームを維持しながら、キャラクターのポーズ、顔、服装を変更します。芸術的なタイポグラフィを用いた視覚的にインパクトのあるポスターを出力します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_poster_recreator', 'ko', '캐릭터 변신을 담은 사실적인 포스터 리디자인', '업로드한 이미지를 사실적인 포스터 디자인으로 변환합니다. 예술적 스타일과 색상 구성을 유지하면서 캐릭터의 포즈, 얼굴, 의상을 변경합니다. 예술적인 타이포그래피가 적용된 시각적으로 강렬한 포스터를 출력합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_poster_recreator', 'es', 'Rediseño de póster realista con transformación de personaje', 'Transforma imágenes subidas en diseños de póster realistas. Cambia las poses, rostros y ropa de los personajes manteniendo el estilo artístico y las combinaciones de colores. Genera un póster visualmente impactante con tipografía artística.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_poster_recreator', 'fr', 'Redesign d''affiche réaliste avec transformation de personnage', 'Transformez les images téléchargées en conceptions d''affiches réalistes. Modifiez les poses, les visages et les vêtements des personnages tout en conservant le style artistique et les schémas de couleurs. Produisez une affiche visuellement percutante avec une typographie artistique.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_poster_recreator', 'ru', 'Реалистичный редизайн постера с трансформацией персонажа', 'Преобразуйте загруженные изображения в реалистичные дизайны постеров. Изменяйте позы, лица и одежду персонажей, сохраняя художественный стиль и цветовые схемы. Создавайте визуально эффектный постер с художественной типографикой.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_poster_recreator', 'tr', 'Karakter Dönüşümü İçeren Gerçekçi Poster Yeniden Tasarımı', 'Yüklenen görüntüleri gerçekçi poster tasarımlarına dönüştürün. Sanatsal stil ve renk şemalarını korurken karakter pozlarını, yüzlerini ve kıyafetlerini değiştirin. Sanatsal tipografi ile görsel olarak etkileyici bir poster çıktısı alın.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_poster_recreator', 'ar', 'إعادة تصميم ملصق واقعي مع تحول الشخصية', 'حوِّل الصور المرفوعة إلى تصاميم بوسترات واقعية. غيِّر أوضاع الشخصيات ووجوهها وملابسها مع الحفاظ على الأسلوب الفني وأنظمة الألوان. أنتج بوسترًا مؤثرًا بصريًا بطباعة فنية.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_poster_recreator', 'pt-BR', 'Redesign de Pôster Realista com Transformação de Personagem', 'Transforme imagens enviadas em designs de pôster realistas. Altere poses, rostos e roupas de personagens mantendo o estilo artístico e esquemas de cores. Gera um pôster visualmente impactante com tipografia artística.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (25, 'templates_rob_fashion_shoot_vton-4in1.app', 1, 24, 'Virtual Try On with Character - 4 in 1', 'Upload an image of your character and a flatlay of an outfit to be tried on. Generate 4 images in 1 Nano Banana prompt.', 'image', 'webp', NULL, '["thumbnail/templates_rob_fashion_shoot_vton-4in1_app.png"]', '["Image Edit","virtual try on"]', '["Nano Banana Pro"]', '[{"provider":"Google"}]', '["comfyui-kjnodes","comfyui_essentials"]', '["cloud"]', '{"inputs":[{"nodeId":1,"nodeType":"LoadImage","file":"subject-templates_rob_fashion_shoot_vton-4in1.png","mediaType":"image"},{"nodeId":35,"nodeType":"LoadImage","file":"outfit-templates_rob_fashion_shoot_vton-4in1.png","mediaType":"image"}],"outputs":[{"nodeId":13,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":15,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":12,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":8,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":14,"nodeType":"SaveImage","file":"","mediaType":"image"}]}', NULL, NULL, '2026-03-09', 0, 'active', 0, 0, 5, 0, 'hellorob', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_fashion_shoot_vton-4in1.app', 'en', 'Virtual Try On with Character - 4 in 1', 'Upload an image of your character and a flatlay of an outfit to be tried on. Generate 4 images in 1 Nano Banana prompt.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_fashion_shoot_vton-4in1.app', 'zh', '虚拟角色试穿 - 四合一', '上传一张角色图片和一套待试穿的平铺服装。在1个Nano Banana提示中生成4张图片。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_fashion_shoot_vton-4in1.app', 'zh-TW', '虛擬角色試穿 - 四合一', '上傳一張角色圖片和一套待試穿的平鋪服裝。在1個Nano Banana提示中生成4張圖片。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_fashion_shoot_vton-4in1.app', 'ja', 'キャラクター仮想試着 - 4 in 1', 'キャラクターの画像と試着する服装のフラットレイをアップロードしてください。1つのNano Bananaプロンプトで4枚の画像を生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_fashion_shoot_vton-4in1.app', 'ko', '캐릭터 가상 착용 - 4 in 1', '캐릭터 이미지와 입어 볼 의상의 플랫레이를 업로드하세요. 1개의 Nano Banana 프롬프트로 4장의 이미지를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_fashion_shoot_vton-4in1.app', 'es', 'Prueba Virtual con Personaje - 4 en 1', 'Sube una imagen de tu personaje y un flatlay de un atuendo para probar. Genera 4 imágenes en 1 prompt de Nano Banana.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_fashion_shoot_vton-4in1.app', 'fr', 'Essai Virtuel avec Personnage - 4 en 1', 'Téléchargez une image de votre personnage et un flatlay d''une tenue à essayer. Générez 4 images en 1 prompt Nano Banana.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_fashion_shoot_vton-4in1.app', 'ru', 'Виртуальная примерка с персонажем - 4 в 1', 'Загрузите изображение вашего персонажа и плоскую раскладку наряда для примерки. Сгенерируйте 4 изображения в 1 промпте Nano Banana.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_fashion_shoot_vton-4in1.app', 'tr', 'Karakter ile Sanal Deneme - 4''ü 1 Arada', 'Karakterinizin bir görselini ve denenecek bir kıyafetin düz yerleşimini yükleyin. 1 Nano Banana istemiyle 4 görsel oluşturun.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_fashion_shoot_vton-4in1.app', 'ar', 'تجربة افتراضية مع شخصية - 4 في 1', 'قم بتحميل صورة لشخصيتك وتخطيط مسطح لزي لتجربته. أنشئ 4 صور في 1 مطالبة Nano Banana.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_fashion_shoot_vton-4in1.app', 'pt-BR', 'Experimentação Virtual com Personagem - 4 em 1', 'Faça upload de uma imagem do seu personagem e de um flatlay de uma roupa para experimentar. Gere 4 imagens em 1 prompt do Nano Banana.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (26, 'templates_rob_kling3_0_multishot_llm_product', 1, 25, 'Kling 3.0: 1 Click Multishot', 'Upload a start frame and references of your product. Select total duration and number of shots and automatically generate prompts for each shot.', 'image', 'webp', NULL, '["output/templates_rob_kling3_0_multishot_llm_product.mp4"]', '["Video"]', '["Kling 3.0"]', '[{"provider":["Kling","Google"]}]', '["comfyui-kjnodes","comfyui-string-converter","was-ns"]', '[]', '{"inputs":[{"nodeId":4,"nodeType":"LoadImage","file":"comfy_gpu_angled.png","mediaType":"image"},{"nodeId":8,"nodeType":"LoadImage","file":"comfy_gpu_flat.png","mediaType":"image"},{"nodeId":12,"nodeType":"LoadImage","file":"comfy_gpu_close_up.png","mediaType":"image"}],"outputs":[{"nodeId":89,"nodeType":"SaveVideo","file":"templates_rob_kling3_0_multishot_llm_product.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-18', 0, 'active', 0, 0, 197, 0, 'hellorob', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_kling3_0_multishot_llm_product', 'en', 'Kling 3.0: 1 Click Multishot', 'Upload a start frame and references of your product. Select total duration and number of shots and automatically generate prompts for each shot.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_kling3_0_multishot_llm_product', 'zh', 'Kling 3.0：一键多拍', '上传产品的起始帧和参考图。选择总时长和镜头数量，自动为每个镜头生成提示词。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_kling3_0_multishot_llm_product', 'zh-TW', 'Kling 3.0：一鍵多拍', '上傳產品的起始幀和參考圖。選擇總時長和鏡頭數量，自動為每個鏡頭生成提示詞。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_kling3_0_multishot_llm_product', 'ja', 'Kling 3.0：ワンクリックマルチショット', '製品の開始フレームと参考画像をアップロードしてください。総時間とショット数を選択し、各ショットのプロンプトを自動生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_kling3_0_multishot_llm_product', 'ko', 'Kling 3.0: 원클릭 멀티샷', '제품의 시작 프레임과 참고 자료를 업로드하세요. 총 지속 시간과 샷 수를 선택하고 각 샷에 대한 프롬프트를 자동으로 생성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_kling3_0_multishot_llm_product', 'es', 'Kling 3.0: Multidisparo con 1 clic', 'Sube un fotograma inicial y referencias de tu producto. Selecciona la duración total y el número de tomas, y genera automáticamente indicaciones para cada toma.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_kling3_0_multishot_llm_product', 'fr', 'Kling 3.0 : Multishot en 1 clic', 'Téléchargez une image de départ et des références de votre produit. Sélectionnez la durée totale et le nombre de plans, puis générez automatiquement des invites pour chaque plan.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_kling3_0_multishot_llm_product', 'ru', 'Kling 3.0: Мультисъемка в 1 клик', 'Загрузите стартовый кадр и референсы вашего продукта. Выберите общую продолжительность и количество кадров, чтобы автоматически сгенерировать промпты для каждого кадра.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_kling3_0_multishot_llm_product', 'tr', 'Kling 3.0: 1 Tıkla Çoklu Çekim', 'Ürününüzün bir başlangıç karesini ve referanslarını yükleyin. Toplam süreyi ve çekim sayısını seçin ve her çekim için otomatik olarak istemler oluşturun.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_kling3_0_multishot_llm_product', 'ar', 'Kling 3.0: لقطة متعددة بنقرة واحدة', 'قم بتحميل إطار بداية ومراجع لمنتجك. اختر المدة الإجمالية وعدد اللقطات وقم بتوليد تلميحات تلقائيًا لكل لقطة.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_rob_kling3_0_multishot_llm_product', 'pt-BR', 'Kling 3.0: Multishot com 1 Clique', 'Faça upload de um quadro inicial e referências do seu produto. Selecione a duração total e o número de cenas e gere automaticamente prompts para cada cena.', 0, NULL, '2026-04-19T13:33:43.915Z');
