INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sferro21_product_ad.app', 'ja', '製品広告シネマティックシーケンスジェネレーター', '製品画像と映画的なスタイルの参考画像をアップロードしてください。一貫した構図と照明でスタイライズされた製品広告のシーケンスを生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sferro21_product_ad.app', 'ko', '제품 광고 시네마틱 시퀀스 생성기', '제품 이미지와 시네마틱 스타일 참고 자료를 업로드하세요. 일관된 구도와 조명으로 스타일화된 제품 광고 시퀀스를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sferro21_product_ad.app', 'es', 'Generador de Secuencias Cinematográficas para Anuncios de Productos', 'Sube una imagen del producto y una referencia de estilo cinematográfico. Genera una secuencia de anuncios de productos estilizados con composición e iluminación consistentes.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sferro21_product_ad.app', 'fr', 'Générateur de Séquences Cinématographiques pour Publicités Produit', 'Téléchargez une image du produit et une référence de style cinématographique. Générez une séquence de publicités de produits stylisées avec une composition et un éclairage cohérents.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sferro21_product_ad.app', 'ru', 'Генератор кинематографических последовательностей для рекламы продуктов', 'Загрузите изображение товара и референс кинематографического стиля. Создайте серию стилизованных рекламных материалов для товара с единообразной композицией и освещением.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sferro21_product_ad.app', 'tr', 'Ürün Reklamı Sinematik Dizi Oluşturucu', 'Bir ürün görseli ve sinematik bir stil referansı yükleyin. Tutarlı kompozisyon ve ışıklandırma ile stilize edilmiş ürün reklamları dizisi oluşturun.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sferro21_product_ad.app', 'ar', 'مولد تسلسل سينمائي لإعلانات المنتجات', 'قم بتحميل صورة المنتج ومرجع أسلوب سينمائي. قم بإنشاء سلسلة من إعلانات المنتجات الأنيقة بتكوين وإضاءة متناسقين.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sferro21_product_ad.app', 'pt-BR', 'Gerador de Sequência Cinematográfica para Anúncios de Produtos', 'Faça upload de uma imagem do produto e uma referência de estilo cinematográfico. Gere uma sequência de anúncios de produtos estilizados com composição e iluminação consistentes.', 0, NULL, '2026-04-19T13:33:43.915Z');
