INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_hellorob_facegen_skindetail_upscale', 'en', 'Skin Enhancer + Upscaler', 'One click workflow to generate a character portrait, refine/add skin details, and upscale to 4k. All done in less than 60 seconds.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_hellorob_facegen_skindetail_upscale', 'zh', '皮肤增强器 + 放大器', '一键式工作流，生成角色肖像、优化/添加皮肤细节，并提升至4K分辨率。全部过程不到60秒完成。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_hellorob_facegen_skindetail_upscale', 'zh-TW', '皮膚增強器 + 放大器', '一鍵式工作流程，生成角色肖像、優化/添加皮膚細節，並提升至4K解析度。全部過程不到60秒完成。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_hellorob_facegen_skindetail_upscale', 'ja', 'スキンエンハンサー + アップスケーラー', 'ワンクリックでキャラクターポートレートを生成し、肌の詳細を調整・追加して4Kにアップスケールするワークフロー。すべて60秒以内で完了します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_hellorob_facegen_skindetail_upscale', 'ko', '스킨 강화기 + 업스케일러', '캐릭터 초상화 생성, 피부 디테일 수정/추가, 4K 업스케일링까지 한 번의 클릭으로 가능한 워크플로우. 전체 과정 60초 미만 소요.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_hellorob_facegen_skindetail_upscale', 'es', 'Mejorador de Piel + Escalador', 'Flujo de trabajo con un clic para generar un retrato de personaje, refinar/añadir detalles de piel y escalar a 4K. Todo realizado en menos de 60 segundos.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_hellorob_facegen_skindetail_upscale', 'fr', 'Améliorateur de Peau + Suréchantillonneur', 'Workflow en un clic pour générer un portrait de personnage, affiner/ajouter des détails de peau et upscaler en 4K. Le tout réalisé en moins de 60 secondes.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_hellorob_facegen_skindetail_upscale', 'ru', 'Улучшитель кожи + Апскейлер', 'Однощелчковый рабочий процесс для создания портрета персонажа, улучшения/добавления деталей кожи и масштабирования до 4K. Все выполняется менее чем за 60 секунд.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_hellorob_facegen_skindetail_upscale', 'tr', 'Cilt Geliştirici + Yükseltici', 'Karakter portresi oluşturmak, cilt detaylarını iyileştirmek/eklemek ve 4K''ya yükseltmek için tek tıklamalı iş akışı. Tümü 60 saniyeden kısa sürede tamamlanır.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_hellorob_facegen_skindetail_upscale', 'ar', 'محسن البشرة + مكبر الدقة', 'سير عمل بنقرة واحدة لإنشاء صورة شخصية للشخصية، وتحسين/إضافة تفاصيل البشرة، والرفع إلى دقة 4K. كل ذلك يتم في أقل من 60 ثانية.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_hellorob_facegen_skindetail_upscale', 'pt-BR', 'Aprimorador de Pele + Upscaler', 'Fluxo de trabalho com um clique para gerar um retrato de personagem, refinar/adicionar detalhes da pele e upscale para 4K. Tudo feito em menos de 60 segundos.', 0, NULL, '2026-04-19T13:33:43.915Z');
