INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ingi_infl8', 'ja', 'インフレーションLoraキャラクター拡張効果動画', 'キャラクター画像をアップロードし、プロンプトを入力してください。キャラクターが膨張効果で膨らむアニメーションビデオを生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
