INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ingi_infl8', 'es', 'Video de Efecto de Expansión de Personaje Lora de Inflación', 'Sube una imagen de personaje e ingresa tu indicación. Genera un video animado donde el personaje se expande con un efecto de inflado.', 0, NULL, '2026-04-19T13:33:43.915Z');
