INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ingi_infl8', 'ru', 'Видео эффекта расширения персонажа Lora инфляции', 'Загрузите изображение персонажа и введите ваш запрос. Создайте анимированное видео, в котором персонаж расширяется с эффектом надувания.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ingi_infl8', 'tr', 'Enflasyon Lora Karakter Genişletme Efekti Videosu', 'Bir karakter görseli yükleyin ve isteminizi girin. Karakterin şişme efektiyle genişlediği animasyonlu bir video oluşturun.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ingi_infl8', 'ar', 'فيديو تأثير توسيع شخصية لورا للتضخم', 'قم بتحميل صورة شخصية وأدخل مطالبتك. أنشئ فيديو متحركًا حيث يتمدد الشخصية بتأثير التضخم.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_ingi_infl8', 'pt-BR', 'Vídeo de Efeito de Expansão de Personagem Lora de Inflação', 'Faça upload de uma imagem de personagem e insira seu prompt. Gere um vídeo animado onde o personagem se expande com um efeito de inflação.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (34, 'templates_3d_match_game_art_style.app', 1, 33, 'Game Asset Style Transfer Sprite Generator', ' Use an outline reference, and a style reference as input to generate 2D sprite as model textures. Useful for background set dressing in 2D/2.5D game.', 'image', 'webp', 'compareSlider', '["input/gas_lamp.png","output/templates_3d_match_game_art_style-1.png"]', '["Game","Style Reference"]', '["Nano Banana Pro"]', '[{"provider":"Google"}]', '[]', '[]', '{"inputs":[{"nodeId":1,"nodeType":"LoadImage","file":"game_style.png","mediaType":"image"},{"nodeId":2,"nodeType":"LoadImage","file":"gas_lamp.png","mediaType":"image"}],"outputs":[{"nodeId":5,"nodeType":"SaveImage","file":"templates_3d_match_game_art_style-1.png","mediaType":"image"},{"nodeId":3,"nodeType":"SaveImage","file":"templates_3d_match_game_art_style-2.png","mediaType":"image"}]}', NULL, NULL, '2026-03-06', 0, 'active', 0, 0, 1, 0, 'shane', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_3d_match_game_art_style.app', 'en', 'Game Asset Style Transfer Sprite Generator', ' Use an outline reference, and a style reference as input to generate 2D sprite as model textures. Useful for background set dressing in 2D/2.5D game.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_3d_match_game_art_style.app', 'zh', '游戏资源风格迁移精灵图生成器', '使用轮廓参考和风格参考作为输入，生成2D精灵作为模型纹理。适用于2D/2.5D游戏的背景布景。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_3d_match_game_art_style.app', 'zh-TW', '遊戲資源風格遷移精靈圖生成器', '使用輪廓參考和風格參考作為輸入，生成2D精靈作為模型紋理。適用於2D/2.5D遊戲的背景佈景。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_3d_match_game_art_style.app', 'ja', 'ゲームアセットスタイル転送スプライトジェネレーター', '輪郭参照とスタイル参照を入力として使用し、モデルテクスチャとして2Dスプライトを生成します。2D/2.5Dゲームの背景セット装飾に役立ちます。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_3d_match_game_art_style.app', 'ko', '게임 에셋 스타일 전환 스프라이트 생성기', '아웃라인 참조와 스타일 참조를 입력으로 사용하여 모델 텍스처로 2D 스프라이트를 생성합니다. 2D/2.5D 게임의 배경 세트 장식에 유용합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_3d_match_game_art_style.app', 'es', 'Generador de Sprites de Transferencia de Estilo para Activos de Juego', 'Utiliza una referencia de contorno y una referencia de estilo como entrada para generar sprites 2D como texturas de modelo. Útil para la ambientación de fondos en juegos 2D/2.5D.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_3d_match_game_art_style.app', 'fr', 'Générateur de Sprites par Transfert de Style d''Actifs de Jeu', 'Utilise une référence de contour et une référence de style comme entrée pour générer des sprites 2D en tant que textures de modèle. Utile pour la décoration de fond dans les jeux 2D/2.5D.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_3d_match_game_art_style.app', 'ru', 'Генератор спрайтов с переносом стиля игровых ассетов', 'Используйте контурную ссылку и ссылку на стиль в качестве входных данных для создания 2D-спрайтов в качестве текстур модели. Полезно для оформления фона в 2D/2.5D играх.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_3d_match_game_art_style.app', 'tr', 'Oyun Varlığı Stil Aktarımı Sprite Oluşturucu', 'Model dokuları olarak 2D sprite''lar oluşturmak için giriş olarak bir taslak referansı ve bir stil referansı kullanın. 2D/2.5D oyunlarda arka plan dekorasyonu için kullanışlıdır.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_3d_match_game_art_style.app', 'ar', 'مولد رسومات الألعاب بنقل النمط', 'استخدم مرجعًا للمخطط ومرجعًا للأسلوب كمدخلات لتوليد رسومات ثنائية الأبعاد كقوام للنموذج. مفيد لتزيين خلفية الألعاب ثنائية الأبعاد/ثنائية ونصف الأبعاد.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_3d_match_game_art_style.app', 'pt-BR', 'Gerador de Sprites por Transferência de Estilo de Ativos de Jogo', 'Use uma referência de contorno e uma referência de estilo como entrada para gerar sprites 2D como texturas de modelo. Útil para a decoração de cenários de fundo em jogos 2D/2.5D.', 0, NULL, '2026-04-19T13:33:43.915Z');
