INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_text_prompt_to_360hdr.app', 'ru', 'Генератор HDR-скайбокса в равнопромежуточной проекции', 'Запросите окружение и создайте равноугольную HDR-изображение для использования в качестве скайбокса или lookdev в разработке игр.', 0, NULL, '2026-04-19T13:33:43.915Z');
