INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_text_prompt_to_360hdr.app', 'pt-BR', 'Gerador de Skybox HDR Equirretangular', 'Solicite um ambiente e gere uma imagem HDR equirretangular para usar como skybox ou lookdev no desenvolvimento de jogos.', 0, NULL, '2026-04-19T13:33:43.915Z');
