INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_graphic_color_remixer', 'ko', '그래픽 디자인 리컴포저', '그래픽 디자인을 업로드하고 원하는 화면비를 선택하세요. 새로운 화면비에 맞게 그래픽을 생성 및 재구성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_graphic_color_remixer', 'es', 'Recompositor de Diseño Gráfico', 'Sube un diseño gráfico y selecciona la relación de aspecto deseada. Genera y recompone el gráfico para ajustarse a la nueva relación de aspecto.', 0, NULL, '2026-04-19T13:33:43.915Z');
