INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_graphic_color_remixer', 'ru', 'Рекомпоновщик графического дизайна', 'Загрузите графический дизайн и выберите желаемое соотношение сторон. Генерирует и перекомпоновывает графику для соответствия новому соотношению сторон.', 0, NULL, '2026-04-19T13:33:43.915Z');
