INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_graphic_color_remixer', 'ar', 'مُعاد تركيب التصميم الجرافيكي', 'قم بتحميل تصميم رسومي واختر نسبة العرض إلى الارتفاع المطلوبة. يقوم بإنشاء وإعادة تركيب الرسم ليتناسب مع نسبة العرض إلى الارتفاع الجديدة.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_graphic_color_remixer', 'pt-BR', 'Recompositor de Design Gráfico', 'Faça upload de um design gráfico e selecione a proporção desejada. Gera e recompõe o gráfico para se ajustar à nova proporção.', 0, NULL, '2026-04-19T13:33:43.915Z');
