INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_liveportrat.app', 'ar', 'LivePortrait للتعبير الوجهي', 'قم بتحميل صورة شخصية وفيديو تعبير مرجعي. أنشئ فيديو للصورة الشخصية بتعبيرات الوجه من المرجع.', 0, NULL, '2026-04-19T13:33:43.915Z');
