INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_image_script_video', 'en', 'Image to Script to Kling Video Generation', 'Upload an image to automatically generate a descriptive script. This script is then used to create a video with the Kling 3.0 Omni model.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_image_script_video', 'zh', '图像到脚本到Kling视频生成', '上传图片以自动生成描述性脚本。该脚本随后将用于通过Kling 3.0 Omni模型创建视频。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_image_script_video', 'zh-TW', '圖像到腳本到Kling影片生成', '上傳圖片以自動生成描述性腳本。該腳本隨後將用於透過Kling 3.0 Omni模型建立影片。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_image_script_video', 'ja', '画像からスクリプトへ、そしてKling動画生成へ', '画像をアップロードすると、自動的に記述スクリプトが生成されます。このスクリプトは、Kling 3.0 Omniモデルを使用して動画を作成するために使用されます。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_image_script_video', 'ko', '이미지에서 스크립트로, Kling 비디오 생성으로', '이미지를 업로드하면 자동으로 설명 스크립트가 생성됩니다. 이 스크립트는 Kling 3.0 Omni 모델을 사용하여 비디오를 만드는 데 사용됩니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_image_script_video', 'es', 'Generación de video Kling: de imagen a guion', 'Sube una imagen para generar automáticamente un guion descriptivo. Este guion se utiliza luego para crear un video con el modelo Kling 3.0 Omni.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_image_script_video', 'fr', 'Génération de vidéo Kling : de l''image au scénario', 'Téléchargez une image pour générer automatiquement un script descriptif. Ce script est ensuite utilisé pour créer une vidéo avec le modèle Kling 3.0 Omni.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_image_script_video', 'ru', 'Генерация видео Kling: от изображения к сценарию', 'Загрузите изображение, чтобы автоматически создать описательный сценарий. Этот сценарий затем используется для создания видео с помощью модели Kling 3.0 Omni.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_image_script_video', 'tr', 'Görüntüden Senaryoya, Kling Video Üretimi', 'Açıklayıcı bir senaryoyu otomatik olarak oluşturmak için bir resim yükleyin. Bu senaryo daha sonra Kling 3.0 Omni modeli ile bir video oluşturmak için kullanılır.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_image_script_video', 'ar', 'إنشاء فيديو Kling: من الصورة إلى السيناريو', 'قم بتحميل صورة لإنشاء نص وصفي تلقائيًا. ثم يُستخدم هذا النص لإنشاء فيديو باستخدام نموذج Kling 3.0 Omni.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_image_script_video', 'pt-BR', 'Geração de vídeo Kling: da imagem ao roteiro', 'Faça upload de uma imagem para gerar automaticamente um roteiro descritivo. Este roteiro é então usado para criar um vídeo com o modelo Kling 3.0 Omni.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (39, 'template_rob_realistic_2k_images_quick_variations', 1, 38, 'Realistic 2k Images - Quick Variations', 'Upload an image that you want a variation of. The workflow captions the input image, generates with Grok Image, and upscales with Z-image to add realistic textures.', 'image', 'webp', 'compareSlider', '["input/rapper_on_cliff_with_moon.png","output/template_rob_realistic_2k_images_quick_variations.png"]', '["Image Upscale","Text to Image"]', '["Grok","Z-Image-Turbo"]', '[{"provider":"Grok"}]', '[]', '[]', '{"inputs":[{"nodeId":77,"nodeType":"LoadImage","file":"rapper_on_cliff_with_moon.png","mediaType":"image"}],"outputs":[{"nodeId":103,"nodeType":"SaveImage","file":"template_rob_realistic_2k_images_quick_variations.png","mediaType":"image"},{"nodeId":108,"nodeType":"SaveImage","file":"","mediaType":"image"}]}', NULL, NULL, '2026-03-08', 0, 'active', 20723217203, 20723217203, 505, 0, 'hellorob', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_realistic_2k_images_quick_variations', 'en', 'Realistic 2k Images - Quick Variations', 'Upload an image that you want a variation of. The workflow captions the input image, generates with Grok Image, and upscales with Z-image to add realistic textures.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_realistic_2k_images_quick_variations', 'zh', '逼真2K图像 - 快速变体', '上传您想要生成变体的图像。工作流程将对输入图像进行描述，使用Grok Image生成，并通过Z-image进行超分辨率处理以添加逼真纹理。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_realistic_2k_images_quick_variations', 'zh-TW', '逼真2K圖像 - 快速變體', '上傳您想要生成變體的圖像。工作流程將對輸入圖像進行描述，使用Grok Image生成，並透過Z-image進行超解析度處理以添加逼真紋理。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_realistic_2k_images_quick_variations', 'ja', 'リアルな2K画像 - クイックバリエーション', 'バリエーションを生成したい画像をアップロードしてください。ワークフローでは、入力画像にキャプションを付け、Grok Imageで生成し、Z-imageで超解像処理を行いリアルなテクスチャを追加します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_realistic_2k_images_quick_variations', 'ko', '리얼한 2K 이미지 - 빠른 변형', '변형을 원하는 이미지를 업로드하세요. 워크플로우는 입력 이미지에 캡션을 생성하고, Grok Image로 생성하며, Z-image로 초해상도 처리하여 사실적인 텍스처를 추가합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_realistic_2k_images_quick_variations', 'es', 'Imágenes realistas 2K - Variaciones rápidas', 'Suba una imagen de la que desee una variación. El flujo de trabajo describe la imagen de entrada, genera con Grok Image y mejora la resolución con Z-image para agregar texturas realistas.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_realistic_2k_images_quick_variations', 'fr', 'Images réalistes 2K - Variations rapides', 'Téléchargez une image dont vous souhaitez une variation. Le flux de travail décrit l''image d''entrée, génère avec Grok Image, et améliore la résolution avec Z-image pour ajouter des textures réalistes.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_realistic_2k_images_quick_variations', 'ru', 'Реалистичные 2K изображения - Быстрые вариации', 'Загрузите изображение, для которого хотите создать вариацию. Рабочий процесс описывает входное изображение, генерирует с помощью Grok Image и повышает разрешение с помощью Z-image для добавления реалистичных текстур.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_realistic_2k_images_quick_variations', 'tr', 'Gerçekçi 2K Görüntüler - Hızlı Varyasyonlar', 'Bir varyasyonunu istediğiniz bir görsel yükleyin. İş akışı, girdi görselini açıklar, Grok Image ile oluşturur ve gerçekçi dokular eklemek için Z-image ile yüksek çözünürlüğe yükseltir.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_realistic_2k_images_quick_variations', 'ar', 'صور واقعية بدقة 2K - اختلافات سريعة', 'قم بتحميل صورة تريد إنشاء نسخة مختلفة منها. يقوم سير العمل بوصف الصورة المدخلة، ثم إنشاؤها باستخدام Grok Image، وتحسين دقتها باستخدام Z-image لإضافة نسيج واقعي.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_rob_realistic_2k_images_quick_variations', 'pt-BR', 'Imagens realistas 2K - Variações rápidas', 'Faça upload de uma imagem da qual você deseja uma variação. O fluxo de trabalho descreve a imagem de entrada, gera com o Grok Image e aprimora a resolução com o Z-image para adicionar texturas realistas.', 0, NULL, '2026-04-19T13:33:43.915Z');
