INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_any_aspect_ratio_nb2', 'en', 'Any Image → Any Aspect Ratio', 'Upload any image and input your desired aspect ratio. Generate an outpainted version of your image to perfectly fit the new dimensions.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_any_aspect_ratio_nb2', 'zh', '任意图像 → 任意宽高比', '上传任意图片并输入您期望的宽高比。生成您图片的扩展绘制版本，以完美适应新尺寸。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_any_aspect_ratio_nb2', 'zh-TW', '任意圖像 → 任意寬高比', '上傳任意圖片並輸入您期望的寬高比。生成您圖片的擴展繪製版本，以完美適應新尺寸。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_any_aspect_ratio_nb2', 'ja', '任意の画像 → 任意のアスペクト比', '任意の画像をアップロードし、希望のアスペクト比を入力してください。新しい寸法に完璧に合わせるために、画像の拡張描画バージョンを生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_any_aspect_ratio_nb2', 'ko', '모든 이미지 → 모든 화면비', '원하는 이미지를 업로드하고 원하는 화면비를 입력하세요. 새로운 크기에 완벽하게 맞도록 이미지의 확장 그리기 버전을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_any_aspect_ratio_nb2', 'es', 'Cualquier imagen → Cualquier relación de aspecto', 'Sube cualquier imagen e ingresa la relación de aspecto deseada. Genera una versión extendida de tu imagen para que se ajuste perfectamente a las nuevas dimensiones.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_any_aspect_ratio_nb2', 'fr', 'N''importe quelle image → N''importe quel rapport d''aspect', 'Téléchargez n''importe quelle image et saisissez le rapport d''aspect souhaité. Générez une version étendue de votre image pour qu''elle s''adapte parfaitement aux nouvelles dimensions.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_any_aspect_ratio_nb2', 'ru', 'Любое изображение → Любое соотношение сторон', 'Загрузите любое изображение и введите желаемое соотношение сторон. Создайте расширенную версию вашего изображения, чтобы она идеально соответствовала новым размерам.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_any_aspect_ratio_nb2', 'tr', 'Herhangi Bir Görsel → Herhangi Bir En Boy Oranı', 'Herhangi bir görsel yükleyin ve istediğiniz en-boy oranını girin. Yeni boyutlara mükemmel uyum sağlaması için görselinizin genişletilmiş bir versiyonunu oluşturun.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_any_aspect_ratio_nb2', 'ar', 'أي صورة → أي نسبة أبعاد', 'قم بتحميل أي صورة وأدخل نسبة العرض إلى الارتفاع المطلوبة. قم بإنشاء نسخة موسعة من صورتك لتناسب الأبعاد الجديدة بشكل مثالي.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_any_aspect_ratio_nb2', 'pt-BR', 'Qualquer Imagem → Qualquer Proporção', 'Faça upload de qualquer imagem e insira a proporção de aspecto desejada. Gere uma versão expandida da sua imagem para se ajustar perfeitamente às novas dimensões.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (44, 'templates_purz_pixel_sort_image', 1, 43, 'Pixel Sort Glitch Effect Image Transformation', 'Apply a pixel sorting algorithm to create glitch art. Control the effect direction, threshold, and blending with the original image. Outputs a stylized, smeared version of the input.', 'image', 'webp', 'compareSlider', '["input/wireframe_dancer.png","output/templates_purz_pixel_sort_image.png"]', '["Image","Style Transfer"]', '["None"]', '[]', '["comfyui_fill-nodes"]', '[]', '{"inputs":[{"nodeId":2,"nodeType":"LoadImage","file":"wireframe_dancer.png","mediaType":"image"}],"outputs":[{"nodeId":3,"nodeType":"SaveImage","file":"templates_purz_pixel_sort_image.png","mediaType":"image"}]}', NULL, NULL, '2026-03-21', 1, 'active', 0, 0, 0, 0, 'PurzBeats', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_pixel_sort_image', 'en', 'Pixel Sort Glitch Effect Image Transformation', 'Apply a pixel sorting algorithm to create glitch art. Control the effect direction, threshold, and blending with the original image. Outputs a stylized, smeared version of the input.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_pixel_sort_image', 'zh', '像素排序故障效果图像转换', '应用像素排序算法创建故障艺术。控制效果方向、阈值以及与原始图像的混合。输出风格化、涂抹效果的输入图像版本。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_pixel_sort_image', 'zh-TW', '像素排序故障效果圖像轉換', '應用像素排序演算法建立故障藝術。控制效果方向、閾值以及與原始影像的混合。輸出風格化、塗抹效果的輸入影像版本。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_pixel_sort_image', 'ja', 'ピクセルソートグリッチ効果画像変換', 'ピクセルソートアルゴリズムを適用してグリッチアートを作成します。効果の方向、しきい値、および元の画像とのブレンドを制御します。入力画像のスタイライズされたスミアバージョンを出力します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_pixel_sort_image', 'ko', '픽셀 정렬 글리치 효과 이미지 변환', '픽셀 정렬 알고리즘을 적용하여 글리치 아트를 생성합니다. 효과 방향, 임계값 및 원본 이미지와의 혼합을 제어합니다. 입력 이미지의 스타일화된 번짐 버전을 출력합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_pixel_sort_image', 'es', 'Transformación de imagen con efecto de glitch de ordenación de píxeles', 'Aplica un algoritmo de ordenación de píxeles para crear arte glitch. Controla la dirección del efecto, el umbral y la mezcla con la imagen original. Genera una versión estilizada y difuminada de la imagen de entrada.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_pixel_sort_image', 'fr', 'Transformation d''image par effet de glitch de tri de pixels', 'Appliquez un algorithme de tri de pixels pour créer un art glitch. Contrôlez la direction de l''effet, le seuil et le mélange avec l''image originale. Produit une version stylisée et étalée de l''image d''entrée.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_pixel_sort_image', 'ru', 'Преобразование изображения с эффектом глитча сортировки пикселей', 'Примените алгоритм сортировки пикселей для создания глитч-арта. Управляйте направлением эффекта, порогом и смешением с исходным изображением. Выводит стилизованную, размазанную версию входного изображения.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_pixel_sort_image', 'tr', 'Piksel Sıralama Hata Efekti Görüntü Dönüşümü', 'Glitch sanatı oluşturmak için bir piksel sıralama algoritması uygulayın. Efekt yönünü, eşik değerini ve orijinal görüntüyle karışımını kontrol edin. Girdi görüntüsünün stilize, bulaşmış bir versiyonunu çıktılar.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_pixel_sort_image', 'ar', 'تحويل الصورة بتأثير خلل فرز البكسل', 'طبق خوارزمية فرز البكسل لإنشاء فن الخلل. تحكم في اتجاه التأثير والعتبة والدمج مع الصورة الأصلية. ينتج نسخة منمقة وملطخة من الصورة المدخلة.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_pixel_sort_image', 'pt-BR', 'Transformação de imagem com efeito de glitch de ordenação de pixels', 'Aplique um algoritmo de ordenação de pixels para criar arte glitch. Controle a direção do efeito, o limite e a mesclagem com a imagem original. Gera uma versão estilizada e borrada da imagem de entrada.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (45, 'template_sirolim_seamless_loop', 1, 44, 'Video to Seamless Loop Converter', 'Upload a video clip to generate a seamless, looping video output.', 'image', 'webp', NULL, '["output/template_sirolim_seamless_loop.mp4"]', '["Video Edit"]', '["Wan2.1 VACE"]', '[]', '["comfyui-kjnodes","comfyui-videohelpersuite","comfyui_essentials"]', '[]', '{"inputs":[{"nodeId":158,"nodeType":"VHS_LoadVideo","file":"seamless_loop_input.mp4","mediaType":"video"}],"outputs":[{"nodeId":251,"nodeType":"SaveVideo","file":"template_sirolim_seamless_loop.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-08', 0, 'active', 41983305318, 41983305318, 111, 0, 'sirolim', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_seamless_loop', 'en', 'Video to Seamless Loop Converter', 'Upload a video clip to generate a seamless, looping video output.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_seamless_loop', 'zh', '视频转无缝循环转换器', '上传视频片段以生成无缝循环视频输出。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_seamless_loop', 'zh-TW', '影片轉無縫循環轉換器', '上傳影片片段以生成無縫循環影片輸出。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_seamless_loop', 'ja', '動画からシームレスループ変換ツール', 'ビデオクリップをアップロードして、シームレスなループ動画を生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_seamless_loop', 'ko', '동영상에서 매끄러운 루프 변환기', '비디오 클립을 업로드하여 매끄럽게 반복되는 비디오 출력을 생성하세요.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_seamless_loop', 'es', 'Conversor de Video a Bucle Continuo', 'Sube un clip de video para generar una salida de video en bucle sin interrupciones.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_seamless_loop', 'fr', 'Convertisseur Vidéo en Boucle Continue', 'Téléchargez un clip vidéo pour générer une sortie vidéo en boucle fluide.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_seamless_loop', 'ru', 'Конвертер видео в бесшовный цикл', 'Загрузите видеоклип для создания бесшовного зацикленного видео.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_seamless_loop', 'tr', 'Video''dan Sorunsuz Döngü Dönüştürücü', 'Kesintisiz, döngüsel bir video çıktısı oluşturmak için bir video klibi yükleyin.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_seamless_loop', 'ar', 'محول الفيديو إلى حلقة سلسة', 'قم بتحميل مقطع فيديو لإنشاء مخرج فيديو سلس ومتكرر.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_sirolim_seamless_loop', 'pt-BR', 'Conversor de Vídeo para Loop Contínuo', 'Faça upload de um clipe de vídeo para gerar uma saída de vídeo em loop contínuo.', 0, NULL, '2026-04-19T13:33:43.915Z');
