INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_nb2_single_image_sprite_sheet', 'en', 'Single Image to Animated Sprite Sheet', 'Upload a single image to generate an animated sequence. The workflow creates a sprite sheet with multiple frames for use in games or animations.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_nb2_single_image_sprite_sheet', 'zh', '单张图像转动画精灵表', '上传单张图像以生成动画序列。该工作流程创建包含多帧的精灵图，适用于游戏或动画。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_nb2_single_image_sprite_sheet', 'zh-TW', '單張圖像轉動畫精靈表', '上傳單張圖像以生成動畫序列。該工作流程創建包含多幀的精靈圖，適用於遊戲或動畫。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_nb2_single_image_sprite_sheet', 'ja', '単一画像からアニメーションスプライトシートへ', '単一の画像をアップロードしてアニメーションシーケンスを生成します。このワークフローは、ゲームやアニメーションで使用するための複数のフレームを含むスプライトシートを作成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_nb2_single_image_sprite_sheet', 'ko', '단일 이미지를 애니메이션 스프라이트 시트로', '단일 이미지를 업로드하여 애니메이션 시퀀스를 생성합니다. 이 워크플로우는 게임이나 애니메이션에 사용할 여러 프레임이 포함된 스프라이트 시트를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_nb2_single_image_sprite_sheet', 'es', 'Imagen única a hoja de sprites animada', 'Sube una sola imagen para generar una secuencia animada. El flujo de trabajo crea una hoja de sprites con múltiples fotogramas para usar en juegos o animaciones.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_nb2_single_image_sprite_sheet', 'fr', 'Image unique vers feuille de sprites animée', 'Téléchargez une seule image pour générer une séquence animée. Le flux de travail crée une feuille de sprites avec plusieurs images pour une utilisation dans les jeux ou les animations.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_nb2_single_image_sprite_sheet', 'ru', 'Одно изображение в анимированный спрайт-лист', 'Загрузите одно изображение для создания анимированной последовательности. Рабочий процесс создает спрайт-лист с несколькими кадрами для использования в играх или анимациях.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_nb2_single_image_sprite_sheet', 'tr', 'Tek Resimden Animasyonlu Sprite Sayfasına', 'Animasyonlu bir dizi oluşturmak için tek bir görsel yükleyin. İş akışı, oyunlarda veya animasyonlarda kullanılmak üzere birden fazla kare içeren bir sprite sayfası oluşturur.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_nb2_single_image_sprite_sheet', 'ar', 'صورة واحدة إلى ورقة سبريت متحركة', 'قم بتحميل صورة واحدة لإنشاء تسلسل متحرك. يقوم سير العمل بإنشاء ورقة سبريت تحتوي على إطارات متعددة للاستخدام في الألعاب أو الرسوم المتحركة.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_purz_nb2_single_image_sprite_sheet', 'pt-BR', 'Imagem Única para Folha de Sprites Animada', 'Faça upload de uma única imagem para gerar uma sequência animada. O fluxo de trabalho cria uma folha de sprites com múltiplos quadros para uso em jogos ou animações.', 0, NULL, '2026-04-19T13:33:43.915Z');
