INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_video_restyle', 'zh-TW', '影片重製', '使用基礎影片 + 風格化參考圖像，透過 WAN 2.1 VACE 建立風格化影片', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_video_restyle', 'ja', 'ビデオリスタイル', 'ベースビデオ + スタイル化された参照画像を使用して、WAN 2.1 VACE でスタイル化されたビデオを作成します', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_video_restyle', 'ko', '비디오 리스타일', '기본 비디오 + 스타일화된 참조 이미지를 사용하여 WAN 2.1 VACE로 스타일화된 비디오를 생성합니다', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_video_restyle', 'es', 'Reestilo de Video', 'Utiliza un video base + una imagen de referencia estilizada para crear el video estilizado usando WAN 2.1 VACE', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_video_restyle', 'fr', 'Restylage Vidéo', 'Utilisez une vidéo de base + une image de référence stylisée pour créer la vidéo stylisée avec WAN 2.1 VACE', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_video_restyle', 'ru', 'Видео Рестайлинг', 'Используйте базовое видео + стилизованное эталонное изображение для создания стилизованного видео с помощью WAN 2.1 VACE', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_video_restyle', 'tr', 'Video Yeniden Stil', 'WAN 2.1 VACE kullanarak stilize edilmiş videoyu oluşturmak için temel bir video + stilize edilmiş bir referans görseli kullanın', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_video_restyle', 'ar', 'إعادة تصميم الفيديو', 'استخدم فيديو أساسي + صورة مرجعية مُمَيزة لإنشاء الفيديو المُمَيز باستخدام WAN 2.1 VACE', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_video_restyle', 'pt-BR', 'Reestilo de Vídeo', 'Use um vídeo base + uma imagem de referência estilizada para criar o vídeo estilizado usando o WAN 2.1 VACE', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (49, 'tempate_eric_seedance_5_subject_and_outfit_combine', 1, 48, 'Outfit Application for Character Portraits', 'Upload your character portrait and outfit reference. Generate a new portrait with the specific outfit applied for consistent wardrobe control. Affordable alternative to Nano Banana Pro and Nano Banana 2.', 'image', 'webp', NULL, '["thumbnail/tempate_eric_seedance_5_subject_and_outfit_combine.png"]', '["virtual try on"]', '["Seedream 4.5"]', '[{"provider":"ByteDance"}]', '[]', '[]', '{"inputs":[{"nodeId":16,"nodeType":"LoadImage","file":"subject_far.png","mediaType":"image"},{"nodeId":26,"nodeType":"LoadImage","file":"clothing.png","mediaType":"image"},{"nodeId":226,"nodeType":"LoadImage","file":"subject_close.png","mediaType":"image"}],"outputs":[{"nodeId":11,"nodeType":"SaveImage","file":"tempate_eric_seedance_5_subject_and_outfit_combine-2.png","mediaType":"image"},{"nodeId":258,"nodeType":"SaveImage","file":"tempate_eric_seedance_5_subject_and_outfit_combine-1.png","mediaType":"image"}]}', NULL, NULL, '2026-03-08', 0, 'active', 0, 0, 206, 0, 'enigmatic_e', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_seedance_5_subject_and_outfit_combine', 'en', 'Outfit Application for Character Portraits', 'Upload your character portrait and outfit reference. Generate a new portrait with the specific outfit applied for consistent wardrobe control. Affordable alternative to Nano Banana Pro and Nano Banana 2.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_seedance_5_subject_and_outfit_combine', 'zh', '角色肖像服装应用', '上传您的角色肖像和服装参考。生成应用特定服装的新肖像，实现一致的衣柜控制。Nano Banana Pro 和 Nano Banana 2 的经济替代方案。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_seedance_5_subject_and_outfit_combine', 'zh-TW', '角色肖像服裝應用', '上傳您的角色肖像和服裝參考。生成應用特定服裝的新肖像，實現一致的衣櫃控制。Nano Banana Pro 和 Nano Banana 2 的經濟替代方案。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_seedance_5_subject_and_outfit_combine', 'ja', 'キャラクターポートレート用衣装アプリケーション', 'キャラクターの肖像画と衣装の参考画像をアップロードしてください。特定の衣装を適用した新しい肖像画を生成し、一貫したワードローブ管理を実現します。Nano Banana Pro および Nano Banana 2 の手頃な代替品です。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_seedance_5_subject_and_outfit_combine', 'ko', '캐릭터 초상화용 의상 애플리케이션', '캐릭터 초상화와 의상 참고 자료를 업로드하세요. 특정 의상을 적용한 새로운 초상화를 생성하여 일관된 의상 관리를 제공합니다. Nano Banana Pro 및 Nano Banana 2의 합리적인 대안입니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_seedance_5_subject_and_outfit_combine', 'es', 'Aplicación de Atuendos para Retratos de Personajes', 'Sube tu retrato de personaje y referencia de atuendo. Genera un nuevo retrato con el atuendo específico aplicado para un control de vestuario consistente. Alternativa asequible a Nano Banana Pro y Nano Banana 2.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_seedance_5_subject_and_outfit_combine', 'fr', 'Application de Tenues pour Portraits de Personnages', 'Téléchargez votre portrait de personnage et référence de tenue. Générez un nouveau portrait avec la tenue spécifique appliquée pour un contrôle cohérent de la garde-robe. Alternative abordable à Nano Banana Pro et Nano Banana 2.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_seedance_5_subject_and_outfit_combine', 'ru', 'Приложение для подбора нарядов для портретов персонажей', 'Загрузите портрет вашего персонажа и образец одежды. Создайте новый портрет с применением конкретного наряда для последовательного контроля гардероба. Доступная альтернатива Nano Banana Pro и Nano Banana 2.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_seedance_5_subject_and_outfit_combine', 'tr', 'Karakter Portreleri için Kıyafet Uygulaması', 'Karakter portrenizi ve kıyafet referansınızı yükleyin. Tutarlı gardırop kontrolü için belirli kıyafet uygulanmış yeni bir portre oluşturun. Nano Banana Pro ve Nano Banana 2''nin uygun fiyatlı alternatifi.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_seedance_5_subject_and_outfit_combine', 'ar', 'تطبيق الملابس لصور الشخصيات', 'قم بتحميل صورة شخصيتك ومرجع الملابس. أنشئ صورة جديدة مع تطبيق الملابس المحددة للتحكم المتسق في الخزانة. بديل ميسور التكلفة لـ Nano Banana Pro و Nano Banana 2.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('tempate_eric_seedance_5_subject_and_outfit_combine', 'pt-BR', 'Aplicativo de Trajes para Retratos de Personagens', 'Faça upload do retrato do seu personagem e referência de roupa. Gere um novo retrato com a roupa específica aplicada para controle consistente do guarda-roupa. Alternativa acessível ao Nano Banana Pro e Nano Banana 2.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (50, 'templates_shane_change_any_objects', 1, 49, 'Change Any Objects', 'Use simple prompt to mask out certain objects within a video, and replace the object using prompt, or optional reference image. Model used: SAM3 + WAN 2.1 VACE inpainting', 'image', 'webp', NULL, '["thumbnail/templates_shane_change_any_objects.mp4"]', '["Inpainting","Video"]', '["SAM3","Wan2.1 VACE"]', '[]', '["ComfyUI-WanVideoWrapper","RES4LYF","comfyui-kjnodes","comfyui-sam3","comfyui-videohelpersuite","comfyui_essentials"]', '["cloud"]', '{"inputs":[{"nodeId":187,"nodeType":"VHS_LoadVideo","file":"woman_holding_the_pipeapple.mp4","mediaType":"video"},{"nodeId":204,"nodeType":"LoadImage","file":"dragon_fruit.png","mediaType":"image"}]}', NULL, NULL, '2026-03-04', 1, 'active', 10737418240, 10737418240, 45, 0, 'shane', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_change_any_objects', 'en', 'Change Any Objects', 'Use simple prompt to mask out certain objects within a video, and replace the object using prompt, or optional reference image. Model used: SAM3 + WAN 2.1 VACE inpainting', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_change_any_objects', 'zh', '更改任意对象', '使用简单提示来遮罩视频中的特定对象，并通过提示或可选的参考图像替换该对象。所用模型：SAM3 + WAN 2.1 VACE 修复', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_change_any_objects', 'zh-TW', '更改任意物件', '使用簡單提示來遮罩影片中的特定物件，並透過提示或可選的參考圖像替換該物件。所用模型：SAM3 + WAN 2.1 VACE 修復', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_change_any_objects', 'ja', '任意のオブジェクトを変更', 'シンプルなプロンプトを使用して動画内の特定のオブジェクトをマスクし、プロンプトまたはオプションの参照画像を使用してオブジェクトを置き換えます。使用モデル：SAM3 + WAN 2.1 VACE インペインティング', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_change_any_objects', 'ko', '모든 객체 변경', '간단한 프롬프트를 사용하여 비디오 내 특정 객체를 마스킹하고, 프롬프트 또는 선택적 참조 이미지를 사용하여 객체를 교체합니다. 사용 모델: SAM3 + WAN 2.1 VACE 인페인팅', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_change_any_objects', 'es', 'Cambiar cualquier objeto', 'Usa un prompt simple para enmascarar ciertos objetos dentro de un video y reemplazar el objeto usando un prompt, o una imagen de referencia opcional. Modelo utilizado: SAM3 + WAN 2.1 VACE inpainting', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_change_any_objects', 'fr', 'Modifier n''importe quel objet', 'Utilisez une invite simple pour masquer certains objets dans une vidéo et remplacez l''objet à l''aide d''une invite ou d''une image de référence facultative. Modèle utilisé : SAM3 + WAN 2.1 VACE inpainting', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_change_any_objects', 'ru', 'Изменить любые объекты', 'Используйте простой запрос для маскировки определенных объектов в видео и замены объекта с помощью запроса или дополнительного эталонного изображения. Используемая модель: SAM3 + WAN 2.1 VACE inpainting', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_change_any_objects', 'tr', 'Herhangi bir Nesneyi Değiştir', 'Bir videodaki belirli nesneleri maskelemek için basit bir istem kullanın ve nesneyi istem veya isteğe bağlı referans görseli kullanarak değiştirin. Kullanılan model: SAM3 + WAN 2.1 VACE inpainting', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_change_any_objects', 'ar', 'تغيير أي كائنات', 'استخدم مطالبة بسيطة لإخفاء كائنات معينة داخل مقطع فيديو، واستبدل الكائن باستخدام مطالبة أو صورة مرجعية اختيارية. النموذج المستخدم: SAM3 + WAN 2.1 VACE inpainting', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_change_any_objects', 'pt-BR', 'Alterar Qualquer Objeto', 'Use um prompt simples para mascarar certos objetos em um vídeo e substitua o objeto usando um prompt ou uma imagem de referência opcional. Modelo utilizado: SAM3 + WAN 2.1 VACE inpainting', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (51, 'templates_shane_single_image_to_3d_model', 1, 50, 'Single Image to 3D model', 'Use one frontal image to generate a consistent and highly detailed 3D model. Model used: Multiangle QWEN Edit + Hunyuan 3D', 'image', 'webp', NULL, '[]', '["3D","Image to 3D"]', '["Hunyuan3D","Qwen-Image-Edit"]', '[{"provider":["Hunyuan","WAN"],"label":"Hunyuan & Qwen"}]', '["comfyui-qwenmultiangle"]', '[]', '{"inputs":[{"nodeId":119,"nodeType":"LoadImage","file":"lucky_cat_sculpture_front.png","mediaType":"image"}],"outputs":[{"nodeId":11,"nodeType":"Preview3D","file":"templates_shane_single_image_to_3d_model.glb","mediaType":"3d"},{"nodeId":118,"nodeType":"SaveImage","file":"lucky_cat_sculpture_back.png","mediaType":"image"}]}', NULL, NULL, '2026-03-04', 0, 'active', 58841051955, 58841051955, 175, 0, 'shane', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_single_image_to_3d_model', 'en', 'Single Image to 3D model', 'Use one frontal image to generate a consistent and highly detailed 3D model. Model used: Multiangle QWEN Edit + Hunyuan 3D', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_single_image_to_3d_model', 'zh', '单张图像转3D模型', '使用一张正面图像生成一致且高度详细的3D模型。所用模型：多角度QWEN编辑+混元3D', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_single_image_to_3d_model', 'zh-TW', '單張圖像轉3D模型', '使用一張正面圖像生成一致且高度詳細的3D模型。所用模型：多角度QWEN編輯+混元3D', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_single_image_to_3d_model', 'ja', '単一画像から3Dモデルへ', '一枚の正面画像を使用して、一貫性があり高度に詳細な3Dモデルを生成します。使用モデル：Multiangle QWEN Edit + Hunyuan 3D', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_single_image_to_3d_model', 'ko', '단일 이미지를 3D 모델로', '한 장의 정면 이미지를 사용하여 일관되고 매우 상세한 3D 모델을 생성합니다. 사용 모델: Multiangle QWEN Edit + Hunyuan 3D', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_single_image_to_3d_model', 'es', 'Imagen única a modelo 3D', 'Utiliza una imagen frontal para generar un modelo 3D consistente y altamente detallado. Modelo utilizado: Multiangle QWEN Edit + Hunyuan 3D', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_single_image_to_3d_model', 'fr', 'Image unique vers modèle 3D', 'Utilisez une image frontale pour générer un modèle 3D cohérent et hautement détaillé. Modèle utilisé : Multiangle QWEN Edit + Hunyuan 3D', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_single_image_to_3d_model', 'ru', 'Одно изображение в 3D-модель', 'Используйте одно фронтальное изображение для создания согласованной и высокодетализированной 3D-модели. Используемая модель: Multiangle QWEN Edit + Hunyuan 3D', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_single_image_to_3d_model', 'tr', 'Tek Görüntüden 3D Modele', 'Tutarlı ve oldukça detaylı bir 3D model oluşturmak için bir ön görüntü kullanın. Kullanılan model: Multiangle QWEN Edit + Hunyuan 3D', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_single_image_to_3d_model', 'ar', 'صورة واحدة إلى نموذج ثلاثي الأبعاد', 'استخدم صورة أمامية واحدة لإنشاء نموذج ثلاثي الأبعاد متسق ومفصل للغاية. النموذج المستخدم: Multiangle QWEN Edit + Hunyuan 3D', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_shane_single_image_to_3d_model', 'pt-BR', 'Imagem única para modelo 3D', 'Use uma imagem frontal para gerar um modelo 3D consistente e altamente detalhado. Modelo utilizado: Multiangle QWEN Edit + Hunyuan 3D', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (52, 'templates_mjm_airt_machIne', 1, 51, 'AIrt MAchIne', 'Upload any image to generate a unique, looping AI video. The workflow uses an LLM to create five prompts, produces images and video clips, and stitches them into a final seamless loop.', 'image', 'webp', NULL, '["output/templates_mjm_airt_machIne.mp4"]', '["FLF2V","Text to Image"]', '["Wan2.2","Z-Image-Turbo"]', '[]', '["comfyui-kjnodes","comfyui-videohelpersuite"]', '[]', '{"inputs":[{"nodeId":94,"nodeType":"LoadImage","file":"AIrt_MAchIne_init.png","mediaType":"image"}],"outputs":[{"nodeId":161,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":164,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":165,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":166,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":167,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":16,"nodeType":"SaveVideo","file":"","mediaType":"video"},{"nodeId":27,"nodeType":"SaveVideo","file":"","mediaType":"video"},{"nodeId":33,"nodeType":"SaveVideo","file":"","mediaType":"video"},{"nodeId":10,"nodeType":"SaveVideo","file":"","mediaType":"video"},{"nodeId":22,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-03-03', 1, 'active', 60129542144, 60129542144, 152, 0, 'Julien | MJM', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machIne', 'en', 'AIrt MAchIne', 'Upload any image to generate a unique, looping AI video. The workflow uses an LLM to create five prompts, produces images and video clips, and stitches them into a final seamless loop.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machIne', 'zh', 'AIrt MAchIne', '上传任意图片即可生成独特的循环AI视频。该工作流程使用LLM创建五个提示，生成图像和视频片段，并将它们拼接成最终的无缝循环。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machIne', 'zh-TW', 'AIrt MAchIne', '上傳任意圖片即可生成獨特的循環AI影片。該工作流程使用LLM創建五個提示，生成圖像和影片片段，並將它們拼接成最終的無縫循環。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machIne', 'ja', 'AIrt MAchIne', '任意の画像をアップロードして、ユニークなループAI動画を生成します。このワークフローはLLMを使用して5つのプロンプトを作成し、画像と動画クリップを生成し、それらを最終的なシームレスなループに結合します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machIne', 'ko', 'AIrt MAchIne', '어떤 이미지든 업로드하여 고유한 루핑 AI 비디오를 생성하세요. 이 워크플로우는 LLM을 사용하여 다섯 개의 프롬프트를 생성하고, 이미지와 비디오 클립을 제작하며, 이를 최종적인 완벽한 루프로 이어붙입니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machIne', 'es', 'AIrt MAchIne', 'Sube cualquier imagen para generar un video de IA único y en bucle. El flujo de trabajo utiliza un LLM para crear cinco indicaciones, produce imágenes y clips de video, y los une en un bucle final sin interrupciones.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machIne', 'fr', 'AIrt MAchIne', 'Téléchargez n''importe quelle image pour générer une vidéo IA unique et en boucle. Le flux de travail utilise un LLM pour créer cinq invites, produit des images et des clips vidéo, et les assemble en une boucle finale sans couture.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machIne', 'ru', 'AIrt MAchIne', 'Загрузите любое изображение, чтобы создать уникальное зацикленное AI-видео. Рабочий процесс использует LLM для создания пяти промптов, генерирует изображения и видеоклипы, а затем объединяет их в итоговый бесшовный цикл.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machIne', 'tr', 'AIrt MAchIne', 'Benzersiz, döngüsel bir AI videosu oluşturmak için herhangi bir görsel yükleyin. İş akışı, beş istem oluşturmak için bir LLM kullanır, görseller ve video klipler üretir ve bunları nihai bir sorunsuz döngüye birleştirir.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machIne', 'ar', 'AIrt MAchIne', 'قم بتحميل أي صورة لإنشاء فيديو ذكي فريد ومتكرر. يستخدم سير العمل نموذج لغة كبيرة لإنشاء خمسة مطالبات، وينتج صورًا ومقاطع فيديو، ويربطها في حلقة نهائية سلسة.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machIne', 'pt-BR', 'AIrt MAchIne', 'Faça upload de qualquer imagem para gerar um vídeo de IA único e em loop. O fluxo de trabalho usa um LLM para criar cinco prompts, produz imagens e clipes de vídeo, e os costura em um loop final sem emendas.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (53, 'template_eric_exploded_view', 1, 52, 'Exploded View Animation', 'Upload an image of a device or object to generate start and end frames. The workflow animates the transition to an exploded view and back, outputting a seamless video loop.', 'image', 'webp', NULL, '["output/template_eric_exploded_view.mp4"]', '["Video","FLF2V"]', '["Nano Banana 2","Seedance 1.5 Pro"]', '[{"provider":["ByteDance","Google"]}]', '[]', '[]', '{"inputs":[{"nodeId":29,"nodeType":"LoadImage","file":"template_eric_exploded_view_first_frame.png","mediaType":"image"},{"nodeId":239,"nodeType":"LoadImage","file":"template_eric_exploded_view_last_frame.png","mediaType":"image"}],"outputs":[{"nodeId":26,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":241,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":227,"nodeType":"SaveVideo","file":"","mediaType":"video"},{"nodeId":381,"nodeType":"SaveVideo","file":"template_eric_exploded_view.mp4","mediaType":"video"},{"nodeId":225,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-03-06', 0, 'active', 0, 0, 107, 0, 'enigmatic_e', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_eric_exploded_view', 'en', 'Exploded View Animation', 'Upload an image of a device or object to generate start and end frames. The workflow animates the transition to an exploded view and back, outputting a seamless video loop.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_eric_exploded_view', 'zh', '爆炸视图动画', '上传设备或物体的图像以生成起始和结束帧。工作流程将动画化过渡到爆炸视图并返回，输出无缝视频循环。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_eric_exploded_view', 'zh-TW', '爆炸視圖動畫', '上傳設備或物體的圖像以生成起始和結束幀。工作流程將動畫化過渡到爆炸視圖並返回，輸出無縫影片循環。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_eric_exploded_view', 'ja', '分解図アニメーション', 'デバイスまたはオブジェクトの画像をアップロードして、開始フレームと終了フレームを生成します。ワークフローは爆発図への遷移と戻りをアニメーション化し、シームレスなビデオループを出力します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_eric_exploded_view', 'ko', '분해도 애니메이션', '장치 또는 물체의 이미지를 업로드하여 시작 및 종료 프레임을 생성합니다. 워크플로는 폭발도로의 전환과 복귀를 애니메이션화하여 매끄러운 비디오 루프를 출력합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_eric_exploded_view', 'es', 'Animación de Vista Explosionada', 'Sube una imagen de un dispositivo u objeto para generar fotogramas de inicio y fin. El flujo de trabajo anima la transición a una vista explosionada y de regreso, generando un bucle de video sin interrupciones.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_eric_exploded_view', 'fr', 'Animation en Vue Explosée', 'Téléchargez une image d''un appareil ou d''un objet pour générer des images de début et de fin. Le flux de travail anime la transition vers une vue éclatée et le retour, produisant une boucle vidéo fluide.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_eric_exploded_view', 'ru', 'Анимация разобранного вида', 'Загрузите изображение устройства или объекта, чтобы создать начальный и конечный кадры. Рабочий процесс анимирует переход к разобранному виду и обратно, выводя бесшовный видеоповтор.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_eric_exploded_view', 'tr', 'Patlamış Görünüm Animasyonu', 'Başlangıç ve bitiş kareleri oluşturmak için bir cihaz veya nesnenin görüntüsünü yükleyin. İş akışı, patlatılmış görünüme geçişi ve geri dönüşü animasyonlaştırarak sorunsuz bir video döngüsü çıktılar.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_eric_exploded_view', 'ar', 'رسوم متحركة للرؤية المنفجرة', 'قم بتحميل صورة لجهاز أو كائن لإنشاء إطارات البداية والنهاية. يحرك سير العمل الانتقال إلى عرض منفجر والعودة، لينتج حلقة فيديو سلسة.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('template_eric_exploded_view', 'pt-BR', 'Animação de Vista Explodida', 'Faça upload de uma imagem de um dispositivo ou objeto para gerar quadros inicial e final. O fluxo de trabalho anima a transição para uma vista explodida e de volta, gerando um loop de vídeo contínuo.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (54, 'templates-fashion_shoot_vton', 1, 53, 'Character + Clothing (OOTD) Flat Lay to Studio Photoshoot', 'Upload an image of your character and a flatlay image of your clothing items. Generate 4 fashion editorial photographs of your character in the outfit. Select which image to upscale and add back details.', 'image', 'webp', NULL, '["thumbnail/templates-fashion_shoot_vton.png"]', '["Fashion","Image Edit"]', '["Google Gemini Image","Nano Banana Pro","Google","Gemini3 Pro Image Preview"]', '[{"provider":"Google"}]', '["comfyui-kjnodes","comfyui_essentials"]', '[]', '{"inputs":[{"nodeId":1,"nodeType":"LoadImage","file":"subject.png","mediaType":"image"},{"nodeId":35,"nodeType":"LoadImage","file":"outfit.png","mediaType":"image"}],"outputs":[{"nodeId":13,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":15,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":12,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":8,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":14,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":26,"nodeType":"SaveImage","file":"","mediaType":"image"}]}', NULL, NULL, '2025-12-15', 0, 'active', 0, 0, 570, 8, 'hellorob', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-fashion_shoot_vton', 'en', 'Character + Clothing (OOTD) Flat Lay to Studio Photoshoot', 'Upload an image of your character and a flatlay image of your clothing items. Generate 4 fashion editorial photographs of your character in the outfit. Select which image to upscale and add back details.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-fashion_shoot_vton', 'zh', '角色+服饰 (OOTD) 平铺到棚拍', '上传角色图片和服装平铺图，生成4张穿搭写真，可选择放大并补充细节。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-fashion_shoot_vton', 'zh-TW', '角色+服飾 (OOTD) 平鋪到攝影棚照片', '上傳角色圖片和服裝平鋪圖，產生4張穿搭寫真，可選擇放大並補細節。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-fashion_shoot_vton', 'ja', 'キャラクター＋服装（OOTD）フラットレイからスタジオ撮影', 'キャラクター画像と服の平置き画像をアップロードし、4枚の着用写真を生成。好きな写真を高解像度化しディテールを追加できます。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-fashion_shoot_vton', 'ko', '캐릭터+의상 (OOTD) 플랫레이에서 스튜디오 화보까지', '캐릭터 사진과 의상 평면 사진을 업로드하면 4장의 패션 화보가 생성됩니다. 원하는 이미지를 확대하고 디테일을 추가할 수 있습니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-fashion_shoot_vton', 'es', 'Personaje + ropa (OOTD) flat lay a sesión de estudio', 'Sube una imagen de tu personaje y otra de la ropa. Se generan 4 fotos editoriales; elige una para mejorarla y añadir detalles.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-fashion_shoot_vton', 'fr', 'Personnage + vêtement (OOTD) flat lay vers séance studio', 'Téléchargez une photo de personnage et de tenues à plat, obtenez 4 photos mode. Sélectionnez-en une à améliorer et ajoutez des détails.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-fashion_shoot_vton', 'ru', 'Персонаж+одежда (OOTD): flat lay в студийную съемку', 'Загрузите фото персонажа и одежды, получите 4 модные снимка. Выберите изображение для увеличения и добавления деталей.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-fashion_shoot_vton', 'tr', 'Karakter + Kıyafet (OOTD) flat lay''den stüdyo çekimine', 'Karakter ve kıyafet fotoğrafını yükle, 4 moda fotoğrafı oluştur. Büyütmek ve detay eklemek istediğini seç.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-fashion_shoot_vton', 'ar', 'شخصية + ملابس (OOTD) من التصوير المسطح لجلسة تصوير استوديو', 'حمّل صورة للشخصية وصورة للملابس، واحصل على 4 صور أزياء. اختر صورة لتحسينها وإضافة تفاصيل.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-fashion_shoot_vton', 'pt-BR', 'Personagem + Roupa (OOTD) Flat Lay para Ensaio de Estúdio', 'Carregue uma imagem do seu personagem e uma imagem flatlay dos seus itens de roupa. Gere 4 fotografias editoriais de moda do seu personagem na roupa. Selecione qual imagem ampliar e adicionar detalhes.', 0, NULL, '2026-04-19T13:33:43.915Z');
