INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-subject_product_swap.app', 'ar', 'تبديل المنتج في يد الشخصية (أسلوب UGC)', 'حمّل صورة لشخصية تحمل منتجًا وصورة منتجك. أنشئ صورة تم فيها تبديل المنتجات.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-subject_product_swap.app', 'pt-BR', 'Swap Product in Character’s Hand, UGC Style', 'Carregue uma foto de um personagem segurando um produto e o produto da sua marca. Gere uma imagem com os produtos trocados.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (63, 'templates-product_scene_relight', 1, 62, 'Composite your Product + Scene and Relight', 'Upload an image of your product and background. Composite them and seamlessly relight and fuse together using Seedream 4.5.', 'image', 'webp', 'compareSlider', '["input/comfy_shampoo.png","output/templates-product_scene_relight.png"]', '["Image Edit","Product","Relight"]', '["ByteDance","Seedream"]', '[{"provider":"ByteDance"}]', '[]', '[]', '{"inputs":[{"nodeId":1,"nodeType":"LoadImage","file":"comfy_shampoo.png","mediaType":"image"},{"nodeId":2,"nodeType":"LoadImage","file":"flower_sea.png","mediaType":"image"}],"outputs":[{"nodeId":23,"nodeType":"SaveImage","file":"templates-product_scene_relight.png","mediaType":"image"}]}', NULL, NULL, '2025-12-15', 0, 'active', 0, 0, 99, 8, 'hellorob', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-product_scene_relight', 'en', 'Composite your Product + Scene and Relight', 'Upload an image of your product and background. Composite them and seamlessly relight and fuse together using Seedream 4.5.', 0, NULL, '2026-04-19T13:33:43.915Z');
