INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-product_scene_relight', 'zh-TW', '產品場景合成與重新光照', '上傳產品與背景圖片，合成場景並自然補光，支援Seedream 4.5。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-product_scene_relight', 'ja', '商品と背景の合成＆再照明', '商品と背景画像をアップロードし、合成＆自然な再照明（Seedream 4.5対応）。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-product_scene_relight', 'ko', '제품과 배경 합성 및 재조명', '제품과 배경 이미지를 업로드하면, 합성 후 자연스럽게 재조명합니다 (Seedream 4.5 지원).', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-product_scene_relight', 'es', 'Fusión de producto y escena con reiluminación', 'Sube imágenes de tu producto y fondo, combínalas y ajusta la luz con Seedream 4.5.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-product_scene_relight', 'fr', 'Fusion produit + scène et rééclairage', 'Ajoute ton produit et un fond, fusionne-les et ajuste la lumière avec Seedream 4.5.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-product_scene_relight', 'ru', 'Совмещение продукта и сцены с переосвещением', 'Загрузите фото продукта и фона, объедините их и скорректируйте освещение (Seedream 4.5).', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-product_scene_relight', 'tr', 'Ürün + Sahne Birleştir ve Yeniden Işıklandır', 'Ürün ve arka plan görseli yükle, birleştir ve Seedream 4.5 ile aydınlatmayı uygula.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-product_scene_relight', 'ar', 'دمج المنتج والمشهد مع إعادة الإضاءة', 'حمِّل صورة منتجك وخلفيتك، ادمج واعد الإضاءة بسلاسة عبر Seedream 4.5.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-product_scene_relight', 'pt-BR', 'Compor seu Produto + Cena e Reluzir', 'Carregue uma imagem do seu produto e fundo. Componha-os e reluzir e funda de forma contínua usando Seedream 4.5.', 0, NULL, '2026-04-19T13:33:43.915Z');
