INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-sprite_sheet', 'en', 'Sprite Sheet Generator', 'Upload an image of your sprite and receive individual frames of idle, attack, walk and jump animations. ', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-sprite_sheet', 'zh', '精灵表生成器', '上传您的精灵图像，即可获得空闲、攻击、行走和跳跃动画的独立帧。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-sprite_sheet', 'zh-TW', '精靈表生成器', '上傳您的精靈圖像，即可獲得閒置、攻擊、行走和跳躍動畫的獨立影格。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-sprite_sheet', 'ja', 'スプライトシートジェネレーター', 'スプライトの画像をアップロードすると、待機、攻撃、歩行、ジャンプのアニメーションの個別フレームを受け取れます。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-sprite_sheet', 'ko', '스프라이트 시트 생성기', '스프라이트 이미지를 업로드하면 대기, 공격, 걷기, 점프 애니메이션의 개별 프레임을 받을 수 있습니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-sprite_sheet', 'es', 'Generador de hojas de sprites', 'Sube una imagen de tu sprite y recibe fotogramas individuales de las animaciones de inactividad, ataque, caminata y salto.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-sprite_sheet', 'fr', 'Générateur de feuilles de sprites', 'Téléchargez une image de votre sprite et recevez des images individuelles des animations d''inactivité, d''attaque, de marche et de saut.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-sprite_sheet', 'ru', 'Генератор спрайт-листов', 'Загрузите изображение вашего спрайта и получите отдельные кадры анимаций бездействия, атаки, ходьбы и прыжка.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-sprite_sheet', 'tr', 'Sprite Sayfası Oluşturucu', 'Sprite''ınızın bir görselini yükleyin ve hareketsizlik, saldırı, yürüme ve zıplama animasyonlarının bireysel karelerini alın.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-sprite_sheet', 'ar', 'مولد ورقة الرسوم المتحركة', 'قم بتحميل صورة للشخصية الخاصة بك واحصل على إطارات فردية لرسوم الحركة الخاملة والهجوم والمشي والقفز.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-sprite_sheet', 'pt-BR', 'Gerador de Folha de Sprites', 'Faça upload de uma imagem do seu sprite e receba quadros individuais das animações de inatividade, ataque, caminhada e salto.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (65, 'templates_mjm_airt_machine_api', 1, 64, 'AIrt MAchIne (API version)', 'Upload an image to generate a unique, looping AI video. The workflow uses an LLM to create prompts, employs Kling3.0 for video generation, and stitches the clips into a seamless final loop.', 'image', 'webp', NULL, '["output/templates_mjm_airt_machine_api.mp4"]', '["API","FLF2V","Video"]', '["Google Gemini","Kling 3.0","Z-Image-Turbo"]', '[{"provider":["Google","BRIA"]}]', '["comfyui-kjnodes"]', '[]', '{"inputs":[{"nodeId":94,"nodeType":"LoadImage","file":"AIrt_MAchIne_init.png","mediaType":"image"}],"outputs":[{"nodeId":161,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":164,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":165,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":166,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":167,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":10,"nodeType":"SaveVideo","file":"","mediaType":"video"},{"nodeId":16,"nodeType":"SaveVideo","file":"","mediaType":"video"},{"nodeId":27,"nodeType":"SaveVideo","file":"","mediaType":"video"},{"nodeId":22,"nodeType":"SaveVideo","file":"","mediaType":"video"},{"nodeId":33,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-03-03', 0, 'active', 20723217203, 20723217203, 37, 0, 'Julien | MJM', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machine_api', 'en', 'AIrt MAchIne (API version)', 'Upload an image to generate a unique, looping AI video. The workflow uses an LLM to create prompts, employs Kling3.0 for video generation, and stitches the clips into a seamless final loop.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machine_api', 'zh', 'AIrt MAchIne（API 版本）', '上传一张图片，生成独特的循环AI视频。该工作流程使用LLM创建提示，采用Kling3.0进行视频生成，并将片段拼接成无缝的最终循环。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machine_api', 'zh-TW', 'AIrt MAchIne（API 版本）', '上傳一張圖片，生成獨特的循環AI影片。該工作流程使用LLM創建提示，採用Kling3.0進行影片生成，並將片段拼接成無縫的最終循環。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machine_api', 'ja', 'AIrt MAchIne（API バージョン）', '画像をアップロードして、ユニークなループAI動画を生成します。このワークフローはLLMを使用してプロンプトを作成し、Kling3.0を動画生成に採用し、クリップをシームレスな最終ループに結合します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machine_api', 'ko', 'AIrt MAchIne（API 버전）', '이미지를 업로드하여 독특한 루핑 AI 비디오를 생성하세요. 이 워크플로우는 LLM을 사용하여 프롬프트를 생성하고, Kling3.0을 비디오 생성에 활용하며, 클립을 매끄러운 최종 루프로 이어붙입니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machine_api', 'es', 'AIrt MAchIne (versión API)', 'Sube una imagen para generar un video de IA único y en bucle. El flujo de trabajo utiliza un LLM para crear indicaciones, emplea Kling3.0 para la generación de video y une los clips en un bucle final sin interrupciones.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machine_api', 'fr', 'AIrt MAchIne (version API)', 'Téléchargez une image pour générer une vidéo IA unique et en boucle. Le flux de travail utilise un LLM pour créer des invites, emploie Kling3.0 pour la génération vidéo et assemble les clips en une boucle finale fluide.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machine_api', 'ru', 'AIrt MAchIne (версия API)', 'Загрузите изображение, чтобы создать уникальное зацикленное AI-видео. Рабочий процесс использует LLM для создания промптов, применяет Kling3.0 для генерации видео и объединяет клипы в бесшовный финальный цикл.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machine_api', 'tr', 'AIrt MAchIne (API sürümü)', 'Benzersiz, döngüsel bir AI videosu oluşturmak için bir görsel yükleyin. İş akışı, istemleri oluşturmak için bir LLM kullanır, video oluşturma için Kling3.0''ı kullanır ve klipleri sorunsuz bir son döngüye birleştirir.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machine_api', 'ar', 'AIrt MAchIne (نسخة API)', 'قم بتحميل صورة لإنشاء فيديو ذكي فريد ومتكرر. يستخدم سير العمل نموذج لغة كبيرة لإنشاء المطالبات، ويستخدم Kling3.0 لتوليد الفيديو، ويربط المقاطع في حلقة نهائية سلسة.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_airt_machine_api', 'pt-BR', 'AIrt MAchIne (versão da API)', 'Faça upload de uma imagem para gerar um vídeo de IA único e em loop. O fluxo de trabalho usa um LLM para criar prompts, emprega o Kling3.0 para geração de vídeo e une os clipes em um loop final contínuo.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (66, 'templates_mjm_looped_restyler', 1, 65, 'Looped Restyler', 'Upload a starting image and its prompt to generate a looping video from the first to the last frame.', 'image', 'webp', NULL, '["output/templates_mjm_looped_restyler.mp4"]', '["Image to Video","Video","FLF2V"]', '["Nano Banana","Google Gemini","Wan2.2"]', '[{"provider":["Google","WAN"]}]', '[]', '[]', '{"inputs":[{"nodeId":4,"nodeType":"LoadImage","file":"looped_restyler_init.png","mediaType":"image"}],"outputs":[{"nodeId":80,"nodeType":"SaveVideo","file":"templates_mjm_looped_restyler.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-03', 0, 'active', 38010460570, 38010460570, 50, 0, 'Julien | MJM', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_looped_restyler', 'en', 'Looped Restyler', 'Upload a starting image and its prompt to generate a looping video from the first to the last frame.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_looped_restyler', 'zh', '循环重制器', '上传起始图像及其提示，以生成从第一帧到最后一帧的循环视频。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_looped_restyler', 'zh-TW', '循環重製器', '上傳起始圖像及其提示，以生成從第一幀到最後一幀的循環影片。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_looped_restyler', 'ja', 'ループド・リスタイラー', '開始画像とそのプロンプトをアップロードして、最初のフレームから最後のフレームまでのループ動画を生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_looped_restyler', 'ko', '루프드 리스타일러', '시작 이미지와 해당 프롬프트를 업로드하여 첫 번째 프레임부터 마지막 프레임까지의 루핑 비디오를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_looped_restyler', 'es', 'Restilizador en Bucle', 'Sube una imagen inicial y su indicación para generar un video en bucle desde el primer hasta el último fotograma.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_looped_restyler', 'fr', 'Restyleur en Boucle', 'Téléchargez une image de départ et son invite pour générer une vidéo en boucle de la première à la dernière image.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_looped_restyler', 'ru', 'Петлевой Рестайлер', 'Загрузите начальное изображение и его промпт, чтобы создать зацикленное видео от первого до последнего кадра.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_looped_restyler', 'tr', 'Döngülü Restilleyici', 'İlk kareden son kareye kadar döngüsel bir video oluşturmak için bir başlangıç görseli ve onun istemini yükleyin.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_looped_restyler', 'ar', 'مُعيد التنسيق الحلقي', 'قم بتحميل صورة بداية والموجه الخاص بها لتوليد فيديو متكرر من الإطار الأول إلى الإطار الأخير.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_looped_restyler', 'pt-BR', 'Restilizador em Loop', 'Faça upload de uma imagem inicial e seu prompt para gerar um vídeo em loop do primeiro ao último quadro.', 0, NULL, '2026-04-19T13:33:43.915Z');
