INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-9grid_social_media-v2.0', 'en', '3x3 Grid For Product Ads', 'Upload your product and enter a brief prompt for each grid position in a 3x3 grid. Generates 9 distinct images. Select the images you like and upscale to 4k using your product as reference.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-9grid_social_media-v2.0', 'zh', '3x3产品广告生成', '上传你的产品，并为 3x3 网格的每个位置输入一个简短提示。系统会根据每个提示生成 9 张独特图片。选中你喜欢的图片后，可以用你的原始产品为参考进行 4K 超分辨率。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-9grid_social_media-v2.0', 'zh-TW', '3x3產品廣告生成', '上傳你的產品，並為 3x3 格子的每一個位置分別輸入簡短提示。系統會根據這些提示生成 9 張獨特圖片。接著選擇你喜歡的圖片，可用產品原圖做參考升級至 4K。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-9grid_social_media-v2.0', 'ja', '3x3商品広告生成', '製品をアップロードし、3x3 グリッドの各ポジションごとに短いプロンプトを入力してください。それぞれのプロンプトに基づいて9枚のユニークな画像が生成されます。気に入った画像を選択し、元の製品画像を参照しながら4Kにアップスケールできます。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-9grid_social_media-v2.0', 'ko', '3x3 광고 이미지 생성', '제품을 업로드하고 3x3 그리드의 각 위치마다 짧은 프롬프트를 입력하세요. 총 9개의 개별 이미지가 생성됩니다. 마음에 드는 이미지를 선택하면 원본 제품을 참고하여 4K로 업스케일할 수 있습니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-9grid_social_media-v2.0', 'es', 'Generador de anuncio 3x3', 'Sube tu producto e introduce un mensaje corto para cada posición en la cuadrícula 3x3. Se generarán 9 imágenes únicas a partir de tus mensajes. A continuación, selecciona las que más te gusten y amplíalas a 4K usando tu producto original como referencia.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-9grid_social_media-v2.0', 'fr', 'Générateur pub 3x3', 'Téléchargez votre produit et saisissez un court prompt pour chaque position de la grille 3x3. 9 images uniques seront générées à partir de vos prompts. Sélectionnez ensuite vos images préférées et agrandissez-les en 4K en utilisant votre produit comme référence.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-9grid_social_media-v2.0', 'ru', '3×3 генерация рекламы', 'Загрузите свой продукт и введите короткую подсказку для каждой из 9 позиций в сетке 3×3. По вашим подсказкам будут сгенерированы 9 уникальных изображений. Затем выберите понравившиеся изображения и увеличьте их до 4K, используя свой продукт в качестве ориентира.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-9grid_social_media-v2.0', 'tr', '3x3 ürün reklamı üretimi', 'Ürününüzü yükleyin ve 3x3 ızgaradaki her konum için kısa bir istem girin. İstemlerinizden 9 benzersiz görsel oluşturulacak. Sonrasında, beğendiğiniz görselleri seçip ürününüzü referans alarak 4K''ya yükseltebilirsiniz.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-9grid_social_media-v2.0', 'ar', 'توليد إعلان منتج 3x3', 'قم برفع منتجك وأدخل موجهًا قصيرًا لكل موضع في شبكة 3×3. سيتم إنشاء 9 صور فريدة بناءً على الموجهات. بعد ذلك اختر الصور التي تعجبك وامكّن من رفع جودتها إلى 4K باستخدام منتجك كمرجع.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-9grid_social_media-v2.0', 'pt-BR', 'Grade 3x3 para Anúncios de Produto', 'Carregue seu produto e insira um breve prompt para cada posição da grade em uma grade 3x3. Gera 9 imagens distintas. Selecione as imagens que gosta e amplie para 4k usando seu produto como referência.', 0, NULL, '2026-04-19T13:33:43.915Z');
