INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-3D_logo_texture_animation', 'ko', '다이내믹 3D 로고 애니메이션', '로고 벡터 이미지를 업로드하고 원하는 텍스처를 입력하면, 3D 첫·마지막 프레임 및 애니메이션을 자동 생성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
