INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-3D_logo_texture_animation', 'ru', 'Динамичные 3D анимации логотипа', 'Загрузите векторный логотип и опишите желаемую текстуру: создадутся 3D начальный и финальный кадры с автогенерацией анимации.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-3D_logo_texture_animation', 'tr', 'Dinamik 3D Logo Animasyonları', 'Logo vektörünü yükle, doku belirt. 3D ilk ve son kareyle otomatik animasyon oluştur.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-3D_logo_texture_animation', 'ar', 'رسوم متحركة ديناميكية ثلاثية الأبعاد للشعار', 'حمّل شعارك المتجهي واطلب نسيجاً. يتم توليد أول وآخر إطار ثلاثي الأبعاد مع التحريك تلقائياً.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-3D_logo_texture_animation', 'pt-BR', 'Animações de Logo 3D Dinâmicas', 'Carregue uma imagem vetorial do seu logo e insira sua textura desejada. Gere um primeiro e último quadro 3D texturizado com prompting automatizado para a animação final.', 0, NULL, '2026-04-19T13:33:43.915Z');
