INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-split_stack', 'ar', 'مستكشف مشاهد ×4 شخصيات', 'حمّل صورة مرجعية، أنشئ شبكة 1×4، اختر صورةُ و حسّنها عبر Nano Banana Pro.', 0, NULL, '2026-04-19T13:33:43.915Z');
