INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-8x8_grid-pfp', 'ja', 'プロフィール画像のスタイルバリエーション', 'プロフィール写真をアップロードし、テーマを入力して64種類のバリエーションを生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
