INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-8x8_grid-pfp', 'es', 'Variaciones estilizadas de foto de perfil', 'Sube tu foto de perfil, elige un tema y genera 64 variaciones.', 0, NULL, '2026-04-19T13:33:43.915Z');
