INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-8x8_grid-pfp', 'ru', 'Стилизованные варианты аватара', 'Загрузите фото профиля, укажите тему — получите 64 варианта.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-8x8_grid-pfp', 'tr', 'Profil resmi stile varyasyonları', 'Profil fotoğrafını yükle, bir tema gir, 64 farklı versiyon oluştur.', 0, NULL, '2026-04-19T13:33:43.915Z');
