INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (73, 'templates_mjm_Injected', 1, 72, 'Noise Injected VideoGen', 'Upload a starting image and a mask video to define the injection area. Generate a dynamic video by injecting noise patterns from a dedicated noise video, with AI auto-generated prompts.', 'image', 'webp', NULL, '["output/templates_mjm_Injected.mp4"]', '["Video","Image to Video"]', '["SD1.5"]', '[]', '["QwenVL","comfyui-animatediff-evolved","comfyui-frame-interpolation","comfyui-videohelpersuite"]', '[]', '{"inputs":[{"nodeId":8,"nodeType":"LoadImage","file":"Init.png","mediaType":"image"},{"nodeId":126,"nodeType":"VHS_LoadVideo","file":"Noise_injection.mp4","mediaType":"video"},{"nodeId":137,"nodeType":"VHS_LoadVideo","file":"Mask.mp4","mediaType":"video"}],"outputs":[{"nodeId":209,"nodeType":"SaveVideo","file":"templates_mjm_Injected.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-02', 1, 'active', 10737418240, 10737418240, 48, 0, 'Julien | MJM', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_Injected', 'en', 'Noise Injected VideoGen', 'Upload a starting image and a mask video to define the injection area. Generate a dynamic video by injecting noise patterns from a dedicated noise video, with AI auto-generated prompts.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_Injected', 'zh', '噪声注入视频生成', '上传起始图像和遮罩视频以定义注入区域。通过从专用噪声视频注入噪声模式，结合AI自动生成的提示，生成动态视频。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_Injected', 'zh-TW', '噪聲注入影片生成', '上傳起始圖像和遮罩影片以定義注入區域。透過從專用噪聲影片注入噪聲模式，結合AI自動生成的提示，生成動態影片。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_Injected', 'ja', 'ノイズ注入動画生成', '開始画像とマスク動画をアップロードして注入領域を定義します。専用のノイズ動画からノイズパターンを注入し、AIが自動生成したプロンプトと組み合わせて動的動画を生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_Injected', 'ko', '노이즈 주입 비디오 생성', '시작 이미지와 마스크 비디오를 업로드하여 주입 영역을 정의합니다. 전용 노이즈 비디오에서 노이즈 패턴을 주입하고 AI가 자동 생성한 프롬프트와 결합하여 동적 비디오를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_Injected', 'es', 'Generación de Video con Inyección de Ruido', 'Sube una imagen inicial y un video de máscara para definir el área de inyección. Genera un video dinámico inyectando patrones de ruido desde un video de ruido dedicado, con indicaciones generadas automáticamente por IA.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_Injected', 'fr', 'Génération de Vidéo par Injection de Bruit', 'Téléchargez une image de départ et une vidéo de masque pour définir la zone d''injection. Générez une vidéo dynamique en injectant des motifs de bruit depuis une vidéo de bruit dédiée, avec des invites générées automatiquement par IA.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_Injected', 'ru', 'Генерация видео с инъекцией шума', 'Загрузите начальное изображение и видео-маску, чтобы определить область инъекции. Создайте динамическое видео, вводя шумовые паттерны из специального шумового видео, с автоматически сгенерированными ИИ подсказками.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_Injected', 'tr', 'Gürültü Enjekte Edilmiş Video Üretimi', 'Enjeksiyon alanını tanımlamak için bir başlangıç görüntüsü ve maske videosu yükleyin. Özel bir gürültü videosundan gürültü desenleri enjekte ederek, AI tarafından otomatik oluşturulan istemlerle dinamik bir video oluşturun.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_Injected', 'ar', 'توليد الفيديو بحقن الضوضاء', 'قم بتحميل صورة بداية وفيديو قناع لتحديد منطقة الحقن. أنشئ فيديو ديناميكيًا بحقن أنماط ضوضاء من فيديو ضوضاء مخصص، مع مطالبات تم إنشاؤها تلقائيًا بواسطة الذكاء الاصطناعي.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_Injected', 'pt-BR', 'Geração de Vídeo com Injeção de Ruído', 'Faça upload de uma imagem inicial e um vídeo de máscara para definir a área de injeção. Gere um vídeo dinâmico injetando padrões de ruído de um vídeo de ruído dedicado, com prompts gerados automaticamente por IA.', 0, NULL, '2026-04-19T13:33:43.915Z');
