INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-textured_logo_elements', 'zh-TW', '為 logo 加上紋理元素', '上傳你的 logo、材質和元素。產生一段品牌風格紋理 logo 的影片素材。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-textured_logo_elements', 'ja', 'logoにテクスチャと要素', 'ロゴ、テクスチャ、要素をアップロードしてください。ロゴにテクスチャが付いたブランド動画を生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-textured_logo_elements', 'ko', 'logo에 텍스처·요소 추가', '로고, 텍스처, 요소를 업로드하세요. 텍스처가 적용된 브랜드 로고 영상을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
