INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_to_2x2_mockups-v2.0', 'pt-BR', 'Mockups de Cena de Pôster', 'Carregue um design de pôster/anúncio e com uma breve entrada sobre sua marca, gere 4 mockups em múltiplas cenas.', 0, NULL, '2026-04-19T13:33:43.915Z');
