INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_product_integration', 'en', 'Generate Poster/Ad Asset with your Product', 'Upload your product and a simple text prompt for the poster or ad design. Iterate on the look before swapping the product into the generate layout.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_product_integration', 'zh', '用你的产品生成海报/广告素材', '上传你的产品图片和一句文案，生成海报设计，替换产品前可多次微调。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_product_integration', 'zh-TW', '使用你的產品產生海報/廣告素材', '上傳你的產品圖和一句文案，產生海報設計，可在更換產品前多次調整。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_product_integration', 'ja', 'あなたの製品でポスター・広告素材を作成', '商品画像と短いテキストをアップロードし、ポスター用デザインを作成。商品差し替え前に微調整できます。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_product_integration', 'ko', '제품으로 포스터/광고 에셋 만들기', '제품 사진과 간단한 문구로 포스터/광고 디자인 생성, 제품 교체 전 여러 번 수정 가능.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_product_integration', 'es', 'Genera póster/anuncio con tu producto', 'Sube tu producto y un texto breve. Genera un póster y ajusta el diseño antes de insertar el producto.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_product_integration', 'fr', 'Créer une affiche/pub avec votre produit', 'Télécharge ton produit et une courte description. Crée une affiche, modifie le design avant d’intégrer le produit.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_product_integration', 'ru', 'Создать постер/рекламу с вашим продуктом', 'Загрузите фото продукта и короткий текст, создайте макет постера. Вы можете менять дизайн до замены продукта.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_product_integration', 'tr', 'Ürününle afiş/reklam varlığı oluştur', 'Ürününü ve kısa bir metni yükle, poster tasarımını oluştur. Ürünü yerleştirmeden önce görünümü düzenleyebilirsin.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_product_integration', 'ar', 'أنشئ ملصقًا/إعلانًا بمنتجك', 'حمّل صورة منتجك ونصًا قصيرًا، أنشئ ملصقاً وعدّل التصميم قبل استبدال المنتج.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-poster_product_integration', 'pt-BR', 'Gerar Ativo de Pôster/Anúncio com seu Produto', 'Carregue seu produto e um prompt de texto simples para o design do pôster ou anúncio. Itere na aparência antes de trocar o produto pelo layout gerado.', 0, NULL, '2026-04-19T13:33:43.915Z');
