INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-led_billboard', 'zh', 'LED广告牌信息', '上传空白广告牌并叠加文字。生成平滑放大镜头，揭示您的信息。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-led_billboard', 'zh-TW', 'LED廣告看板訊息', '上傳空白廣告牌並疊加文字。生成平滑放大鏡頭，揭示您的訊息。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-led_billboard', 'ja', 'LEDビルボードメッセージ', '空白のビルボードをアップロードし、テキストを重ねます。メッセージを明らかにするスムーズなズームインショットを生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-led_billboard', 'ko', 'LED 빌보드 메시지', '빈 광고판을 업로드하고 텍스트를 오버레이합니다. 메시지를 드러내는 부드러운 줌인 샷을 생성하세요.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-led_billboard', 'es', 'Mensaje de Valla Publicitaria LED', 'Sube una valla publicitaria en blanco y superpone texto. Genera una toma de acercamiento suave que revele tu mensaje.', 0, NULL, '2026-04-19T13:33:43.915Z');
