INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-led_billboard', 'tr', 'LED Billboard Mesajı', 'Boş bir reklam panosu yükleyin ve üzerine metin ekleyin. Mesajınızı ortaya çıkaran düzgün bir yakınlaştırma çekimi oluşturun.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-led_billboard', 'ar', 'رسالة لوحة إعلانات LED', 'قم بتحميل لوحة إعلانية فارغة وضع نصًا فوقها. أنشئ لقطة تكبير سلسة تكشف رسالتك.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates-led_billboard', 'pt-BR', 'Mensagem de Painel LED', 'Faça upload de um painel de publicidade em branco e sobreponha texto. Gere uma tomada de zoom suave que revele sua mensagem.', 0, NULL, '2026-04-19T13:33:43.915Z');
