INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image_turbo', 'ja', 'Z-Image-Turbo テキストから画像へ', '単一ストリーム拡散トランスフォーマを用いた高効率な画像生成基盤モデルで、英語と中国語の両方に対応しています。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image_turbo', 'ko', 'Z-Image-Turbo 텍스트 투 이미지', '싱글 스트림 디퓨전 트랜스포머를 사용하는 효율적인 이미지 생성 기초 모델로, 영어와 중국어를 모두 지원합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image_turbo', 'es', 'Z-Image-Turbo texto a imagen', 'Modelo fundacional eficiente de generación de imágenes con transformador de difusión de flujo único, compatible con inglés y chino.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image_turbo', 'fr', 'Z-Image-Turbo texte vers image', 'Un modèle fondamental efficace de génération d’images utilisant un transformateur de diffusion à flux unique, compatible anglais et chinois.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image_turbo', 'ru', 'Z-Image-Turbo преобразование текста в изображение', 'Эффективная базовая модель генерации изображений с использованием однонаправленного диффузионного трансформера, поддерживает английский и китайский языки.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image_turbo', 'tr', 'Z-Image-Turbo Metinden Görüntüye', 'Tek akışlı difüzyon dönüştürücü kullanan verimli bir görsel üretim temel modeli, İngilizce ve Çince desteğiyle.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image_turbo', 'ar', 'Z-Image-Turbo تحويل النص إلى صورة', 'نموذج أساس فعال لتوليد الصور يستخدم محول انتشار أحادي التدفق، ويدعم اللغتين الإنجليزية والصينية.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image_turbo', 'pt-BR', 'Z-Image-Turbo Texto para Imagem', 'Um Modelo Fundacional de Geração de Imagem Eficiente com Transformer de Difusão de Fluxo Único, suporta inglês & chinês.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (91, 'api_google_nano_banana2_image_edit', 2, 1, 'Nano Banana 2: Image Edit', 'Upload an image and a text prompt to edit it. Generate a new image that modifies the original based on your instructions, maintaining subject consistency and high visual fidelity.', 'image', 'webp', NULL, '[]', '["API","Image Edit"]', '["Google","Nano Banana 2"]', '[{"provider":"Google"}]', '[]', '[]', '{"inputs":[{"nodeId":16,"nodeType":"LoadImage","file":"man_with_dog.png","mediaType":"image"}],"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"api_google_nano_banana2_image_edit.png","mediaType":"image"}]}', NULL, NULL, '2026-02-26', 0, 'active', 0, 0, 7689, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_google_nano_banana2_image_edit', 'en', 'Nano Banana 2: Image Edit', 'Upload an image and a text prompt to edit it. Generate a new image that modifies the original based on your instructions, maintaining subject consistency and high visual fidelity.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_google_nano_banana2_image_edit', 'zh', 'Nano Banana 2：图像编辑', '上传一张图片和一个文本提示来编辑它。根据您的指令生成一张修改原图的新图片，保持主体一致性和高视觉保真度。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_google_nano_banana2_image_edit', 'zh-TW', 'Nano Banana 2：圖像編輯', '上傳一張圖片和一個文字提示來編輯它。根據您的指令生成一張修改原圖的新圖片，保持主體一致性和高視覺保真度。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_google_nano_banana2_image_edit', 'ja', 'Nano Banana 2：画像編集', '画像とテキストプロンプトをアップロードして編集します。元の画像をあなたの指示に基づいて変更し、被写体の一貫性と高い視覚的忠実度を維持した新しい画像を生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_google_nano_banana2_image_edit', 'ko', 'Nano Banana 2: 이미지 편집', '이미지와 텍스트 프롬프트를 업로드하여 편집하세요. 원본을 기반으로 주제 일관성과 높은 시각적 충실도를 유지하면서, 당신의 지시에 따라 수정된 새로운 이미지를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_google_nano_banana2_image_edit', 'es', 'Nano Banana 2: Edición de imagen', 'Sube una imagen y un texto de instrucción para editarla. Genera una nueva imagen que modifique la original según tus indicaciones, manteniendo la coherencia del sujeto y una alta fidelidad visual.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_google_nano_banana2_image_edit', 'fr', 'Nano Banana 2 : Édition d''image', 'Téléchargez une image et une instruction textuelle pour la modifier. Générez une nouvelle image qui modifie l''originale selon vos instructions, en maintenant la cohérence du sujet et une haute fidélité visuelle.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_google_nano_banana2_image_edit', 'ru', 'Nano Banana 2: Редактирование изображений', 'Загрузите изображение и текстовый запрос для его редактирования. Создайте новое изображение, которое изменяет оригинал в соответствии с вашими инструкциями, сохраняя согласованность объекта и высокую визуальную точность.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_google_nano_banana2_image_edit', 'tr', 'Nano Banana 2: Görsel Düzenleme', 'Düzenlemek için bir görsel ve bir metin istemi yükleyin. Orijinal görseli talimatlarınıza göre değiştiren, konu tutarlılığını ve yüksek görsel doğruluğu koruyan yeni bir görsel oluşturun.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_google_nano_banana2_image_edit', 'ar', 'Nano Banana 2: تحرير الصور', 'قم بتحميل صورة وموجه نصي لتحريرها. أنشئ صورة جديدة تعدل الصورة الأصلية بناءً على تعليماتك، مع الحفاظ على اتساق الموضوع ودقة بصرية عالية.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_google_nano_banana2_image_edit', 'pt-BR', 'Nano Banana 2: Edição de Imagem', 'Faça upload de uma imagem e de um prompt de texto para editá-la. Gere uma nova imagem que modifica a original com base nas suas instruções, mantendo a consistência do assunto e alta fidelidade visual.', 0, NULL, '2026-04-19T13:33:43.915Z');
