INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image', 'zh', 'Z-Image: 文生图', '创意自由的基础。多样美学与出色写实品质；适合微调；对负面提示敏感；生成多样性高。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image', 'zh-TW', 'Z-Image: 文生圖', '創意自由的基礎。多元美學與出色寫實品質；適合微調；對負面提示敏感；生成多樣性高。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image', 'ja', 'Z-Image: テキストから画像へ', '創造の自由の基盤。多様な美学と優れたフォトリアル品質。ファインチューニングに最適。ネガティブプロンプトに敏感。高い生成多様性。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image', 'ko', 'Z-Image: 텍스트에서 이미지로', '창작의 자유를 위한 기반. 다양한 미학과 뛰어난 사진적 품질; 파인튜닝에 이상적; 네거티브 프롬프트에 반응적; 높은 생성 다양성.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image', 'es', 'Z-Image: Texto a Imagen', 'Base para la libertad creativa. Estéticas diversas con calidad fotorrealista excepcional; ideal para fine-tuning; responde bien a los prompts negativos; alta diversidad de generación.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image', 'fr', 'Z-Image: Texte vers Image', 'Fondation pour la liberté créative. Esthétiques diverses et qualité photoréaliste exceptionnelle ; idéal pour le fine-tuning ; réactif aux prompts négatifs ; grande diversité de génération.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image', 'ru', 'Z-Image: Текст в изображение', 'Основа творческой свободы. Разнообразная эстетика с исключительным фотореалистичным качеством; идеален для дообучения; чувствителен к негативным промптам; высокая разнообразность генерации.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image', 'tr', 'Z-Image: Metinden Görüntüye', 'Yaratıcı özgürlük için temel. Olağanüstü fotogerçekçi kalitede çeşitli estetikler; ince ayar için ideal; negatif promptlara duyarlı; yüksek üretim çeşitliliği.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image', 'ar', 'Z-Image: نص إلى صورة', 'أساس حرية الإبداع. جماليات متنوعة وجودة واقعية استثنائية؛ مثالي للضبط الدقيق؛ يستجيب للمطالبات السلبية؛ تنوع عالٍ في التوليد.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_z_image', 'pt-BR', 'Z-Image: Texto para Imagem', 'Base para liberdade criativa. Estéticas diversas com qualidade fotorrealista excepcional; ideal para fine-tuning; responsivo a prompts negativos; alta diversidade de geração.', 0, NULL, '2026-04-19T13:33:43.915Z');
