INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_firered_image_edit1_1', 'en', 'FireRed Image Edit 1.1: Image Edit', 'Upload an image and a text prompt to edit it. Generate a modified image with enhanced identity consistency, multi-element fusion, or professional photo restoration.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_firered_image_edit1_1', 'zh', 'FireRed 图像编辑 1.1：图像编辑', '上传一张图片和一个文本提示来编辑它。生成一张经过修改的图片，具有增强的身份一致性、多元素融合或专业照片修复功能。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_firered_image_edit1_1', 'zh-TW', 'FireRed 圖像編輯 1.1：圖像編輯', '上傳一張圖片和一個文字提示來編輯它。生成一張經過修改的圖片，具有增強的身份一致性、多元素融合或專業照片修復功能。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_firered_image_edit1_1', 'ja', 'FireRed 画像編集 1.1：画像編集', '画像とテキストプロンプトをアップロードして編集します。アイデンティティの一貫性を強化した、複数要素の融合、またはプロフェッショナルな写真修復を施した修正画像を生成します。', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_firered_image_edit1_1', 'ko', 'FireRed 이미지 편집 1.1：이미지 편집', '이미지와 텍스트 프롬프트를 업로드하여 편집하세요. 향상된 정체성 일관성, 다중 요소 융합 또는 전문적인 사진 복원 기능을 갖춘 수정된 이미지를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_firered_image_edit1_1', 'es', 'FireRed Edición de Imagen 1.1: Edición de Imagen', 'Sube una imagen y un texto de instrucción para editarla. Genera una imagen modificada con consistencia de identidad mejorada, fusión de múltiples elementos o restauración fotográfica profesional.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_firered_image_edit1_1', 'fr', 'FireRed Édition d''Image 1.1 : Édition d''Image', 'Téléchargez une image et une instruction textuelle pour la modifier. Générez une image modifiée avec une cohérence d''identité améliorée, une fusion multi-éléments ou une restauration photo professionnelle.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_firered_image_edit1_1', 'ru', 'FireRed Редактирование Изображения 1.1: Редактирование Изображения', 'Загрузите изображение и текстовый запрос для его редактирования. Создайте измененное изображение с улучшенной согласованностью идентичности, слиянием нескольких элементов или профессиональной реставрацией фотографии.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_firered_image_edit1_1', 'tr', 'FireRed Görüntü Düzenleme 1.1: Görüntü Düzenleme', 'Düzenlemek için bir görsel ve bir metin istemi yükleyin. Geliştirilmiş kimlik tutarlılığı, çoklu öğe birleşimi veya profesyonel fotoğraf restorasyonu ile değiştirilmiş bir görsel oluşturun.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_firered_image_edit1_1', 'ar', 'FireRed تحرير الصورة 1.1: تحرير الصورة', 'قم بتحميل صورة وموجه نصي لتحريرها. قم بإنشاء صورة معدلة مع تحسين اتساق الهوية، أو دمج عناصر متعددة، أو ترميم الصور الاحترافي.', 0, NULL, '2026-04-19T13:33:43.915Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_firered_image_edit1_1', 'pt-BR', 'FireRed Edição de Imagem 1.1: Edição de Imagem', 'Faça upload de uma imagem e de um prompt de texto para editá-la. Gere uma imagem modificada com consistência de identidade aprimorada, fusão de múltiplos elementos ou restauração fotográfica profissional.', 0, NULL, '2026-04-19T13:33:43.915Z');
