INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_9b_kv_image_edit', 'ar', 'Flux.2 Klein KV: تحرير الصورة', 'قم بتحميل صور مرجعية وموجه نصي. قم بإنشاء صور معدلة متعددة باستخدام بيانات الصور المخزنة مؤقتًا لمعالجة أسرع.', 0, NULL, '2026-04-19T13:33:43.916Z');
