INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image_turbo', 'en', 'Ernie Image Turbo: Text To Image', 'Generate images from text prompts using the ERNIE-Image turbo model. Input a text description and receive a high-quality image with precise text rendering and structured layouts.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image_turbo', 'zh', 'Ernie Image Turbo：文生图', '使用ERNIE-Image turbo模型从文本提示生成图像。输入文本描述，即可获得具有精确文本渲染和结构化布局的高质量图像。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image_turbo', 'zh-TW', 'Ernie Image Turbo：文生圖', '使用ERNIE-Image turbo模型從文本提示生成圖像。輸入文本描述，即可獲得具有精確文本渲染和結構化佈局的高質量圖像。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image_turbo', 'ja', 'Ernie Image Turbo：テキストから画像', 'ERNIE-Image turboモデルを使用して、テキストプロンプトから画像を生成します。テキストの説明を入力すると、正確なテキストレンダリングと構造化されたレイアウトを備えた高品質な画像を受け取ります。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image_turbo', 'ko', 'Ernie Image Turbo: 텍스트를 이미지로', 'ERNIE-Image turbo 모델을 사용하여 텍스트 프롬프트에서 이미지를 생성합니다. 텍스트 설명을 입력하면 정확한 텍스트 렌더링과 구조화된 레이아웃을 갖춘 고품질 이미지를 받을 수 있습니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image_turbo', 'es', 'Ernie Image Turbo: Texto a Imagen', 'Genera imágenes a partir de indicaciones de texto utilizando el modelo ERNIE-Image turbo. Introduce una descripción de texto y recibe una imagen de alta calidad con representación precisa del texto y diseños estructurados.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image_turbo', 'fr', 'Ernie Image Turbo : Texte vers Image', 'Générez des images à partir d''invites textuelles en utilisant le modèle ERNIE-Image turbo. Saisissez une description textuelle et recevez une image de haute qualité avec un rendu de texte précis et des mises en page structurées.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image_turbo', 'ru', 'Ernie Image Turbo: Текст в изображение', 'Создавайте изображения из текстовых запросов с помощью модели ERNIE-Image turbo. Введите текстовое описание и получите высококачественное изображение с точной отрисовкой текста и структурированными макетами.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image_turbo', 'tr', 'Ernie Image Turbo: Metinden Görüntüye', 'ERNIE-Image turbo modelini kullanarak metin istemlerinden görüntüler oluşturun. Bir metin açıklaması girin ve kesin metin işleme ve yapılandırılmış düzenlerle yüksek kaliteli bir görüntü alın.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image_turbo', 'ar', 'Ernie Image Turbo: نص إلى صورة', 'قم بإنشاء الصور من نصوص الإدخال باستخدام نموذج ERNIE-Image turbo. أدخل وصفًا نصيًا واحصل على صورة عالية الجودة مع عرض نص دقيق وتخطيطات منظمة.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image_turbo', 'pt-BR', 'Ernie Image Turbo: Texto para Imagem', 'Gere imagens a partir de prompts de texto usando o modelo ERNIE-Image turbo. Insira uma descrição de texto e receba uma imagem de alta qualidade com renderização precisa de texto e layouts estruturados.', 0, NULL, '2026-04-19T13:33:43.916Z');
