INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image', 'zh', 'Ernie Image：文生图', '使用ERNIE-Image模型从文本提示生成图像。输入文本描述，即可生成风格多样、细节丰富的结构化视觉效果。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image', 'zh-TW', 'Ernie Image：文生圖', '使用ERNIE-Image模型從文本提示生成圖像。輸入文本描述，即可生成風格多樣、細節豐富的結構化視覺效果。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image', 'ja', 'Ernie Image：テキストから画像へ', 'ERNIE-Imageモデルを使用して、テキストプロンプトから画像を生成します。テキストで説明を入力すると、幅広いスタイルの詳細な構造化ビジュアルが作成されます。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image', 'ko', 'Ernie Image: 텍스트를 이미지로', 'ERNIE-Image 모델을 사용하여 텍스트 프롬프트에서 이미지를 생성합니다. 텍스트 설명을 입력하면 다양한 스타일의 세부적이고 구조화된 시각적 결과물을 생성할 수 있습니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image', 'es', 'Ernie Image: Texto a Imagen', 'Genera imágenes a partir de indicaciones de texto utilizando el modelo ERNIE-Image. Introduce una descripción de texto para producir imágenes detalladas y estructuradas con una amplia gama de estilos.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image', 'fr', 'Ernie Image : Texte vers Image', 'Générez des images à partir de suggestions textuelles en utilisant le modèle ERNIE-Image. Saisissez une description textuelle pour produire des visuels détaillés et structurés avec une large gamme de styles.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image', 'ru', 'Ernie Image: Текст в изображение', 'Создавайте изображения из текстовых запросов с помощью модели ERNIE-Image. Введите текстовое описание, чтобы получить детализированные, структурированные визуальные элементы с широким стилистическим диапазоном.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ernie_image', 'tr', 'Ernie Image: Metinden Görüntüye', 'ERNIE-Image modelini kullanarak metin istemlerinden görüntüler oluşturun. Geniş bir stil yelpazesine sahip ayrıntılı, yapılandırılmış görseller üretmek için bir metin açıklaması girin.', 0, NULL, '2026-04-19T13:33:43.916Z');
