INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_seedream_5_0_lite_t2i', 'zh', 'Seedream 5.0 Lite：文生图', '输入您的文本提示以生成详细图像。此工作流程根据您的描述创建视觉呈现，精确控制样式和布局。', 0, NULL, '2026-04-19T13:33:43.916Z');
