INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_seedream_5_0_lite_t2i', 'ja', 'Seedream 5.0 Lite：テキストから画像へ', '詳細な画像を生成するためにテキストプロンプトを入力してください。このワークフローは、スタイルとレイアウトを正確に制御しながら、ご記述内容の視覚的表現を作成します。', 0, NULL, '2026-04-19T13:33:43.916Z');
