INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_seedream_5_0_lite_t2i', 'es', 'Seedream 5.0 Lite: Texto a Imagen', 'Ingrese su indicación de texto para generar una imagen detallada. Este flujo de trabajo crea una representación visual de su descripción con control preciso sobre el estilo y el diseño.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_seedream_5_0_lite_t2i', 'fr', 'Seedream 5.0 Lite : Texte vers Image', 'Saisissez votre invite de texte pour générer une image détaillée. Ce flux de travail crée une représentation visuelle de votre description avec un contrôle précis du style et de la mise en page.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_seedream_5_0_lite_t2i', 'ru', 'Seedream 5.0 Lite: Текст в изображение', 'Введите свой текстовый запрос для создания детального изображения. Этот рабочий процесс создает визуальное представление вашего описания с точным контролем стиля и макета.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_seedream_5_0_lite_t2i', 'tr', 'Seedream 5.0 Lite: Metinden Görüntüye', 'Detaylı bir görsel oluşturmak için metin isteminizi girin. Bu iş akışı, stil ve düzen üzerinde hassas kontrol ile açıklamanızın görsel bir temsilini oluşturur.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_seedream_5_0_lite_t2i', 'ar', 'Seedream 5.0 Lite: النص إلى الصورة', 'أدخل مطالبتك النصية لإنشاء صورة مفصلة. يخلق سير العمل هذا تمثيلًا مرئيًا لوصفك مع تحكم دقيق في النمط والتخطيط.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_seedream_5_0_lite_t2i', 'pt-BR', 'Seedream 5.0 Lite: Texto para Imagem', 'Insira seu prompt de texto para gerar uma imagem detalhada. Este fluxo de trabalho cria uma representação visual da sua descrição com controle preciso sobre estilo e layout.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (103, 'image_qwen_Image_2512', 2, 13, 'Qwen Image 2512', 'Text-to-image model with enhanced human realism, finer natural details for landscapes and animal fur, and improved text rendering with accurate layout and multimodal composition.', 'image', 'webp', NULL, '["output/image_qwen_Image_2512.png"]', '["Image","Text to Image"]', '["Qwen","Qwen-Image"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":60,"nodeType":"SaveImage","file":"image_qwen_Image_2512.png","mediaType":"image"}]}', NULL, NULL, '2025-12-31', 1, 'active', 31782757990, 31782757990, 1989, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512', 'en', 'Qwen Image 2512', 'Text-to-image model with enhanced human realism, finer natural details for landscapes and animal fur, and improved text rendering with accurate layout and multimodal composition.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512', 'zh', 'Qwen Image 2512', '文本到图像模型，具备更真实的人体细节、更精细的自然风景和动物毛发效果，以及更准确的文字排版和多模态融合。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512', 'zh-TW', 'Qwen Image 2512', '文字轉圖像模型，提升人體真實感、自然風景和動物毛髮更細緻，並加強文字排版及多模態組合表現。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512', 'ja', 'Qwen Image 2512', 'テキストから画像への変換モデル。人物のリアルさや、風景・動物の毛並みの細かな表現、文字やレイアウト、多モーダル合成が強化されています。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512', 'ko', 'Qwen Image 2512', '텍스트-이미지 모델로 인간 사실감, 자연 경관과 동물 털의 세밀함, 텍스트 레이아웃과 멀티모달 구성 모두 향상됨.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512', 'es', 'Qwen Image 2512', 'Modelo de texto a imagen con realismo humano mejorado, detalles naturales finos en paisajes y pelaje animal, y mejor renderizado de texto y composición multimodal.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512', 'fr', 'Qwen Image 2512', 'Modèle texte-vers-image offrant un réalisme humain accru, des détails naturels fins pour paysages et pelages d’animaux, et un rendu de texte amélioré avec composition multimodale.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512', 'ru', 'Qwen Image 2512', 'Модель текст-в-изображение: улучшенный реализим людей, тонкие натуральные детали пейзажей и шерсти животных, улучшенное отображение текста и мультимодальная компоновка.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512', 'tr', 'Qwen Image 2512', 'Yazıdan-görüntüye model: Gelişmiş insan gerçekçiliği, doğa ve hayvan tüylerinde daha ince detaylar, metin düzeninde ve çoklu mod kompozisyonda gelişmişlik.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512', 'ar', 'Qwen Image 2512', 'نموذج تحويل النص إلى صورة مع تعزيز واقعية الأشخاص، تفاصيل طبيعية أدق للمناظر والفرو، وتحسين عرض النص وتنسيقه وتكوين متعدد الوسائط.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512', 'pt-BR', 'Qwen Image 2512', 'Modelo texto-para-imagem com realismo humano aprimorado, detalhes naturais mais finos em paisagens e pelos de animais e melhor renderização e composição multimodal de texto.', 0, NULL, '2026-04-19T13:33:43.916Z');
