INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (105, 'api_recraft_v4_t2i', 2, 15, 'Recraft v4: Text to Image', 'Input a text prompt to generate a high-resolution image. Use the Recraft V4 model for enhanced realism, text accuracy, and detailed vector graphics. Output a 1024x1024 or 2048x2048 image based on your selected version.', 'image', 'webp', NULL, '["output/api_recraft_v4_t2i.png"]', '["API","Image","Text to Image"]', '["Recraft"]', '[{"provider":"Recraft"}]', '[]', '[]', '{"outputs":[{"nodeId":5,"nodeType":"SaveImage","file":"api_recraft_v4_t2i.png","mediaType":"image"}]}', NULL, NULL, '2026-02-17', 0, 'active', 0, 0, 329, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_t2i', 'en', 'Recraft v4: Text to Image', 'Input a text prompt to generate a high-resolution image. Use the Recraft V4 model for enhanced realism, text accuracy, and detailed vector graphics. Output a 1024x1024 or 2048x2048 image based on your selected version.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_t2i', 'zh', 'Recraft v4：文生图', '输入文本提示以生成高分辨率图像。使用Recraft V4模型以获得增强的真实感、文本准确性和详细的矢量图形。根据您选择的版本输出1024x1024或2048x2048的图像。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_t2i', 'zh-TW', 'Recraft v4：文字轉圖像', '輸入文字提示以生成高解析度影像。使用Recraft V4模型以獲得增強的寫實感、文字準確性和詳細的向量圖形。根據您選擇的版本輸出1024x1024或2048x2048的影像。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_t2i', 'ja', 'Recraft v4：テキストから画像へ', 'テキストプロンプトを入力して高解像度画像を生成します。Recraft V4モデルを使用して、リアリズム、テキスト精度、詳細なベクターグラフィックスを強化します。選択したバージョンに基づいて1024x1024または2048x2048の画像を出力します。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_t2i', 'ko', 'Recraft v4：텍스트를 이미지로', '텍스트 프롬프트를 입력하여 고해상도 이미지를 생성합니다. 향상된 사실감, 텍스트 정확도 및 상세한 벡터 그래픽을 위해 Recraft V4 모델을 사용합니다. 선택한 버전에 따라 1024x1024 또는 2048x2048 이미지를 출력합니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_t2i', 'es', 'Recraft v4: Texto a imagen', 'Introduzca un texto de entrada para generar una imagen de alta resolución. Utilice el modelo Recraft V4 para mejorar el realismo, la precisión del texto y los gráficos vectoriales detallados. Genere una imagen de 1024x1024 o 2048x2048 según la versión seleccionada.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_t2i', 'fr', 'Recraft v4 : Texte en image', 'Saisissez une invite textuelle pour générer une image haute résolution. Utilisez le modèle Recraft V4 pour un réalisme amélioré, une précision textuelle et des graphiques vectoriels détaillés. Produisez une image de 1024x1024 ou 2048x2048 selon la version sélectionnée.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_t2i', 'ru', 'Recraft v4: Текст в изображение', 'Введите текстовый запрос для создания изображения высокого разрешения. Используйте модель Recraft V4 для улучшенного реализма, точности текста и детализированной векторной графики. Выведите изображение размером 1024x1024 или 2048x2048 в зависимости от выбранной версии.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_t2i', 'tr', 'Recraft v4: Metinden Görüntüye', 'Yüksek çözünürlüklü bir görüntü oluşturmak için bir metin istemi girin. Gelişmiş gerçekçilik, metin doğruluğu ve ayrıntılı vektör grafikleri için Recraft V4 modelini kullanın. Seçtiğiniz sürüme göre 1024x1024 veya 2048x2048 boyutunda bir görüntü çıktısı alın.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_t2i', 'ar', 'Recraft v4: نص إلى صورة', 'أدخل نصًا لإنشاء صورة عالية الدقة. استخدم نموذج Recraft V4 لتحسين الواقعية ودقة النصوص والرسومات المتجهة التفصيلية. أنتج صورة بحجم 1024x1024 أو 2048x2048 بناءً على الإصدار الذي تختاره.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_t2i', 'pt-BR', 'Recraft v4: Texto para Imagem', 'Insira um prompt de texto para gerar uma imagem de alta resolução. Use o modelo Recraft V4 para realismo aprimorado, precisão de texto e gráficos vetoriais detalhados. Gere uma imagem de 1024x1024 ou 2048x2048 com base na versão selecionada.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (106, 'image_qwen_image_edit_2511', 2, 16, 'Qwen Image Edit 2511 - Material Replacement', 'Replace materials in objects (e.g., furniture) by combining reference images with Qwen-Image-Edit-2511.', 'image', 'webp', 'compareSlider', '["input/leather_sofa.png","output/image_qwen_image_edit_2511.png"]', '["Image Edit"]', '["Qwen-Image-Edit"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":41,"nodeType":"LoadImage","file":"leather_sofa.png","mediaType":"image"},{"nodeId":83,"nodeType":"LoadImage","file":"texture_fur.png","mediaType":"image"}],"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"image_qwen_image_edit_2511.png","mediaType":"image"}]}', NULL, NULL, '2025-12-23', 1, 'active', 51324859187, 51324859187, 1946, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_edit_2511', 'en', 'Qwen Image Edit 2511 - Material Replacement', 'Replace materials in objects (e.g., furniture) by combining reference images with Qwen-Image-Edit-2511.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_edit_2511', 'zh', 'Qwen Image Edit 2511 - 材质替换', '通过组合参考图像，使用 Qwen-Image-Edit-2511 替换物体（如家具）的材质。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_edit_2511', 'zh-TW', 'Qwen Image Edit 2511 - 材質更換', '結合參考圖像，使用 Qwen-Image-Edit-2511 替換物件（如家具）的材質。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_edit_2511', 'ja', 'Qwen Image Edit 2511 - 素材置き換え', '参照画像を組み合わせて、Qwen-Image-Edit-2511 でオブジェクト（例：家具）の素材を入れ替えます。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_edit_2511', 'ko', 'Qwen Image Edit 2511 - 소재 교체', '참조 이미지를 조합하여 Qwen-Image-Edit-2511로 객체(예: 가구)의 재질을 교체합니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_edit_2511', 'es', 'Qwen Image Edit 2511 - Reemplazo de Materiales', 'Combina imágenes de referencia para reemplazar materiales en objetos (por ejemplo, muebles) con Qwen-Image-Edit-2511.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_edit_2511', 'fr', 'Qwen Image Edit 2511 - Remplacement de matériau', 'Remplacez les matériaux d''objets (ex. meubles) en combinant des images de référence avec Qwen-Image-Edit-2511.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_edit_2511', 'ru', 'Qwen Image Edit 2511 — Замена материала', 'Замените материалы объектов (например, мебели), комбинируя референсные изображения с Qwen-Image-Edit-2511.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_edit_2511', 'tr', 'Qwen Image Edit 2511 - Malzeme Değişimi', 'Referans görselleri birleştirerek Qwen-Image-Edit-2511 ile nesnelerdeki (örn. mobilya) malzemeleri değiştirin.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_edit_2511', 'ar', 'Qwen Image Edit 2511 - استبدال الخامة', 'استبدل المواد في الأشياء (مثل الأثاث) من خلال دمج الصور المرجعية مع Qwen-Image-Edit-2511.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_edit_2511', 'pt-BR', 'Qwen Image Edit 2511 - Troca de Material', 'Substitua materiais em objetos (ex: móveis) combinando imagens de referência com Qwen-Image-Edit-2511.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (107, 'image_longcat_image_edit', 2, 17, 'LongCat Image Edit', 'Edit images using the LongCat-Image-Edit model. Supports bilingual instructions for global, local, text, and reference-guided editing while preserving visual consistency.', 'image', 'webp', 'compareSlider', '["input/steel_in_the_mist.png","output/image_longcat_image_edit.png"]', '["Image","Image Edit"]', '["LongCat Image Edit"]', '[]', '[]', '["local"]', '{"inputs":[{"nodeId":13,"nodeType":"LoadImage","file":"steel_in_the_mist.png","mediaType":"image"}],"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"image_longcat_image_edit.png","mediaType":"image"}]}', NULL, NULL, '2026-03-23', 1, 'active', 22226455757, 22226455757, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_image_edit', 'en', 'LongCat Image Edit', 'Edit images using the LongCat-Image-Edit model. Supports bilingual instructions for global, local, text, and reference-guided editing while preserving visual consistency.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_image_edit', 'zh', '长猫图片编辑', '使用LongCat-Image-Edit模型编辑图像。支持双语指令，用于全局、局部、文本和参考引导编辑，同时保持视觉一致性。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_image_edit', 'zh-TW', '長貓圖片編輯', '使用LongCat-Image-Edit模型編輯圖像。支援雙語指令，用於全域、局部、文字和參考引導編輯，同時保持視覺一致性。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_image_edit', 'ja', 'ロングキャット画像編集', 'LongCat-Image-Editモデルを使用して画像を編集します。視覚的一貫性を保ちながら、グローバル、ローカル、テキスト、および参照ガイド編集のための二言語指示をサポートします。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_image_edit', 'ko', '롱캣 이미지 편집', 'LongCat-Image-Edit 모델을 사용하여 이미지를 편집합니다. 시각적 일관성을 유지하면서 전역, 지역, 텍스트 및 참조 안내 편집을 위한 이중 언어 지침을 지원합니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_image_edit', 'es', 'Edición de Imagen LongCat', 'Edita imágenes usando el modelo LongCat-Image-Edit. Admite instrucciones bilingües para edición global, local, de texto y guiada por referencia, manteniendo la coherencia visual.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_image_edit', 'fr', 'Édition d''Image LongCat', 'Modifiez des images à l''aide du modèle LongCat-Image-Edit. Prend en charge des instructions bilingues pour l''édition globale, locale, textuelle et guidée par référence, tout en préservant la cohérence visuelle.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_image_edit', 'ru', 'Редактирование изображения LongCat', 'Редактируйте изображения с помощью модели LongCat-Image-Edit. Поддерживает двуязычные инструкции для глобального, локального, текстового и эталонного редактирования с сохранением визуальной согласованности.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_image_edit', 'tr', 'LongCat Görsel Düzenleme', 'LongCat-Image-Edit modelini kullanarak görüntüleri düzenleyin. Görsel tutarlılığı korurken küresel, yerel, metin ve referans rehberli düzenleme için çift dilli talimatları destekler.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_image_edit', 'ar', 'تحرير صورة لونغ كات', 'قم بتحرير الصور باستخدام نموذج LongCat-Image-Edit. يدعم تعليمات ثنائية اللغة للتحرير الشامل والمحلي والنصي والموجه بالمراجع مع الحفاظ على الاتساق البصري.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_image_edit', 'pt-BR', 'Edição de Imagem LongCat', 'Edite imagens usando o modelo LongCat-Image-Edit. Suporta instruções bilíngues para edição global, local, de texto e guiada por referência, preservando a consistência visual.', 0, NULL, '2026-04-19T13:33:43.916Z');
