INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512_controlnet', 'en', 'Qwen-Image 2512: Fun Union ControlNet', 'Upload an image and select a control type from Canny, HED, Depth, Pose, MLSD, Scribble, or Grayscale. Generate a new image guided by the chosen structural condition.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512_controlnet', 'zh', 'Qwen-Image 2512：趣味联盟控制网', '上传一张图片，并从Canny、HED、Depth、Pose、MLSD、Scribble或Grayscale中选择一种控制类型。根据所选的结构条件生成一张新图像。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512_controlnet', 'zh-TW', 'Qwen-Image 2512：趣味聯盟控制網', '上傳一張圖片，並從Canny、HED、Depth、Pose、MLSD、Scribble或Grayscale中選擇一種控制類型。根據所選的結構條件生成一張新圖像。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512_controlnet', 'ja', 'Qwen-Image 2512：ファンユニオンコントロールネット', '画像をアップロードし、Canny、HED、Depth、Pose、MLSD、Scribble、またはGrayscaleから制御タイプを選択してください。選択した構造条件に基づいて新しい画像を生成します。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512_controlnet', 'ko', 'Qwen-Image 2512: 펀 유니온 컨트롤넷', '이미지를 업로드하고 Canny, HED, Depth, Pose, MLSD, Scribble 또는 Grayscale 중에서 제어 유형을 선택하세요. 선택한 구조적 조건에 따라 새로운 이미지를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512_controlnet', 'es', 'Qwen-Image 2512: Red de Control de Unión Divertida', 'Sube una imagen y selecciona un tipo de control entre Canny, HED, Depth, Pose, MLSD, Scribble o Grayscale. Genera una nueva imagen guiada por la condición estructural elegida.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512_controlnet', 'fr', 'Qwen-Image 2512 : Réseau de Contrôle de l''Union Amusante', 'Téléchargez une image et sélectionnez un type de contrôle parmi Canny, HED, Depth, Pose, MLSD, Scribble ou Grayscale. Générez une nouvelle image guidée par la condition structurelle choisie.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512_controlnet', 'ru', 'Qwen-Image 2512: Весёлый Союз ControlNet', 'Загрузите изображение и выберите тип управления из Canny, HED, Depth, Pose, MLSD, Scribble или Grayscale. Создайте новое изображение, руководствуясь выбранным структурным условием.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512_controlnet', 'tr', 'Qwen-Image 2512: Eğlence Birliği Kontrol Ağı', 'Bir görsel yükleyin ve Canny, HED, Depth, Pose, MLSD, Scribble veya Grayscale''dan bir kontrol türü seçin. Seçilen yapısal koşula göre yeni bir görsel oluşturun.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512_controlnet', 'ar', 'Qwen-Image 2512: شبكة تحكم اتحاد المرح', 'قم بتحميل صورة واختر نوع تحكم من Canny أو HED أو Depth أو Pose أو MLSD أو Scribble أو Grayscale. أنشئ صورة جديدة مسترشدة بالشرط الهيكلي المختار.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_Image_2512_controlnet', 'pt-BR', 'Qwen-Image 2512: Rede de Controle da União Divertida', 'Faça upload de uma imagem e selecione um tipo de controle entre Canny, HED, Depth, Pose, MLSD, Scribble ou Grayscale. Gere uma nova imagem guiada pela condição estrutural escolhida.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (110, 'image_longcat_text_to_image', 2, 20, 'LongCat Image: Text to Image', 'Generate an image from a text prompt. Input your desired scene description in English or Chinese. Output a photorealistic image with accurate text rendering.', 'image', 'webp', NULL, '["output/image_longcat_text_to_image.png"]', '["Image","Text to Image"]', '["LongCat"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"image_longcat_text_to_image.png","mediaType":"image"}]}', NULL, NULL, '2026-03-02', 1, 'active', 22226455757, 22226455757, 392, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_text_to_image', 'en', 'LongCat Image: Text to Image', 'Generate an image from a text prompt. Input your desired scene description in English or Chinese. Output a photorealistic image with accurate text rendering.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_text_to_image', 'zh', 'LongCat Image：文生图', '根据文本提示生成图像。输入您想要的场景描述（英文或中文）。输出具有准确文本渲染的逼真图像。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_text_to_image', 'zh-TW', 'LongCat Image：文字轉圖像', '根據文本提示生成圖像。輸入您想要的場景描述（英文或中文）。輸出具有準確文本渲染的逼真圖像。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_text_to_image', 'ja', 'LongCat Image：テキストから画像へ', 'テキストプロンプトから画像を生成します。希望のシーン説明を英語または中国語で入力してください。正確なテキストレンダリングを備えた写実的な画像を出力します。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_text_to_image', 'ko', 'LongCat Image：텍스트를 이미지로', '텍스트 프롬프트에서 이미지를 생성합니다. 원하는 장면 설명을 영어 또는 중국어로 입력하세요. 정확한 텍스트 렌더링이 포함된 사실적인 이미지를 출력합니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_text_to_image', 'es', 'LongCat Image: Texto a imagen', 'Genera una imagen a partir de un texto descriptivo. Ingresa la descripción de la escena que deseas en inglés o chino. Produce una imagen fotorrealista con representación precisa del texto.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_text_to_image', 'fr', 'LongCat Image : Texte vers image', 'Générez une image à partir d''une invite textuelle. Saisissez la description de la scène souhaitée en anglais ou en chinois. Produisez une image photoréaliste avec un rendu de texte précis.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_text_to_image', 'ru', 'LongCat Image: Текст в изображение', 'Создайте изображение по текстовому запросу. Введите описание желаемой сцены на английском или китайском языке. Получите фотореалистичное изображение с точной отрисовкой текста.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_text_to_image', 'tr', 'LongCat Image: Metinden Görüntüye', 'Bir metin isteminden görsel oluşturun. İstediğiniz sahne açıklamasını İngilizce veya Çince girin. Doğru metin işlemeli fotogerçekçi bir görsel çıktısı alın.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_text_to_image', 'ar', 'LongCat Image: نص إلى صورة', 'إنشاء صورة من نص موجه. أدخل وصف المشهد المطلوب باللغة الإنجليزية أو الصينية. إخراج صورة واقعية مع عرض نص دقيق.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_longcat_text_to_image', 'pt-BR', 'LongCat Image: Texto para Imagem', 'Gere uma imagem a partir de um prompt de texto. Insira a descrição da cena desejada em inglês ou chinês. Produza uma imagem fotorrealista com renderização precisa de texto.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (111, 'api_kling_o3_image', 2, 21, 'Kling O3: Image Genertaion', 'Upload up to 10 reference images to guide the synthesis. Generate a new image using the Kling O3 model based on your provided visual inputs.', 'image', 'webp', NULL, '["output/api_kling_o3_image.json"]', '["API","Image Edit","Text to Image"]', '["Kling O3"]', '[{"provider":"Kling"}]', '[]', '[]', '{"inputs":[{"nodeId":31,"nodeType":"LoadImage","file":"vintage_portrait.png","mediaType":"image"},{"nodeId":32,"nodeType":"LoadImage","file":"Urban_Fashion.png","mediaType":"image"}],"outputs":[{"nodeId":29,"nodeType":"SaveImage","file":"api_kling_o3_image.json","mediaType":"image"}]}', NULL, NULL, '2026-02-10', 0, 'active', 0, 0, 985, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_image', 'en', 'Kling O3: Image Genertaion', 'Upload up to 10 reference images to guide the synthesis. Generate a new image using the Kling O3 model based on your provided visual inputs.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_image', 'zh', 'Kling O3：图像生成', '上传最多10张参考图像以指导合成。使用Kling O3模型，基于您提供的视觉输入生成新图像。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_image', 'zh-TW', 'Kling O3：圖像生成', '上傳最多10張參考圖像以指導合成。使用Kling O3模型，基於您提供的視覺輸入生成新圖像。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_image', 'ja', 'Kling O3：画像生成', '合成をガイドするために最大10枚の参照画像をアップロードしてください。提供された視覚入力に基づいて、Kling O3モデルを使用して新しい画像を生成します。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_image', 'ko', 'Kling O3：이미지 생성', '합성을 안내하기 위해 최대 10개의 참조 이미지를 업로드하세요. 제공된 시각적 입력을 기반으로 Kling O3 모델을 사용하여 새로운 이미지를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_image', 'es', 'Kling O3: Generación de imágenes', 'Sube hasta 10 imágenes de referencia para guiar la síntesis. Genera una nueva imagen utilizando el modelo Kling O3 basado en tus entradas visuales proporcionadas.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_image', 'fr', 'Kling O3 : Génération d''images', 'Téléchargez jusqu''à 10 images de référence pour guider la synthèse. Générez une nouvelle image en utilisant le modèle Kling O3 basé sur vos entrées visuelles fournies.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_image', 'ru', 'Kling O3: Генерация изображений', 'Загрузите до 10 эталонных изображений для управления синтезом. Создайте новое изображение с помощью модели Kling O3 на основе предоставленных вами визуальных данных.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_image', 'tr', 'Kling O3: Görüntü Oluşturma', 'Sentezi yönlendirmek için en fazla 10 referans görsel yükleyin. Sağladığınız görsel girdilere dayanarak Kling O3 modelini kullanarak yeni bir görsel oluşturun.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_image', 'ar', 'Kling O3: توليد الصور', 'قم بتحميل ما يصل إلى 10 صور مرجعية لتوجيه التركيب. قم بإنشاء صورة جديدة باستخدام نموذج Kling O3 استنادًا إلى المدخلات البصرية التي قدمتها.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_image', 'pt-BR', 'Kling O3: Geração de Imagens', 'Faça upload de até 10 imagens de referência para orientar a síntese. Gere uma nova imagem usando o modelo Kling O3 com base nas suas entradas visuais fornecidas.', 0, NULL, '2026-04-19T13:33:43.916Z');
