INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux2_max_sofa_swap', 'zh', 'BFL FLUX.2 [max]: 物体替换', '使用FLUX.2 [max]实现高质量物体替换，适用于产品拍摄、家居更换，轻松保持场景一致性。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux2_max_sofa_swap', 'zh-TW', 'BFL FLUX.2 [max]: 物件替換', '利用FLUX.2 [max]高品質更換物件，適用產品攝影、傢俱替換，輕鬆維持場景一致性。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux2_max_sofa_swap', 'ja', 'BFL FLUX.2 [max]: オブジェクト入れ替え', 'FLUX.2 [max]で高品質なオブジェクト入替。商品撮影や家具交換に最適、シーンの一貫性も維持。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux2_max_sofa_swap', 'ko', 'BFL FLUX.2 [max]: 오브젝트 교체', 'FLUX.2 [max]로 고품질 객체 교체. 제품 촬영, 가구 교체, 장면 일관성 유지에 적합.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux2_max_sofa_swap', 'es', 'BFL FLUX.2 [max]: Cambio de objeto', 'Reemplaza objetos en imágenes con FLUX.2 [max] de alta calidad. Perfecto para fotografía de productos y cambiar muebles manteniendo la coherencia.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux2_max_sofa_swap', 'fr', 'BFL FLUX.2 [max] : Remplacement d''objet', 'Remplacez des objets avec FLUX.2 [max], qualité supérieure. Idéal pour photos produit, échanges de meubles et cohérence de scène.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux2_max_sofa_swap', 'ru', 'BFL FLUX.2 [max]: Замена объекта', 'Замена объектов в изображениях с высочайшим качеством через FLUX.2 [max]. Подходит для съёмки товаров, замены мебели и единого вида сцены.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux2_max_sofa_swap', 'tr', 'BFL FLUX.2 [max]: Nesne Değişimi', 'FLUX.2 [max] ile yüksek kalitede nesne değişimi. Ürün fotoğrafçılığı, mobilya değişimi ve sahne tutarlılığı için ideal.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux2_max_sofa_swap', 'ar', 'BFL FLUX.2 [max]: تبديل الكائن', 'استبدل الكائنات بدقة عالية باستخدام FLUX.2 [max]، مثالي لتصوير المنتجات وتبديل الأثاث والحفاظ على تناسق المشهد.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux2_max_sofa_swap', 'pt-BR', 'BFL FLUX.2 [max]: Troca de objeto', 'Troque objetos com alta qualidade usando FLUX.2 [max]. Ideal para fotos de produtos, trocar móveis e manter a cena consistente.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (113, 'api_kling_v3_t2i', 2, 23, 'Kling 3.0: Text to Image', 'Generate an image from a text prompt using the Kling 3.0 model. Input your descriptive text to receive a high-quality, prompt-accurate visual output.', 'image', 'webp', NULL, '["output/api_kling_v3_t2i.png"]', '["API","Image"]', '["Kling","Kling 3.0"]', '[{"provider":"Kling"}]', '[]', '[]', '{"outputs":[{"nodeId":29,"nodeType":"SaveImage","file":"api_kling_v3_t2i.png","mediaType":"image"}]}', NULL, NULL, '2026-02-10', 0, 'active', 0, 0, 363, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_t2i', 'en', 'Kling 3.0: Text to Image', 'Generate an image from a text prompt using the Kling 3.0 model. Input your descriptive text to receive a high-quality, prompt-accurate visual output.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_t2i', 'zh', 'Kling 3.0：文生图', '使用 Kling 3.0 模型根据文本提示生成图像。输入您的描述性文本，即可获得高质量、与提示高度吻合的视觉输出。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_t2i', 'zh-TW', 'Kling 3.0：文字轉圖像', '使用 Kling 3.0 模型根據文字提示生成圖像。輸入您的描述性文字，即可獲得高品質、與提示高度吻合的視覺輸出。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_t2i', 'ja', 'Kling 3.0：テキストから画像へ', 'Kling 3.0 モデルを使用して、テキストプロンプトから画像を生成します。記述的なテキストを入力すると、高品質でプロンプトに忠実な視覚的出力が得られます。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_t2i', 'ko', 'Kling 3.0: 텍스트를 이미지로', 'Kling 3.0 모델을 사용하여 텍스트 프롬프트에서 이미지를 생성합니다. 설명적인 텍스트를 입력하면 고품질이고 프롬프트에 정확한 시각적 출력을 받을 수 있습니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_t2i', 'es', 'Kling 3.0: Texto a Imagen', 'Genera una imagen a partir de un texto descriptivo utilizando el modelo Kling 3.0. Ingresa tu texto descriptivo para recibir una salida visual de alta calidad y precisa al texto.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_t2i', 'fr', 'Kling 3.0 : Texte vers Image', 'Générez une image à partir d''une invite textuelle en utilisant le modèle Kling 3.0. Saisissez votre texte descriptif pour recevoir une sortie visuelle de haute qualité et fidèle à l''invite.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_t2i', 'ru', 'Kling 3.0: Текст в изображение', 'Создайте изображение по текстовому запросу с помощью модели Kling 3.0. Введите описательный текст, чтобы получить высококачественный визуальный результат, точно соответствующий запросу.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_t2i', 'tr', 'Kling 3.0: Metinden Görüntüye', 'Kling 3.0 modelini kullanarak bir metin isteminden görsel oluşturun. Açıklayıcı metninizi girerek yüksek kaliteli, isteme uygun görsel çıktı alın.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_t2i', 'ar', 'Kling 3.0: النص إلى الصورة', 'قم بإنشاء صورة من نص وصفي باستخدام نموذج Kling 3.0. أدخل النص الوصفي الخاص بك للحصول على مخرجات بصرية عالية الجودة ودقيقة وفق النص.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_t2i', 'pt-BR', 'Kling 3.0: Texto para Imagem', 'Gere uma imagem a partir de um prompt de texto usando o modelo Kling 3.0. Insira seu texto descritivo para receber uma saída visual de alta qualidade e precisa em relação ao prompt.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (114, 'image_flux2_klein_image_edit_9b_distilled', 2, 24, 'Flux.2 [Klein] 9B Distilled: Image Edit', 'BFL distilled model. Outstanding quality at sub-second speed. Great for real-time generation while retaining quality. Marketing launch will focus on this model.', 'image', 'webp', 'compareSlider', '["output/image_flux2_klein_image_edit_9b_distilled.png","output/image_flux2_klein_image_edit_9b_distilled.png"]', '["Image","Text to Image"]', '["Flux","Flux.2 Klein"]', '[]', '[]', '["local"]', '{"inputs":[{"nodeId":76,"nodeType":"LoadImage","file":"bold_outfit_woman.jpeg","mediaType":"image"},{"nodeId":121,"nodeType":"LoadImage","file":"handbag_white.png","mediaType":"image"}],"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"image_flux2_klein_image_edit_9b_distilled.png","mediaType":"image"},{"nodeId":122,"nodeType":"SaveImage","file":"","mediaType":"image"}]}', NULL, NULL, '2026-01-16', 1, 'active', 19112604467, 21045339750, 496, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_distilled', 'en', 'Flux.2 [Klein] 9B Distilled: Image Edit', 'BFL distilled model. Outstanding quality at sub-second speed. Great for real-time generation while retaining quality. Marketing launch will focus on this model.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_distilled', 'zh', 'Flux.2 [Klein] 9B 蒸馏：图像编辑', 'BFL 蒸馏模型。亚秒级速度下仍具出色画质。适合实时生成并保留质量。营销发布将重点聚焦该模型。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_distilled', 'zh-TW', 'Flux.2 [Klein] 9B 蒸餾：影像編輯', 'BFL 蒸餾模型。亞秒級速度下仍具出色畫質。適合即時生成並保留品質。行銷發佈將重點聚焦該模型。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_distilled', 'ja', 'Flux.2 [Klein] 9B 蒸留：画像編集', 'BFLの蒸留モデル。サブ秒の速度でも高品質。品質を保ったリアルタイム生成に最適。マーケティングのローンチはこのモデルに集中します。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_distilled', 'ko', 'Flux.2 [Klein] 9B 증류: 이미지 편집', 'BFL 증류 모델. 1초 미만 속도에서도 뛰어난 품질. 품질을 유지하며 실시간 생성에 적합. 마케팅 론칭은 이 모델에 집중됩니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_distilled', 'es', 'Flux.2 [Klein] 9B destilado: Edición de imagen', 'Modelo destilado de BFL. Calidad sobresaliente a velocidad sub-segundo. Ideal para generación en tiempo real manteniendo la calidad. El lanzamiento de marketing se centrará en este modelo.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_distilled', 'fr', 'Flux.2 [Klein] 9B distillé : Édition d’image', 'Modèle distillé de BFL. Qualité remarquable à une vitesse inférieure à la seconde. Idéal pour la génération en temps réel tout en conservant la qualité. Le lancement marketing se concentrera sur ce modèle.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_distilled', 'ru', 'Flux.2 [Klein] 9B дистиллированная: Редактирование изображений', 'Дистиллированная модель BFL. Отличное качество при скорости меньше секунды. Отлично подходит для генерации в реальном времени с сохранением качества. Маркетинговый запуск будет сфокусирован на этой модели.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_distilled', 'tr', 'Flux.2 [Klein] 9B Damıtılmış: Görüntü Düzenleme', 'BFL damıtılmış model. Saniye altı hızda üstün kalite. Kaliteyi koruyarak gerçek zamanlı üretim için ideal. Pazarlama lansmanı bu modele odaklanacak.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_distilled', 'ar', 'Flux.2 [Klein] 9B مُقطَّر: تحرير الصورة', 'نموذج BFL مُقطَّر. جودة ممتازة بسرعة أقل من ثانية. رائع للتوليد في الوقت الحقيقي مع الحفاظ على الجودة. سيتركّز الإطلاق التسويقي على هذا النموذج.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_distilled', 'pt-BR', 'Flux.2 [Klein] 9B destilado: Edição de imagem', 'Modelo destilado da BFL. Qualidade excepcional em velocidade sub-segundo. Ótimo para geração em tempo real mantendo a qualidade. O lançamento de marketing focará neste modelo.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (115, 'image_flux2_klein_image_edit_4b_base', 2, 25, 'Flux.2 [Klein] 4B: Image Edit', 'A smaller foundation model with exceptional quality-to-size ratio. Ideal for local deployment, fine-tuning on limited hardware, and efficient generation and editing workflows.', 'image', 'webp', NULL, '["thumbnail/image_flux2_klein_image_edit_4b_base.png"]', '["Image","Image Edit"]', '["Flux","Flux.2 Klein"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":76,"nodeType":"LoadImage","file":"robed_women.png","mediaType":"image"},{"nodeId":81,"nodeType":"LoadImage","file":"pink_tone_chair.png","mediaType":"image"}],"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":94,"nodeType":"SaveImage","file":"","mediaType":"image"}]}', 'https://docs.comfy.org/tutorials/flux/flux-2-klein', NULL, '2026-01-16', 1, 'active', 17072495002, 9878424781, 1412, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_base', 'en', 'Flux.2 [Klein] 4B: Image Edit', 'A smaller foundation model with exceptional quality-to-size ratio. Ideal for local deployment, fine-tuning on limited hardware, and efficient generation and editing workflows.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_base', 'zh', 'Flux.2 [Klein] 4B：图片编辑', '更小型的基础模型，具备卓越的模型大小与质量比。非常适合本地部署、在有限硬件上微调，以及高效生成与编辑工作流。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_base', 'zh-TW', 'Flux.2 [Klein] 4B：圖像編輯', '體積更精巧的基礎模型，具有卓越的品質與體積比。非常適合本地端部署、有限硬體設備的微調，以及高效生成與編輯流程。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_base', 'ja', 'Flux.2 [Klein] 4B：画像編集', '小型の基礎モデルで、卓越したサイズ対品質比を実現。ローカル運用や限られたハードウェアでのファインチューニング、高効率な生成や編集ワークフローに最適。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_base', 'ko', 'Flux.2 [Klein] 4B：이미지 편집', '더 작은 크기의 기본 모델로, 탁월한 품질 대비 용량 비율을 자랑합니다. 로컬 배포, 제한된 하드웨어에서의 파인튜닝, 효율적인 생성 및 편집 워크플로우에 이상적입니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_base', 'es', 'Flux.2 [Klein] 4B：Edición Imagen', 'Modelo fundamental más pequeño con una excepcional relación calidad/tamaño. Ideal para implementaciones locales, ajuste fino en hardware limitado y flujos eficientes de generación y edición.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_base', 'fr', 'Flux.2 [Klein] 4B：Édition d’Image', 'Un modèle de base plus compact avec un rapport qualité/taille exceptionnel. Parfait pour un déploiement local, l’ajustement sur matériel limité et des flux de génération/édition efficaces.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_base', 'ru', 'Flux.2 [Klein] 4B：редактор изображений', 'Более компактная базовая модель с исключительным соотношением качества и размера. Идеально подходит для локального развертывания, дообучения на ограниченном оборудовании и эффективных рабочих процессов генерации и редактирования.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_base', 'tr', 'Flux.2 [Klein] 4B：Görsel Düzenleme', 'Boyut/kalite oranı mükemmel, daha küçük bir temel model. Yerel dağıtım, sınırlı donanımda ince ayar ve verimli üretim/düzenleme iş akışları için idealdir.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_base', 'ar', 'Flux.2 [Klein] 4B：تحرير صورة', 'نموذج أساسي أصغر يتمتع بنسبة جودة إلى حجم استثنائية. مثالي للنشر المحلي، وضبط النماذج على عتاد محدود، وسير عمل فعال في التوليد والتحرير.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_base', 'pt-BR', 'Flux.2 [Klein] 4B：Edição de Imagem', 'Modelo fundamental menor, com excepcional relação qualidade/tamanho. Ideal para implantação local, ajustes em hardware limitado e fluxos eficientes de geração e edição.', 0, NULL, '2026-04-19T13:33:43.916Z');
