INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_base', 'en', 'Flux.2 [Klein] 9B: Image Edit', 'BFL undistilled foundation model. Maximum flexibility and control. Great for fine-tuning.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_base', 'zh', 'Flux.2 [Klein] 9B：图像编辑', 'BFL 未蒸馏基础模型。灵活性与可控性最高。非常适合微调。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_base', 'zh-TW', 'Flux.2 [Klein] 9B：影像編輯', 'BFL 未蒸餾基礎模型。彈性與可控性最高。非常適合微調。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_base', 'ja', 'Flux.2 [Klein] 9B：画像編集', 'BFLの未蒸留基盤モデル。最大限の柔軟性と制御性。微調整に最適。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_base', 'ko', 'Flux.2 [Klein] 9B: 이미지 편집', 'BFL 비증류 기반 모델. 최대한의 유연성과 제어. 파인튜닝에 적합.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_base', 'es', 'Flux.2 [Klein] 9B: Edición de imagen', 'Modelo base no destilado de BFL. Máxima flexibilidad y control. Ideal para fine-tuning.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_base', 'fr', 'Flux.2 [Klein] 9B : Édition d’image', 'Modèle de base non distillé de BFL. Flexibilité et contrôle maximum. Idéal pour le fine-tuning.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_base', 'ru', 'Flux.2 [Klein] 9B: Редактирование изображений', 'Недистиллированная базовая модель BFL. Максимальная гибкость и контроль. Отлично подходит для дообучения.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_base', 'tr', 'Flux.2 [Klein] 9B: Görüntü Düzenleme', 'BFL damıtılmamış temel model. Azami esneklik ve kontrol. İnce ayar için ideal.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_base', 'ar', 'Flux.2 [Klein] 9B: تحرير الصورة', 'نموذج أساس غير مُقطَّر من BFL. أقصى مرونة وتحكم. مناسب جداً للضبط الدقيق.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_9b_base', 'pt-BR', 'Flux.2 [Klein] 9B: Edição de imagem', 'Modelo base não destilado da BFL. Máxima flexibilidade e controle. Ótimo para fine-tuning.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (117, 'image_flux2_text_to_image_9b', 2, 27, 'Flux.2 [Klein] 9B: Text to Image', 'BFL distilled model. Outstanding quality at sub-second speed. Great for real-time generation while retaining quality. Marketing launch will focus on this model.', 'image', 'webp', NULL, '["output/image_flux2_text_to_image_9b.png"]', '["Image","Text to Image"]', '["Flux","Flux.2 Klein"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":78,"nodeType":"SaveImage","file":"image_flux2_text_to_image_9b.png","mediaType":"image"}]}', NULL, NULL, '2026-01-16', 1, 'active', 19327352832, 23300197581, 646, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_text_to_image_9b', 'en', 'Flux.2 [Klein] 9B: Text to Image', 'BFL distilled model. Outstanding quality at sub-second speed. Great for real-time generation while retaining quality. Marketing launch will focus on this model.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_text_to_image_9b', 'zh', 'Flux.2 [Klein] 9B：文生图', 'BFL 蒸馏模型。亚秒级速度下仍具出色画质。适合实时生成并保留质量。营销发布将重点聚焦该模型。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_text_to_image_9b', 'zh-TW', 'Flux.2 [Klein] 9B：文生圖', 'BFL 蒸餾模型。亞秒級速度下仍具出色畫質。適合即時生成並保留品質。行銷發佈將重點聚焦該模型。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_text_to_image_9b', 'ja', 'Flux.2 [Klein] 9B：テキストから画像', 'BFLの蒸留モデル。サブ秒の速度でも高品質。品質を保ったリアルタイム生成に最適。マーケティングのローンチはこのモデルに集中します。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_text_to_image_9b', 'ko', 'Flux.2 [Klein] 9B: 텍스트-이미지', 'BFL 증류 모델. 1초 미만 속도에서도 뛰어난 품질. 품질을 유지하며 실시간 생성에 적합. 마케팅 론칭은 이 모델에 집중됩니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_text_to_image_9b', 'es', 'Flux.2 [Klein] 9B: Texto a imagen', 'Modelo destilado de BFL. Calidad sobresaliente a velocidad sub-segundo. Ideal para generación en tiempo real manteniendo la calidad. El lanzamiento de marketing se centrará en este modelo.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_text_to_image_9b', 'fr', 'Flux.2 [Klein] 9B : Texte vers image', 'Modèle distillé de BFL. Qualité remarquable à une vitesse inférieure à la seconde. Idéal pour la génération en temps réel tout en conservant la qualité. Le lancement marketing se concentrera sur ce modèle.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_text_to_image_9b', 'ru', 'Flux.2 [Klein] 9B: Текст в изображение', 'Дистиллированная модель BFL. Отличное качество при скорости меньше секунды. Отлично подходит для генерации в реальном времени с сохранением качества. Маркетинговый запуск будет сфокусирован на этой модели.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_text_to_image_9b', 'tr', 'Flux.2 [Klein] 9B: Metinden Görüntü', 'BFL damıtılmış model. Saniye altı hızda üstün kalite. Kaliteyi koruyarak gerçek zamanlı üretim için ideal. Pazarlama lansmanı bu modele odaklanacak.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_text_to_image_9b', 'ar', 'Flux.2 [Klein] 9B: نص إلى صورة', 'نموذج BFL مُقطَّر. جودة ممتازة بسرعة أقل من ثانية. رائع للتوليد في الوقت الحقيقي مع الحفاظ على الجودة. سيتركّز الإطلاق التسويقي على هذا النموذج.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_text_to_image_9b', 'pt-BR', 'Flux.2 [Klein] 9B: Texto para imagem', 'Modelo destilado da BFL. Qualidade excepcional em velocidade sub-segundo. Ótimo para geração em tempo real mantendo a qualidade. O lançamento de marketing focará neste modelo.', 0, NULL, '2026-04-19T13:33:43.916Z');
