INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image-qwen_image_edit_2511_lora_inflation', 'es', 'Efecto de Inflación de Imagen con INFL8 LoRA', 'Sube una imagen y especifica un sujeto. Genera una versión inflada de ese sujeto usando el INFL8 LoRA para Qwen Image Edit.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image-qwen_image_edit_2511_lora_inflation', 'fr', 'Effet d''Inflation d''Image avec INFL8 LoRA', 'Téléchargez une image et spécifiez un sujet. Générez une version gonflée de ce sujet en utilisant le INFL8 LoRA pour Qwen Image Edit.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image-qwen_image_edit_2511_lora_inflation', 'ru', 'Эффект надувания изображения с INFL8 LoRA', 'Загрузите изображение и укажите объект. Сгенерируйте раздутую версию этого объекта с помощью INFL8 LoRA для Qwen Image Edit.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image-qwen_image_edit_2511_lora_inflation', 'tr', 'INFL8 LoRA ile Görsel Şişirme Efekti', 'Bir görsel yükleyin ve bir konu belirtin. INFL8 LoRA for Qwen Image Edit kullanarak o konunun şişirilmiş bir versiyonunu oluşturun.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image-qwen_image_edit_2511_lora_inflation', 'ar', 'تأثير تضخيم الصورة باستخدام INFL8 LoRA', 'قم بتحميل صورة وحدد موضوعًا. أنشئ نسخة منتفخة من ذلك الموضوع باستخدام INFL8 LoRA لـ Qwen Image Edit.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image-qwen_image_edit_2511_lora_inflation', 'pt-BR', 'Efeito de Inflação de Imagem com INFL8 LoRA', 'Faça upload de uma imagem e especifique um assunto. Gere uma versão inflada desse assunto usando o INFL8 LoRA para Qwen Image Edit.', 0, NULL, '2026-04-19T13:33:43.916Z');
