INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_style_reference', 'en', 'Recraft Style Reference Generation', 'Upload multiple images to create a consistent style reference. Generate new images using this reference to maintain visual coherence across outputs.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_style_reference', 'zh', 'Recraft 风格参考生成', '上传多张图片以创建一致的风格参考。使用此参考生成新图像，以保持输出之间的视觉连贯性。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_style_reference', 'zh-TW', 'Recraft 風格參考生成', '上傳多張圖片以建立一致的風格參考。使用此參考生成新圖像，以保持輸出之間的視覺連貫性。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_style_reference', 'ja', 'Recraft スタイル参照生成', '複数の画像をアップロードして一貫したスタイルリファレンスを作成します。このリファレンスを使用して新しい画像を生成し、出力全体で視覚的一貫性を維持します。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_style_reference', 'ko', 'Recraft 스타일 참조 생성', '일관된 스타일 참조를 생성하려면 여러 이미지를 업로드하세요. 이 참조를 사용하여 새로운 이미지를 생성하고 출력물 간의 시각적 일관성을 유지합니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_style_reference', 'es', 'Generación de Referencia de Estilo Recraft', 'Sube varias imágenes para crear una referencia de estilo consistente. Genera nuevas imágenes usando esta referencia para mantener la coherencia visual en todas las salidas.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_style_reference', 'fr', 'Génération de Référence de Style Recraft', 'Téléchargez plusieurs images pour créer une référence de style cohérente. Générez de nouvelles images en utilisant cette référence pour maintenir une cohérence visuelle entre les sorties.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_style_reference', 'ru', 'Генерация эталона стиля Recraft', 'Загрузите несколько изображений, чтобы создать единый стилевой референс. Генерируйте новые изображения с использованием этого референса для сохранения визуальной согласованности результатов.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_style_reference', 'tr', 'Recraft Stil Referansı Oluşturma', 'Tutarlı bir stil referansı oluşturmak için birden fazla görsel yükleyin. Çıktılar arasında görsel tutarlılığı sağlamak için bu referansı kullanarak yeni görseller oluşturun.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_style_reference', 'ar', 'توليد مرجع النمط Recraft', 'قم بتحميل صور متعددة لإنشاء مرجع نمط متسق. قم بإنشاء صور جديدة باستخدام هذا المرجع للحفاظ على التماسك البصري عبر المخرجات.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_style_reference', 'pt-BR', 'Geração de Referência de Estilo Recraft', 'Faça upload de várias imagens para criar uma referência de estilo consistente. Gere novas imagens usando esta referência para manter a coerência visual entre as saídas.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (121, 'api_recraft_v4_text_to_vector', 2, 31, 'Recraft v4: Text to Vector', 'Input text prompts to generate clean, editable vector SVG graphics. Create logos, icons, or illustrations with structured paths suitable for design tools.', 'image', 'webp', NULL, '[]', '["API","Image","Vector"]', '["Recraft"]', '[{"provider":"Recraft"}]', '[]', '[]', NULL, NULL, NULL, '2026-02-17', 0, 'active', 0, 0, 60, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_text_to_vector', 'en', 'Recraft v4: Text to Vector', 'Input text prompts to generate clean, editable vector SVG graphics. Create logos, icons, or illustrations with structured paths suitable for design tools.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_text_to_vector', 'zh', 'Recraft v4：文生矢量', '输入文本提示以生成干净、可编辑的矢量SVG图形。创建适用于设计工具的结构化路径的徽标、图标或插图。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_text_to_vector', 'zh-TW', 'Recraft v4：文字轉向量', '輸入文字提示以生成乾淨、可編輯的向量SVG圖形。建立適用於設計工具之結構化路徑的標誌、圖示或插圖。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_text_to_vector', 'ja', 'Recraft v4：テキストからベクターへ', 'クリーンで編集可能なベクターSVGグラフィックを生成するためのテキストプロンプトを入力します。デザインツールに適した構造化されたパスでロゴ、アイコン、またはイラストを作成します。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_text_to_vector', 'ko', 'Recraft v4: 텍스트를 벡터로', '깨끗하고 편집 가능한 벡터 SVG 그래픽을 생성하기 위한 텍스트 프롬프트를 입력하세요. 디자인 도구에 적합한 구조화된 경로로 로고, 아이콘 또는 일러스트레이션을 만듭니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_text_to_vector', 'es', 'Recraft v4: Texto a vector', 'Introduce indicaciones de texto para generar gráficos SVG vectoriales limpios y editables. Crea logotipos, iconos o ilustraciones con rutas estructuradas adecuadas para herramientas de diseño.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_text_to_vector', 'fr', 'Recraft v4 : Texte vers vecteur', 'Saisissez des invites textuelles pour générer des graphiques SVG vectoriels propres et modifiables. Créez des logos, icônes ou illustrations avec des tracés structurés adaptés aux outils de conception.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_text_to_vector', 'ru', 'Recraft v4: Текст в вектор', 'Вводите текстовые подсказки для создания чистых, редактируемых векторных SVG-графиков. Создавайте логотипы, иконки или иллюстрации со структурированными контурами, подходящими для инструментов дизайна.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_text_to_vector', 'tr', 'Recraft v4: Metinden vektöre', 'Temiz, düzenlenebilir vektör SVG grafikleri oluşturmak için metin istemleri girin. Tasarım araçlarına uygun yapılandırılmış yollarla logolar, simgeler veya illüstrasyonlar oluşturun.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_text_to_vector', 'ar', 'Recraft v4: النص إلى متجه', 'أدخل نصوصًا توجيهية لتوليد رسومات SVG متجهية نظيفة وقابلة للتعديل. أنشئ شعارات أو أيقونات أو رسومًا توضيحية بمسارات منظمة مناسبة لأدوات التصميم.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_v4_text_to_vector', 'pt-BR', 'Recraft v4: Texto para vetor', 'Insira prompts de texto para gerar gráficos SVG vetoriais limpos e editáveis. Crie logotipos, ícones ou ilustrações com caminhos estruturados adequados para ferramentas de design.', 0, NULL, '2026-04-19T13:33:43.916Z');
