INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_2512_with_2steps_lora', 'zh', 'Qwen-Image 2512 Turbo', 'Qwen-Image 2512 图像生成采用 2 步 Turbo LoRA 技术。输入您的文本提示即可快速生成结果，但为了速度会牺牲一些质量。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_2512_with_2steps_lora', 'zh-TW', 'Qwen-Image 2512 Turbo', 'Qwen-Image 2512 圖像生成採用 2 步 Turbo LoRA 技術。輸入您的文字提示即可快速產生結果，但為了速度會犧牲一些品質。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_2512_with_2steps_lora', 'ja', 'Qwen-Image 2512 Turbo', 'Qwen-Image 2512 は 2 ステップの Turbo LoRA による画像生成を行います。テキストプロンプトを入力すると迅速に結果が生成されますが、速度のために多少の品質が犠牲になります。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_2512_with_2steps_lora', 'ko', 'Qwen-Image 2512 Turbo', 'Qwen-Image 2512는 2단계 Turbo LoRA를 사용한 이미지 생성입니다. 텍스트 프롬프트를 입력하면 빠르게 결과물을 생성할 수 있지만, 속도를 위해 일부 품질이 희생됩니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_2512_with_2steps_lora', 'es', 'Qwen-Image 2512 Turbo', 'Qwen-Image 2512 genera imágenes con Turbo LoRA de 2 pasos. Ingrese su indicación de texto para producir rápidamente un resultado, aunque se sacrifica cierta calidad por la velocidad.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_2512_with_2steps_lora', 'fr', 'Qwen-Image 2512 Turbo', 'Qwen-Image 2512 génère des images avec Turbo LoRA en 2 étapes. Saisissez votre invite texte pour produire rapidement un résultat, bien qu''une certaine qualité soit sacrifiée pour la vitesse.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_2512_with_2steps_lora', 'ru', 'Qwen-Image 2512 Turbo', 'Qwen-Image 2512 генерирует изображения с помощью 2-шагового Turbo LoRA. Введите текстовый запрос, чтобы быстро получить результат, хотя некоторое качество приносится в жертву скорости.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_2512_with_2steps_lora', 'tr', 'Qwen-Image 2512 Turbo', 'Qwen-Image 2512, 2 adımlı Turbo LoRA ile görüntü oluşturur. Metin isteminizi girerek hızlıca bir sonuç üretebilirsiniz, ancak hız için bazı kalite kayıpları yaşanır.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_2512_with_2steps_lora', 'ar', 'Qwen-Image 2512 Turbo', 'Qwen-Image 2512 يقوم بتوليد الصور باستخدام Turbo LoRA ذو الخطوتين. أدخل نصك المطلوب لإنتاج نتيجة بسرعة، على الرغم من التضحية ببعض الجودة من أجل السرعة.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_2512_with_2steps_lora', 'pt-BR', 'Qwen-Image 2512 Turbo', 'Qwen-Image 2512 gera imagens com Turbo LoRA de 2 etapas. Insira seu prompt de texto para produzir rapidamente um resultado, embora alguma qualidade seja sacrificada pela velocidade.', 0, NULL, '2026-04-19T13:33:43.916Z');
