INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (125, 'image_flux2_klein_text_to_image', 2, 35, 'Flux.2 [Klein] 4B: Text to Image', 'BFL distilled model. Outstanding quality at sub-second speed. Great for real-time generation while retaining quality. Marketing launch will focus on this model.', 'image', 'webp', NULL, '["output/image_flux2_klein_text_to_image.png"]', '["Image","Text to Image"]', '["Flux","Flux.2 Klein"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":78,"nodeType":"SaveImage","file":"image_flux2_klein_text_to_image.png","mediaType":"image"}]}', 'https://docs.comfy.org/tutorials/flux/flux-2-klein', NULL, '2026-01-16', 1, 'active', 17072495002, 9878424781, 240, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_text_to_image', 'en', 'Flux.2 [Klein] 4B: Text to Image', 'BFL distilled model. Outstanding quality at sub-second speed. Great for real-time generation while retaining quality. Marketing launch will focus on this model.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_text_to_image', 'zh', 'Flux.2 [Klein] 4B：文生图', 'BFL 蒸馏模型。亚秒级速度下的卓越画质，非常适合实时生成且保证质量。市场推广将聚焦该模型。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_text_to_image', 'zh-TW', 'Flux.2 [Klein] 4B：文字轉圖像', 'BFL 蒸餾模型。毫秒級速度與優異畫質兼具，適合即時產生並保有高品質。行銷主推此模型。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_text_to_image', 'ja', 'Flux.2 [Klein] 4B：テキスト→画像', 'BFL蒸留モデル。サブセカンドの高速かつ優れた品質。リアルタイム生成に最適で品質も維持。マーケティングの中心となるモデルです。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_text_to_image', 'ko', 'Flux.2 [Klein] 4B: 텍스트→이미지', 'BFL 증류 모델. 초고속(1초 미만) 추론과 뛰어난 품질, 품질을 유지하며 실시간 생성에 적합. 이 모델이 마케팅 주력입니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_text_to_image', 'es', 'Flux.2 [Klein] 4B: Texto a Imagen', 'Modelo destilado BFL. Calidad sobresaliente y velocidad inferior a un segundo. Ideal para generación en tiempo real sin sacrificar calidad. El lanzamiento de marketing se centrará en este modelo.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_text_to_image', 'fr', 'Flux.2 [Klein] 4B : Texte en Image', 'Modèle distillé BFL. Qualité exceptionnelle à une vitesse inférieure à la seconde. Parfait pour la génération en temps réel tout en conservant la qualité. Ce modèle sera mis en avant lors du lancement marketing.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_text_to_image', 'ru', 'Flux.2 [Klein] 4B: текст в изображение', 'Дистиллированная модель BFL. Превосходное качество при генерации за доли секунды. Отлично подходит для генерации в реальном времени при сохранении качества. Маркетинговый запуск будет ориентирован на эту модель.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_text_to_image', 'tr', 'Flux.2 [Klein] 4B: Metinden Görsele', 'BFL damıtılmış modeli. Saniyenin altında üstün kalite, gerçek zamanlı üretimde kaliteyi korur. Pazarlama lansmanı bu modele odaklanacak.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_text_to_image', 'ar', 'Flux.2 [Klein] 4B: نص إلى صورة', 'نموذج BFL المقطّر. جودة فائقة وسرعة أقل من الثانية. مثالي للتوليد الفوري مع الحفاظ على الجودة. سيتم التركيز على هذا النموذج في إطلاق التسويق.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_text_to_image', 'pt-BR', 'Flux.2 [Klein] 4B: Texto para Imagem', 'Modelo destilado BFL. Qualidade excepcional em velocidade inferior a um segundo. Excelente para geração em tempo real mantendo a qualidade. O lançamento de marketing focará neste modelo.', 0, NULL, '2026-04-19T13:33:43.916Z');
