INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_seedream4', 'ja', 'ByteDance Seedream 4.0', 'テキストから画像生成と画像編集のためのマルチモーダルAIモデル。自然言語制御で2秒以内に2K画像を生成します。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_seedream4', 'ko', 'ByteDance Seedream 4.0', '텍스트에서 이미지 생성 및 이미지 편집을 위한 멀티모달 AI 모델. 자연어 제어로 2초 이내에 2K 이미지를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
