INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_seedream4', 'ar', 'ByteDance Seedream 4.0', 'نموذج ذكاء اصطناعي متعدد الوسائط لتحويل النص إلى صورة وتحرير الصور. توليد صور بدقة 2K في أقل من ثانيتين مع التحكم باللغة الطبيعية.', 0, NULL, '2026-04-19T13:33:43.916Z');
