INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (129, 'api_reve_image_edit', 2, 39, 'Reve: Image Edit', 'Upload an image and provide text instructions to edit it. Generate a modified output image using Reve''s advanced editing model for tasks like object removal, restoration, or recomposition.', 'image', 'webp', 'compareSlider', '["input/woman_runing_in_feild.png","output/api_reve_image_edit.png"]', '["API","Image Edit"]', '["Reve"]', '[{"provider":"Reve"}]', '[]', '[]', '{"inputs":[{"nodeId":4,"nodeType":"LoadImage","file":"woman_runing_in_feild.png","mediaType":"image"}],"outputs":[{"nodeId":5,"nodeType":"SaveImage","file":"api_reve_image_edit.png","mediaType":"image"}]}', NULL, NULL, '2026-03-14', 0, 'active', 0, 0, 236, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_reve_image_edit', 'en', 'Reve: Image Edit', 'Upload an image and provide text instructions to edit it. Generate a modified output image using Reve''s advanced editing model for tasks like object removal, restoration, or recomposition.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_reve_image_edit', 'zh', 'Reve：图像编辑', '上传一张图片并提供文字指令进行编辑。使用Reve的高级编辑模型生成修改后的输出图像，用于对象移除、修复或重构等任务。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_reve_image_edit', 'zh-TW', 'Reve：圖像編輯', '上傳一張圖片並提供文字指令進行編輯。使用Reve的高級編輯模型生成修改後的輸出圖像，用於物件移除、修復或重構等任務。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_reve_image_edit', 'ja', 'Reve：画像編集', '画像をアップロードし、編集するためのテキスト指示を提供します。Reveの高度な編集モデルを使用して、オブジェクトの削除、修復、再構成などのタスクのための修正済み出力画像を生成します。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_reve_image_edit', 'ko', 'Reve：이미지 편집', '이미지를 업로드하고 편집할 텍스트 지침을 제공하세요. 객체 제거, 복원 또는 재구성과 같은 작업을 위해 Reve의 고급 편집 모델을 사용하여 수정된 출력 이미지를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_reve_image_edit', 'es', 'Reve: Edición de imágenes', 'Sube una imagen y proporciona instrucciones de texto para editarla. Genera una imagen de salida modificada utilizando el modelo de edición avanzada de Reve para tareas como eliminación de objetos, restauración o recomposición.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_reve_image_edit', 'fr', 'Reve : Édition d''images', 'Téléchargez une image et fournissez des instructions textuelles pour la modifier. Générez une image de sortie modifiée en utilisant le modèle d''édition avancé de Reve pour des tâches telles que la suppression d''objets, la restauration ou la recomposition.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_reve_image_edit', 'ru', 'Reve: Редактирование изображений', 'Загрузите изображение и предоставьте текстовые инструкции для его редактирования. Сгенерируйте модифицированное выходное изображение с использованием продвинутой модели редактирования Reve для таких задач, как удаление объектов, восстановление или рекомпозиция.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_reve_image_edit', 'tr', 'Reve: Görsel Düzenleme', 'Bir görsel yükleyin ve düzenlemek için metin talimatları sağlayın. Nesne kaldırma, restorasyon veya yeniden kompozisyon gibi görevler için Reve''nin gelişmiş düzenleme modelini kullanarak değiştirilmiş bir çıktı görseli oluşturun.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_reve_image_edit', 'ar', 'Reve: تحرير الصور', 'قم بتحميل صورة وقدم تعليمات نصية لتحريرها. قم بإنشاء صورة مخرجة معدلة باستخدام نموذج التحرير المتقدم من Reve لمهام مثل إزالة الكائنات أو الترميم أو إعادة التركيب.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_reve_image_edit', 'pt-BR', 'Reve: Edição de Imagens', 'Faça upload de uma imagem e forneça instruções de texto para editá-la. Gere uma imagem de saída modificada usando o modelo de edição avançado da Reve para tarefas como remoção de objetos, restauração ou recomposição.', 0, NULL, '2026-04-19T13:33:43.916Z');
