INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_distilled', 'zh-TW', 'Flux.2 [Klein] 4B 蒸餾版：圖像編輯', 'Klein 系列中最快速的機型。專為互動應用、即時預覽及延遲敏感的生產情境打造。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_distilled', 'ja', 'Flux.2 [Klein] 4B 蒸留版：画像編集', 'Kleinファミリーで最速のバリアント。インタラクティブなアプリケーション、リアルタイムプレビュー、超低遅延な本番ユースケース向けに設計。', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_distilled', 'ko', 'Flux.2 [Klein] 4B 증류판: 이미지 편집', 'Klein 패밀리에서 가장 빠른 버전입니다. 인터랙티브 애플리케이션, 실시간 미리보기, 저지연 환경에 최적화되어 있습니다.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_distilled', 'es', 'Flux.2 [Klein] 4B Destilado: Edición de Imagen', 'La variante más rápida de la familia Klein. Creada para aplicaciones interactivas, previsualizaciones en tiempo real y casos de uso críticos en latencia.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_distilled', 'fr', 'Flux.2 [Klein] 4B Distillé : Édition d’Image', 'La variante la plus rapide de la famille Klein. Conçue pour les applications interactives, les aperçus en temps réel et les cas d’usage où la latence est critique.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_distilled', 'ru', 'Flux.2 [Klein] 4B Дистиллированная: Редактор изображений', 'Самый быстрый вариант в семействе Klein. Предназначен для интерактивных приложений, предпросмотров в реальном времени и критичных к задержкам производственных сценариев.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_distilled', 'tr', 'Flux.2 [Klein] 4B Damıtılmış: Görsel Düzenleme', 'Klein ailesinin en hızlı varyantı. Etkileşimli uygulamalar, gerçek zamanlı önizlemeler ve düşük gecikme gerektiren üretim senaryoları için üretildi.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_distilled', 'ar', 'Flux.2 [Klein] 4B المقطر: تحرير صورة', 'أسرع إصدار في عائلة Klein. مصمم للتطبيقات التفاعلية والمعاينات الفورية وحالات الإنتاج الحساسة من حيث الكمون.', 0, NULL, '2026-04-19T13:33:43.916Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_klein_image_edit_4b_distilled', 'pt-BR', 'Flux.2 [Klein] 4B Destilado: Edição de Imagem', 'A variante mais rápida da família Klein. Criada para aplicações interativas, visualizações em tempo real e cenários de produção críticos para latência.', 0, NULL, '2026-04-19T13:33:43.916Z');
