INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux1_dev_uso_reference_image_gen', 'zh', 'Flux.1 Dev USO参考图像生成', '使用参考图像来控制风格和主题 - 在改变艺术风格的同时保持角色的脸部，或将艺术风格应用于新场景', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux1_dev_uso_reference_image_gen', 'zh-TW', 'Flux.1 Dev USO 參考圖像生成', '使用參考圖像來控制風格和主題 - 在改變藝術風格的同時保持角色的臉部，或將藝術風格應用於新場景', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux1_dev_uso_reference_image_gen', 'ja', 'Flux.1 Dev USO リファレンス画像生成', 'リファレンス画像を使用してスタイルと主題の両方を制御します。キャラクターの顔を維持しながらアートスタイルを変更するか、新しいシーンにアートスタイルを適用します。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux1_dev_uso_reference_image_gen', 'ko', 'Flux.1 Dev USO 참조 이미지 생성', '참조 이미지를 사용하여 스타일과 주제를 모두 제어합니다. 캐릭터의 얼굴을 유지하면서 예술적 스타일을 변경하거나, 새로운 장면에 예술적 스타일을 적용합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux1_dev_uso_reference_image_gen', 'es', 'Generación de Imágenes de Referencia Flux.1 Dev USO', 'Usa imágenes de referencia para controlar tanto el estilo como el sujeto: mantén el rostro de tu personaje mientras cambias el estilo artístico, o aplica estilos artísticos a nuevas escenas', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux1_dev_uso_reference_image_gen', 'fr', 'Génération d''images de référence Flux.1 Dev USO', 'Utilisez des images de référence pour contrôler à la fois le style et le sujet : conservez le visage de votre personnage tout en changeant de style artistique, ou appliquez des styles artistiques à de nouvelles scènes', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux1_dev_uso_reference_image_gen', 'ru', 'Flux.1 Dev USO Генерация с Референсным Изображением', 'Используйте референсные изображения для контроля стиля и объекта - сохраняйте лицо персонажа при изменении художественного стиля или применяйте художественные стили к новым сценам', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux1_dev_uso_reference_image_gen', 'tr', 'Flux.1 Dev USO Referans Görüntü Oluşturma', 'Hem stili hem de konuyu kontrol etmek için referans görüntüleri kullanın - sanatsal stili değiştirirken karakterinizin yüzünü koruyun veya yeni sahnelere sanatsal stiller uygulayın', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux1_dev_uso_reference_image_gen', 'ar', 'Flux.1 Dev USO توليد الصور المرجعية', 'استخدم صورًا مرجعية للتحكم في الأسلوب والموضوع - حافظ على وجه الشخصية أثناء تغيير النمط الفني، أو طبق الأنماط الفنية على مشاهد جديدة.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux1_dev_uso_reference_image_gen', 'pt-BR', 'Flux.1 Dev USO Geração de Imagem de Referência', 'Use imagens de referência para controlar estilo e assunto - mantenha o rosto do seu personagem enquanto muda o estilo artístico, ou aplique estilos artísticos a novas cenas', 0, NULL, '2026-04-19T13:33:43.917Z');
