INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_text_to_image', 'ja', 'Capybara：テキストから画像', '画像を生成するためのテキストプロンプトを入力してください。このワークフローは、テキストから画像への合成にCapybara統一モデルを使用します。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_text_to_image', 'ko', 'Capybara：텍스트에서 이미지로', '이미지를 생성할 텍스트 프롬프트를 입력하세요. 이 워크플로우는 텍스트-이미지 합성을 위해 Capybara 통합 모델을 사용합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_text_to_image', 'es', 'Capybara: Texto a Imagen', 'Introduce un texto para generar una imagen. Este flujo de trabajo utiliza el modelo unificado Capybara para la síntesis de texto a imagen.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_text_to_image', 'fr', 'Capybara : Texte vers Image', 'Saisissez une invite textuelle pour générer une image. Ce flux de travail utilise le modèle unifié Capybara pour la synthèse de texte en image.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_text_to_image', 'ru', 'Capybara: Текст в изображение', 'Введите текстовый запрос для создания изображения. Этот рабочий процесс использует унифицированную модель Capybara для синтеза изображения из текста.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_text_to_image', 'tr', 'Capybara: Metinden Görüntü', 'Bir görsel oluşturmak için bir metin istemi girin. Bu iş akışı, metinden görüntü sentezi için Capybara birleşik modelini kullanır.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_text_to_image', 'ar', 'Capybara: نص إلى صورة', 'أدخل نصًا لإنشاء صورة. يستخدم سير العمل هذا نموذج Capybara الموحد لتحويل النص إلى صورة.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_text_to_image', 'pt-BR', 'Capybara: Texto para Imagem', 'Insira um prompt de texto para gerar uma imagem. Este fluxo de trabalho usa o modelo unificado Capybara para síntese de texto em imagem.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (137, 'Image_capybara_v0_1_image_edit', 2, 47, 'Capybara: Image Edit', 'Upload an image or video and input a text instruction. Generate an edited output using the Capybara model for tasks like style changes, object replacement, or time-of-day adjustments.', 'image', 'webp', 'compareSlider', '["input/wind_woman.png","output/Image_capybara_v0_1_image_edit.png"]', '["Image Edit"]', '["Capybara"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":80,"nodeType":"LoadImage","file":"wind_woman.png","mediaType":"image"}],"outputs":[{"nodeId":102,"nodeType":"SaveImage","file":"Image_capybara_v0_1_image_edit.png","mediaType":"image"}]}', NULL, NULL, '2026-02-23', 1, 'active', 37044092928, 37044092928, 504, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_image_edit', 'en', 'Capybara: Image Edit', 'Upload an image or video and input a text instruction. Generate an edited output using the Capybara model for tasks like style changes, object replacement, or time-of-day adjustments.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_image_edit', 'zh', 'Capybara：图像编辑', '上传图像或视频并输入文本指令。使用Capybara模型生成编辑后的输出，适用于风格更改、对象替换或时间调整等任务。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_image_edit', 'zh-TW', 'Capybara：圖像編輯', '上傳圖像或影片並輸入文字指令。使用Capybara模型生成編輯後的輸出，適用於風格更改、物件替換或時間調整等任務。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_image_edit', 'ja', 'Capybara：画像編集', '画像または動画をアップロードし、テキスト指示を入力してください。Capybaraモデルを使用して、スタイル変更、オブジェクト置換、時間帯調整などのタスクで編集済み出力を生成します。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_image_edit', 'ko', 'Capybara：이미지 편집', '이미지 또는 비디오를 업로드하고 텍스트 지시를 입력하세요. Capybara 모델을 사용하여 스타일 변경, 객체 교체 또는 시간대 조정과 같은 작업을 위한 편집된 출력을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_image_edit', 'es', 'Capybara: Edición de imagen', 'Sube una imagen o video e ingresa una instrucción de texto. Genera una salida editada usando el modelo Capybara para tareas como cambios de estilo, reemplazo de objetos o ajustes de hora del día.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_image_edit', 'fr', 'Capybara : Édition d''image', 'Téléchargez une image ou une vidéo et saisissez une instruction textuelle. Générez une sortie éditée en utilisant le modèle Capybara pour des tâches telles que les changements de style, le remplacement d''objets ou les ajustements d''heure de la journée.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_image_edit', 'ru', 'Capybara: Редактирование изображений', 'Загрузите изображение или видео и введите текстовую инструкцию. Сгенерируйте отредактированный результат с использованием модели Capybara для таких задач, как изменение стиля, замена объектов или корректировка времени суток.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_image_edit', 'tr', 'Capybara: Görsel Düzenleme', 'Bir görsel veya video yükleyin ve bir metin talimatı girin. Capybara modelini kullanarak stil değişiklikleri, nesne değiştirme veya günün saatine göre ayarlamalar gibi görevler için düzenlenmiş bir çıktı oluşturun.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_image_edit', 'ar', 'Capybara: تحرير الصور', 'قم بتحميل صورة أو فيديو وأدخل تعليمات نصية. قم بإنشاء مخرجات مُحررة باستخدام نموذج Capybara لمهام مثل تغييرات النمط أو استبدال الكائنات أو تعديلات وقت اليوم.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('Image_capybara_v0_1_image_edit', 'pt-BR', 'Capybara: Edição de Imagem', 'Faça upload de uma imagem ou vídeo e insira uma instrução de texto. Gere uma saída editada usando o modelo Capybara para tarefas como alterações de estilo, substituição de objetos ou ajustes de horário do dia.', 0, NULL, '2026-04-19T13:33:43.917Z');
