INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (139, 'api_kling_omni_image', 2, 49, 'Kling O1: Image', 'Generate high-quality images from text prompts using Kling O1, with support for up to 10 reference images to guide style and content. Features flexible aspect ratios and 1K/2K resolution options.', 'image', 'webp', NULL, '["output/api_kling_omni_image.png"]', '["API","Character Reference","Text to Image"]', '["Kling O1"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":5,"nodeType":"SaveImage","file":"api_kling_omni_image.png","mediaType":"image"}]}', NULL, NULL, '2026-01-05', 0, 'active', 0, 0, 190, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_image', 'en', 'Kling O1: Image', 'Generate high-quality images from text prompts using Kling O1, with support for up to 10 reference images to guide style and content. Features flexible aspect ratios and 1K/2K resolution options.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_image', 'zh', 'Kling : O1 图像', '使用 Kling O1 从文本提示生成高质量图像，支持最多10张参考图像来指导风格和内容。具有灵活的宽高比和1K/2K分辨率选项。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_image', 'zh-TW', 'Kling O1：圖像', '使用 Kling O1 從文字提示生成高質量圖像，支援最多10張參考圖像來指導風格和內容。具有靈活的寬高比和1K/2K解析度選項。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_image', 'ja', 'Kling O1：画像', 'Kling O1を使用してテキストプロンプトから高品質な画像を生成。最大10枚の参照画像でスタイルとコンテンツをガイド。柔軟なアスペクト比と1K/2K解像度オプションを提供。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_image', 'ko', 'Kling O1：이미지', 'Kling O1를 사용하여 텍스트 프롬프트에서 고품질 이미지를 생성합니다. 최대 10개의 참조 이미지를 지원하여 스타일과 콘텐츠를 안내합니다. 유연한 종횡비와 1K/2K 해상도 옵션을 제공합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_image', 'es', 'Kling O1：Imagen', 'Genera imágenes de alta calidad a partir de indicaciones de texto usando Kling O1, con soporte para hasta 10 imágenes de referencia para guiar el estilo y el contenido. Incluye relaciones de aspecto flexibles y opciones de resolución 1K/2K.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_image', 'fr', 'Kling O1：Image', 'Générez des images de haute qualité à partir d''invites texte en utilisant Kling O1, avec prise en charge de jusqu''à 10 images de référence pour guider le style et le contenu. Comprend des ratios d''aspect flexibles et des options de résolution 1K/2K.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_image', 'ru', 'Kling O1：Изображение', 'Генерируйте высококачественные изображения из текстовых подсказок с помощью Kling O1, с поддержкой до 10 эталонных изображений для управления стилем и содержимым. Включает гибкие соотношения сторон и опции разрешения 1K/2K.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_image', 'tr', 'Kling O1：Görüntü', 'Kling O1 kullanarak metin istemlerinden yüksek kaliteli görüntüler oluşturun. Stil ve içeriği yönlendirmek için en fazla 10 referans görüntü desteği. Esnek en-boy oranları ve 1K/2K çözünürlük seçenekleri sunar.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_image', 'ar', 'Kling O1：صورة', 'أنشئ صورًا عالية الجودة من المطالبات النصية باستخدام Kling O1، مع دعم ما يصل إلى 10 صور مرجعية لتوجيه النمط والمحتوى. يتضمن نسب عرض إلى ارتفاع مرنة وخيارات دقة 1K/2K.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_image', 'pt-BR', 'Kling O1：Imagem', 'Gere imagens de alta qualidade a partir de prompts de texto usando Kling O1, com suporte para até 10 imagens de referência para orientar estilo e conteúdo. Inclui proporções flexíveis e opções de resolução 1K/2K.', 0, NULL, '2026-04-19T13:33:43.917Z');
