INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (142, 'flux_dev_checkpoint_example', 2, 52, 'Flux.1 Dev fp8: Text to Image', 'Generate images using Flux.1 Dev fp8 quantized version. Suitable for devices with limited VRAM, requires only one model file, but image quality is slightly lower than the full version.', 'image', 'webp', NULL, '[]', '["Text to Image","Image"]', '["Flux.1","Flux"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"flux_dev_checkpoint_example.png","mediaType":"image"}]}', 'https://docs.comfy.org/tutorials/flux/flux-1-text-to-image', NULL, '2025-03-01', 1, 'active', 34144990003, 34144990003, 471, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_checkpoint_example', 'en', 'Flux.1 Dev fp8: Text to Image', 'Generate images using Flux.1 Dev fp8 quantized version. Suitable for devices with limited VRAM, requires only one model file, but image quality is slightly lower than the full version.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_checkpoint_example', 'zh', 'Flux.1 Dev fp8：文生图', '使用Flux Dev fp8量化版本生成图像。适用于显存有限的设备，只需要一个模型文件，但图像质量略低于完整版本。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_checkpoint_example', 'zh-TW', 'Flux.1 Dev fp8：文字轉圖像', '使用 Flux Dev fp8 量化版本生成影像。適合顯存有限的裝置，僅需一個模型檔案，但畫質略低於完整版。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_checkpoint_example', 'ja', 'Flux.1 Dev fp8：テキストから画像へ', 'Flux Dev fp8量子化バージョンを使用して画像を生成します。VRAMが限られたデバイスに適しており、モデルファイルが1つだけで済みますが、画質は完全版より少し低くなります。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_checkpoint_example', 'ko', 'Flux.1 Dev fp8: 텍스트를 이미지로', 'Flux Dev fp8 양자화 버전을 사용하여 이미지를 생성합니다. VRAM이 제한된 장치에 적합하며 모델 파일 하나만 필요하지만 이미지 품질은 전체 버전보다 약간 낮습니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_checkpoint_example', 'es', 'Flux.1 Dev fp8: Texto a Imagen', 'Generar imágenes usando la versión cuantizada Flux Dev fp8. Adecuado para dispositivos con VRAM limitada, requiere solo un archivo de modelo, pero la calidad de imagen es ligeramente inferior a la versión completa.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_checkpoint_example', 'fr', 'Flux.1 Dev fp8 : Texte vers Image', 'Générer des images en utilisant la version quantifiée Flux Dev fp8. Convient aux appareils avec une VRAM limitée, ne nécessite qu''un seul fichier de modèle, mais la qualité de l''image est légèrement inférieure à la version complète.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_checkpoint_example', 'ru', 'Flux.1 Dev fp8: Текст в изображение', 'Генерация изображений с использованием квантованной версии Flux Dev fp8. Подходит для устройств с ограниченной видеопамятью, требует только один файл модели, но качество изображения немного ниже, чем у полной версии.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_checkpoint_example', 'tr', 'Flux.1 Dev fp8: Metinden Görüntüye', 'Flux Dev fp8 kuantize sürümü kullanarak görüntüler oluşturun. Sınırlı VRAM''e sahip cihazlar için uygundur, yalnızca bir model dosyası gerektirir, ancak görüntü kalitesi tam sürümden biraz daha düşüktür.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_checkpoint_example', 'ar', 'Flux.1 Dev fp8: النص إلى الصورة', 'توليد صور باستخدام Flux Dev fp8 إصدار كمومي. مناسب للأجهزة محدود الذاكرة (VRAM)، يحتاج إلى ملف نموذج واحد فقط لكن جودة الصورة أقل قليلاً من النسخة الكاملة.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_checkpoint_example', 'pt-BR', 'Flux.1 Dev fp8: Texto para Imagem', 'Gere imagens usando a versão quantizada fp8 do Flux Dev. Adequado para dispositivos com VRAM limitado, requer apenas um arquivo de modelo, mas a qualidade da imagem é ligeiramente inferior à versão completa.', 0, NULL, '2026-04-19T13:33:43.917Z');
