INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_fp8', 'en', 'Product Mockup(Flux.2 Dev FP8)', 'Create product mockups by applying design patterns to packaging, mugs, and other products using multi-reference consistency.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_fp8', 'zh', '产品样机（Flux.2 Dev FP8）', '通过使用多参考一致性将设计图案应用到包装、马克杯等产品上，创建产品模型图。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_fp8', 'zh-TW', '產品樣機（Flux.2 Dev FP8）', '通過使用多參考一致性將設計圖案應用到包裝、馬克杯等產品上，創建產品模型圖。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_fp8', 'ja', '製品モックアップ（Flux.2 Dev FP8）', '複数リファレンスの一貫性を用いて、パッケージやマグカップなどの製品にデザインパターンを適用した商品モックアップを作成します。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_fp8', 'ko', '제품 목업(Flux.2 Dev FP8)', '다중 참조 일관성을 사용해 디자인 패턴을 포장, 머그잔 등 다양한 제품에 적용하여 제품 목업을 만듭니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_fp8', 'es', 'Maqueta de producto (Flux.2 Dev FP8)', 'Crea maquetas de productos aplicando patrones de diseño a envases, tazas y otros productos usando consistencia multi-referencia.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_fp8', 'fr', 'Maquette de produit (Flux.2 Dev FP8)', 'Créez des maquettes de produits en appliquant des motifs de conception sur des emballages, des mugs et d''autres produits à l''aide de la cohérence multi-références.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_fp8', 'ru', 'Макет продукта (Flux.2 Dev FP8)', 'Создайте макеты продуктов, применяя дизайнерские шаблоны к упаковке, кружкам и другим товарам с использованием мульти-референсной согласованности.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_fp8', 'tr', 'Ürün Maketi (Flux.2 Dev FP8)', 'Tasarım desenlerini çoklu referans tutarlılığıyla ambalaj, kupa ve diğer ürünlere uygulayarak ürün maketleri oluşturun.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_fp8', 'ar', 'نموذج منتج (Flux.2 Dev FP8)', 'أنشئ نماذج منتجات من خلال تطبيق الأنماط التصميمية على العبوات والأكواب ومنتجات أخرى باستخدام تناسق متعدد المراجع.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_flux2_fp8', 'pt-BR', 'Mockup de Produto(Flux.2 Dev FP8)', 'Crie mockups de produto aplicando padrões de design a embalagens, canecas e outros produtos usando consistência de múltiplas referências.', 0, NULL, '2026-04-19T13:33:43.917Z');
