INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_full_text_to_image', 'zh', 'Flux.1 Dev: 文生图', '使用Flux Dev完整版本生成高质量图像。需要更大的显存和多个模型文件，但提供最佳的提示跟随能力和图像质量。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_full_text_to_image', 'zh-TW', 'Flux.1 Dev: 文生圖', '使用 Flux Dev 完整版生成高品質影像。需要較大顯存與多個模型檔案，但提供最佳提示遵循能力與畫質。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_full_text_to_image', 'ja', 'Flux.1 Dev: テキストから画像', 'Flux Dev完全版で高品質な画像を生成します。より大きなVRAMと複数のモデルファイルが必要ですが、最高のプロンプト追従能力と画質を提供します。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_full_text_to_image', 'ko', 'Flux.1 Dev: 텍스트를 이미지로', 'Flux Dev 전체 버전으로 고품질 이미지를 생성합니다. 더 많은 VRAM과 여러 모델 파일이 필요하지만 최고의 프롬프트 따름 능력과 이미지 품질을 제공합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_full_text_to_image', 'es', 'Flux.1 Dev: Texto a Imagen', 'Generar imágenes de alta calidad con la versión completa de Flux Dev. Requiere mayor VRAM y múltiples archivos de modelo, pero proporciona la mejor capacidad de seguimiento de indicaciones y calidad de imagen.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_full_text_to_image', 'fr', 'Flux.1 Dev : Texte vers Image', 'Générer des images de haute qualité avec la version complète de Flux Dev. Nécessite plus de VRAM et plusieurs fichiers de modèles, mais offre la meilleure capacité de suivi des prompts et la qualité d''image.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_full_text_to_image', 'ru', 'Flux.1 Dev: Текст в изображение', 'Создание изображений высокого качества с полной версией Flux Dev. Требует больше видеопамяти и нескольких файлов моделей, но обеспечивает лучшую способность следовать запросам и качество изображений.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_full_text_to_image', 'tr', 'Flux.1 Dev: Metinden Görüntü', 'Flux Dev tam sürümü ile yüksek kaliteli görüntüler oluşturun. Daha büyük VRAM ve birden fazla model dosyası gerektirir, ancak en iyi istem takip yeteneği ve görüntü kalitesi sağlar.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_full_text_to_image', 'ar', 'Flux.1 Dev: نص إلى صورة', 'توليد صور عالية الجودة باستخدام Flux Dev النسخة الكاملة. يتطلب ذاكرة VRAM كبيرة وملفات نموذج متعددة، لكنه يوفر أفضل قدرة على اتباع الأوامر النصية وأعلى جودة صورة.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('flux_dev_full_text_to_image', 'pt-BR', 'Flux.1 Dev: Texto para Imagem', 'Gere imagens de alta qualidade com a versão completa do Flux Dev. Requer VRAM maior e múltiplos arquivos de modelo, mas fornece a melhor capacidade de seguimento de prompt e qualidade de imagem.', 0, NULL, '2026-04-19T13:33:43.917Z');
