INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image', 'ar', 'Qwen-Image تحويل نص إلى صورة', 'إنشاء صور بقدرات تحرير وعرض نصوص متعددة اللغات استثنائية باستخدام نموذج Qwen-Image 20B MMDiT.', 1, '["title"]', '2026-03-28T15:31:27.053Z');
