INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_kandinsky5_t2i', 'zh-TW', 'Kandinsky 5.0 影像 Lite 文字到影像', '輕量級 2B 模型，從英文和俄文提示生成高視覺品質影像。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_kandinsky5_t2i', 'ja', 'Kandinsky 5.0 Image Lite テキストから画像', '英語とロシア語のプロンプトから高視覚品質の画像を生成する軽量2Bモデル。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_kandinsky5_t2i', 'ko', 'Kandinsky 5.0 Image Lite 텍스트에서 이미지', '영어와 러시아어 프롬프트에서 고품질 시각 이미지를 생성하는 경량 2B 모델。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_kandinsky5_t2i', 'es', 'Kandinsky 5.0 Image Lite Texto a Imagen', 'Un modelo ligero de 2B que genera imágenes de alta calidad visual a partir de indicaciones en inglés y ruso.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_kandinsky5_t2i', 'fr', 'Kandinsky 5.0 Image Lite Texte vers Image', 'Un modèle léger de 2B qui génère des images de haute qualité visuelle à partir de prompts en anglais et russe.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_kandinsky5_t2i', 'ru', 'Kandinsky 5.0 Image Lite Текст в Изображение', 'Легковесная 2B-модель, создающая качественные изображения по текстовым подсказкам на английском и русском языках.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_kandinsky5_t2i', 'tr', 'Kandinsky 5.0 Image Lite Metinden Görüntüye', 'İngilizce ve Rusça istemlerden yüksek görsel kalitesinde görüntüler üreten hafif 2B model.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_kandinsky5_t2i', 'ar', 'كاندينسكي 5.0 صورة لايت نص إلى صورة', 'نموذج خفيف الوزن 2B يولد صورًا عالية الجودة البصرية من التلميحات الإنجليزية والروسية.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_kandinsky5_t2i', 'pt-BR', 'Kandinsky 5.0 Image Lite Texto para Imagem', 'Um modelo leve de 2B que gera imagens de alta qualidade visual a partir de prompts em inglês e russo.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (151, 'image_chroma1_radiance_text_to_image', 2, 61, 'Chroma1 Radiance Text to Image', 'Chroma1-Radiance works directly with image pixels instead of compressed latents, delivering higher quality images with reduced artifacts and distortion.', 'image', 'webp', NULL, '["output/image_chroma1_radiance_text_to_image.png"]', '["Image","Text to Image"]', '["Chroma"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":740,"nodeType":"SaveImage","file":"image_chroma1_radiance_text_to_image.png","mediaType":"image"}]}', NULL, NULL, '2025-09-18', 1, 'active', 24159191040, 24159191040, 246, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_chroma1_radiance_text_to_image', 'en', 'Chroma1 Radiance Text to Image', 'Chroma1-Radiance works directly with image pixels instead of compressed latents, delivering higher quality images with reduced artifacts and distortion.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_chroma1_radiance_text_to_image', 'zh', 'Chroma1 Radiance文生图', 'Chroma1-Radiance 直接处理图像像素而非压缩潜变量，提供更高质量的图像，减少伪影和失真。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_chroma1_radiance_text_to_image', 'zh-TW', 'Chroma1 Radiance 文本生成圖像', 'Chroma1-Radiance 直接處理圖像像素而非壓縮潛變量，提供更高質量的圖像，減少偽影和失真。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_chroma1_radiance_text_to_image', 'ja', 'Chroma1 Radiance テキストから画像へ', 'Chroma1-Radianceは圧縮された潜在変数ではなく画像ピクセルを直接処理し、アーティファクトと歪みを削減した高品質な画像を提供します。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_chroma1_radiance_text_to_image', 'ko', 'Chroma1 Radiance 텍스트에서 이미지로', 'Chroma1-Radiance는 압축된 잠재 변수 대신 이미지 픽셀을 직접 처리하여 아티팩트와 왜곡이 줄어든 고품질 이미지를 제공합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_chroma1_radiance_text_to_image', 'es', 'Chroma1 Radiance Texto a Imagen', 'Chroma1-Radiance trabaja directamente con píxeles de imagen en lugar de latentes comprimidos, ofreciendo imágenes de mayor calidad con menos artefactos y distorsión.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_chroma1_radiance_text_to_image', 'fr', 'Chroma1 Radiance Texte vers Image', 'Chroma1-Radiance travaille directement avec les pixels d''image au lieu des latents compressés, offrant des images de meilleure qualité avec moins d''artefacts et de distorsion.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_chroma1_radiance_text_to_image', 'ru', 'Chroma1 Radiance Текст в Изображение', 'Chroma1-Radiance работает напрямую с пикселями изображения вместо сжатых латентов, обеспечивая изображения более высокого качества с меньшим количеством артефактов и искажений.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_chroma1_radiance_text_to_image', 'tr', 'Chroma1 Radiance Metinden Görüntüye', 'Chroma1-Radiance, sıkıştırılmış gizli veriler yerine doğrudan görüntü pikselleriyle çalışarak azaltılmış yapaylık ve bozulma ile daha yüksek kaliteli görüntüler sunar.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_chroma1_radiance_text_to_image', 'ar', 'Chroma1 Radiance تحويل نص إلى صورة', 'يعمل Chroma1-Radiance مباشرة مع وحدات بكسل الصور بدلًا من البيانات الكامنة المضغوطة لتحقيق جودة صور أعلى وتقليل التشوهات.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_chroma1_radiance_text_to_image', 'pt-BR', 'Chroma1 Radiance Texto para Imagem', 'Chroma1-Radiance trabalha diretamente com pixels de imagem em vez de latentes comprimidos, entregando imagens de maior qualidade com artefatos e distorção reduzidos.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (152, 'image_anima_preview', 2, 62, 'Anima Anime Text-to-Image Generation', 'Input a text prompt to generate an anime-style image using the Anima model. Configure settings like steps and CFG scale to control the output. The workflow produces a non-photorealistic illustration based on your description.', 'image', 'webp', NULL, '["output/image_anima_preview.png"]', '["Anime","Text to Image"]', '["Anima"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":46,"nodeType":"SaveImage","file":"image_anima_preview.png","mediaType":"image"}]}', NULL, NULL, '2025-05-07', 1, 'active', 5583457485, 5583457485, 973, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_anima_preview', 'en', 'Anima Anime Text-to-Image Generation', 'Input a text prompt to generate an anime-style image using the Anima model. Configure settings like steps and CFG scale to control the output. The workflow produces a non-photorealistic illustration based on your description.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_anima_preview', 'zh', 'Anima 动漫文生图', '输入文本提示，使用Anima模型生成动漫风格图像。配置步数和CFG比例等设置以控制输出。该工作流程将根据您的描述生成非写实风格的插图。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_anima_preview', 'zh-TW', 'Anima 動漫文生圖', '輸入文字提示，使用Anima模型生成動漫風格圖像。配置步數和CFG比例等設定以控制輸出。該工作流程將根據您的描述生成非寫實風格的插圖。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_anima_preview', 'ja', 'Anima アニメ文生図', 'テキストプロンプトを入力して、Animaモデルを使用してアニメ風の画像を生成します。ステップ数やCFGスケールなどの設定を構成して出力を制御します。このワークフローは、あなたの説明に基づいて非写実的なイラストを生成します。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_anima_preview', 'ko', 'Anima 애니메이션 텍스트-이미지 생성', '텍스트 프롬프트를 입력하여 Anima 모델을 사용해 애니메이션 스타일 이미지를 생성합니다. 단계 및 CFG 스케일과 같은 설정을 구성하여 출력을 제어합니다. 이 워크플로우는 설명에 기반하여 비사실적인 일러스트레이션을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_anima_preview', 'es', 'Generación de Imágenes a partir de Texto Anima Anime', 'Introduce un texto descriptivo para generar una imagen de estilo anime utilizando el modelo Anima. Configura ajustes como pasos y escala CFG para controlar la salida. El flujo de trabajo produce una ilustración no fotorrealista basada en tu descripción.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_anima_preview', 'fr', 'Génération d''Images à partir de Texte Anima Anime', 'Saisissez une invite textuelle pour générer une image de style anime en utilisant le modèle Anima. Configurez des paramètres tels que les étapes et l''échelle CFG pour contrôler le résultat. Le flux de travail produit une illustration non photoréaliste basée sur votre description.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_anima_preview', 'ru', 'Anima Аниме Генерация Изображений из Текста', 'Введите текстовый запрос для создания изображения в аниме-стиле с использованием модели Anima. Настройте параметры, такие как шаги и масштаб CFG, чтобы управлять результатом. Рабочий процесс создает нефотореалистичную иллюстрацию на основе вашего описания.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_anima_preview', 'tr', 'Anima Anime Metinden Görüntü Oluşturma', 'Anima modelini kullanarak anime tarzı bir görüntü oluşturmak için bir metin istemi girin. Adımlar ve CFG ölçeği gibi ayarları yapılandırarak çıktıyı kontrol edin. İş akışı, açıklamanıza dayalı fotoğraf gerçekçiliğinde olmayan bir illüstrasyon üretir.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_anima_preview', 'ar', 'أنيما أنيمي توليد الصور من النص', 'أدخل نصًا توجيهيًا لإنشاء صورة بأسلوب الأنمي باستخدام نموذج أنيما. قم بتكوين إعدادات مثل الخطوات ومقياس CFG للتحكم في الإخراج. ينتج سير العمل رسمًا توضيحيًا غير واقعي بناءً على وصفك.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_anima_preview', 'pt-BR', 'Geração de Imagem a partir de Texto Anima Anime', 'Insira um prompt de texto para gerar uma imagem no estilo anime usando o modelo Anima. Configure parâmetros como etapas e escala CFG para controlar a saída. O fluxo de trabalho produz uma ilustração não fotorrealista baseada na sua descrição.', 0, NULL, '2026-04-19T13:33:43.917Z');
