INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_from_photo_2_miniature', 'zh-TW', '照片轉模型風格', '將真實建築照片轉化為建築藍圖，再轉化為精緻的實體比例模型。實現從照片到微縮模型的完整建築可視化流程。', 0, NULL, '2026-04-19T13:33:43.917Z');
