INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_union_control_lora', 'en', 'Qwen-Image Union Control', 'Generate images with precise structural control using Qwen-Image''s unified ControlNet LoRA. Supports multiple control types including canny, depth, lineart, softedge, normal, and openpose for diverse creative applications.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_union_control_lora', 'zh', 'Qwen-Image Union Control', '使用Qwen-Image统一的ControlNet LoRA进行精确结构控制生成图像。支持多种控制类型，包括canny、depth、lineart、softedge、normal和openpose，适用于各种创意应用。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_union_control_lora', 'zh-TW', 'Qwen-Image Union Control', '使用 Qwen-Image 統一的 ControlNet LoRA 進行精確結構控制生成影像。支援多種控制類型，包括 canny、depth、lineart、softedge、normal 與 openpose，適用於各種創意應用。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_union_control_lora', 'ja', 'Qwen-Image Union Control', 'Qwen-Imageの統合ControlNet LoRAを使用して、正確な構造制御で画像を生成します。canny、depth、lineart、softedge、normal、openposeを含む複数の制御タイプをサポートし、多様な創造的アプリケーションに適しています。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_union_control_lora', 'ko', 'Qwen-Image Union Control', 'Qwen-Image의 통합 ControlNet LoRA를 사용하여 정밀한 구조 제어로 이미지를 생성합니다. 다양한 창의적 응용을 위한 canny, depth, lineart, softedge, normal 및 openpose를 포함한 여러 제어 유형을 지원합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_union_control_lora', 'es', 'Qwen-Image Union Control', 'Generar imágenes con control estructural preciso usando el ControlNet LoRA unificado de Qwen-Image. Soporta múltiples tipos de control incluyendo canny, profundidad, lineart, softedge, normal y openpose para aplicaciones creativas diversas.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_union_control_lora', 'fr', 'Qwen-Image Union Control', 'Générer des images avec un contrôle structurel précis en utilisant le LoRA ControlNet unifié de Qwen-Image. Prend en charge plusieurs types de contrôle incluant canny, depth, lineart, softedge, normal et openpose pour diverses applications créatives.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_union_control_lora', 'ru', 'Qwen-Image Union Control', 'Генерация изображений с точным структурным контролем с использованием унифицированного ControlNet LoRA Qwen-Image. Поддерживает несколько типов управления, включая canny, depth, lineart, softedge, normal и openpose для различных творческих применений.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_union_control_lora', 'tr', 'Qwen-Image Union Control', 'Qwen-Image''in birleşik ControlNet LoRA''sını kullanarak hassas yapısal kontrol ile görüntüler oluşturun. Çeşitli yaratıcı uygulamalar için canny, derinlik, çizgi, yumuşak kenar, normal ve openpose dahil birden fazla kontrol türünü destekler.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_union_control_lora', 'ar', 'Qwen-Image اتحاد التحكم', 'إنشاء صور بتحكم هيكلي دقيق باستخدام Qwen-Image الموحد ControlNet LoRA. يدعم عدة أنواع من التحكم مثل canny وdepth وlineart وsoftedge وnormal وopenpose لتطبيقات إبداعية متنوعة.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_union_control_lora', 'pt-BR', 'Qwen-Image Union Control', 'Gere imagens com controle estrutural preciso usando o ControlNet LoRA unificado do Qwen-Image. Suporta múltiplos tipos de controle incluindo canny, profundidade, lineart, softedge, normal e openpose para diversas aplicações criativas.', 0, NULL, '2026-04-19T13:33:43.917Z');
