INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_controlnet_patch', 'en', 'Qwen-Image ControlNet Model Patch', 'Control image generation using Qwen-Image ControlNet models. Supports canny, depth, and inpainting controls through model patching.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_controlnet_patch', 'zh', 'Qwen-Image ControlNet 模型补丁', '使用 Qwen-Image ControlNet 模型控制图像生成。通过模型修补支持 canny、深度和修复控制。', 0, NULL, '2026-04-19T13:33:43.917Z');
