INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_controlnet_patch', 'ja', 'Qwen-Image ControlNetモデルパッチ', 'Qwen-Image ControlNetモデルを使用して画像生成を制御します。モデルパッチングを通じて、canny、深度、インペイント制御をサポートします。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_controlnet_patch', 'ko', 'Qwen-Image ControlNet 모델 패치', 'Qwen-Image ControlNet 모델을 사용하여 이미지 생성을 제어합니다. 모델 패칭을 통해 canny, depth 및 inpainting 제어를 지원합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_qwen_image_controlnet_patch', 'es', 'Parche de modelo Qwen-Image ControlNet', 'Controla la generación de imágenes usando modelos Qwen-Image ControlNet. Compatible con controles canny, profundidad e inpainting mediante parcheo de modelo.', 0, NULL, '2026-04-19T13:33:43.917Z');
