INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_style_transfer', 'ko', 'Magnific：스타일 참조', '대상 이미지와 스타일 참조 이미지를 업로드하세요. 참조 이미지의 예술적 스타일과 대상 이미지의 구조를 융합한 새로운 이미지를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
