INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (196, 'image_ovis_text_to_image', 2, 106, 'Ovis-Image Text to Image', 'Ovis-Image is a 7B text-to-image model specifically optimized for high-quality text rendering in generated images. Designed to operate efficiently under computational constraints, it excels at accurately generating images containing text content.', 'image', 'webp', NULL, '[]', '["Text to Image","Image"]', '["Ovis-Image"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"","mediaType":"image"}]}', NULL, NULL, '2025-12-02', 0, 'active', 20228222222, 20228222222, 43, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ovis_text_to_image', 'en', 'Ovis-Image Text to Image', 'Ovis-Image is a 7B text-to-image model specifically optimized for high-quality text rendering in generated images. Designed to operate efficiently under computational constraints, it excels at accurately generating images containing text content.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ovis_text_to_image', 'zh', 'Ovis-Image 文生像', 'Ovis-Image 是一个 7B 参数的文本生成图像模型，专门针对生成图像中的高质量文本渲染进行了优化。该模型设计用于在计算资源受限的情况下高效运行，擅长准确生成包含文本内容的图像。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ovis_text_to_image', 'zh-TW', 'Ovis-Image 文生圖', 'Ovis-Image 是一個 7B 參數的文字生成圖像模型，專門針對生成圖像中的高品質文字渲染進行了優化。該模型設計用於在計算資源受限的情況下高效運行，擅長準確生成包含文字內容的圖像。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ovis_text_to_image', 'ja', 'Ovis-Image テキスト画像生成', 'Ovis-Image は、生成画像における高品質なテキストレンダリングに特化して最適化された70億パラメータのテキスト画像生成モデルです。計算リソースの制約下で効率的に動作するように設計されており、テキストコンテンツを含む画像を正確に生成することに優れています。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ovis_text_to_image', 'ko', 'Ovis-Image 텍스트-이미지 생성', 'Ovis-Image는 생성된 이미지에서 고품질 텍스트 렌더링에 특화되어 최적화된 70억 파라미터 텍스트-이미지 생성 모델입니다. 제한된 컴퓨팅 환경에서 효율적으로 작동하도록 설계되었으며, 텍스트 콘텐츠가 포함된 이미지를 정확하게 생성하는 데 탁월합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ovis_text_to_image', 'es', 'Ovis-Image texto a imagen', 'Ovis-Image es un modelo de texto a imagen de 7B parámetros optimizado específicamente para renderizado de texto de alta calidad en imágenes generadas. Diseñado para operar eficientemente bajo restricciones computacionales, sobresale en la generación precisa de imágenes que contienen contenido textual.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ovis_text_to_image', 'fr', 'Ovis-Image texte vers image', 'Ovis-Image est un modèle texte-image de 7 milliards de paramètres spécifiquement optimisé pour le rendu de texte de haute qualité dans les images générées. Conçu pour fonctionner efficacement sous des contraintes de calcul, il excelle dans la génération précise d''images contenant du contenu textuel.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ovis_text_to_image', 'ru', 'Ovis-Image текст в изображение', 'Ovis-Image — это модель преобразования текста в изображение с 7 миллиардами параметров, специально оптимизированная для высококачественного рендеринга текста в сгенерированных изображениях. Разработанная для эффективной работы в условиях ограниченных вычислительных ресурсов, она превосходно генерирует изображения с текстовым контентом.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ovis_text_to_image', 'tr', 'Ovis-Image metinden görüntüye', 'Ovis-Image, oluşturulan görüntülerde yüksek kaliteli metin oluşturma için özel olarak optimize edilmiş 7 milyar parametreli bir metinden görüntüye modelidir. Hesaplama kısıtlamaları altında verimli çalışacak şekilde tasarlanmış olup, metin içeriği içeren görüntüleri doğru bir şekilde oluşturmada mükemmeldir.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ovis_text_to_image', 'ar', 'Ovis-Image نص إلى صورة', 'Ovis-Image هو نموذج نص إلى صورة بسعة 7 مليار معامل محسّن خصيصًا لعرض نص عالي الجودة في الصور المولدة. تم تصميمه للعمل بكفاءة في ظل قيود حسابية، ويتفوق في إنشاء صور تحتوي على محتوى نصي بدقة.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('image_ovis_text_to_image', 'pt-BR', 'Ovis-Image Texto para Imagem', 'Ovis-Image é um modelo texto-para-imagem de 7B especificamente otimizado para renderização de texto de alta qualidade em imagens geradas. Projetado para operar eficientemente sob restrições computacionais, se destaca em gerar imagens com precisão contendo conteúdo de texto.', 0, NULL, '2026-04-19T13:33:43.917Z');
