INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_image_gen_with_color_control', 'ko', 'Recraft: 색상 제어 이미지 생성', 'Recraft를 사용하여 사용자 정의 색상 팔레트와 브랜드별 시각적 요소로 이미지를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
