INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_image_gen_with_color_control', 'ru', 'Recraft: генерация изображений с управлением цветом', 'Генерация изображений с пользовательскими цветовыми палитрами и визуалами, специфичными для бренда, с использованием Recraft.', 0, NULL, '2026-04-19T13:33:43.917Z');
