INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_image_gen_with_style_control', 'zh', 'Recraft：风格控制图像生成', '通过视觉示例控制风格，调整定位并微调对象。存储和分享风格以实现完美的品牌一致性。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_image_gen_with_style_control', 'zh-TW', 'Recraft：風格控制影像生成', '透過視覺範例控制風格、調整定位並微調物件。儲存與分享風格以實現完美的品牌一致性。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_image_gen_with_style_control', 'ja', 'Recraft: スタイルコントロール画像生成', '視覚的例でスタイルを制御し、位置を調整し、オブジェクトを微調整します。完璧なブランド一貫性のためにスタイルを保存および共有します。', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_image_gen_with_style_control', 'ko', 'Recraft: 스타일 제어 이미지 생성', '시각적 예제로 스타일을 제어하고, 위치를 정렬하며, 객체를 미세 조정합니다. 완벽한 브랜드 일관성을 위해 스타일을 저장하고 공유합니다.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_image_gen_with_style_control', 'es', 'Recraft: Generación de imágenes con control de estilo', 'Controlar estilo con ejemplos visuales, alinear posicionamiento y ajustar objetos finamente. Almacenar y compartir estilos para consistencia perfecta de marca.', 0, NULL, '2026-04-19T13:33:43.917Z');
