INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_image_gen_with_style_control', 'ru', 'Recraft: генерация изображений с управлением стилем', 'Управление стилем с помощью визуальных примеров, выравнивание позиционирования и точная настройка объектов. Сохранение и обмен стилями для идеального соответствия бренду.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_image_gen_with_style_control', 'tr', 'Recraft: Stil Kontrollü Görüntü Oluşturma', 'Görsel örneklerle stili kontrol edin, konumlandırmayı hizalayın ve nesneleri ince ayarlayın. Mükemmel marka tutarlılığı için stilleri saklayın ve paylaşın.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_image_gen_with_style_control', 'ar', 'Recraft: توليد صور مع التحكم بالأسلوب', 'التحكم بالأسلوب باستخدام أمثلة بصرية، ومحاذاة المواضع، وضبط الكائنات بدقة. تخزين ومشاركة الأساليب لاتساق مثالي للعلامة التجارية.', 0, NULL, '2026-04-19T13:33:43.917Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_recraft_image_gen_with_style_control', 'pt-BR', 'Recraft: Geração de Imagem com Controle de Estilo', 'Controle o estilo com exemplos visuais, alinhe posicionamento e ajuste objetos. Armazene e compartilhe estilos para consistência perfeita da marca.', 0, NULL, '2026-04-19T13:33:43.917Z');
