INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (208, 'api_seedance2_0_r2v', 3, 0, 'Seedance 2.0: Reference to Video', 'Generate cinematic videos from reference images and text prompts. Preserve subject identity and composition while adding expressive motion with synchronized audio. Control camera movement and lighting through detailed prompts.', 'image', 'webp', NULL, '["output/Seedance2.0_r2v_00006_.mp4"]', '["API","Image to Video","Video"]', '["Seedance 2.0"]', '[{"provider":"ByteDance"}]', '[]', '[]', '{"inputs":[{"nodeId":352,"nodeType":"LoadImage","file":"sd_outfit_1.png","mediaType":"image"},{"nodeId":353,"nodeType":"LoadImage","file":"sd_outfit_2.png","mediaType":"image"},{"nodeId":354,"nodeType":"LoadImage","file":"sd_outfit_3.png","mediaType":"image"},{"nodeId":356,"nodeType":"LoadImage","file":"selfie_cartoon_style.png","mediaType":"image"}],"outputs":[{"nodeId":344,"nodeType":"SaveVideo","file":"Seedance2.0_r2v_00006_.mp4","mediaType":"video"}]}', NULL, NULL, '2026-04-13', 0, 'active', 0, 0, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_r2v', 'en', 'Seedance 2.0: Reference to Video', 'Generate cinematic videos from reference images and text prompts. Preserve subject identity and composition while adding expressive motion with synchronized audio. Control camera movement and lighting through detailed prompts.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_r2v', 'zh', 'Seedance 2.0：视频参考生成', '根据参考图像和文本提示生成电影级视频。在保留主体身份和构图的同时，通过同步音频添加富有表现力的运动。通过详细提示控制摄像机移动和灯光。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_r2v', 'zh-TW', 'Seedance 2.0：影片參考', '根據參考圖像和文字提示生成電影級影片。在保留主體身份和構圖的同時，透過同步音訊添加富有表現力的動態。透過詳細提示控制攝影機移動和燈光。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_r2v', 'ja', 'Seedance 2.0：ビデオ参照', '参照画像とテキストプロンプトから映画的な動画を生成します。被写体のアイデンティティと構図を維持しながら、同期したオーディオで表現力豊かな動きを追加します。詳細なプロンプトを通じてカメラの動きと照明を制御します。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_r2v', 'ko', 'Seedance 2.0: 비디오 참조', '참조 이미지와 텍스트 프롬프트로 시네마틱 비디오를 생성합니다. 주체의 정체성과 구도를 보존하면서 동기화된 오디오로 표현력 있는 움직임을 추가합니다. 상세한 프롬프트를 통해 카메라 이동과 조명을 제어합니다.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_r2v', 'es', 'Seedance 2.0: Referencia de video', 'Genera videos cinematográficos a partir de imágenes de referencia y textos descriptivos. Preserva la identidad y composición del sujeto mientras añades movimiento expresivo con audio sincronizado. Controla el movimiento de cámara y la iluminación mediante descripciones detalladas.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_r2v', 'fr', 'Seedance 2.0 : Référence vidéo', 'Générez des vidéos cinématographiques à partir d''images de référence et de descriptions textuelles. Préservez l''identité et la composition du sujet tout en ajoutant un mouvement expressif avec un audio synchronisé. Contrôlez le mouvement de la caméra et l''éclairage via des descriptions détaillées.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_r2v', 'ru', 'Seedance 2.0: Ссылка на видео', 'Создавайте кинематографичные видео на основе референсных изображений и текстовых описаний. Сохраняйте идентичность и композицию объекта, добавляя выразительное движение с синхронизированным звуком. Управляйте движением камеры и освещением с помощью детальных описаний.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_r2v', 'tr', 'Seedance 2.0: Video Referansı', 'Referans görsellerden ve metin istemlerinden sinematik videolar oluşturun. Konunun kimliğini ve kompozisyonunu korurken senkronize sesle ifade edici hareket ekleyin. Detaylı istemler aracılığıyla kamera hareketini ve ışığı kontrol edin.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_r2v', 'ar', 'Seedance 2.0: مرجع الفيديو', 'أنشئ مقاطع فيديو سينمائية من صور مرجعية ونصوص وصفية. احتفظ بهوية الموضوع وتكوينه مع إضافة حركة تعبيرية مع صوت متزامن. تحكم في حركة الكاميرا والإضاءة من خلال أوصاف مفصلة.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_r2v', 'pt-BR', 'Seedance 2.0: Referência de Vídeo', 'Gere vídeos cinematográficos a partir de imagens de referência e descrições textuais. Preserve a identidade e composição do sujeito enquanto adiciona movimento expressivo com áudio sincronizado. Controle o movimento da câmera e a iluminação por meio de descrições detalhadas.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (209, 'api_seedance2_0_t2v', 3, 1, 'Seedance 2.0: Text to Video ', 'Generate cinematic videos from text prompts with synchronized audio, controlled camera motion, and stable visuals. Input text descriptions to output high-quality video sequences.', 'image', 'webp', NULL, '["output/api_seedance2_0_t2v.mp4"]', '["Text to Video","Video"]', '["Seedance 2.0"]', '[{"provider":"ByteDance"}]', '[]', '[]', '{"outputs":[{"nodeId":344,"nodeType":"SaveVideo","file":"api_seedance2_0_t2v.mp4","mediaType":"video"}]}', NULL, NULL, '2026-04-13', 0, 'active', 0, 0, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_t2v', 'en', 'Seedance 2.0: Text to Video ', 'Generate cinematic videos from text prompts with synchronized audio, controlled camera motion, and stable visuals. Input text descriptions to output high-quality video sequences.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_t2v', 'zh', 'Seedance 2.0：文生视频', '通过文本提示生成电影级视频，具备同步音频、可控相机运动和稳定视觉效果。输入文本描述即可输出高质量视频序列。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_t2v', 'zh-TW', 'Seedance 2.0：文字轉影片', '透過文字提示生成電影級影片，具備同步音訊、可控相機運動和穩定視覺效果。輸入文字描述即可輸出高品質影片序列。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_t2v', 'ja', 'Seedance 2.0：テキストからビデオへ', 'テキストプロンプトから映画的なビデオを生成し、同期したオーディオ、制御されたカメラモーション、安定した視覚効果を実現します。テキスト記述を入力して高品質なビデオシーケンスを出力します。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_t2v', 'ko', 'Seedance 2.0: 텍스트를 비디오로', '동기화된 오디오, 제어된 카메라 모션, 안정적인 시각 효과를 갖춘 텍스트 프롬프트로 시네마틱 비디오를 생성합니다. 텍스트 설명을 입력하여 고품질 비디오 시퀀스를 출력합니다.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_t2v', 'es', 'Seedance 2.0: Texto a Video', 'Genere videos cinematográficos a partir de indicaciones de texto con audio sincronizado, movimiento controlado de cámara y efectos visuales estables. Ingrese descripciones de texto para generar secuencias de video de alta calidad.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_t2v', 'fr', 'Seedance 2.0 : Texte vers Vidéo', 'Générez des vidéos cinématographiques à partir de prompts textuels avec audio synchronisé, mouvement contrôlé de la caméra et effets visuels stables. Saisissez des descriptions textuelles pour produire des séquences vidéo de haute qualité.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_t2v', 'ru', 'Seedance 2.0: Текст в Видео', 'Создавайте кинематографические видео из текстовых запросов с синхронизированным звуком, контролируемым движением камеры и стабильной визуализацией. Вводите текстовые описания для вывода высококачественных видеопоследовательностей.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_t2v', 'tr', 'Seedance 2.0: Metinden Videoya', 'Senkronize ses, kontrollü kamera hareketi ve kararlı görsel efektlerle metin istemlerinden sinematik videolar oluşturun. Yüksek kaliteli video dizileri çıktısı almak için metin açıklamaları girin.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_t2v', 'ar', 'Seedance 2.0: النص إلى الفيديو', 'أنشئ مقاطع فيديو سينمائية من نصوص نصية مع صوت متزامن وحركة كاميرا مضبوطة وتأثيرات بصرية مستقرة. أدخل أوصاف نصية لإخراج تسلسلات فيديو عالية الجودة.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_t2v', 'pt-BR', 'Seedance 2.0: Texto para Vídeo', 'Gere vídeos cinematográficos a partir de prompts de texto com áudio sincronizado, movimento controlado de câmera e efeitos visuais estáveis. Insira descrições de texto para gerar sequências de vídeo de alta qualidade.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (210, 'api_seedance2_0_flf2v', 3, 2, 'Seedance2.0: First-Last-Frame to Video', 'Upload the first and last frames of your video. Generate a high-quality video sequence using the Seedance2.0 model.', 'image', 'webp', NULL, '["output/api_seedance2_0_flf2v.mp4"]', '["Video","FLF2V","API"]', '["Seedance 2.0"]', '[{"provider":"ByteDance"}]', '[]', '[]', '{"inputs":[{"nodeId":3,"nodeType":"LoadImage","file":"sd_first_frame.png","mediaType":"image"},{"nodeId":4,"nodeType":"LoadImage","file":"sd_last_frame.png","mediaType":"image"}],"outputs":[{"nodeId":2,"nodeType":"SaveVideo","file":"api_seedance2_0_flf2v.mp4","mediaType":"video"}]}', NULL, NULL, '2026-04-13', 0, 'active', 0, 0, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_flf2v', 'en', 'Seedance2.0: First-Last-Frame to Video', 'Upload the first and last frames of your video. Generate a high-quality video sequence using the Seedance2.0 model.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_flf2v', 'zh', 'Seedance2.0：首尾帧视频', '上传视频的首尾帧。使用Seedance2.0模型生成高质量视频序列。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_flf2v', 'zh-TW', 'Seedance2.0：首尾幀生成影片', '上傳影片的首尾幀。使用Seedance2.0模型生成高品質影片序列。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_flf2v', 'ja', 'Seedance2.0：最初と最後のフレームから動画生成', '動画の最初と最後のフレームをアップロードしてください。Seedance2.0モデルを使用して高品質な動画シーケンスを生成します。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_flf2v', 'ko', 'Seedance2.0: 첫-마지막 프레임에서 비디오 생성', '동영상의 첫 번째와 마지막 프레임을 업로드하세요. Seedance2.0 모델을 사용하여 고품질 동영상 시퀀스를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_flf2v', 'es', 'Seedance2.0: De primera-última fotograma a vídeo', 'Sube el primer y el último fotograma de tu video. Genera una secuencia de video de alta calidad utilizando el modelo Seedance2.0.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_flf2v', 'fr', 'Seedance2.0 : De la première-dernière image à la vidéo', 'Téléchargez la première et la dernière image de votre vidéo. Générez une séquence vidéo de haute qualité à l''aide du modèle Seedance2.0.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_flf2v', 'ru', 'Seedance2.0: От первого-последнего кадра к видео', 'Загрузите первый и последний кадры вашего видео. Создайте высококачественную видеопоследовательность с помощью модели Seedance2.0.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_flf2v', 'tr', 'Seedance2.0: İlk-Son Kareden Videoya', 'Videonuzun ilk ve son karelerini yükleyin. Seedance2.0 modelini kullanarak yüksek kaliteli bir video dizisi oluşturun.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_flf2v', 'ar', 'Seedance2.0: من الإطار الأول-الأخير إلى الفيديو', 'قم بتحميل الإطار الأول والأخير من الفيديو الخاص بك. قم بإنشاء تسلسل فيديو عالي الجودة باستخدام نموذج Seedance2.0.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_seedance2_0_flf2v', 'pt-BR', 'Seedance2.0: Do primeiro-último quadro para vídeo', 'Faça upload do primeiro e do último quadro do seu vídeo. Gere uma sequência de vídeo de alta qualidade usando o modelo Seedance2.0.', 0, NULL, '2026-04-19T13:33:43.918Z');
