INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_2_14B_i2v', 'en', 'Wan 2.2 14B Image to Video', 'Transform static images into dynamic videos with precise motion control and style preservation using Wan 2.2.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_2_14B_i2v', 'zh', 'Wan 2.2 14B图生视频', '使用Wan 2.2将静态图像转换为具有精确运动控制和风格保持的动态视频。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_2_14B_i2v', 'zh-TW', 'Wan 2.2 14B 影像到影片', '使用 Wan 2.2 將靜態影像轉換為具有精確運動控制與風格保持的動態影片。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_2_14B_i2v', 'ja', 'Wan 2.2 14B画像からビデオ', 'Wan 2.2を使用して、正確なモーション制御とスタイル保持で静止画像を動的なビデオに変換します。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_2_14B_i2v', 'ko', 'Wan 2.2 14B 이미지에서 비디오', 'Wan 2.2를 사용하여 정적인 이미지를 정밀한 모션 제어와 스타일 보존으로 동적 비디오로 변환합니다.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_2_14B_i2v', 'es', 'Imagen a video Wan 2.2 14B', 'Transformar imágenes estáticas en videos dinámicos con control de movimiento preciso y preservación de estilo usando Wan 2.2.', 0, NULL, '2026-04-19T13:33:43.918Z');
