INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_grok_video_extend', 'ko', 'Grok: 비디오 확장', '짧은 동영상과 다음 장면을 설명하는 텍스트 프롬프트를 업로드하세요. Grok extend를 사용하여 매끄러운 동영상 확장을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_grok_video_extend', 'es', 'Grok: Extensión de video', 'Sube un video corto y un texto que describa la siguiente escena. Genera una extensión de video sin interrupciones usando Grok extend.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_grok_video_extend', 'fr', 'Grok : Extension vidéo', 'Téléchargez une courte vidéo et un texte décrivant la scène suivante. Générez une extension vidéo fluide en utilisant Grok extend.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_grok_video_extend', 'ru', 'Grok: Расширение видео', 'Загрузите короткое видео и текстовое описание следующей сцены. Создайте плавное расширение видео с помощью Grok extend.', 0, NULL, '2026-04-19T13:33:43.918Z');
