INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_grok_video_extend', 'ar', 'Grok: تمديد الفيديو', 'قم بتحميل مقطع فيديو قصير ونص يصف المشهد التالي. قم بإنشاء امتداد فيديو سلس باستخدام Grok extend.', 0, NULL, '2026-04-19T13:33:43.918Z');
