INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (217, 'video_ltx2_3_i2v', 3, 9, 'LTX-2.3: Image to Video', 'Upload an image to generate a video with improved motion consistency and fine details, including enhanced support for portrait formats and audio quality.', 'image', 'webp', NULL, '[]', '["Image to Video","Video"]', '["LTX-2.3","Lightricks"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":269,"nodeType":"LoadImage","file":"egyptian_queen.png","mediaType":"image"}],"outputs":[{"nodeId":75,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-03-05', 1, 'active', 47244640256, 47244640256, 20742, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_i2v', 'en', 'LTX-2.3: Image to Video', 'Upload an image to generate a video with improved motion consistency and fine details, including enhanced support for portrait formats and audio quality.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_i2v', 'zh', 'LTX-2.3：图生视频', '上传图像以生成视频，提升运动一致性和精细细节，包括增强的竖屏格式支持和音频质量。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_i2v', 'zh-TW', 'LTX-2.3：圖像轉影片', '上傳圖像以生成影片，提升運動一致性和精細細節，包括增強的豎屏格式支援和音訊品質。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_i2v', 'ja', 'LTX-2.3：画像から動画へ', '画像をアップロードして動画を生成し、動きの一貫性と細部を向上させ、縦長フォーマットと音質のサポートを強化します。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_i2v', 'ko', 'LTX-2.3: 이미지에서 비디오로', '이미지를 업로드하여 동영상을 생성하면 움직임 일관성과 세부 사항이 개선되며, 세로 형식 지원과 오디오 품질이 향상됩니다.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_i2v', 'es', 'LTX-2.3: Imagen a video', 'Sube una imagen para generar un video con mejor consistencia de movimiento y detalles finos, incluido un soporte mejorado para formatos verticales y calidad de audio.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_i2v', 'fr', 'LTX-2.3 : Image vers vidéo', 'Téléchargez une image pour générer une vidéo avec une meilleure cohérence de mouvement et des détails fins, incluant un support amélioré pour les formats portrait et la qualité audio.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_i2v', 'ru', 'LTX-2.3: Изображение в видео', 'Загрузите изображение, чтобы создать видео с улучшенной согласованностью движения и мелкими деталями, включая расширенную поддержку портретных форматов и качества звука.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_i2v', 'tr', 'LTX-2.3: Görüntüden Videoya', 'Geliştirilmiş hareket tutarlılığı ve ince detaylara sahip bir video oluşturmak için bir görsel yükleyin; portre formatları ve ses kalitesi için geliştirilmiş destek dahildir.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_i2v', 'ar', 'LTX-2.3: صورة إلى فيديو', 'قم بتحميل صورة لإنشاء فيديو مع تحسين اتساق الحركة والتفاصيل الدقيقة، بما في ذلك دعم محسّن للتنسيقات الرأسية وجودة الصوت.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_i2v', 'pt-BR', 'LTX-2.3: Imagem para Vídeo', 'Faça upload de uma imagem para gerar um vídeo com melhor consistência de movimento e detalhes refinados, incluindo suporte aprimorado para formatos retrato e qualidade de áudio.', 0, NULL, '2026-04-19T13:33:43.918Z');
