INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_ia2v', 'en', 'LTX-2.3: Image Audio to Video', 'Upload an image and an audio file to generate a high-quality video with synchronized lip movements using LTX-2.3.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_ia2v', 'zh', 'LTX-2.3：图像音频转视频', '上传图像和音频文件，使用LTX-2.3生成具有同步唇部动作的高质量视频。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_ia2v', 'zh-TW', 'LTX-2.3：圖像音訊轉視訊', '上傳圖像和音訊檔案，使用LTX-2.3生成具有同步唇部動作的高品質影片。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_ia2v', 'ja', 'LTX-2.3：画像オーディオからビデオへ', '画像とオーディオファイルをアップロードし、LTX-2.3を使用して同期した唇の動きを伴う高品質な動画を生成します。', 0, NULL, '2026-04-19T13:33:43.918Z');
