INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_ia2v', 'es', 'LTX-2.3: Imagen y audio a video', 'Sube una imagen y un archivo de audio para generar un video de alta calidad con movimientos de labios sincronizados usando LTX-2.3.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_ia2v', 'fr', 'LTX-2.3 : Image et audio en vidéo', 'Téléchargez une image et un fichier audio pour générer une vidéo de haute qualité avec des mouvements de lèvres synchronisés en utilisant LTX-2.3.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_ia2v', 'ru', 'LTX-2.3: Изображение и аудио в видео', 'Загрузите изображение и аудиофайл, чтобы создать высококачественное видео с синхронизированными движениями губ с помощью LTX-2.3.', 0, NULL, '2026-04-19T13:33:43.918Z');
