INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_ia2v', 'ar', 'LTX-2.3: الصورة والصوت إلى فيديو', 'قم بتحميل صورة وملف صوتي لإنشاء فيديو عالي الجودة بحركات شفاه متزامنة باستخدام LTX-2.3.', 0, NULL, '2026-04-19T13:33:43.918Z');
