INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_flf2v', 'zh', 'LTX-2.3: FLF2V', '上传起始图像以生成视频序列。该工作流程会创建一个风格一致、带有动感的短视频，从您提供的帧开始。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_flf2v', 'zh-TW', 'LTX-2.3: FLF2V', '上傳起始圖像以生成影片序列。該工作流程會創建一個風格一致、帶有動感的短片，從您提供的幀開始。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_flf2v', 'ja', 'LTX-2.3: FLF2V', '開始画像をアップロードしてビデオシーケンスを生成します。このワークフローは、提供されたフレームから始まり、一貫したスタイルと動きを持つ短いビデオを作成します。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_flf2v', 'ko', 'LTX-2.3: FLF2V', '시작 이미지를 업로드하여 비디오 시퀀스를 생성하세요. 이 워크플로우는 제공한 프레임으로 시작하여 일관된 스타일과 움직임을 가진 짧은 비디오를 만듭니다.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_flf2v', 'es', 'LTX-2.3: FLF2V', 'Sube una imagen inicial para generar una secuencia de video. El flujo de trabajo crea un video corto con estilo y movimiento consistentes, comenzando con el fotograma que proporcionaste.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_flf2v', 'fr', 'LTX-2.3: FLF2V', 'Téléchargez une image de départ pour générer une séquence vidéo. Le flux de travail crée une courte vidéo avec un style et un mouvement cohérents, en commençant par l''image que vous avez fournie.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_flf2v', 'ru', 'LTX-2.3: FLF2V', 'Загрузите начальное изображение для создания видеопоследовательности. Рабочий процесс создает короткое видео с единообразным стилем и движением, начиная с предоставленного вами кадра.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_flf2v', 'tr', 'LTX-2.3: FLF2V', 'Bir video dizisi oluşturmak için başlangıç görseli yükleyin. İş akışı, sağladığınız kareyle başlayarak tutarlı tarz ve hareket içeren kısa bir video oluşturur.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_flf2v', 'ar', 'LTX-2.3: FLF2V', 'قم بتحميل صورة بداية لإنشاء تسلسل فيديو. يخلق سير العمل فيديو قصيرًا بأسلوب وحركة متناسقين، بدءًا من الإطار الذي قدمته.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_flf2v', 'pt-BR', 'LTX-2.3: FLF2V', 'Faça upload de uma imagem inicial para gerar uma sequência de vídeo. O fluxo de trabalho cria um vídeo curto com estilo e movimento consistentes, começando com o quadro fornecido por você.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (220, 'video_ltx2_3_t2v', 3, 12, 'LTX-2.3: Text to Video', 'Generate a video from a text prompt, optionally using an image for reference. Receive a high-quality video with improved motion, audio, and detail, optimized for portrait or landscape formats.', 'image', 'webp', NULL, '["output/video_ltx2_3_t2v.mp4"]', '["Text to Video","Video"]', '["LTX-2.3","Lightricks"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":75,"nodeType":"SaveVideo","file":"video_ltx2_3_t2v.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-05', 1, 'active', 47244640256, 47244640256, 4403, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_t2v', 'en', 'LTX-2.3: Text to Video', 'Generate a video from a text prompt, optionally using an image for reference. Receive a high-quality video with improved motion, audio, and detail, optimized for portrait or landscape formats.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_t2v', 'zh', 'LTX-2.3：文生视频', '根据文本提示生成视频，可选择使用参考图像。获得高质量视频，具有改进的运动、音频和细节，优化为纵向或横向格式。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_t2v', 'zh-TW', 'LTX-2.3：文字轉影片', '根據文字提示生成影片，可選擇使用參考圖像。獲得高品質影片，具有改進的動作、音訊和細節，最佳化為縱向或橫向格式。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_t2v', 'ja', 'LTX-2.3：テキストからビデオへ', 'テキストプロンプトからビデオを生成し、オプションで参照用画像を使用できます。高品質なビデオを受け取り、動き、音声、詳細が改善され、縦向きまたは横向きフォーマットに最適化されています。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_t2v', 'ko', 'LTX-2.3: 텍스트를 비디오로', '텍스트 프롬프트에서 비디오를 생성하며, 선택적으로 참조용 이미지를 사용할 수 있습니다. 개선된 모션, 오디오 및 디테일을 갖춘 고품질 비디오를 받고, 세로 또는 가로 형식에 최적화됩니다.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_t2v', 'es', 'LTX-2.3: Texto a video', 'Genera un video a partir de un texto, opcionalmente usando una imagen como referencia. Recibe un video de alta calidad con movimiento, audio y detalles mejorados, optimizado para formatos verticales o horizontales.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_t2v', 'fr', 'LTX-2.3 : Texte en vidéo', 'Générez une vidéo à partir d''une invite texte, en utilisant éventuellement une image comme référence. Recevez une vidéo de haute qualité avec un mouvement, un audio et des détails améliorés, optimisée pour les formats portrait ou paysage.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_t2v', 'ru', 'LTX-2.3: Текст в видео', 'Создайте видео по текстовому запросу, при необходимости используя изображение в качестве образца. Получите высококачественное видео с улучшенным движением, звуком и детализацией, оптимизированное для портретного или альбомного формата.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_t2v', 'tr', 'LTX-2.3: Metinden Videoya', 'Bir metin isteminden video oluşturun, isteğe bağlı olarak referans için bir görsel kullanın. Geliştirilmiş hareket, ses ve detaylara sahip, dikey veya yatay formatlar için optimize edilmiş yüksek kaliteli bir video alın.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_t2v', 'ar', 'LTX-2.3: نص إلى فيديو', 'أنشئ فيديو من نص، مع إمكانية استخدام صورة كمرجع. احصل على فيديو عالي الجودة بحركة وصوت وتفاصيل محسنة، ومُحسّن للأشكال الرأسية أو الأفقية.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_t2v', 'pt-BR', 'LTX-2.3: Texto para Vídeo', 'Gere um vídeo a partir de um prompt de texto, opcionalmente usando uma imagem como referência. Receba um vídeo de alta qualidade com movimento, áudio e detalhes aprimorados, otimizado para formatos retrato ou paisagem.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (221, 'video_ltx2_3_id_lora', 3, 13, 'LTX-2.3: ID LoRA', 'Generate personalized videos with synchronized audio from a text prompt, reference image, and short audio clip. Use ID-LoRA to adapt a person''s appearance and voice in a single generative model.', 'image', 'webp', NULL, '["output/video_ltx2_3_id_lora.mp4"]', '["Lip Sync","Video","Voice Cloning"]', '["LTX-2.3"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":269,"nodeType":"LoadImage","file":"vintage_thinker.png","mediaType":"image"},{"nodeId":276,"nodeType":"LoadAudio","file":"ltx23_reference_audio.mp3","mediaType":"audio"}],"outputs":[{"nodeId":341,"nodeType":"SaveVideo","file":"video_ltx2_3_id_lora.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-27', 1, 'active', 48318382080, 48318382080, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_id_lora', 'en', 'LTX-2.3: ID LoRA', 'Generate personalized videos with synchronized audio from a text prompt, reference image, and short audio clip. Use ID-LoRA to adapt a person''s appearance and voice in a single generative model.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_id_lora', 'zh', 'LTX-2.3: ID LoRA', '通过文本提示、参考图像和简短音频片段生成带同步音频的个性化视频。使用ID-LoRA在单一生成模型中适配人物的外观和声音。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_id_lora', 'zh-TW', 'LTX-2.3: ID LoRA', '透過文字提示、參考圖像和簡短音訊片段生成帶同步音訊的個人化影片。使用ID-LoRA在單一生成模型中適配人物的外觀和聲音。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_id_lora', 'ja', 'LTX-2.3: ID LoRA', 'テキストプロンプト、参照画像、短い音声クリップから同期した音声付きのパーソナライズ動画を生成します。ID-LoRAを使用して、単一の生成モデルで人物の外見と声を適応させます。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_id_lora', 'ko', 'LTX-2.3: ID LoRA', '텍스트 프롬프트, 참조 이미지 및 짧은 오디오 클립으로 동기화된 오디오가 포함된 맞춤형 동영상을 생성하세요. ID-LoRA를 사용하여 단일 생성 모델에서 사람의 외모와 목소리를 적용합니다.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_id_lora', 'es', 'LTX-2.3: ID LoRA', 'Genera videos personalizados con audio sincronizado a partir de un texto, una imagen de referencia y un clip de audio corto. Usa ID-LoRA para adaptar la apariencia y la voz de una persona en un único modelo generativo.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_id_lora', 'fr', 'LTX-2.3: ID LoRA', 'Générez des vidéos personnalisées avec audio synchronisé à partir d''une invite texte, d''une image de référence et d''un court extrait audio. Utilisez ID-LoRA pour adapter l''apparence et la voix d''une personne dans un modèle génératif unique.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_id_lora', 'ru', 'LTX-2.3: ID LoRA', 'Создавайте персонализированные видео с синхронизированным аудио на основе текстового запроса, эталонного изображения и короткого аудиоклипа. Используйте ID-LoRA для адаптации внешности и голоса человека в единой генеративной модели.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_id_lora', 'tr', 'LTX-2.3: ID LoRA', 'Bir metin istemi, referans görseli ve kısa ses klibinden senkronize sesli kişiselleştirilmiş videolar oluşturun. Tek bir üretken modelde bir kişinin görünümünü ve sesini uyarlamak için ID-LoRA kullanın.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_id_lora', 'ar', 'LTX-2.3: ID LoRA', 'أنشئ مقاطع فيديو مخصصة مع صوت متزامن من خلال نص مكتوب، وصورة مرجعية، ومقطع صوتي قصير. استخدم ID-LoRA لتكييف مظهر الشخص وصوته في نموذج توليدي واحد.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_3_id_lora', 'pt-BR', 'LTX-2.3: ID LoRA', 'Gere vídeos personalizados com áudio sincronizado a partir de um prompt de texto, imagem de referência e um clipe de áudio curto. Use ID-LoRA para adaptar a aparência e a voz de uma pessoa em um único modelo generativo.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (222, 'video_ltx2_i2v', 3, 14, 'LTX-2: Image to Video', 'Transform static images into dynamic videos with synchronized audio-video generation using LTX-2. Features expressive lip sync, natural motion, and efficient performance.', 'image', 'webp', NULL, '["output/video_ltx2_i2v.mp4"]', '["Image to Video","Video"]', '["LTX-2","Lightricks"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":98,"nodeType":"LoadImage","file":"freckled_curly_girl.png","mediaType":"image"}],"outputs":[{"nodeId":75,"nodeType":"SaveVideo","file":"video_ltx2_i2v.mp4","mediaType":"video"}]}', NULL, NULL, '2026-01-06', 1, 'active', 38010460570, 38010460570, 2094, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v', 'en', 'LTX-2: Image to Video', 'Transform static images into dynamic videos with synchronized audio-video generation using LTX-2. Features expressive lip sync, natural motion, and efficient performance.', 0, NULL, '2026-03-18T10:07:55.931Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v', 'zh', 'LTX-2：图生视频', '使用LTX-2将静态图像变为动态视频，音视频同步，表情自然，动作流畅。', 1, '["title"]', '2026-03-18T10:07:55.931Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v', 'zh-TW', 'LTX-2：圖像轉影片', '使用LTX-2將靜態圖片轉換為動態影片，影音同步，表情口型自然，動作流暢。', 1, '["title"]', '2026-03-18T10:07:55.931Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v', 'ja', 'LTX-2：画像から動画へ', 'LTX-2で静止画像を動きのある動画に変換。音声と映像が同期し、自然なリップシンクと動きを実現。', 1, '["title"]', '2026-03-18T10:07:55.931Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v', 'ko', 'LTX-2: 이미지에서 비디오로', 'LTX-2로 정적 이미지를 동영상으로 변환, 오디오-비디오 동기화 및 자연스러운 립싱크와 동작 제공.', 1, '["title"]', '2026-03-18T10:07:55.931Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v', 'es', 'LTX-2: De imagen a vídeo', 'Convierte imágenes estáticas en vídeos dinámicos con LTX-2; audio y vídeo sincronizados con movimientos y labios naturales.', 1, '["title"]', '2026-03-18T10:07:55.931Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v', 'fr', 'LTX-2 : De l''image à la vidéo', 'Transformez des images statiques en vidéos dynamiques avec LTX-2, synchronisation audio/vidéo et mouvements naturels.', 1, '["title"]', '2026-03-18T10:07:55.931Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v', 'ru', 'LTX-2: Изображение в видео', 'Преобразуйте статичные изображения в динамичные видео с помощью LTX-2: синхронизация аудио и видео, естественная мимика и движения.', 1, '["title"]', '2026-03-18T10:07:55.931Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v', 'tr', 'LTX-2: Görüntüden Videoya', 'LTX-2 ile durağan görselleri dinamik videolara çevirin; senkronize ses-görüntü, doğal mimik ve hareketler.', 1, '["title"]', '2026-03-18T10:07:55.931Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v', 'ar', 'LTX-2: من صورة إلى فيديو', 'حوّل الصور الثابتة إلى فيديو ديناميكي بمزامنة الصوت والصورة باستخدام LTX-2 مع تعبيرات وحركات طبيعية.', 1, '["title"]', '2026-03-18T10:07:55.931Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v', 'pt-BR', 'LTX-2: Imagem para Vídeo', 'Transforme imagens estáticas em vídeos dinâmicos com LTX-2, áudio e vídeo sincronizados, movimentos e expressões naturais.', 1, '["title"]', '2026-03-18T10:07:55.931Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (223, 'api_wan2_7_i2v', 3, 15, 'Wan2.7: Image to Video', 'Upload an image and audio file to generate a video with synchronized sound, using the first and last frames for control.', 'image', 'webp', NULL, '[]', '["Image to Video","Video"]', '["Wan2.7"]', '[{"provider":"WAN"}]', '[]', '[]', '{"inputs":[{"nodeId":24,"nodeType":"LoadImage","file":"tv_head.png","mediaType":"image"}],"outputs":[{"nodeId":32,"nodeType":"SaveVideo","file":"api_wan2_7_i2v.mp4","mediaType":"video"}]}', NULL, NULL, '2026-04-02', 0, 'active', 0, 0, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_7_i2v', 'en', 'Wan2.7: Image to Video', 'Upload an image and audio file to generate a video with synchronized sound, using the first and last frames for control.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_7_i2v', 'zh', 'Wan2.7：图生视频', '上传图像和音频文件以生成带同步声音的视频，使用首尾帧进行控制。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_7_i2v', 'zh-TW', 'Wan2.7：圖像轉影片', '上傳圖像和音訊檔案以生成帶同步聲音的影片，使用首尾幀進行控制。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_7_i2v', 'ja', 'Wan2.7：画像から動画へ', '画像と音声ファイルをアップロードして同期音声付き動画を生成し、最初と最後のフレームを使用して制御します。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_7_i2v', 'ko', 'Wan2.7: 이미지를 동영상으로', '이미지와 오디오 파일을 업로드하여 동기화된 사운드가 포함된 비디오를 생성하고, 첫 번째와 마지막 프레임을 사용하여 제어합니다.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_7_i2v', 'es', 'Wan2.7: Imagen a video', 'Sube una imagen y un archivo de audio para generar un video con sonido sincronizado, utilizando el primer y último fotograma para el control.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_7_i2v', 'fr', 'Wan2.7 : Image en vidéo', 'Téléchargez une image et un fichier audio pour générer une vidéo avec son synchronisé, en utilisant la première et la dernière image pour le contrôle.', 0, NULL, '2026-04-19T13:33:43.918Z');
