INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control3', 'en', 'Kling 3.0: Motion Control', 'Upload a character image and a motion reference video. Generate a new video where your character performs the actions from the reference, with enhanced facial consistency using optional element binding.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control3', 'zh', 'Kling 3.0: Motion Control', '上传角色图像和动作参考视频。生成新视频，让您的角色执行参考视频中的动作，并通过可选元素绑定增强面部一致性。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control3', 'zh-TW', 'Kling 3.0: Motion Control', '上傳角色圖像和動作參考影片。生成新影片，讓您的角色執行參考影片中的動作，並透過可選元素綁定增強面部一致性。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control3', 'ja', 'Kling 3.0: Motion Control', 'キャラクター画像とモーションリファレンス動画をアップロードしてください。リファレンスの動作をキャラクターが行う新しい動画を生成し、オプションの要素バインディングを使用して顔の一貫性を強化します。', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control3', 'ko', 'Kling 3.0: Motion Control', '캐릭터 이미지와 동작 참조 동영상을 업로드하세요. 참조 동영상의 동작을 캐릭터가 수행하는 새로운 동영상을 생성하고, 선택적 요소 바인딩을 통해 얼굴 일관성을 향상시킵니다.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control3', 'es', 'Kling 3.0: Motion Control', 'Sube una imagen del personaje y un video de referencia de movimiento. Genera un nuevo video donde tu personaje realice las acciones de la referencia, con consistencia facial mejorada mediante enlace de elementos opcional.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control3', 'fr', 'Kling 3.0: Motion Control', 'Téléchargez une image de personnage et une vidéo de référence de mouvement. Générez une nouvelle vidéo où votre personnage effectue les actions de la référence, avec une cohérence faciale améliorée grâce à une liaison d''éléments optionnelle.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control3', 'ru', 'Kling 3.0: Motion Control', 'Загрузите изображение персонажа и видео-образец движения. Создайте новое видео, в котором ваш персонаж выполняет действия из образца, с улучшенной согласованностью лица с помощью опциональной привязки элементов.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control3', 'tr', 'Kling 3.0: Motion Control', 'Bir karakter görseli ve bir hareket referans videosu yükleyin. Karakterinizin referanstaki eylemleri gerçekleştirdiği yeni bir video oluşturun, isteğe bağlı element bağlama ile geliştirilmiş yüz tutarlılığı sağlayın.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control3', 'ar', 'Kling 3.0: Motion Control', 'قم بتحميل صورة شخصية وفيديو مرجعي للحركة. أنشئ فيديو جديدًا حيث يؤدي شخصيتك الإجراءات من المرجع، مع تحسين اتساق الوجه باستخدام ربط العناصر الاختياري.', 0, NULL, '2026-04-19T13:33:43.918Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control3', 'pt-BR', 'Kling 3.0: Motion Control', 'Faça upload de uma imagem do personagem e de um vídeo de referência de movimento. Gere um novo vídeo onde seu personagem executa as ações da referência, com consistência facial aprimorada usando vinculação de elementos opcional.', 0, NULL, '2026-04-19T13:33:43.918Z');
