INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_avatar2', 'pt-BR', 'Kling: Avatar 2.0', 'Faça upload de um retrato e um arquivo de áudio para gerar um vídeo de avatar falante com movimentos labiais sincronizados e expressões faciais naturais.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (232, 'api_bytedance_image_to_video', 3, 24, 'Seedance 1.0 Pro: Image to Video', 'Transform static images into dynamic videos using ByteDance''s Seedance model. Analyzes image structure and generates natural motion with consistent visual style and coherent video sequences.', 'image', 'webp', NULL, '[]', '["API","Image to Video","Video"]', '["Seedance1.0 Pro","ByteDance"]', '[{"provider":"ByteDance"}]', '[]', '[]', '{"inputs":[{"nodeId":12,"nodeType":"LoadImage","file":"api_bytedance_image_to_video_input_image.png","mediaType":"image"}],"outputs":[{"nodeId":7,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', '', NULL, '2025-10-06', 0, 'active', 0, 0, 1656, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_image_to_video', 'en', 'Seedance 1.0 Pro: Image to Video', 'Transform static images into dynamic videos using ByteDance''s Seedance model. Analyzes image structure and generates natural motion with consistent visual style and coherent video sequences.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_image_to_video', 'zh', 'ByteDance: 图生视频', '使用 ByteDance 的 Seedance 模型将静态图像转换为动态视频。分析图像结构并生成自然运动，具有一致的视觉风格和连贯的视频序列。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_image_to_video', 'zh-TW', 'ByteDance: 圖生視頻', '使用 ByteDance 的 Seedance 模型將靜態圖像轉換為動態視頻。分析圖像結構並生成具有一致視覺風格和連貫視頻序列的自然運動。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_image_to_video', 'ja', 'ByteDance: 画像から動画', 'ByteDanceのSeedanceモデルを使用して静止画像を動的ビデオに変換します。画像構造を分析し、一貫した視覚スタイルと整合性のあるビデオシーケンスで自然な動きを生成します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_image_to_video', 'ko', 'ByteDance: 이미지에서 비디오', 'ByteDance의 Seedance 모델을 사용하여 정적 이미지를 동적 비디오로 변환합니다. 이미지 구조를 분석하고 일관된 시각적 스타일과 일관된 비디오 시퀀스로 자연스러운 모션을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_image_to_video', 'es', 'ByteDance: Imagen a Video', 'Transforma imágenes estáticas en videos dinámicos usando el modelo Seedance de ByteDance. Analiza la estructura de la imagen y genera movimiento natural con estilo visual consistente y secuencias de video coherentes.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_image_to_video', 'fr', 'ByteDance: Image vers Vidéo', 'Transformez des images statiques en vidéos dynamiques avec le modèle Seedance de ByteDance. Analyse la structure de l''image et génère un mouvement naturel avec un style visuel cohérent et des séquences vidéo cohérentes.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_image_to_video', 'ru', 'ByteDance: Изображение в Видео', 'Преобразование статичных изображений в динамичные видео с помощью модели Seedance от ByteDance. Анализирует структуру изображения и генерирует естественное движение с согласованным визуальным стилем и последовательными видеопоследовательностями.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_image_to_video', 'tr', 'ByteDance: Görüntüden Video''ya', 'ByteDance''in Seedance modelini kullanarak statik görüntüleri dinamik videolara dönüştürün. Görüntü yapısını analiz eder ve tutarlı görsel stil ve tutarlı video dizileriyle doğal hareket oluşturur.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_image_to_video', 'ar', 'ByteDance: من صورة إلى فيديو', 'تحويل الصور الثابتة إلى فيديوهات ديناميكية باستخدام نموذج Seedance من ByteDance. يحلل هيكل الصورة ويولد حركة طبيعية مع أسلوب بصري متسق وتسلسلات فيديو متماسكة.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_image_to_video', 'pt-BR', 'ByteDance: Imagem para Vídeo', 'Transforme imagens estáticas em vídeos dinâmicos usando o modelo Seedance da ByteDance. Analisa a estrutura da imagem e gera movimento natural com estilo visual consistente e sequências de vídeo coerentes.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (233, 'api_kling_dual_characters_effects', 3, 25, 'Kling: Dual Character Effect', 'Upload two character images side - by - side. Generate a video in which the characters hug, kiss, or form a heart gesture together.', 'image', 'webp', NULL, '["output/api_kling_dual_characters_effects.mp4"]', '["API","Video"]', '["Kling 1.6","Kling"]', '[{"provider":"Kling"}]', '[]', '[]', '{"inputs":[{"nodeId":13,"nodeType":"LoadImage","file":"deep_curl_portrait.png","mediaType":"image"},{"nodeId":14,"nodeType":"LoadImage","file":"blue_tone_woman.png","mediaType":"image"}],"outputs":[{"nodeId":17,"nodeType":"SaveVideo","file":"api_kling_dual_characters_effects.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-02', 0, 'active', 0, 0, 63, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_dual_characters_effects', 'en', 'Kling: Dual Character Effect', 'Upload two character images side - by - side. Generate a video in which the characters hug, kiss, or form a heart gesture together.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_dual_characters_effects', 'zh', 'Kling：双重角色效果', '并排上传两张角色图像。生成角色拥抱、亲吻或一起比心手势的视频。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_dual_characters_effects', 'zh-TW', 'Kling：雙重角色效果', '並排上傳兩張角色圖像。生成角色擁抱、親吻或一起比心手勢的影片。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_dual_characters_effects', 'ja', 'Kling：デュアルキャラクター効果', '2枚のキャラクター画像を並べてアップロードしてください。キャラクターが抱擁、キス、または一緒にハートのジェスチャーをする動画を生成します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_dual_characters_effects', 'ko', 'Kling: 듀얼 캐릭터 효과', '두 개의 캐릭터 이미지를 나란히 업로드하세요. 캐릭터가 포옹, 키스 또는 함께 하트 제스처를 하는 동영상을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_dual_characters_effects', 'es', 'Kling: Efecto de Personaje Dual', 'Sube dos imágenes de personajes una al lado de la otra. Genera un video en el que los personajes se abracen, besen o formen un gesto de corazón juntos.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_dual_characters_effects', 'fr', 'Kling : Effet de Personnage Double', 'Téléchargez deux images de personnages côte à côte. Générez une vidéo dans laquelle les personnages s''embrassent, s''étreignent ou forment ensemble un geste en forme de cœur.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_dual_characters_effects', 'ru', 'Kling: Эффект двойного персонажа', 'Загрузите два изображения персонажей рядом. Создайте видео, в котором персонажи обнимаются, целуются или вместе образуют жест в виде сердца.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_dual_characters_effects', 'tr', 'Kling: Çift Karakter Etkisi', 'Yan yana iki karakter görseli yükleyin. Karakterlerin sarıldığı, öpüştüğü veya birlikte kalp işareti yaptığı bir video oluşturun.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_dual_characters_effects', 'ar', 'Kling: تأثير الشخصية المزدوجة', 'قم بتحميل صورتين للشخصيات جنبًا إلى جنب. أنشئ مقطع فيديو تعانق فيه الشخصيات أو تقبل بعضها أو تشكل معًا إيماءة قلب.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_dual_characters_effects', 'pt-BR', 'Kling: Efeito de Personagem Duplo', 'Faça upload de duas imagens de personagens lado a lado. Gere um vídeo em que os personagens se abraçam, se beijam ou formam um gesto de coração juntos.', 0, NULL, '2026-04-19T13:33:43.920Z');
