INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_v2v', 'ko', 'Wan VACE 제어 비디오', 'Wan VACE를 사용하여 입력 비디오와 참조 이미지를 제어하여 비디오를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
