INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_v2v', 'ru', 'Wan VACE Control видео', 'Генерация видео путем управления входными видео и опорными изображениями с использованием Wan VACE.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_v2v', 'tr', 'Wan2.1 VACE Kontrol Videosu', 'Wan VACE kullanarak girdi videolarını ve referans görüntülerini kontrol ederek videolar oluşturun.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_v2v', 'ar', 'Wan2.1 VACE تحكم في الفيديو', 'توليد فيديوهات عبر التحكم بفيديوهات ومدخلات مرجعية باستخدام Wan VACE.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_v2v', 'pt-BR', 'Wan2.1 VACE Controle de Vídeo', 'Gere vídeos controlando vídeos de entrada e imagens de referência usando Wan VACE.', 0, NULL, '2026-04-19T13:33:43.920Z');
