INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx_2_audio_to_video', 'zh', 'LTX-2：音频转视频', '上传音频文件和起始图像帧。使用LTX-2模型生成与音频同步的视频。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx_2_audio_to_video', 'zh-TW', 'LTX-2：音訊轉視訊', '上傳音訊檔案和起始影像幀。使用LTX-2模型生成與音訊同步的影片。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx_2_audio_to_video', 'ja', 'LTX-2：オーディオからビデオへ', '音声ファイルと開始画像フレームをアップロードしてください。LTX-2モデルを使用して音声に同期した動画を生成します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx_2_audio_to_video', 'ko', 'LTX-2: 오디오를 비디오로', '오디오 파일과 시작 이미지 프레임을 업로드하세요. LTX-2 모델을 사용하여 오디오와 동기화된 비디오를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx_2_audio_to_video', 'es', 'LTX-2: Audio a video', 'Sube un archivo de audio y un fotograma de imagen inicial. Genera un vídeo sincronizado con el audio utilizando el modelo LTX-2.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx_2_audio_to_video', 'fr', 'LTX-2 : Audio vers vidéo', 'Téléchargez un fichier audio et une image de départ. Générez une vidéo synchronisée avec l''audio à l''aide du modèle LTX-2.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx_2_audio_to_video', 'ru', 'LTX-2: Аудио в видео', 'Загрузите аудиофайл и начальный кадр изображения. Создайте видео, синхронизированное с аудио, с помощью модели LTX-2.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx_2_audio_to_video', 'tr', 'LTX-2: Sesli Görüntü', 'Bir ses dosyası ve bir başlangıç görüntü karesi yükleyin. LTX-2 modelini kullanarak sese senkronize bir video oluşturun.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx_2_audio_to_video', 'ar', 'LTX-2: الصوت إلى الفيديو', 'قم بتحميل ملف صوتي وإطار صورة بداية. قم بإنشاء فيديو متزامن مع الصوت باستخدام نموذج LTX-2.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx_2_audio_to_video', 'pt-BR', 'LTX-2: Áudio para Vídeo', 'Faça upload de um arquivo de áudio e de um quadro de imagem inicial. Gere um vídeo sincronizado com o áudio usando o modelo LTX-2.', 0, NULL, '2026-04-19T13:33:43.920Z');
