INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_lora', 'zh-TW', '使用LTX-2 I2V和LoRA壓縮一切', '上傳任意圖像以應用Squish It LoRA效果。使用LTX-2 I2V模型生成擠壓動畫。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_lora', 'ja', 'LTX-2 I2VとLoRAで何でも圧縮', '任意の画像をアップロードしてSquish It LoRA効果を適用します。LTX-2 I2Vモデルを使用して圧縮アニメーションを生成します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_lora', 'ko', 'LTX-2 I2V와 LoRA로 모든 것을 압축하세요', 'Squish It LoRA 효과를 적용하려면 이미지를 업로드하세요. LTX-2 I2V 모델을 사용하여 압축 애니메이션을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_lora', 'es', 'Comprime cualquier cosa con LTX-2 I2V y LoRA', 'Sube cualquier imagen para aplicar el efecto Squish It LoRA. Genera una animación comprimida usando el modelo LTX-2 I2V.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_lora', 'fr', 'Compressez tout avec LTX-2 I2V et LoRA', 'Téléchargez n''importe quelle image pour appliquer l''effet Squish It LoRA. Générez une animation compressée en utilisant le modèle LTX-2 I2V.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_lora', 'ru', 'Сжимайте что угодно с LTX-2 I2V и LoRA', 'Загрузите любое изображение, чтобы применить эффект Squish It LoRA. Создайте сжатую анимацию с помощью модели LTX-2 I2V.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_lora', 'tr', 'LTX-2 I2V ve LoRA ile Her Şeyi Sıkıştırın', 'Squish It LoRA efektini uygulamak için herhangi bir görsel yükleyin. LTX-2 I2V modelini kullanarak sıkıştırılmış bir animasyon oluşturun.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_lora', 'ar', 'اضغط أي شيء باستخدام LTX-2 I2V وLoRA', 'قم بتحميل أي صورة لتطبيق تأثير Squish It LoRA. أنشئ رسومًا متحركة مضغوطة باستخدام نموذج LTX-2 I2V.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_lora', 'pt-BR', 'Comprima qualquer coisa com LTX-2 I2V e LoRA', 'Faça upload de qualquer imagem para aplicar o efeito Squish It LoRA. Gere uma animação comprimida usando o modelo LTX-2 I2V.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (237, 'api_kling_v3_flf2v', 3, 29, 'Kling 3.0: First Last Frame to Video', 'Input a first and last frame image to generate a continuous video sequence with multi-shot generation, precise element control, and support for multilingual prompts.', 'image', 'webp', NULL, '["output/Kling_v3_flf2v.mp4"]', '["API","Video","FLF2V"]', '["Kling 3.0"]', '[{"provider":"Kling"}]', '[]', '[]', '{"inputs":[{"nodeId":1,"nodeType":"LoadImage","file":"goldenfish_in_bag.png","mediaType":"image"},{"nodeId":13,"nodeType":"LoadImage","file":"man_in_daydream.png","mediaType":"image"}],"outputs":[{"nodeId":2,"nodeType":"SaveVideo","file":"Kling_v3_flf2v.mp4","mediaType":"video"}]}', NULL, NULL, '2026-02-10', 0, 'active', 0, 0, 1034, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_flf2v', 'en', 'Kling 3.0: First Last Frame to Video', 'Input a first and last frame image to generate a continuous video sequence with multi-shot generation, precise element control, and support for multilingual prompts.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_flf2v', 'zh', 'Kling 3.0：首尾帧视频', '输入首尾帧图像，生成连续视频序列，支持多镜头生成、精确元素控制及多语言提示。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_flf2v', 'zh-TW', 'Kling 3.0：首尾幀生成影片', '輸入首尾幀圖像，生成連續影片序列，支援多鏡頭生成、精確元素控制及多語言提示。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_flf2v', 'ja', 'Kling 3.0：最初と最後のフレームから動画生成', '最初と最後のフレーム画像を入力して、連続したビデオシーケンスを生成します。マルチショット生成、精密な要素制御、多言語プロンプトに対応しています。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_flf2v', 'ko', 'Kling 3.0: 첫 프레임과 마지막 프레임으로 비디오 생성', '첫 번째와 마지막 프레임 이미지를 입력하여 연속 비디오 시퀀스를 생성합니다. 멀티샷 생성, 정밀한 요소 제어 및 다국어 프롬프트를 지원합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_flf2v', 'es', 'Kling 3.0: De la primera y última imagen al video', 'Introduce una imagen del primer y último fotograma para generar una secuencia de vídeo continua con generación de múltiples tomas, control preciso de elementos y soporte para indicaciones multilingües.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_flf2v', 'fr', 'Kling 3.0 : De la première et dernière image à la vidéo', 'Saisissez une image de la première et de la dernière image pour générer une séquence vidéo continue avec génération multi-prises, contrôle précis des éléments et prise en charge des invites multilingues.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_flf2v', 'ru', 'Kling 3.0: От первого и последнего кадра к видео', 'Введите изображение первого и последнего кадра, чтобы создать непрерывную видеопоследовательность с многокадровой генерацией, точным контролем элементов и поддержкой многоязычных подсказок.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_flf2v', 'tr', 'Kling 3.0: İlk ve Son Kareden Videoya', 'Çoklu çekim oluşturma, hassas öğe kontrolü ve çok dilli istem desteği ile sürekli bir video dizisi oluşturmak için bir ilk ve son kare görüntüsü girin.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_flf2v', 'ar', 'Kling 3.0: من الإطار الأول والأخير إلى الفيديو', 'أدخل صورة الإطار الأول والأخير لإنشاء تسلسل فيديو مستمر مع توليد متعدد اللقطات، والتحكم الدقيق في العناصر، ودعم المطالبات متعددة اللغات.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_v3_flf2v', 'pt-BR', 'Kling 3.0: Do Primeiro e Último Quadro para Vídeo', 'Insira uma imagem do primeiro e do último quadro para gerar uma sequência de vídeo contínua com geração de múltiplas tomadas, controle preciso de elementos e suporte a prompts multilíngues.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (238, 'api_kling_o3_video_edit', 3, 30, 'Kling O3: Video Edit', 'Upload a video and a reference image to edit with Kling O3. Generate a professionally edited video with precise subject editing, scene composition, and native audio-visual synchronization.', 'image', 'webp', 'compareSlider', '[]', '["Video Edit","API","Video"]', '["Kling O3"]', '[{"provider":"Kling"}]', '[]', '[]', '{"inputs":[{"nodeId":17,"nodeType":"LoadImage","file":"giant_trees_sky_pyramid.png","mediaType":"image"},{"nodeId":25,"nodeType":"LoadVideo","file":"kling_o3_video_input.mp4","mediaType":"video"}],"outputs":[{"nodeId":14,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-02-10', 0, 'active', 0, 0, 540, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_video_edit', 'en', 'Kling O3: Video Edit', 'Upload a video and a reference image to edit with Kling O3. Generate a professionally edited video with precise subject editing, scene composition, and native audio-visual synchronization.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_video_edit', 'zh', 'Kling O3：视频编辑', '上传视频和参考图片，使用Kling O3进行编辑。生成专业编辑的视频，具备精确的主体编辑、场景构图和原生音视频同步。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_video_edit', 'zh-TW', 'Kling O3：影片編輯', '上傳影片和參考圖片，使用Kling O3進行編輯。生成專業編輯的影片，具備精確的主體編輯、場景構圖和原生音視訊同步。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_video_edit', 'ja', 'Kling O3：ビデオ編集', '動画と参照画像をアップロードし、Kling O3で編集します。正確な被写体編集、シーン構成、ネイティブな音声・映像同期を備えたプロフェッショナルな編集動画を生成します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_video_edit', 'ko', 'Kling O3: 비디오 편집', '동영상과 참조 이미지를 업로드하여 Kling O3로 편집하세요. 정확한 피사체 편집, 장면 구성, 네이티브 오디오-비디오 동기화를 갖춘 전문적으로 편집된 동영상을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_video_edit', 'es', 'Kling O3: Edición de video', 'Sube un video y una imagen de referencia para editar con Kling O3. Genera un video editado profesionalmente con edición precisa del sujeto, composición de escena y sincronización nativa de audio y video.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_video_edit', 'fr', 'Kling O3 : Édition vidéo', 'Téléchargez une vidéo et une image de référence pour éditer avec Kling O3. Générez une vidéo éditée professionnellement avec un montage précis du sujet, une composition de scène et une synchronisation audio-visuelle native.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_video_edit', 'ru', 'Kling O3: Редактирование видео', 'Загрузите видео и эталонное изображение для редактирования с помощью Kling O3. Создайте профессионально отредактированное видео с точным редактированием объекта, композицией сцены и нативной синхронизацией аудио и видео.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_video_edit', 'tr', 'Kling O3: Video Düzenleme', 'Kling O3 ile düzenlemek için bir video ve bir referans görseli yükleyin. Hassas konu düzenlemesi, sahne kompozisyonu ve yerel görsel-işitsel senkronizasyon ile profesyonelce düzenlenmiş bir video oluşturun.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_video_edit', 'ar', 'Kling O3: تحرير الفيديو', 'قم بتحميل مقطع فيديو وصورة مرجعية للتحرير باستخدام Kling O3. أنشئ فيديو محررًا بشكل احترافي مع تحرير دقيق للعنصر، وتكوين المشهد، ومزامنة صوتية بصرية أصلية.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_video_edit', 'pt-BR', 'Kling O3: Edição de Vídeo', 'Faça upload de um vídeo e uma imagem de referência para editar com o Kling O3. Gere um vídeo editado profissionalmente com edição precisa do assunto, composição de cena e sincronização nativa de áudio e vídeo.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (239, 'api_kling_o3_flf2v', 3, 31, 'Kling O3: FLF2V', 'Upload reference images or specify start and end frames. Generate a video with precise semantic control, longer duration, and improved narrative coherence.', 'image', 'webp', NULL, '[]', '["API","FLF2V"]', '["Kling O3"]', '[{"provider":"Kling"}]', '[]', '[]', '{"inputs":[{"nodeId":17,"nodeType":"LoadImage","file":"ivory_rider_right_front_view.png","mediaType":"image"},{"nodeId":34,"nodeType":"LoadImage","file":"ivory_rider.png","mediaType":"image"},{"nodeId":35,"nodeType":"LoadImage","file":"ivory_rider_left_side_view.png","mediaType":"image"},{"nodeId":36,"nodeType":"LoadImage","file":"ivory_rider_right_side_view.png","mediaType":"image"}],"outputs":[{"nodeId":14,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-02-10', 0, 'active', 0, 0, 299, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_flf2v', 'en', 'Kling O3: FLF2V', 'Upload reference images or specify start and end frames. Generate a video with precise semantic control, longer duration, and improved narrative coherence.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_flf2v', 'zh', 'Kling O3：首尾帧视频', '上传参考图像或指定起始帧和结束帧。生成具有精确语义控制、更长时长和更强叙事连贯性的视频。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_flf2v', 'zh-TW', 'Kling O3：首尾幀影片', '上傳參考圖像或指定起始幀和結束幀。生成具有精確語義控制、更長時長和更強敘事連貫性的影片。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_flf2v', 'ja', 'Kling O3：FLF2V', '参照画像をアップロードするか、開始フレームと終了フレームを指定してください。正確な意味制御、より長い継続時間、および改善された物語の一貫性を備えた動画を生成します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_flf2v', 'ko', 'Kling O3: FLF2V', '참조 이미지를 업로드하거나 시작 프레임과 종료 프레임을 지정하세요. 정확한 의미론적 제어, 더 긴 지속 시간, 향상된 내러티브 일관성을 갖춘 동영상을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_flf2v', 'es', 'Kling O3: FLF2V', 'Sube imágenes de referencia o especifica los fotogramas de inicio y fin. Genera un vídeo con control semántico preciso, mayor duración y mejor coherencia narrativa.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_flf2v', 'fr', 'Kling O3 : FLF2V', 'Téléchargez des images de référence ou spécifiez les images de début et de fin. Générez une vidéo avec un contrôle sémantique précis, une durée plus longue et une meilleure cohérence narrative.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_flf2v', 'ru', 'Kling O3: FLF2V', 'Загрузите эталонные изображения или укажите начальный и конечный кадры. Создайте видео с точным семантическим управлением, большей продолжительностью и улучшенной повествовательной связностью.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_flf2v', 'tr', 'Kling O3: FLF2V', 'Referans görselleri yükleyin veya başlangıç ve bitiş karelerini belirtin. Kesin anlamsal kontrol, daha uzun süre ve geliştirilmiş anlatı tutarlılığı ile bir video oluşturun.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_flf2v', 'ar', 'Kling O3: FLF2V', 'قم بتحميل صور مرجعية أو حدد الإطارات البداية والنهاية. أنشئ فيديو مع تحكم دلالي دقيق، ومدة أطول، وتماسك سردي محسن.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_flf2v', 'pt-BR', 'Kling O3: FLF2V', 'Faça upload de imagens de referência ou especifique os quadros inicial e final. Gere um vídeo com controle semântico preciso, duração mais longa e melhor coerência narrativa.', 0, NULL, '2026-04-19T13:33:43.920Z');
