INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_king_o3_t2v', 'zh', 'Kling O3：文生视频', '上传文本、音频或图像，生成具有同步音频、角色一致性和故事板控制的15秒视频。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_king_o3_t2v', 'zh-TW', 'Kling O3：文字轉影片', '上傳文本、音訊或圖像，生成具有同步音訊、角色一致性和故事板控制的15秒影片。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_king_o3_t2v', 'ja', 'Kling O3：テキストから動画へ', 'テキスト、オーディオ、または画像をアップロードして、同期されたオーディオ、キャラクターの一貫性、ストーリーボード制御を備えた15秒の動画を生成します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_king_o3_t2v', 'ko', 'Kling O3: 텍스트를 동영상으로', '텍스트, 오디오 또는 이미지를 업로드하여 동기화된 오디오, 캐릭터 일관성 및 스토리보드 제어 기능이 있는 15초 비디오를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_king_o3_t2v', 'es', 'Kling O3: Texto a video', 'Sube texto, audio o imágenes para generar un video de 15 segundos con audio sincronizado, consistencia de personajes y control del guion gráfico.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_king_o3_t2v', 'fr', 'Kling O3 : Texte en vidéo', 'Téléchargez du texte, de l''audio ou des images pour générer une vidéo de 15 secondes avec audio synchronisé, cohérence des personnages et contrôle du storyboard.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_king_o3_t2v', 'ru', 'Kling O3: Текст в видео', 'Загрузите текст, аудио или изображения, чтобы создать 15-секундное видео с синхронизированным аудио, согласованностью персонажей и контролем раскадровки.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_king_o3_t2v', 'tr', 'Kling O3: Metinden Videoya', 'Senkronize ses, karakter tutarlılığı ve storyboard kontrolü ile 15 saniyelik bir video oluşturmak için metin, ses veya görüntü yükleyin.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_king_o3_t2v', 'ar', 'Kling O3: نص إلى فيديو', 'قم بتحميل نص أو صوت أو صور لإنشاء فيديو مدته 15 ثانية مع صوت متزامن واتساق الشخصيات والتحكم في القصة المصورة.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_king_o3_t2v', 'pt-BR', 'Kling O3: Texto para Vídeo', 'Faça upload de texto, áudio ou imagens para gerar um vídeo de 15 segundos com áudio sincronizado, consistência de personagens e controle de storyboard.', 0, NULL, '2026-04-19T13:33:43.920Z');
