INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_v2v', 'en', 'Kling O1: Video to Video', 'Transform videos with Kling O1. Edit video content, change styles, or replace characters using text prompts and reference images.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_v2v', 'zh', 'Kling O1: 视频转视频', '使用 Kling O1 转换视频。通过文本提示和参考图像编辑视频内容、更改风格或替换角色。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_v2v', 'zh-TW', 'Kling O1: 視頻轉視頻', '使用 Kling O1 轉換視頻。透過文字提示和參考圖像編輯視頻內容、更改風格或替換角色。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_v2v', 'ja', 'Kling O1: 動画から動画へ', 'Kling O1で動画を変換。テキストプロンプトと参照画像を使用して、動画コンテンツを編集、スタイルを変更、またはキャラクターを置き換えます。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_v2v', 'ko', 'Kling O1: 비디오에서 비디오로', 'Kling O1로 비디오를 변환합니다. 텍스트 프롬프트와 참조 이미지를 사용하여 비디오 콘텐츠를 편집하고, 스타일을 변경하거나 캐릭터를 교체할 수 있습니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_v2v', 'es', 'Kling O1: Video a Video', 'Transforma videos con Kling O1. Edita contenido de video, cambia estilos o reemplaza personajes usando indicaciones de texto e imágenes de referencia.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_v2v', 'fr', 'Kling O1 : Vidéo vers Vidéo', 'Transformez des vidéos avec Kling O1. Modifiez le contenu vidéo, changez les styles ou remplacez les personnages en utilisant des invites texte et des images de référence.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_v2v', 'ru', 'Kling O1: Видео в видео', 'Преобразуйте видео с помощью Kling O1. Редактируйте содержимое видео, изменяйте стили или заменяйте персонажей, используя текстовые подсказки и эталонные изображения.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_v2v', 'tr', 'Kling O1: Videodan Videoya', 'Kling O1 ile videoları dönüştürün. Metin istemleri ve referans görüntüler kullanarak video içeriğini düzenleyin, stilleri değiştirin veya karakterleri değiştirin.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_v2v', 'ar', 'Kling O1: من الفيديو إلى الفيديو', 'حوّل الفيديوهات باستخدام Kling O1. عدّل محتوى الفيديو، غيّر الأنماط، أو استبدل الشخصيات باستخدام المطالبات النصية والصور المرجعية.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_v2v', 'pt-BR', 'Kling O1: Vídeo para Vídeo', 'Transforme vídeos com Kling O1. Edite conteúdo de vídeo, altere estilos ou substitua personagens usando prompts de texto e imagens de referência.', 0, NULL, '2026-04-19T13:33:43.920Z');
