INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_i2v', 'en', 'Kling O3: Reference to Video', 'Upload a reference image and optional audio or text prompt. Generate a character-consistent video with native audio output and precise storyboard control.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_i2v', 'zh', 'Kling O3：视频参考', '上传参考图像及可选的音频或文本提示。生成角色一致的视频，具备原生音频输出和精确的故事板控制。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_i2v', 'zh-TW', 'Kling O3：影片參考', '上傳參考圖像及可選的音訊或文字提示。生成角色一致的影片，具備原生音訊輸出和精確的故事板控制。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_i2v', 'ja', 'Kling O3：ビデオ参照', '参照画像とオプションの音声またはテキストプロンプトをアップロードしてください。キャラクターに一貫性のあるビデオを、ネイティブ音声出力と精密なストーリーボード制御で生成します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_i2v', 'ko', 'Kling O3: 비디오 참조', '참조 이미지와 선택적 오디오 또는 텍스트 프롬프트를 업로드하세요. 네이티브 오디오 출력과 정밀한 스토리보드 제어로 캐릭터 일관성 있는 비디오를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_i2v', 'es', 'Kling O3: Referencia de video', 'Sube una imagen de referencia y un prompt opcional de audio o texto. Genera un video con coherencia de personaje, salida de audio nativa y control preciso del guion gráfico.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_i2v', 'fr', 'Kling O3 : Référence vidéo', 'Téléchargez une image de référence et une invite audio ou texte facultative. Générez une vidéo cohérente avec le personnage, avec sortie audio native et contrôle précis du storyboard.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_i2v', 'ru', 'Kling O3: Ссылка на видео', 'Загрузите эталонное изображение и необязательный аудио- или текстовый запрос. Создайте видео с согласованным персонажем, нативным аудиовыходом и точным контролем раскадровки.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_i2v', 'tr', 'Kling O3: Video Referansı', 'Bir referans görseli ve isteğe bağlı ses veya metin istemi yükleyin. Yerel ses çıkışı ve kesin storyboard kontrolü ile karakter tutarlı bir video oluşturun.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_i2v', 'ar', 'Kling O3: إشارة إلى الفيديو', 'قم بتحميل صورة مرجعية وموجه صوتي أو نصي اختياري. أنشئ فيديو متسقًا مع الشخصية مع إخراج صوتي أصلي وتحكم دقيق في القصة المصورة.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_o3_i2v', 'pt-BR', 'Kling O3: Referência de Vídeo', 'Faça upload de uma imagem de referência e um prompt opcional de áudio ou texto. Gere um vídeo com consistência de personagem, saída de áudio nativa e controle preciso do storyboard.', 0, NULL, '2026-04-19T13:33:43.920Z');
