INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q3_image_to_video', 'pt-BR', 'Vidu Q3 Imagem para Vídeo com Áudio', 'Faça upload de uma imagem e forneça um prompt de texto para gerar um vídeo de 1 a 16 segundos com áudio sincronizado e transições de cena inteligentes.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (248, 'api_wan2_6_i2v', 3, 40, 'Wan2.6: Image to Video', 'Transform images into high-quality videos with enhanced image quality, smoother motion, 1080P resolution support, and natural movement generation for professional results.', 'image', 'webp', NULL, '[]', '["Image to Video","Video","API"]', '["Wan2.6","Wan"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":42,"nodeType":"LoadImage","file":"red_car.png","mediaType":"image"}],"outputs":[{"nodeId":43,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', '', NULL, '2025-12-20', 0, 'active', 0, 0, 870, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_i2v', 'en', 'Wan2.6: Image to Video', 'Transform images into high-quality videos with enhanced image quality, smoother motion, 1080P resolution support, and natural movement generation for professional results.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_i2v', 'zh', 'Wan2.6: 图生视频', '将图像转换为高质量视频，具备增强的图像质量、更流畅的运动、1080P分辨率支持和自然的运动生成，实现专业效果。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_i2v', 'zh-TW', 'Wan2.6: 圖像轉視頻', '將圖像轉換為高質量視頻，具備增強的圖像質量、更流暢的運動、1080P解析度支援和自然的運動生成，實現專業效果。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_i2v', 'ja', 'Wan2.6: 画像から動画へ', '画像を高品質な動画に変換。画質向上、滑らかな動き、1080P解像度対応、自然な動き生成により、プロフェッショナルな結果を実現。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_i2v', 'ko', 'Wan2.6: 이미지에서 비디오로', '향상된 이미지 품질, 더 부드러운 움직임, 1080P 해상도 지원 및 자연스러운 움직임 생성으로 이미지를 고품질 비디오로 변환하여 전문적인 결과를 제공합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_i2v', 'es', 'Wan2.6: Imagen a Video', 'Transforma imágenes en videos de alta calidad con calidad de imagen mejorada, movimiento más suave, soporte para resolución 1080P y generación de movimiento natural para resultados profesionales.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_i2v', 'fr', 'Wan2.6 : Image vers Vidéo', 'Transformez des images en vidéos de haute qualité avec une qualité d''image améliorée, un mouvement plus fluide, une prise en charge de la résolution 1080P et une génération de mouvement naturel pour des résultats professionnels.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_i2v', 'ru', 'Wan2.6: Изображение в видео', 'Преобразуйте изображения в высококачественные видео с улучшенным качеством изображения, более плавным движением, поддержкой разрешения 1080P и естественной генерацией движения для профессиональных результатов.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_i2v', 'tr', 'Wan2.6: Görüntüden Videoya', 'Gelişmiş görüntü kalitesi, daha akıcı hareket, 1080P çözünürlük desteği ve doğal hareket üretimi ile görüntüleri profesyonel sonuçlar için yüksek kaliteli videolara dönüştürün.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_i2v', 'ar', 'Wan2.6: من الصورة إلى الفيديو', 'حوّل الصور إلى فيديوهات عالية الجودة مع تحسين جودة الصورة، وحركة أكثر سلاسة، ودعم دقة 1080P، وتوليد حركة طبيعية للحصول على نتائج احترافية.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_i2v', 'pt-BR', 'Wan2.6: Imagem para Vídeo', 'Transforme imagens em vídeos de alta qualidade com qualidade de imagem aprimorada, movimento mais suave, suporte para resolução 1080P e geração de movimento natural para resultados profissionais.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (249, 'api_bytedace_seedance1_5_flf2v', 3, 41, 'Seedance 1.5 Pro: FLF2V', 'Upload a start frame and end frame, and Seedance 1.5 Pro automatically generates a smooth video transition with synchronized audio between them.', 'image', 'webp', NULL, '[]', '["FLF2V","Image to Video","API"]', '["ByteDance","Seedance"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":4,"nodeType":"LoadImage","file":"dancing_capybara.png","mediaType":"image"},{"nodeId":11,"nodeType":"LoadImage","file":"dj_capybara.png","mediaType":"image"}],"outputs":[{"nodeId":16,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-01-19', 0, 'active', 0, 0, 627, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedace_seedance1_5_flf2v', 'en', 'Seedance 1.5 Pro: FLF2V', 'Upload a start frame and end frame, and Seedance 1.5 Pro automatically generates a smooth video transition with synchronized audio between them.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedace_seedance1_5_flf2v', 'zh', 'Seedance 1.5 Pro: FLF2V', '上传起始帧和结束帧，Seedance 1.5 Pro 会自动在它们之间生成带有同步音频的流畅视频过渡。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedace_seedance1_5_flf2v', 'zh-TW', 'Seedance 1.5 Pro: FLF2V', '上傳起始幀和結束幀，Seedance 1.5 Pro 會自動在它們之間生成帶有同步音訊的流暢影片過渡。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedace_seedance1_5_flf2v', 'ja', 'Seedance 1.5 Pro: FLF2V', '開始フレームと終了フレームをアップロードすると、Seedance 1.5 Pro がそれらの間に同期されたオーディオ付きの滑らかなビデオトランジションを自動生成します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedace_seedance1_5_flf2v', 'ko', 'Seedance 1.5 Pro: FLF2V', '시작 프레임과 종료 프레임을 업로드하면 Seedance 1.5 Pro가 동기화된 오디오를 포함한 부드러운 비디오 전환을 자동으로 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedace_seedance1_5_flf2v', 'es', 'Seedance 1.5 Pro: FLF2V', 'Sube un fotograma inicial y un fotograma final, y Seedance 1.5 Pro genera automáticamente una transición de video fluida con audio sincronizado entre ellos.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedace_seedance1_5_flf2v', 'fr', 'Seedance 1.5 Pro: FLF2V', 'Téléchargez une image de début et une image de fin, et Seedance 1.5 Pro génère automatiquement une transition vidéo fluide avec audio synchronisé entre elles.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedace_seedance1_5_flf2v', 'ru', 'Seedance 1.5 Pro: FLF2V', 'Загрузите начальный и конечный кадры, и Seedance 1.5 Pro автоматически создаст плавный видеопереход с синхронизированным звуком между ними.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedace_seedance1_5_flf2v', 'tr', 'Seedance 1.5 Pro: FLF2V', 'Bir başlangıç karesi ve bitiş karesi yükleyin, Seedance 1.5 Pro aralarında senkronize sesle düzgün bir video geçişi otomatik olarak oluşturur.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedace_seedance1_5_flf2v', 'ar', 'Seedance 1.5 Pro: FLF2V', 'قم بتحميل إطار البداية وإطار النهاية، وسيقوم Seedance 1.5 Pro تلقائيًا بإنشاء انتقال فيديو سلس مع صوت متزامن بينهما.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedace_seedance1_5_flf2v', 'pt-BR', 'Seedance 1.5 Pro: FLF2V', 'Faça upload de um quadro inicial e um quadro final, e o Seedance 1.5 Pro gera automaticamente uma transição de vídeo suave com áudio sincronizado entre eles.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (250, 'api_kling_motion_control', 3, 42, 'Kling2.6: Motion Control', 'Apply precise character actions and expressions from a reference video to your character image with synchronized motion control.', 'image', 'webp', NULL, '[]', '["Video","Motion Control","API"]', '["Kling 2.6","Kling"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":2,"nodeType":"LoadVideo","file":"street_dancer.mp4","mediaType":"video"},{"nodeId":11,"nodeType":"LoadImage","file":"streetwear_fox.jpg","mediaType":"image"}],"outputs":[{"nodeId":9,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-01-12', 0, 'active', 0, 0, 986, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control', 'en', 'Kling2.6: Motion Control', 'Apply precise character actions and expressions from a reference video to your character image with synchronized motion control.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control', 'zh', 'Kling2.6：运动控制', '通过同步运动控制，将参考视频中的精确角色动作和表情应用到您的角色图像上。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control', 'zh-TW', 'Kling2.6：運動控制', '透過同步運動控制，將參考影片中的精確角色動作和表情應用到您的角色圖像上。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control', 'ja', 'Kling2.6：モーションコントロール', '同期モーション制御により、参照動画の正確なキャラクターの動作と表情をあなたのキャラクター画像に適用します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control', 'ko', 'Kling2.6：모션 컨트롤', '동기화된 모션 제어를 통해 참조 영상의 정확한 캐릭터 동작과 표정을 귀하의 캐릭터 이미지에 적용하세요.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control', 'es', 'Kling2.6: Control de Movimiento', 'Aplique acciones y expresiones precisas de personajes desde un video de referencia a su imagen de personaje con control de movimiento sincronizado.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control', 'fr', 'Kling2.6 : Contrôle du Mouvement', 'Appliquez des actions et expressions précises de personnage depuis une vidéo de référence à votre image de personnage avec un contrôle de mouvement synchronisé.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control', 'ru', 'Kling2.6: Управление движением', 'Применяйте точные действия и выражения персонажа из эталонного видео к вашему изображению персонажа с синхронизированным управлением движением.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control', 'tr', 'Kling2.6: Hareket Kontrolü', 'Senkronize hareket kontrolü ile bir referans videosundan alınan kesin karakter hareketlerini ve ifadelerini karakter görselinize uygulayın.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control', 'ar', 'Kling2.6: التحكم في الحركة', 'طبق إجراءات وتعبيرات دقيقة للشخصية من فيديو مرجعي على صورتك الشخصية مع تحكم متزامن في الحركة.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_motion_control', 'pt-BR', 'Kling2.6: Controle de Movimento', 'Aplique ações e expressões precisas de personagem de um vídeo de referência à sua imagem de personagem com controle de movimento sincronizado.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (251, 'api_veo3', 3, 43, 'Veo3: Image to Video', 'Generate high-quality 8-second videos from text prompts or images using Google''s advanced Veo 3 API. Features audio generation, prompt enhancement, and dual model options for speed or quality.', 'image', 'webp', NULL, '[]', '["Image to Video","Text to Video","API"]', '["Veo","Google"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":11,"nodeType":"LoadImage","file":"api_veo3_input_image.png","mediaType":"image"}],"outputs":[{"nodeId":10,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', '', NULL, '2025-03-01', 0, 'active', 0, 0, 629, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_veo3', 'en', 'Veo3: Image to Video', 'Generate high-quality 8-second videos from text prompts or images using Google''s advanced Veo 3 API. Features audio generation, prompt enhancement, and dual model options for speed or quality.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_veo3', 'zh', 'Veo3：图生视频', '使用Google的高级Veo 3 API从文本提示或图像生成高质量8秒视频。具有音频生成、提示增强和速度或质量的双重模型选项。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_veo3', 'zh-TW', 'Veo3：影像到影片', '使用 Google 的進階 Veo 3 API 從文字提示或影像生成高品質 8 秒影片。具備音訊生成、提示增強與速度或品質的雙模型選項。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_veo3', 'ja', 'Veo3: 画像からビデオ', 'Googleの高度なVeo 3 APIを使用して、テキストプロンプトまたは画像から高品質な8秒ビデオを生成します。オーディオ生成、プロンプト強化、速度または品質のためのデュアルモデルオプションを提供します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_veo3', 'ko', 'Veo3: 이미지에서 비디오', 'Google의 고급 Veo 3 API를 사용하여 텍스트 프롬프트나 이미지에서 고품질 8초 비디오를 생성합니다. 오디오 생성, 프롬프트 강화 및 속도나 품질을 위한 이중 모델 옵션을 제공합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_veo3', 'es', 'Veo3: Imagen a video', 'Generar videos de 8 segundos de alta calidad a partir de indicaciones de texto o imágenes usando la API avanzada Veo 3 de Google. Cuenta con generación de audio, mejora de indicaciones y opciones duales de modelo para velocidad o calidad.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_veo3', 'fr', 'Veo3: Image vers Vidéo', 'Generate high-quality 8-second videos from text prompts or images using Google''s advanced Veo 3 API. Features audio generation, prompt enhancement, and dual model options for speed or quality.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_veo3', 'ru', 'Veo3: изображение в видео', 'Генерация видео высокого качества продолжительностью 8 секунд из текстовых запросов или изображений с использованием продвинутого API Google Veo 3. Включает генерацию аудио, улучшение запросов и варианты двойной модели для скорости или качества.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_veo3', 'tr', 'Veo3: Görüntüden Video''ya', 'Google''ın gelişmiş Veo 3 API''sini kullanarak metin istemlerinden veya görüntülerden 8 saniyelik yüksek kaliteli videolar oluşturun. Ses üretimi, istem geliştirme ve hız veya kalite için çift model seçenekleri içerir.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_veo3', 'ar', 'Veo3: من صورة إلى فيديو', 'توليد فيديوهات عالية الجودة بمدة 8 ثوانٍ من مطالبات نصية أو صور باستخدام واجهة Veo 3 المتقدمة من Google. يتضمن توليد الصوت، وتحسين الأوامر، وخيارات نموذج مزدوج للسرعة أو الجودة.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_veo3', 'pt-BR', 'Veo3: Imagem para Vídeo', 'Gere vídeos de alta qualidade de 8 segundos a partir de prompts de texto ou imagens usando a API avançada Veo 3 do Google. Recursos de geração de áudio, aprimoramento de prompt e opções duplas de modelo para velocidade ou qualidade.', 0, NULL, '2026-04-19T13:33:43.920Z');
