INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_i2v', 'ko', 'Vidu Q2: 이미지에서 비디오로', '정적 이미지를 동적 1080p 비디오로 변환합니다. 영화적 카메라 제어와 다중 주제 일관성을 제공합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_i2v', 'es', 'Vidu Q2: Imagen a Video', 'Transforma imágenes estáticas en videos dinámicos 1080p con control de cámara cinematográfico y consistencia multi-sujeto.', 0, NULL, '2026-04-19T13:33:43.920Z');
