INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_i2v', 'ru', 'Vidu Q2: Изображение в видео', 'Преобразуйте статические изображения в динамические видео 1080p с кинематографическим управлением камерой и согласованностью нескольких объектов.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_i2v', 'tr', 'Vidu Q2: Görüntüden Videoya', 'Statik görüntüleri sinematik kamera kontrolü ve çoklu konu tutarlılığı ile dinamik 1080p videolara dönüştürün.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_i2v', 'ar', 'Vidu Q2: من الصورة إلى الفيديو', 'حوّل الصور الثابتة إلى فيديوهات ديناميكية بدقة 1080p مع تحكم كاميرا سينمائي واتساق متعدد المواضيع.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_i2v', 'pt-BR', 'Vidu Q2: Imagem para Vídeo', 'Transforme imagens estáticas em vídeos dinâmicos 1080p com controle de câmera cinematográfico e consistência multi-assunto.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (254, 'video_ltx2_i2v_distilled', 3, 46, 'LTX-2 Image to Video (Distilled)', 'Transform static images into dynamic videos with synchronized audio-video generation using LTX-2 distilled model. Optimized for faster generation while maintaining quality. Features expressive lip sync, natural motion, and improved speed.', 'image', 'webp', NULL, '[]', '["Image to Video","Video"]', '["LTX-2","Lightricks"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":98,"nodeType":"LoadImage","file":"snow_bike_jump_crew.png","mediaType":"image"}],"outputs":[{"nodeId":75,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-01-06', 1, 'active', 38010460570, 38010460570, 364, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_distilled', 'en', 'LTX-2 Image to Video (Distilled)', 'Transform static images into dynamic videos with synchronized audio-video generation using LTX-2 distilled model. Optimized for faster generation while maintaining quality. Features expressive lip sync, natural motion, and improved speed.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_distilled', 'zh', 'LTX-2 图生视频（蒸馏版）', '使用LTX-2蒸馏模型将静态图像变为动态视频，音视频同步。专为快速生成优化，同时保持质量。支持表情口型、自然动作，生成速度更快。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_distilled', 'zh-TW', 'LTX-2 圖轉影片（蒸餾版）', '使用LTX-2蒸餾模型將靜態圖片轉換為動態影片，影音同步。專為快速生成優化，同時保持品質。表情口型自然，動作流暢，生成速度更快。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_distilled', 'ja', 'LTX-2 画像からビデオ（蒸留版）', 'LTX-2蒸留モデルで静止画像を動きのある動画に変換。音声と映像が同期。品質を保ちつつ高速生成に最適化。自然なリップシンクと動き、生成速度が向上。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_distilled', 'ko', 'LTX-2 이미지 투 비디오 (디스틸)', 'LTX-2 디스틸 모델로 정적 이미지를 동영상으로 변환, 오디오-비디오 동기화. 품질 유지하며 빠른 생성에 최적화, 자연스러운 립싱크와 동작, 생성 속도 향상.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_distilled', 'es', 'LTX-2 Imagen a Video (Distilado)', 'Convierte imágenes estáticas en vídeos dinámicos con LTX-2 modelo destilado, audio y vídeo sincronizados. Optimizado para generación más rápida manteniendo calidad. Labios expresivos, movimiento natural y velocidad mejorada.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_distilled', 'fr', 'LTX-2 Image en Vidéo (Distillé)', 'Transformez des images statiques en vidéos dynamiques avec LTX-2 modèle distillé, synchronisation audio/vidéo. Optimisé pour génération rapide tout en maintenant la qualité. Synchronisation labiale expressive, mouvements naturels et vitesse améliorée.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_distilled', 'ru', 'LTX-2 изображение в видео (дистиллят)', 'Преобразуйте статичные изображения в динамичные видео с помощью LTX-2 дистиллированной модели: синхронизация аудио и видео. Оптимизировано для быстрой генерации с сохранением качества. Выразительная синхронизация губ, естественные движения, улучшенная скорость.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_distilled', 'tr', 'LTX-2 Görselden Videoya (Damıtılmış)', 'LTX-2 damıtılmış modeliyle durağan görselleri dinamik videolara çevirin; senkronize ses-görüntü. Kaliteyi korurken hızlı üretim için optimize edilmiş, doğal mimik ve hareketler, hızlandırılmış üretim.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_distilled', 'ar', 'LTX-2 صورة إلى فيديو (مقطر)', 'حوّل الصور الثابتة إلى فيديو ديناميكي باستخدام LTX-2 النموذج المقطر؛ مزامنة الصوت مع الصورة. محسّن للإنشاء السريع مع الحفاظ على الجودة؛ مزامنة شفوية معبرة وحركات طبيعية وسرعة محسّنة.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_i2v_distilled', 'pt-BR', 'LTX-2 Imagem para Vídeo (Destilado)', 'Transforme imagens estáticas em vídeos dinâmicos com LTX-2 modelo destilado, áudio e vídeo sincronizados. Otimizado para geração mais rápida mantendo qualidade, lipsync expressivo, movimento natural e velocidade aprimorada.', 0, NULL, '2026-04-19T13:33:43.920Z');
