INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_pose_to_video', 'en', 'LTX-2 Pose to Video', 'Generate high-quality videos from pose guidance with synchronized audio-video generation using LTX-2. Features precise pose control, expressive motion, and efficient performance.', 0, NULL, '2026-04-19T13:33:43.920Z');
