INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_pose_to_video', 'ko', 'LTX-2 포즈 투 비디오', 'LTX-2로 포즈를 기반으로 고품질 영상을 생성, 오디오-비디오 동기화 및 자연스러운 동작.', 0, NULL, '2026-04-19T13:33:43.920Z');
