INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_pose_to_video', 'fr', 'LTX-2 Pose vers Vidéo', 'Générez des vidéos de haute qualité à partir de poses avec LTX-2 : synchronisation audio-vidéo et mouvements expressifs.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_pose_to_video', 'ru', 'LTX-2 поза в видео', 'Создавайте качественные видео по позе с помощью LTX-2: синхронизация аудио и видео, выразительная мимика, естественные движения.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_pose_to_video', 'tr', 'LTX-2 Pozdan Videoya', 'LTX-2 ile pozdan yüksek kaliteli videolar oluşturun, ses-görüntü senkron ve doğal hareketler.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_pose_to_video', 'ar', 'LTX-2 تحويل وضعية إلى فيديو', 'أنشئ فيديو عالي الجودة من وضعية إرشادية باستخدام LTX-2؛ مزامنة الصوت والصورة وحركات معبرة.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_pose_to_video', 'pt-BR', 'LTX-2 Pose para Vídeo', 'Gere vídeos de alta qualidade a partir de poses com LTX-2, áudio e vídeo sincronizados e movimentos naturais.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (256, 'video_ltx2_t2v_distilled', 3, 48, 'LTX-2 Text to Video (Distilled)', 'Generate high-quality videos from text prompts with synchronized audio-video generation using LTX-2 distilled model. Optimized for faster generation while maintaining quality. Features expressive lip sync, dynamic motion generation, and improved speed.', 'image', 'webp', NULL, '[]', '["Text to Video","Video"]', '["LTX-2","Lightricks"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":104,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-01-06', 1, 'active', 38010460570, 38010460570, 128, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_t2v_distilled', 'en', 'LTX-2 Text to Video (Distilled)', 'Generate high-quality videos from text prompts with synchronized audio-video generation using LTX-2 distilled model. Optimized for faster generation while maintaining quality. Features expressive lip sync, dynamic motion generation, and improved speed.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_t2v_distilled', 'zh', 'LTX-2 文生视频（蒸馏版）', '使用LTX-2蒸馏模型将文本提示生成高质量视频，音视频同步。专为快速生成优化，同时保持质量。支持表情口型、动态动作，生成速度更快。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_t2v_distilled', 'zh-TW', 'LTX-2 文字轉影片（蒸餾版）', '使用LTX-2蒸餾模型將文字提示轉為高品質影片，影音同步。專為快速生成優化，同時保持品質。展現豐富表情與動作，生成速度更快。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_t2v_distilled', 'ja', 'LTX-2 テキストからビデオ（蒸留版）', 'LTX-2蒸留モデルでテキストから高品質なビデオを生成。音声映像同期。品質を保ちつつ高速生成に最適化。豊かなリップシンクと動き、生成速度が向上。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_t2v_distilled', 'ko', 'LTX-2 텍스트 영상 생성 (디스틸)', 'LTX-2 디스틸 모델로 텍스트 프롬프트에서 고화질 영상 생성, 오디오-비디오 동기화. 품질 유지하며 빠른 생성에 최적화, 자연스러운 립싱크와 동작, 생성 속도 향상.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_t2v_distilled', 'es', 'LTX-2 Texto a Video (Distilado)', 'Genera vídeos de alta calidad a partir de texto con LTX-2 modelo destilado, audio sincronizado. Optimizado para generación más rápida manteniendo calidad. Labios expresivos, movimiento dinámico y velocidad mejorada.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_t2v_distilled', 'fr', 'LTX-2 Texte en Vidéo (Distillé)', 'Générez des vidéos de haute qualité à partir de texte avec LTX-2 modèle distillé, audio/vidéo synchronisés. Optimisé pour génération rapide tout en maintenant la qualité. Synchronisation labiale expressive, mouvements dynamiques et vitesse améliorée.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_t2v_distilled', 'ru', 'LTX-2 текст в видео (дистиллят)', 'Создавайте видео высокого качества по тексту с помощью LTX-2 дистиллированной модели: синхронизация аудио и видео. Оптимизировано для быстрой генерации с сохранением качества. Выразительная синхронизация губ, динамичные движения, улучшенная скорость.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_t2v_distilled', 'tr', 'LTX-2 Metinden Videoya (Damıtılmış)', 'LTX-2 damıtılmış modeliyle metinle yüksek kaliteli video üretimi, ses-görüntü senkronizasyonu. Kaliteyi korurken hızlı üretim için optimize edilmiş, doğal mimik, dinamik hareketler ve hızlandırılmış üretim.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_t2v_distilled', 'ar', 'LTX-2 نص إلى فيديو (مقطر)', 'أنشئ فيديوهات عالية الجودة من نص باستخدام LTX-2 النموذج المقطر؛ تزامن الصوت مع الصورة. محسّن للإنشاء السريع مع الحفاظ على الجودة؛ مزامنة شفوية معبرة وحركات ديناميكية وسرعة محسّنة.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_ltx2_t2v_distilled', 'pt-BR', 'LTX-2 Texto para Vídeo (Destilado)', 'Gere vídeos de alta qualidade de texto com LTX-2 modelo destilado, áudio e vídeo sincronizados. Otimizado para geração mais rápida mantendo qualidade, lipsync expressivo, movimento dinâmico e velocidade aprimorada.', 0, NULL, '2026-04-19T13:33:43.920Z');
