INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_i2v', 'en', 'Hunyuan Video 1.5 Image to Video', 'Animate still images into dynamic videos with precise motion and camera control. Maintains visual consistency while bringing photos and illustrations to life with smooth, natural movements.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_i2v', 'zh', 'Hunyuan Video 1.5 图生视频', '将静态图像动画化为动态视频，具备精确的运动与镜头控制。在带来流畅自然动作的同时，还能保持照片和插画的视觉一致性并赋予其生命力。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_i2v', 'zh-TW', 'Hunyuan Video 1.5 圖生視頻', '將靜態圖像動畫化為動態影片，具備精確的動作與鏡頭控制。在帶來流暢自然動作的同時，亦可保持照片與插畫的視覺一致性，賦予其生命力。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_i2v', 'ja', 'Hunyuan Video 1.5 画像から動画へ', '静止画像を正確な動きとカメラ制御でアニメーション化し、ダイナミックな動画に変換します。写真やイラストを滑らかかつ自然な動きで生命を吹き込み、一貫したビジュアルを保ちます。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_i2v', 'ko', 'Hunyuan Video 1.5 이미지 투 비디오', '정확한 동작 및 카메라 제어로 정지 이미지를 생동감 넘치는 동영상으로 애니메이션화합니다. 부드럽고 자연스러운 움직임으로 사진과 일러스트에 생명을 불어넣으며 시각적 일관성을 유지합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_i2v', 'es', 'Hunyuan Video 1.5 Imagen a Video', 'Anima imágenes fijas y conviértelas en videos dinámicos con movimiento preciso y control de cámara. Mantiene la coherencia visual mientras da vida a fotos e ilustraciones con movimientos suaves y naturales.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_i2v', 'fr', 'Hunyuan Video 1.5 Image vers Vidéo', 'Animez des images fixes en vidéos dynamiques avec des mouvements précis et un contrôle de caméra. Préserve la cohérence visuelle tout en donnant vie aux photos et illustrations grâce à des mouvements fluides et naturels.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_i2v', 'ru', 'Hunyuan Video 1.5 Изображение в видео', 'Анимируйте статичные изображения в динамичные видео с точным управлением движением и камерой. Сохраняет визуальную целостность и оживляет фотографии и иллюстрации плавными, естественными движениями.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_i2v', 'tr', 'Hunyuan Video 1.5 Görüntüden Videoya', 'Durağan görselleri hassas hareket ve kamera kontrolüyle dinamik videolara dönüştürün. Fotoğraf ve çizimleri canlı, akıcı ve doğal hareketlerle canlandırırken görsel tutarlılığı korur.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_i2v', 'ar', 'Hunyuan Video 1.5 من صورة إلى فيديو', 'حوّل الصور الثابتة إلى مقاطع فيديو ديناميكية مع حركة دقيقة وتحكم دقيق بالكاميرا. يحافظ على الاتساق البصري بينما يضفي الحيوية على الصور والرسوم التوضيحية بحركات سلسة وطبيعية.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_i2v', 'pt-BR', 'Hunyuan Video 1.5 Imagem para Vídeo', 'Anime imagens estáticas em vídeos dinâmicos com controle preciso de movimento e câmera. Mantém consistência visual enquanto dá vida a fotos e ilustrações com movimentos suaves e naturais.', 0, NULL, '2026-04-19T13:33:43.920Z');
