INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_edit_video', 'zh', 'Kling O1：视频编辑', '支持自然语言指令编辑视频，新增视频参考模式，可快速完成风格转换、元素添加、背景修改等多种高质量视频创作任务。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_edit_video', 'zh-TW', 'Kling O1：影片編輯', '支援自然語言指令編輯影片，新增影片參考模式，可快速完成風格轉換、元素添加、背景修改等多種高品質影片創作任務。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_edit_video', 'ja', 'Kling O1: ビデオ編集', '自然言語コマンドで動画を編集。動画参照モードを搭載し、スタイル変換、要素追加、背景修正などの高品質な動画制作を素早く実現。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_edit_video', 'ko', 'Kling O1: 비디오 편집', '자연어 명령으로 비디오 편집. 비디오 참조 모드로 스타일 전환, 요소 추가, 배경 수정 등 고품질 비디오 제작을 빠르게 완료.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_edit_video', 'es', 'Kling O1: Edición de Video', 'Edita videos con comandos de lenguaje natural, con modo de referencia de video para generar rápidamente transferencias de estilo, adiciones de elementos y modificaciones de fondo de alta calidad.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_edit_video', 'fr', 'Kling O1 : Montage Vidéo', 'Éditez des vidéos avec des commandes en langage naturel, avec un mode de référence vidéo pour générer rapidement des transferts de style, ajouts d''éléments et modifications d''arrière-plan de haute qualité.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_edit_video', 'ru', 'Kling O1: Редактирование видео', 'Редактируйте видео с помощью команд на естественном языке. Режим видеореференса позволяет быстро создавать качественные переносы стиля, добавление элементов и изменение фона.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_edit_video', 'tr', 'Kling O1: Video Düzenleme', 'Doğal dil komutlarıyla video düzenleme. Video referans modu ile stil transferi, öğe ekleme ve arka plan değişikliklerini hızlıca gerçekleştirin.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_edit_video', 'ar', 'Kling O1: تحرير الفيديو', 'حرر الفيديوهات بأوامر اللغة الطبيعية، مع وضع مرجع الفيديو لإنشاء تحويلات الأسلوب وإضافات العناصر وتعديلات الخلفية بجودة عالية بسرعة.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_edit_video', 'pt-BR', 'Kling O1: Edição de Vídeo', 'Edite vídeos com comandos de linguagem natural, apresentando modo de referência de vídeo para geração rápida de transferências de estilo de alta qualidade, adições de elementos e modificações de fundo.', 0, NULL, '2026-04-19T13:33:43.920Z');
