INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_i2v', 'zh', 'Kling O1: 图生视频', '使用 Kling O1 将静态图像转换为动态视频。通过文本提示为图像添加运动、相机移动和生命力。', 0, NULL, '2026-04-19T13:33:43.920Z');
