INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_i2v', 'es', 'Kling O1: Imagen a Video', 'Transforma imágenes estáticas en videos dinámicos con Kling O1. Añade movimiento, movimientos de cámara y vida a tus imágenes usando indicaciones de texto.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_i2v', 'fr', 'Kling O1 : Image vers Vidéo', 'Transformez des images statiques en vidéos dynamiques avec Kling O1. Ajoutez du mouvement, des mouvements de caméra et de la vie à vos images en utilisant des invites texte.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_i2v', 'ru', 'Kling O1: Изображение в видео', 'Преобразуйте статические изображения в динамические видео с помощью Kling O1. Добавьте движение, движения камеры и живость к вашим изображениям, используя текстовые подсказки.', 0, NULL, '2026-04-19T13:33:43.920Z');
