INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_i2v', 'ar', 'Kling O1: من الصورة إلى الفيديو', 'حوّل الصور الثابتة إلى فيديوهات ديناميكية باستخدام Kling O1. أضف الحركة وحركات الكاميرا والحياة إلى صورك باستخدام المطالبات النصية.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_kling_omni_i2v', 'pt-BR', 'Kling O1: Imagem para Vídeo', 'Transforme imagens estáticas em vídeos dinâmicos com Kling O1. Adicione movimento, movimentos de câmera e vida às suas imagens usando prompts de texto.', 0, NULL, '2026-04-19T13:33:43.920Z');
