INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_inpainting', 'ko', 'Wan VACE 인페인트', '주변 콘텐츠를 보존하면서 비디오의 특정 영역을 편집합니다. 객체 제거나 교체에 탁월합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
