INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_flf2v', 'zh-TW', 'ByteDance: 起始結束幀視頻', '使用 ByteDance 的 Seedance 模型生成起始幀和結束幀之間的電影級視頻過渡，具有流暢運動、場景一致性和專業品質。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_flf2v', 'ja', 'ByteDance: 開始終了から動画', 'ByteDanceのSeedanceモデルを使用して、流動的な動き、シーンの一貫性、プロフェッショナルな仕上がりで開始フレームと終了フレーム間の映画的なビデオトランジションを生成します。', 0, NULL, '2026-04-19T13:33:43.920Z');
