INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_flf2v', 'es', 'ByteDance: Inicio-Fin a Video', 'Genera transiciones de video cinematográficas entre fotogramas de inicio y fin con movimiento fluido, consistencia de escena y acabado profesional usando el modelo Seedance de ByteDance.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_flf2v', 'fr', 'ByteDance: Début-Fin vers Vidéo', 'Générez des transitions vidéo cinématographiques entre les images de début et de fin avec un mouvement fluide, une cohérence de scène et une finition professionnelle avec le modèle Seedance de ByteDance.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_flf2v', 'ru', 'ByteDance: Начало-Конец в Видео', 'Генерация кинематографических видеопереходов между начальными и конечными кадрами с плавным движением, согласованностью сцен и профессиональной отделкой с помощью модели Seedance от ByteDance.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_flf2v', 'tr', 'ByteDance: Başlangıç Bitişten Video''ya', 'ByteDance''in Seedance modelini kullanarak akıcı hareket, sahne tutarlılığı ve profesyonel parlatma ile başlangıç ve bitiş kareleri arasında sinematik video geçişleri oluşturun.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_flf2v', 'ar', 'ByteDance: من البداية والنهاية إلى فيديو', 'توليد انتقالات فيديو سينمائية بين إطارات البداية والنهاية مع حركة سلسة واتساق المشهد وبراعة احترافية باستخدام نموذج Seedance من ByteDance.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_flf2v', 'pt-BR', 'ByteDance: Início Fim para Vídeo', 'Gere transições de vídeo cinematográficas entre quadros de início e fim com movimento fluido, consistência de cena e polimento profissional usando o modelo Seedance da ByteDance.', 0, NULL, '2026-04-19T13:33:43.920Z');
