INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_r2v', 'zh', 'Vidu Q2：参考生视频', '生成具有参考一致性的视频，最多支持3个主体，在整个视频序列中保持角色和风格的连续性，并具有电影级相机运动。', 0, NULL, '2026-04-19T13:33:43.920Z');
