INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_r2v', 'ja', 'Vidu Q2：ビデオ参照', '参照ベースの一貫性を持つ動画を生成。最大3つの被写体に対応し、動画シーケンス全体でキャラクターとスタイルの連続性を維持し、映画的なカメラの動きを実現。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_r2v', 'ko', 'Vidu Q2: 비디오 참조', '참조 기반 일관성을 가진 비디오를 생성합니다. 최대 3개의 주제를 지원하며, 비디오 시퀀스 전체에서 캐릭터와 스타일의 연속성을 유지하고 영화적 카메라 움직임을 제공합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_r2v', 'es', 'Vidu Q2: Referencia a video', 'Genera videos con consistencia basada en referencias para hasta 3 sujetos, manteniendo la continuidad de personajes y estilos a lo largo de la secuencia de video con movimientos de cámara cinematográficos.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_r2v', 'fr', 'Vidu Q2 : Référence à la vidéo', 'Générez des vidéos avec une cohérence basée sur des références pour jusqu''à 3 sujets, en maintenant la continuité des personnages et des styles tout au long de la séquence vidéo avec des mouvements de caméra cinématographiques.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_r2v', 'ru', 'Vidu Q2: Ссылка на видео', 'Генерируйте видео с согласованностью на основе ссылок для до 3 субъектов, сохраняя непрерывность персонажей и стилей по всей видеопоследовательности с кинематографическими движениями камеры.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_r2v', 'tr', 'Vidu Q2: Video Referansı', 'En fazla 3 konu için referans tabanlı tutarlılığa sahip videolar oluşturun, sinematik kamera hareketleriyle video dizisi boyunca karakter ve stil sürekliliğini koruyun.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_r2v', 'ar', 'Vidu Q2: إشارة إلى الفيديو', 'أنشئ فيديوهات مع اتساق قائم على المرجع لما يصل إلى 3 مواضيع، مع الحفاظ على استمرارية الشخصية والأسلوب عبر تسلسل الفيديو مع حركات الكاميرا السينمائية.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_q2_r2v', 'pt-BR', 'Vidu Q2: Referência ao vídeo', 'Gere vídeos com consistência baseada em referência para até 3 assuntos, mantendo a continuidade de personagens e estilos em toda a sequência de vídeo com movimentos de câmera cinematográficos.', 0, NULL, '2026-04-19T13:33:43.920Z');
