INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (274, 'api_ltxv_image_to_video', 3, 66, 'LTX-2: Image to Video', 'Transform static images into dynamic videos with LTX-2 Pro. Generate cinematic video sequences with natural motion, synchronized audio, and support for up to 4K resolution at 50fps.', 'image', 'webp', NULL, '[]', '["Image to Video","Video","API"]', '["LTX-2","Lightricks"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":47,"nodeType":"LoadImage","file":"api_ltxv_image_to_video_input_image.png","mediaType":"image"}],"outputs":[{"nodeId":41,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2025-10-28', 0, 'active', 0, 0, 256, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_image_to_video', 'en', 'LTX-2: Image to Video', 'Transform static images into dynamic videos with LTX-2 Pro. Generate cinematic video sequences with natural motion, synchronized audio, and support for up to 4K resolution at 50fps.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_image_to_video', 'zh', 'LTX-2：图生视频', '使用 LTX-2 Pro 将静态图像转化为动态视频。可生成具有自然运动、同步音频且支持最高 4K@50fps 的电影级视频序列。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_image_to_video', 'zh-TW', 'LTX-2：圖像轉影片', '使用 LTX-2 Pro 將靜態圖像轉換為動態影片。可產生具自然運動、同步音訊且支援最高 4K@50fps 的電影級影片序列。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_image_to_video', 'ja', 'LTX-2：画像から動画へ', 'LTX-2 Pro を使って静止画像をダイナミックな動画に変換します。自然な動きと同期オーディオ、最大4K解像度50fps対応のシネマティック動画を生成できます。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_image_to_video', 'ko', 'LTX-2: 이미지→비디오', 'LTX-2 Pro로 정적인 이미지를 생동감 있는 영상으로 변환하세요. 자연스러운 모션과 동기화된 오디오, 최대 4K 50fps를 지원하는 시네마틱 비디오 시퀀스를 생성할 수 있습니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_image_to_video', 'es', 'LTX-2: Imagen a Video', 'Transforma imágenes estáticas en videos dinámicos con LTX-2 Pro. Genera secuencias cinematográficas con movimiento natural, audio sincronizado y soporte de hasta 4K y 50fps.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_image_to_video', 'fr', 'LTX-2 : Image vers Vidéo', 'Transformez des images statiques en vidéos dynamiques avec LTX-2 Pro. Générez des séquences cinématographiques avec mouvement naturel, audio synchronisé et prise en charge jusqu''à 4K à 50 ips.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_image_to_video', 'ru', 'LTX-2: Изображение в видео', 'Преобразуйте статичные изображения в динамичные видео с помощью LTX-2 Pro. Создавайте кинематографические видеоролики с естественным движением, синхронизированным звуком и поддержкой до 4K при 50 к/с.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_image_to_video', 'tr', 'LTX-2: Görüntüden Videoya', 'LTX-2 Pro ile durağan görselleri dinamik videolara dönüştürün. Doğal hareket, senkronize ses ve 4K 50fps''ye kadar destekle sinematik video dizileri oluşturun.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_image_to_video', 'ar', 'LTX-2: من صورة إلى فيديو', 'حوّل الصور الثابتة إلى مقاطع فيديو ديناميكية باستخدام LTX-2 Pro. أنشئ تسلسلات فيديو سينمائية بحركة طبيعية وصوت متزامن ودعم حتى دقة 4K بمعدل 50 إطارًا في الثانية.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_image_to_video', 'pt-BR', 'LTX-2: Imagem para Vídeo', 'Transforme imagens estáticas em vídeos dinâmicos com LTX-2 Pro. Gere sequências de vídeo cinematográficas com movimento natural, áudio sincronizado e suporte para até resolução 4K a 50fps.', 0, NULL, '2026-04-19T13:33:43.920Z');
