INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_t2v', 'ko', 'Wan2.5: 텍스트에서 비디오', '동기화된 오디오, 향상된 모션 및 우수한 품질의 비디오를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
