INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_t2v', 'fr', 'Wan2.5: Texte vers Vidéo', 'Générez des vidéos avec audio synchronisé, mouvement amélioré et qualité supérieure.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_t2v', 'ru', 'Wan2.5: Текст в Видео', 'Генерация видео с синхронизированным аудио, улучшенным движением и превосходным качеством.', 0, NULL, '2026-04-19T13:33:43.920Z');
