INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wan2_6_t2v', 'ar', 'Wan2.5: من نص إلى فيديو', 'توليد فيديوهات مع صوت متزامن، وحركة محسّنة، وجودة فائقة.', 0, NULL, '2026-04-19T13:33:43.920Z');
