INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (279, 'video_hunyuan_video_1.5_720p_t2v', 3, 71, 'Hunyuan Video 1.5 Text to Video', 'Generate high-quality 720p videos from text prompts with cinematic camera control, emotional expressions, and physics simulation. Supports multiple styles including realistic, anime, and 3D with text rendering.', 'image', 'webp', NULL, '["output/video_hunyuan_video_1.5_720p_t2v.mp4"]', '["Text to Video","Video"]', '["Hunyuan Video"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":102,"nodeType":"SaveVideo","file":"video_hunyuan_video_1.5_720p_t2v.mp4","mediaType":"video"},{"nodeId":118,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2025-11-21', 1, 'active', 45419279155, 45419279155, 60, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_t2v', 'en', 'Hunyuan Video 1.5 Text to Video', 'Generate high-quality 720p videos from text prompts with cinematic camera control, emotional expressions, and physics simulation. Supports multiple styles including realistic, anime, and 3D with text rendering.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_t2v', 'zh', 'Hunyuan Video 1.5 文生视频', '由文本提示生成高质量 720p 视频，具备电影级镜头控制、情感表达和物理仿真。支持多种风格，包括写实、动漫和 3D 文字渲染。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_t2v', 'zh-TW', 'Hunyuan Video 1.5 文生視頻', '由文字提示生成高品質 720p 影片，具備電影級鏡頭控制、情感表現及物理模擬。支援多種風格，包括寫實、動漫與 3D 文字渲染。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_t2v', 'ja', 'Hunyuan Video 1.5 テキストからビデオへ', 'テキストプロンプトから高品質な720pビデオを生成します。映画のようなカメラ制御、感情表現、物理シミュレーションに対応。リアル、アニメ、3Dのテキストレンダリングなど複数のスタイルをサポートします。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_t2v', 'ko', 'Hunyuan Video 1.5 텍스트 투 비디오', '텍스트 프롬프트로 고화질 720p 영상을 생성하며, 시네마틱 카메라 제어, 감정 표현, 물리 시뮬레이션을 지원합니다. 사실적, 애니메이션, 3D 텍스트 렌더링 등 다양한 스타일을 제공합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_t2v', 'es', 'Hunyuan Video 1.5 Texto a Video', 'Genera vídeos 720p de alta calidad a partir de indicaciones de texto, con control cinematográfico de cámara, expresiones emocionales y simulación física. Soporta varios estilos, incluyendo realista, anime y renderizado de texto 3D.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_t2v', 'fr', 'Hunyuan Video 1.5 Texte en vidéo', 'Générez des vidéos 720p de haute qualité à partir de prompts textuels, avec un contrôle cinématographique de la caméra, des expressions émotionnelles et une simulation physique. Prend en charge plusieurs styles dont réaliste, anime et rendu 3D du texte.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_t2v', 'ru', 'Hunyuan Video 1.5 Текст в видео', 'Генерируйте высококачественное 720p видео по текстовым подсказкам с кинематографическим управлением камерой, эмоциональной мимикой и физическим моделированием. Поддерживаются различные стили: реализм, аниме и 3D-рендеринг текста.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_t2v', 'tr', 'Hunyuan Video 1.5 Metinden Videoya', 'Metin girdilerinden yüksek kaliteli 720p videolar oluşturur. Sinematik kamera kontrolü, duygusal ifadeler ve fizik simülasyonu sağlar. Gerçekçi, anime ve 3B metin render gibi çeşitli stilleri destekler.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_t2v', 'ar', 'Hunyuan Video 1.5 تحويل النص إلى فيديو', 'إنشاء مقاطع فيديو عالية الجودة بدقة 720p من مطالبات نصية مع تحكم سينمائي بالكاميرا وتعبيرات عاطفية ومحاكاة فيزيائية. يدعم أنماطًا متعددة مثل الواقعي والأنمي وتصوير النص ثلاثي الأبعاد.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_hunyuan_video_1.5_720p_t2v', 'pt-BR', 'Hunyuan Video 1.5 Texto para Vídeo', 'Gere vídeos 720p de alta qualidade a partir de prompts de texto com controle de câmera cinematográfica, expressões emocionais e simulação física. Suporta múltiplos estilos incluindo realista, anime e 3D com renderização de texto.', 0, NULL, '2026-04-19T13:33:43.920Z');
