INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_ref2v', 'ko', 'Wan VACE 참조에서 비디오', '참조 이미지의 스타일과 내용과 일치하는 비디오를 생성합니다. 스타일 일관성 있는 비디오 생성에 완벽합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_ref2v', 'es', 'Referencia a video Wan VACE', 'Crear videos que coincidan con el estilo y contenido de una imagen de referencia. Perfecto para generación de video consistente en estilo.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_ref2v', 'fr', 'Wan VACE Reference to Video', 'Créer des vidéos qui correspondent au style et au contenu d''une image de référence. Parfait pour la génération de vidéos cohérentes en style.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_ref2v', 'ru', 'Wan VACE Reference в видео', 'Создание видео, соответствующих стилю и содержанию опорного изображения. Идеально подходит для генерации видео с согласованным стилем.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_ref2v', 'tr', 'Wan2.1 VACE Referanstan Video''ya', 'Bir referans görüntüsünün stilini ve içeriğini eşleştiren videolar oluşturun. Stil tutarlı video üretimi için idealdir.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_ref2v', 'ar', 'Wan2.1 VACE صورة مرجعية إلى فيديو', 'إنشاء فيديوهات تتطابق مع نمط ومحتوى صورة مرجعية. مثالي لتوليد فيديوهات بنمط متسق.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan_vace_14B_ref2v', 'pt-BR', 'Wan2.1 VACE Referência para Vídeo', 'Crie vídeos que correspondem ao estilo e conteúdo de uma imagem de referência. Perfeito para geração de vídeo com estilo consistente.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (282, 'video_wan2_1_infinitetalk', 3, 74, 'InfiniteTalk: Audio-Driven Full-Body Video Dubbing', 'Upload a source Image and target audio. Generate a full-body dubbed video with synchronized motion while preserving the original identity, background, and camera movement.', 'image', 'webp', NULL, '[]', '["Audio to Video","Lip Sync","Video"]', '["Wan2.1 InfiniteTalk"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":24,"nodeType":"LoadAudio","file":"audio_speaker1_woman.mp3","mediaType":"audio"},{"nodeId":32,"nodeType":"LoadImage","file":"two_character_talking.png","mediaType":"image"},{"nodeId":90,"nodeType":"LoadAudio","file":"audio_speaker2_man.mp3","mediaType":"audio"}],"outputs":[{"nodeId":162,"nodeType":"SaveVideo","file":"","mediaType":"video"},{"nodeId":141,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-01-26', 1, 'active', 29635274342, 29635274342, 188, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_1_infinitetalk', 'en', 'InfiniteTalk: Audio-Driven Full-Body Video Dubbing', 'Upload a source Image and target audio. Generate a full-body dubbed video with synchronized motion while preserving the original identity, background, and camera movement.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_1_infinitetalk', 'zh', 'InfiniteTalk：音频驱动的全身视频配音', '上传源图像和目标音频。生成全身配音视频，同步动作，同时保留原始身份、背景和摄像机运动。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_1_infinitetalk', 'zh-TW', 'InfiniteTalk：音訊驅動的全身影片配音', '上傳源圖像和目標音訊。生成全身配音影片，同步動作，同時保留原始身份、背景和攝影機運動。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_1_infinitetalk', 'ja', 'InfiniteTalk：オーディオ駆動の全身ビデオダビング', 'ソース画像とターゲットオーディオをアップロードしてください。全身の吹き替え動画を生成し、同期した動きを実現しながら、元のアイデンティティ、背景、カメラの動きを保持します。', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_1_infinitetalk', 'ko', 'InfiniteTalk: 오디오 기반 전신 비디오 더빙', '소스 이미지와 대상 오디오를 업로드하세요. 원래의 신원, 배경, 카메라 움직임을 유지하면서 동기화된 동작으로 전신 더빙 비디오를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_1_infinitetalk', 'es', 'InfiniteTalk: Doblaje de video corporal completo impulsado por audio', 'Sube una imagen de origen y un audio objetivo. Genera un video doblado de cuerpo completo con movimiento sincronizado, preservando la identidad original, el fondo y el movimiento de la cámara.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_1_infinitetalk', 'fr', 'InfiniteTalk : Doublage vidéo corporel complet piloté par l''audio', 'Téléchargez une image source et un audio cible. Générez une vidéo doublée en plan large avec un mouvement synchronisé, tout en préservant l''identité originale, l''arrière-plan et le mouvement de la caméra.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_1_infinitetalk', 'ru', 'InfiniteTalk: Полное озвучивание видео тела на основе аудио', 'Загрузите исходное изображение и целевое аудио. Создайте полнометражное дублированное видео с синхронизированным движением, сохраняя оригинальную идентичность, фон и движение камеры.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_1_infinitetalk', 'tr', 'InfiniteTalk: Ses Tabanlı Tam Vücut Video Dublajı', 'Bir kaynak görsel ve hedef ses yükleyin. Orijinal kimliği, arka planı ve kamera hareketini korurken senkronize hareketle tam vücut dublajlı bir video oluşturun.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_1_infinitetalk', 'ar', 'InfiniteTalk: دبلجة الفيديو الكامل للجسم مدفوعة بالصوت', 'قم بتحميل صورة مصدر وصوت مستهدف. أنشئ فيديو مدبلجًا للجسم بالكامل بحركة متزامنة مع الحفاظ على الهوية الأصلية والخلفية وحركة الكاميرا.', 0, NULL, '2026-04-19T13:33:43.920Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_wan2_1_infinitetalk', 'pt-BR', 'InfiniteTalk: Dublagem de Vídeo Corporal Completo Acionada por Áudio', 'Faça upload de uma imagem de origem e um áudio alvo. Gere um vídeo dublado de corpo inteiro com movimento sincronizado, preservando a identidade original, o plano de fundo e o movimento da câmera.', 0, NULL, '2026-04-19T13:33:43.920Z');
