INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_video_edit', 'en', 'Capybara: Video Edit', 'Upload an image or video and a text instruction to perform generation or editing tasks. Generate a new or edited image or video based on the provided instruction.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_video_edit', 'zh', 'Capybara：视频编辑', '上传图像或视频及文本指令以执行生成或编辑任务。根据提供的指令生成新的或编辑后的图像或视频。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_video_edit', 'zh-TW', 'Capybara：影片編輯', '上傳圖像或影片及文字指令以執行生成或編輯任務。根據提供的指令生成新的或編輯後的圖像或影片。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_video_edit', 'ja', 'Capybara：ビデオ編集', '画像または動画とテキスト指示をアップロードして、生成または編集タスクを実行します。提供された指示に基づいて、新しいまたは編集された画像または動画を生成します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_video_edit', 'ko', 'Capybara：비디오 편집', '이미지 또는 비디오와 텍스트 지침을 업로드하여 생성 또는 편집 작업을 수행합니다. 제공된 지침에 따라 새롭거나 편집된 이미지 또는 비디오를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_video_edit', 'es', 'Capybara: Edición de video', 'Sube una imagen o video y una instrucción de texto para realizar tareas de generación o edición. Genera una imagen o video nuevo o editado basado en la instrucción proporcionada.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_video_edit', 'fr', 'Capybara : Édition vidéo', 'Téléchargez une image ou une vidéo et une instruction textuelle pour effectuer des tâches de génération ou d''édition. Générez une image ou une vidéo nouvelle ou éditée basée sur l''instruction fournie.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_video_edit', 'ru', 'Capybara: Редактирование видео', 'Загрузите изображение или видео и текстовую инструкцию для выполнения задач генерации или редактирования. Создайте новое или отредактированное изображение или видео на основе предоставленной инструкции.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_video_edit', 'tr', 'Capybara: Video Düzenleme', 'Oluşturma veya düzenleme görevlerini gerçekleştirmek için bir görsel veya video ve bir metin talimatı yükleyin. Sağlanan talimata dayalı olarak yeni veya düzenlenmiş bir görsel veya video oluşturun.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_video_edit', 'ar', 'Capybara: تحرير الفيديو', 'قم بتحميل صورة أو فيديو وتعليمات نصية لأداء مهام التوليد أو التحرير. قم بإنشاء صورة أو فيديو جديد أو محرر بناءً على التعليمات المقدمة.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_video_edit', 'pt-BR', 'Capybara: Edição de Vídeo', 'Faça upload de uma imagem ou vídeo e uma instrução de texto para realizar tarefas de geração ou edição. Gere uma imagem ou vídeo novo ou editado com base na instrução fornecida.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (306, 'video_capybara_v0_1_image_to_video', 3, 98, 'Capybara: Image to Video', 'Upload an image and provide a text instruction. Generate a new video where the input is edited according to your instruction, preserving structure and temporal coherence.', 'image', 'webp', NULL, '["output/video_capybara_v0_1_image_to_video.mp4"]', '["Video","Image to Video"]', '["Capybara"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":126,"nodeType":"LoadImage","file":"joy_snap.png","mediaType":"image"}],"outputs":[{"nodeId":114,"nodeType":"SaveVideo","file":"video_capybara_v0_1_image_to_video.mp4","mediaType":"video"}]}', NULL, NULL, '2026-02-23', 1, 'active', 37044092928, 37044092928, 162, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_image_to_video', 'en', 'Capybara: Image to Video', 'Upload an image and provide a text instruction. Generate a new video where the input is edited according to your instruction, preserving structure and temporal coherence.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_image_to_video', 'zh', 'Capybara：图生视频', '上传一张图片并提供文字指令。生成一个新视频，其中输入内容会根据您的指令进行编辑，同时保持结构和时间连贯性。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_image_to_video', 'zh-TW', 'Capybara：圖像轉影片', '上傳一張圖片並提供文字指令。生成一個新影片，其中輸入內容會根據您的指令進行編輯，同時保持結構和時間連貫性。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_image_to_video', 'ja', 'Capybara：画像から動画へ', '画像をアップロードし、テキスト指示を入力してください。入力内容が指示に従って編集され、構造と時間的一貫性を保ちながら新しい動画を生成します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_image_to_video', 'ko', 'Capybara：이미지에서 비디오로', '이미지를 업로드하고 텍스트 지시를 제공하세요. 입력 내용이 지시에 따라 편집되며 구조와 시간적 일관성을 유지한 새로운 동영상을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_image_to_video', 'es', 'Capybara: Imagen a video', 'Sube una imagen y proporciona una instrucción de texto. Genera un nuevo video donde la entrada se edita según tu instrucción, preservando la estructura y la coherencia temporal.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_image_to_video', 'fr', 'Capybara : Image vers vidéo', 'Téléchargez une image et fournissez une instruction textuelle. Générez une nouvelle vidéo où l''entrée est modifiée selon votre instruction, en préservant la structure et la cohérence temporelle.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_image_to_video', 'ru', 'Capybara: Изображение в видео', 'Загрузите изображение и предоставьте текстовую инструкцию. Создайте новое видео, в котором входные данные редактируются в соответствии с вашей инструкцией, сохраняя структуру и временную согласованность.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_image_to_video', 'tr', 'Capybara: Görüntüden Videoya', 'Bir görsel yükleyin ve bir metin talimatı sağlayın. Girdinin talimatınıza göre düzenlendiği, yapıyı ve zamansal tutarlılığı koruyan yeni bir video oluşturun.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_image_to_video', 'ar', 'Capybara: صورة إلى فيديو', 'قم بتحميل صورة وقدم تعليمات نصية. قم بإنشاء فيديو جديد حيث يتم تحرير المدخلات وفقًا لتعليماتك، مع الحفاظ على الهيكل والتماسك الزمني.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('video_capybara_v0_1_image_to_video', 'pt-BR', 'Capybara: Imagem para Vídeo', 'Faça upload de uma imagem e forneça uma instrução de texto. Gere um novo vídeo onde a entrada é editada de acordo com sua instrução, preservando a estrutura e a coerência temporal.', 0, NULL, '2026-04-19T13:33:43.921Z');
