INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (316, 'api_ltxv_text_to_video', 3, 108, 'LTX-2: Text to Video', 'Generate high-quality videos from text prompts using Lightricks LTX-2 with synchronized audio. Supports up to 4K resolution at 50fps with Fast, Pro, and Ultra modes for various production needs.', 'image', 'webp', NULL, '[]', '["Text to Video","Video","API"]', '["LTX-2","Lightricks"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":27,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2025-10-28', 0, 'active', 0, 0, 196, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_text_to_video', 'en', 'LTX-2: Text to Video', 'Generate high-quality videos from text prompts using Lightricks LTX-2 with synchronized audio. Supports up to 4K resolution at 50fps with Fast, Pro, and Ultra modes for various production needs.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_text_to_video', 'zh', 'LTX-2：文生视频', '使用Lightricks LTX-2和同步音频，根据文本提示生成高质量视频。支持最高4K分辨率和50帧/秒，满足快速、专业和超高清等多种制作需求。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_text_to_video', 'zh-TW', 'LTX-2：文字轉影片', '使用Lightricks LTX-2與同步音訊，根據文字提示生成高品質影片。支援最高4K解析度與50fps，適合快速、專業和超高等多種製作需求。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_text_to_video', 'ja', 'LTX-2：テキストからビデオへ', 'Lightricks LTX-2と同期オーディオを使い、テキストプロンプトから高品質な動画を生成します。最大4K解像度・50fps対応で、ファスト・プロ・ウルトラ各モードにより様々な制作ニーズに応えます。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_text_to_video', 'ko', 'LTX-2: 텍스트를 비디오로', 'Lightricks LTX-2와 동기화된 오디오를 사용하여 텍스트 프롬프트로 고품질 영상을 생성합니다. Fast, Pro, Ultra 모드로 다양한 제작 요구에 맞춰 최대 4K 해상도, 50fps를 지원합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_text_to_video', 'es', 'LTX-2: Texto a vídeo', 'Genera vídeos de alta calidad a partir de indicaciones de texto usando Lightricks LTX-2 con audio sincronizado. Soporta hasta 4K de resolución a 50fps con modos Rápido, Pro y Ultra para diversas necesidades de producción.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_text_to_video', 'fr', 'LTX-2 : Texte en vidéo', 'Générez des vidéos de haute qualité à partir de suggestions textuelles avec Lightricks LTX-2 et audio synchronisé. Prise en charge jusqu''à 4K à 50fps avec les modes Rapide, Pro et Ultra pour divers besoins de production.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_text_to_video', 'ru', 'LTX-2: текст в видео', 'Создавайте высококачественные видео по текстовым подсказкам с использованием Lightricks LTX-2 и синхронизированного аудио. Поддерживается до 4K при 50 кадрах/с с режимами Fast, Pro и Ultra для различных производственных задач.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_text_to_video', 'tr', 'LTX-2: Metinden videoya', 'Lightricks LTX-2 ve senkronize ses kullanarak metin girdilerinden yüksek kaliteli videolar oluşturun. Farklı prodüksiyon ihtiyaçlarına yönelik Hızlı, Pro ve Ultra modlarıyla 4K çözünürlükte ve 50fps''ye kadar destekler.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_text_to_video', 'ar', 'LTX-2: تحويل النص إلى فيديو', 'أنشئ مقاطع فيديو عالية الجودة من مطالبات نصية باستخدام Lightricks LTX-2 مع صوت متزامن. يدعم دقة تصل إلى 4K بمعدل 50 إطارًا في الثانية مع أوضاع سريع، احترافي وفائق لتلبية مختلف احتياجات الإنتاج.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_ltxv_text_to_video', 'pt-BR', 'LTX-2: Texto para Vídeo', 'Gere vídeos de alta qualidade a partir de prompts de texto usando Lightricks LTX-2 com áudio sincronizado. Suporta até resolução 4K a 50fps com modos Fast, Pro e Ultra para várias necessidades de produção.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (317, 'api_vidu_text_to_video', 3, 109, 'Vidu Q1: Text to Video', 'Generate high-quality 1080p videos from text prompts with adjustable movement amplitude and duration control using Vidu''s advanced AI model.', 'image', 'webp', NULL, '[]', '["Text to Video","Video","API"]', '["Vidu Q1","Vidu"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":14,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', '', NULL, '2025-08-23', 0, 'active', 0, 0, 6, 0, 'ComfyUI', 1, 1, datetime('now'));
