INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_text_to_video', 'zh', 'Vidu Q1：文生视频', '使用Vidu的高级AI模型，通过可调节的运动幅度和持续时间控制，从文本提示生成高质量1080p视频。', 0, NULL, '2026-04-19T13:33:43.921Z');
