INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_text_to_video', 'fr', 'Vidu Q1 : Texte en Vidéo', 'Générer des vidéos 1080p de haute qualité à partir de prompts textuels avec un contrôle ajustable de l''amplitude des mouvements et de la durée en utilisant le modèle AI avancé de Vidu.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_text_to_video', 'ru', 'Vidu Q1: Текст в Видео', 'Генерация видео высокого качества 1080p по текстовым запросам с регулируемой амплитудой движения и управлением продолжительностью с использованием продвинутой ИИ-модели Vidu.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_text_to_video', 'tr', 'Vidu Q1: Metinden Videoya', 'Vidu''nun gelişmiş AI modelini kullanarak ayarlanabilir hareket genliği ve süre kontrollü metin istemlerinden 1080p yüksek kaliteli videolar oluşturun.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_text_to_video', 'ar', 'Vidu Q1: نص إلى فيديو', 'توليد فيديوهات عالية الجودة بدقة 1080p من مطالبات نصية مع سعة حركة قابلة للتعديل والتحكم بالمدة باستخدام نموذج Vidu المتقدم.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_text_to_video', 'pt-BR', 'Vidu Q1: Texto para Vídeo', 'Gere vídeos 1080p de alta qualidade a partir de prompts de texto com amplitude de movimento ajustável e controle de duração usando o modelo avançado de IA da Vidu.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (318, 'api_bytedance_text_to_video', 3, 110, 'Seedance1.0 Pro: Text to Video', 'Generate high-quality videos directly from text prompts using ByteDance''s Seedance model. Supports multiple resolutions and aspect ratios with natural motion and cinematic quality.', 'image', 'webp', NULL, '[]', '["Video","API","Text to Video"]', '["Seedance1.0 Pro","ByteDance"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":7,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', '', NULL, '2025-10-06', 0, 'active', 0, 0, 56, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_text_to_video', 'en', 'Seedance1.0 Pro: Text to Video', 'Generate high-quality videos directly from text prompts using ByteDance''s Seedance model. Supports multiple resolutions and aspect ratios with natural motion and cinematic quality.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_text_to_video', 'zh', 'ByteDance: 文生视频', '使用 ByteDance 的 Seedance 模型直接从文本提示生成高质量视频。支持多种分辨率和宽高比，具有自然运动和电影级质量。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_text_to_video', 'zh-TW', 'ByteDance: 文生視頻', '使用 ByteDance 的 Seedance 模型直接從文本提示生成高質量視頻。支持多種分辨率和寬高比，具有自然運動和電影質量。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_text_to_video', 'ja', 'ByteDance: テキストから動画', 'ByteDanceのSeedanceモデルを使用してテキストプロンプトから直接高品質ビデオを生成します。自然な動きと映画的な品質で複数の解像度とアスペクト比をサポートします。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_text_to_video', 'ko', 'ByteDance: 텍스트에서 비디오', 'ByteDance의 Seedance 모델을 사용하여 텍스트 프롬프트에서 직접 고품질 비디오를 생성합니다. 자연스러운 모션과 영화적 품질로 여러 해상도 및 종횡비를 지원합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_text_to_video', 'es', 'ByteDance: Texto a Video', 'Genera videos de alta calidad directamente desde prompts de texto usando el modelo Seedance de ByteDance. Compatible con múltiples resoluciones y relaciones de aspecto con movimiento natural y calidad cinematográfica.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_text_to_video', 'fr', 'ByteDance: Texte vers Vidéo', 'Générez des vidéos de haute qualité directement à partir de prompts textuels avec le modèle Seedance de ByteDance. Prend en charge plusieurs résolutions et ratios d''aspect avec un mouvement naturel et une qualité cinématographique.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_text_to_video', 'ru', 'ByteDance: Текст в Видео', 'Генерация высококачественных видео напрямую из текстовых промптов с помощью модели Seedance от ByteDance. Поддержка множества разрешений и соотношений сторон с естественным движением и кинематографическим качеством.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_text_to_video', 'tr', 'ByteDance: Metinden Video''ya', 'ByteDance''in Seedance modelini kullanarak doğrudan metin istemlerinden yüksek kaliteli videolar oluşturun. Doğal hareket ve sinematik kaliteyle birden fazla çözünürlük ve en boy oranlarını destekler.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_text_to_video', 'ar', 'ByteDance: من نص إلى فيديو', 'توليد فيديوهات عالية الجودة مباشرة من مطالبات نصية باستخدام نموذج Seedance من ByteDance. يدعم دقات متعددة ونسب عرض إلى ارتفاع مع حركة طبيعية وجودة سينمائية.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bytedance_text_to_video', 'pt-BR', 'ByteDance: Texto para Vídeo', 'Gere vídeos de alta qualidade diretamente a partir de prompts de texto usando o modelo Seedance da ByteDance. Suporta múltiplas resoluções e proporções com movimento natural e qualidade cinematográfica.', 0, NULL, '2026-04-19T13:33:43.921Z');
