INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_image_to_video', 'zh', 'Vidu Q1：图生视频', '使用Vidu将静态图像转换为具有精确运动控制和可定制运动幅度的动态1080p视频。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_image_to_video', 'zh-TW', 'Vidu Q1：圖生影片', '使用 Vidu 將靜態影像轉換為具有精確運動控制與可自訂運動幅度的動態 1080p 影片。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_image_to_video', 'ja', 'Vidu Q1：画像から動画へ', 'Viduを使用して、静止画像を正確なモーション制御とカスタマイズ可能な動きの振幅でダイナミックな1080pビデオに変換します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_image_to_video', 'ko', 'Vidu Q1: 이미지에서 비디오로', 'Vidu를 사용하여 정적 이미지를 정밀한 모션 제어와 사용자 정의 가능한 움직임 진폭으로 동적 1080p 비디오로 변환합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_image_to_video', 'es', 'Vidu Q1: De imagen a video', 'Transformar imágenes estáticas en videos 1080p dinámicos con control de movimiento preciso y amplitud de movimiento personalizable usando Vidu.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_image_to_video', 'fr', 'Vidu Q1 : De l''image à la vidéo', 'Transformer des images statiques en vidéos 1080p dynamiques avec un contrôle précis du mouvement et une amplitude de mouvement personnalisable en utilisant Vidu.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_image_to_video', 'ru', 'Vidu Q1: Изображение в видео', 'Преобразование статических изображений в динамические видео 1080p с точным управлением движением и настраиваемой амплитудой движения с использованием Vidu.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_image_to_video', 'tr', 'Vidu Q1: Görüntüden Videoya', 'Vidu kullanarak hassas hareket kontrolü ve özelleştirilebilir hareket genliği ile statik görüntüleri dinamik 1080p videolara dönüştürün.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_image_to_video', 'ar', 'Vidu Q1: من صورة إلى فيديو', 'تحويل الصور الثابتة إلى فيديوهات ديناميكية بدقة 1080p مع تحكم دقيق بالحركة وسعة حركة قابلة للتخصيص باستخدام Vidu.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_image_to_video', 'pt-BR', 'Vidu Q1: Imagem para Vídeo', 'Transforme imagens estáticas em vídeos dinâmicos 1080p com controle preciso de movimento e amplitude de movimento personalizável usando Vidu.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (320, 'api_hailuo_minimax_t2v', 3, 112, 'MiniMax: Text to Video', 'Generate high-quality videos directly from text prompts. Explore MiniMax''s advanced AI capabilities to create diverse visual narratives with professional CGI effects and stylistic elements to bring your descriptions to life.', 'image', 'webp', NULL, '[]', '["Text to Video","Video","API"]', '["MiniMax"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":8,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', '', NULL, '2025-03-01', 0, 'active', 0, 0, 10, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_t2v', 'en', 'MiniMax: Text to Video', 'Generate high-quality videos directly from text prompts. Explore MiniMax''s advanced AI capabilities to create diverse visual narratives with professional CGI effects and stylistic elements to bring your descriptions to life.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_t2v', 'zh', 'MiniMax：文生视频', '直接从文本提示生成高质量视频。探索MiniMax的高级AI功能，利用专业CGI效果和风格元素创建多样化的视觉叙事，让您的描述生动起来。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_t2v', 'zh-TW', 'MiniMax：文字到影片', '直接從文字提示生成高品質影片。探索 MiniMax 的進階 AI 功能，利用專業 CGI 效果與風格元素建立多樣化的視覺敘事，讓您的描述生動起來。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_t2v', 'ja', 'MiniMax: テキストからビデオ', 'テキストプロンプトから直接高品質なビデオを生成します。MiniMaxの高度なAI機能を探索して、プロフェッショナルなCGI効果とスタイル要素で多様な視覚的ナラティブを作成し、説明を生き生きとさせます。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_t2v', 'ko', 'MiniMax: 텍스트에서 비디오', '직접 텍스트 프롬프트에서 고품질 비디오를 생성합니다. MiniMax의 고급 AI 기능을 탐색하여 전문 CGI 효과와 스타일 요소로 다양한 시각적 내러티브를 생성하여 설명을 생생하게 만듭니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_t2v', 'es', 'MiniMax: Texto a video', 'Generar videos de alta calidad directamente a partir de indicaciones de texto. Explorar las capacidades avanzadas de IA de MiniMax para crear narrativas visuales diversas con efectos CGI profesionales y elementos estilísticos que den vida a sus descripciones.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_t2v', 'fr', 'MiniMax: Texte vers Vidéo', 'Generate high-quality videos directly from text prompts. Explore MiniMax''s advanced AI capabilities to create diverse visual narratives with professional CGI effects and stylistic elements to bring your descriptions to life.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_t2v', 'ru', 'MiniMax: текст в видео', 'Генерация видео высокого качества непосредственно из текстовых запросов. Изучите расширенные возможности ИИ MiniMax для создания разнообразных визуальных нарративов с профессиональными эффектами CGI и стилистическими элементами, чтобы оживить ваши описания.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_t2v', 'tr', 'MiniMax: Metinden Video''ya', 'Doğrudan metin istemlerinden yüksek kaliteli videolar oluşturun. Açıklamalarınızı hayata geçirmek için MiniMax''ın gelişmiş AI yeteneklerini keşfedin.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_t2v', 'ar', 'MiniMax: من نص إلى فيديو', 'توليد فيديوهات عالية الجودة مباشرة من مطالبات نصية. اكتشف قدرات الذكاء الاصطناعي المتقدمة من MiniMax لإنشاء سرديات بصرية متنوعة مع تأثيرات CGI احترافية وعناصر أسلوبية لإحياء أوصافك.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_t2v', 'pt-BR', 'MiniMax: Texto para Vídeo', 'Gere vídeos de alta qualidade diretamente a partir de prompts de texto. Explore as capacidades avançadas de IA da MiniMax para criar narrativas visuais diversas com efeitos CGI profissionais e elementos estilísticos para dar vida às suas descrições.', 0, NULL, '2026-04-19T13:33:43.921Z');
