INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (323, 'api_hailuo_minimax_video', 3, 115, 'MiniMax: Video', 'Generate high-quality videos from text prompts with optional first-frame control using MiniMax Hailuo-02 model. Supports multiple resolutions (768P/1080P) and durations (6/10s) with intelligent prompt optimization.', 'image', 'webp', NULL, '["output/api_hailuo_minimax_video.mp4"]', '["API","Text to Video","Video"]', '["MiniMax"]', '[{"provider":"MiniMax"}]', '[]', '[]', '{"inputs":[{"nodeId":13,"nodeType":"LoadImage","file":"api_hailuo_minimax_video_first_frame.png","mediaType":"image"}],"outputs":[{"nodeId":14,"nodeType":"SaveVideo","file":"api_hailuo_minimax_video.mp4","mediaType":"video"}]}', '', NULL, '2025-03-01', 0, 'active', 0, 0, 5, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_video', 'en', 'MiniMax: Video', 'Generate high-quality videos from text prompts with optional first-frame control using MiniMax Hailuo-02 model. Supports multiple resolutions (768P/1080P) and durations (6/10s) with intelligent prompt optimization.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_video', 'zh', 'MiniMax：视频', '使用MiniMax Hailuo-02模型，通过可选的首帧控制从文本提示生成高质量视频。支持多种分辨率（768P/1080P）和时长（6/10秒），具有智能提示优化功能。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_video', 'zh-TW', 'MiniMax：影片', '使用 MiniMax Hailuo-02 模型，透過可選的首幀控制從文字提示生成高品質影片。支援多種解析度（768P/1080P）與時長（6/10 秒），具有智慧提示最佳化功能。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_video', 'ja', 'MiniMax: ビデオ', 'MiniMax Hailuo-02モデルを使用して、オプションの最初のフレーム制御で高品質なビデオをテキストプロンプトから生成します。768P/1080Pの複数の解像度と6/10秒の持続時間をサポートし、インテリジェントなプロンプト最適化を提供します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_video', 'ko', 'MiniMax: 비디오', 'MiniMax Hailuo-02 모델을 사용하여 선택적 첫 프레임 제어로 고품질 비디오를 텍스트 프롬프트에서 생성합니다. 768P/1080P 해상도와 6/10초 지속 시간을 지원하며 지능형 프롬프트 최적화를 제공합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_video', 'es', 'MiniMax: Video', 'Generar videos de alta calidad a partir de indicaciones de texto con control opcional del primer fotograma usando el modelo MiniMax Hailuo-02. Soporta múltiples resoluciones (768P/1080P) y duraciones (6/10s) con optimización inteligente de indicaciones.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_video', 'fr', 'MiniMax: Vidéo', 'Générez des vidéos de haute qualité à partir de prompts textuels avec contrôle optionnel de la première image en utilisant le modèle MiniMax Hailuo-02. Prend en charge plusieurs résolutions (768P/1080P) et durées (6/10s) avec optimisation intelligente des prompts.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_video', 'ru', 'MiniMax: видео', 'Генерация видео высокого качества по текстовым запросам с опциональным управлением первым кадром с использованием модели MiniMax Hailuo-02. Поддерживает несколько разрешений (768P/1080P) и продолжительностей (6/10s) с интеллектуальной оптимизацией запросов.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_video', 'tr', 'MiniMax: Video', 'MiniMax Hailuo-02 modelini kullanarak metin istemlerinden yüksek kaliteli videolar oluşturun. Akıllı istem optimizasyonu ile birden fazla çözünürlük (768P/1080P) ve süre (6/10s) destekler.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_video', 'ar', 'MiniMax: فيديو', 'توليد فيديوهات عالية الجودة من مطالبات نصية مع تحكم اختياري بالإطار الأول باستخدام نموذج MiniMax Hailuo-02. يدعم دقات متعددة (768P/1080P) ومدد زمنية (6/10 ثانية) مع تحسين ذكي للأوامر.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hailuo_minimax_video', 'pt-BR', 'MiniMax: Vídeo', 'Gere vídeos de alta qualidade a partir de prompts de texto com controle opcional de primeiro quadro usando o modelo MiniMax Hailuo-02. Suporta múltiplas resoluções (768P/1080P) e durações (6/10s) com otimização inteligente de prompt.', 0, NULL, '2026-04-19T13:33:43.921Z');
