INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (334, 'api_sonilo_v2m', 4, 0, 'Sonilo: Video Soundtrack Generation', 'Generate synchronized soundtracks from video footage. Input a video to produce music that matches its pacing and emotional cues, outputting a perfectly timed audio file.', 'image', 'webp', NULL, '[]', '["Audio","Music","Soundtrack"]', '["Sonilo"]', '[{"provider":"Sonilo"}]', '[]', '[]', '{"inputs":[{"nodeId":705,"nodeType":"LoadVideo","file":"leopard_rider.mp4","mediaType":"video"}],"outputs":[{"nodeId":708,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-04-12', 0, 'active', 0, 0, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_v2m', 'en', 'Sonilo: Video Soundtrack Generation', 'Generate synchronized soundtracks from video footage. Input a video to produce music that matches its pacing and emotional cues, outputting a perfectly timed audio file.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_v2m', 'zh', 'Sonilo：视频配乐生成', '从视频素材生成同步配乐。输入视频以制作与其节奏和情感线索相匹配的音乐，输出完美定时的音频文件。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_v2m', 'zh-TW', 'Sonilo：影片配樂生成', '從影片素材生成同步配樂。輸入影片以製作與其節奏和情感線索相匹配的音樂，輸出完美定時的音訊檔案。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_v2m', 'ja', 'Sonilo：ビデオサウンドトラック生成', '映像素材から同期したサウンドトラックを生成します。映像を入力して、そのペースと感情の手がかりに合った音楽を作成し、完璧にタイミングが合ったオーディオファイルを出力します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_v2m', 'ko', 'Sonilo: 비디오 사운드트랙 생성', '영상 자료에서 동기화된 사운드트랙을 생성합니다. 영상을 입력하여 그 속도와 감정적 단서에 맞는 음악을 제작하고, 완벽하게 시간이 맞춰진 오디오 파일을 출력합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_v2m', 'es', 'Sonilo: Generación de banda sonora de video', 'Genera bandas sonoras sincronizadas a partir de material de video. Introduce un video para producir música que coincida con su ritmo y señales emocionales, generando un archivo de audio perfectamente sincronizado.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_v2m', 'fr', 'Sonilo : Génération de bande-son pour vidéo', 'Générez des bandes-son synchronisées à partir de séquences vidéo. Saisissez une vidéo pour produire une musique correspondant à son rythme et à ses indices émotionnels, en sortant un fichier audio parfaitement synchronisé.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_v2m', 'ru', 'Sonilo: Генерация саундтрека для видео', 'Создавайте синхронизированные саундтреки из видеоматериалов. Введите видео, чтобы создать музыку, соответствующую его темпу и эмоциональным сигналам, выводя идеально синхронизированный аудиофайл.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_v2m', 'tr', 'Sonilo: Video Müzik Oluşturma', 'Video görüntülerinden senkronize müzik parçaları oluşturun. Bir video girerek, onun temposuna ve duygusal ipuçlarına uygun müzik üretin ve mükemmel zamanlanmış bir ses dosyası çıktısı alın.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_v2m', 'ar', 'Sonilo: إنشاء موسيقى تصويرية للفيديو', 'أنشئ موسيقى تصويرية متزامنة من لقطات الفيديو. أدخل فيديو لإنتاج موسيقى تتطابق مع سرعته وإشاراته العاطفية، مما ينتج ملف صوتي مؤقت بشكل مثالي.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_v2m', 'pt-BR', 'Sonilo: Geração de Trilha Sonora para Vídeo', 'Gere trilhas sonoras sincronizadas a partir de filmagens de vídeo. Insira um vídeo para produzir música que corresponda ao seu ritmo e pistas emocionais, gerando um arquivo de áudio perfeitamente sincronizado.', 0, NULL, '2026-04-19T13:33:43.921Z');
