INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_t2m', 'zh', 'Sonilo：文生音乐', '通过文本提示生成高质量、可用于制作的高品质音乐。输入描述性文本，创建具有流媒体播放和精确时长控制的原创配乐。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_t2m', 'zh-TW', 'Sonilo：文生音樂', '透過文字提示生成高品質、可用於製作的高品質音樂。輸入描述性文字，創建具有串流播放和精確時長控制的原創配樂。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_t2m', 'ja', 'Sonilo：テキストから音楽生成', 'テキストプロンプトから高品質で制作可能な音楽を生成します。記述的なテキストを入力し、ストリーミング再生と正確な時間制御を備えたオリジナルサウンドトラックを作成します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_t2m', 'ko', 'Sonilo: 텍스트 음악 생성', '텍스트 프롬프트에서 고품질의 제작 준비된 음악을 생성합니다. 설명적인 텍스트를 입력하여 스트리밍 재생과 정확한 지속 시간 제어 기능을 갖춘 오리지널 사운드트랙을 만듭니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_t2m', 'es', 'Sonilo: Generación de música a partir de texto', 'Genera música de alta calidad lista para producción a partir de indicaciones de texto. Ingresa texto descriptivo para crear bandas sonoras originales con reproducción en streaming y control preciso de la duración.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_t2m', 'fr', 'Sonilo : Génération de musique à partir de texte', 'Générez une musique de haute qualité, prête pour la production, à partir de prompts textuels. Saisissez un texte descriptif pour créer des bandes-son originales avec lecture en streaming et contrôle précis de la durée.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_t2m', 'ru', 'Sonilo: Генерация музыки из текста', 'Создавайте высококачественную, готовую к использованию музыку по текстовым запросам. Введите описательный текст, чтобы создать оригинальные саундтреки с потоковым воспроизведением и точным контролем длительности.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_t2m', 'tr', 'Sonilo: Metinden Müzik Üretimi', 'Metin istemlerinden yüksek kaliteli, üretime hazır müzik oluşturun. Akışlı oynatma ve hassas süre kontrolü ile özgün film müzikleri oluşturmak için açıklayıcı metin girin.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_t2m', 'ar', 'Sonilo: توليد الموسيقى من النص', 'أنشئ موسيقى عالية الجودة وجاهزة للإنتاج من خلال نصوص موجهة. أدخل نصًا وصفيًا لإنشاء موسيقى تصويرية أصلية مع تشغيل متدفق وتحكم دقيق في المدة.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_sonilo_t2m', 'pt-BR', 'Sonilo: Geração de Música a partir de Texto', 'Gere música de alta qualidade e pronta para produção a partir de prompts de texto. Insira texto descritivo para criar trilhas sonoras originais com reprodução em streaming e controle preciso de duração.', 0, NULL, '2026-04-19T13:33:43.921Z');
