INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (345, 'audio_melbandroformer_audio_separation', 4, 11, 'MelBandRoFormer Audio Separation', 'Load an audio file and separate it into vocal and instrumental stems using the MelBandRoFormer model. Outputs two MP3 files for isolated vocals and background music.', 'image', 'webp', NULL, '[]', '["Audio","Voice Isolation"]', '["None"]', '[]', '["ComfyUI-MelBandRoFormer"]', '[]', '{"inputs":[{"nodeId":1,"nodeType":"LoadAudio","file":"melbandroformer_input.mp3","mediaType":"audio"}]}', NULL, NULL, '2026-03-30', 1, 'active', 429496730, 429496730, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_melbandroformer_audio_separation', 'en', 'MelBandRoFormer Audio Separation', 'Load an audio file and separate it into vocal and instrumental stems using the MelBandRoFormer model. Outputs two MP3 files for isolated vocals and background music.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_melbandroformer_audio_separation', 'zh', 'MelBandRoFormer音频分离', '加载音频文件并使用MelBandRoFormer模型将其分离为人声和伴奏音轨。输出两个MP3文件，分别包含独立人声和背景音乐。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_melbandroformer_audio_separation', 'zh-TW', 'MelBandRoFormer音訊分離', '載入音訊檔案並使用MelBandRoFormer模型將其分離為人聲和伴奏音軌。輸出兩個MP3檔案，分別包含獨立人聲和背景音樂。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_melbandroformer_audio_separation', 'ja', 'MelBandRoFormerオーディオ分離', 'オーディオファイルを読み込み、MelBandRoFormerモデルを使用してボーカルとインストゥルメンタルの音源に分離します。分離されたボーカルとバックグラウンドミュージックの2つのMP3ファイルを出力します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_melbandroformer_audio_separation', 'ko', 'MelBandRoFormer 오디오 분리', '오디오 파일을 로드하고 MelBandRoFormer 모델을 사용하여 보컬과 반주 트랙으로 분리합니다. 분리된 보컬과 배경 음악에 대한 두 개의 MP3 파일을 출력합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_melbandroformer_audio_separation', 'es', 'Separación de audio MelBandRoFormer', 'Carga un archivo de audio y sepáralo en pistas vocales e instrumentales utilizando el modelo MelBandRoFormer. Genera dos archivos MP3 para las voces aisladas y la música de fondo.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_melbandroformer_audio_separation', 'fr', 'Séparation audio MelBandRoFormer', 'Chargez un fichier audio et séparez-le en pistes vocales et instrumentales à l''aide du modèle MelBandRoFormer. Produit deux fichiers MP3 pour les voix isolées et la musique de fond.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_melbandroformer_audio_separation', 'ru', 'Разделение аудио MelBandRoFormer', 'Загрузите аудиофайл и разделите его на вокальные и инструментальные дорожки с помощью модели MelBandRoFormer. Выводит два MP3-файла для изолированного вокала и фоновой музыки.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_melbandroformer_audio_separation', 'tr', 'MelBandRoFormer Ses Ayrıştırma', 'Bir ses dosyası yükleyin ve MelBandRoFormer modelini kullanarak vokal ve enstrümantal parçalara ayırın. İzole vokaller ve arka plan müziği için iki MP3 dosyası çıktılar.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_melbandroformer_audio_separation', 'ar', 'فصل الصوت MelBandRoFormer', 'قم بتحميل ملف صوتي وافصله إلى مسارات صوتية وآلاتية باستخدام نموذج MelBandRoFormer. يُخرج ملفين MP3 للأصوات المنعزلة والموسيقى الخلفية.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_melbandroformer_audio_separation', 'pt-BR', 'Separação de áudio MelBandRoFormer', 'Carregue um arquivo de áudio e separe-o em faixas vocais e instrumentais usando o modelo MelBandRoFormer. Gera dois arquivos MP3 para vocais isolados e música de fundo.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (346, 'audio_ace_step_1_5_split_llm', 4, 12, 'ACE-Step 1.5 AI Lyric Song Generation', 'Input a music style and optional lyrics. Generate a full song with AI-created lyrics and audio.', 'audio', 'mp3', NULL, '[]', '["API","Text to Audio"]', '["ACE-Step","Google Gemini"]', '[{"provider":"Google"}]', '[]', '[]', '{"outputs":[{"nodeId":1,"nodeType":"SaveAudioMP3","file":"audio_ace_step_1_5_split_llm.mp3","mediaType":"audio"}]}', NULL, NULL, '2026-02-09', 0, 'active', 9985798963, 9985798963, 142, 0, 'ComfyUI', 1, 1, datetime('now'));
