INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_llm', 'zh', 'ACE-Step 1.5 AI 歌词歌曲生成', '输入音乐风格和可选歌词。使用AI生成完整歌曲，包括歌词和音频。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_llm', 'zh-TW', 'ACE-Step 1.5 AI 歌詞歌曲生成', '輸入音樂風格和可選歌詞。使用AI生成完整歌曲，包括歌詞和音訊。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_llm', 'ja', 'ACE-Step 1.5 AI 歌詞・楽曲生成', '音楽スタイルとオプションの歌詞を入力してください。AIが歌詞と音声を含む完全な曲を生成します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_llm', 'ko', 'ACE-Step 1.5 AI 가사 및 노래 생성', '음악 스타일과 선택적 가사를 입력하세요. AI가 가사와 오디오를 포함한 완전한 노래를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_llm', 'es', 'ACE-Step 1.5 Generación de Letras y Canciones con IA', 'Introduce un estilo musical y letras opcionales. Genera una canción completa con letras y audio creados por IA.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_llm', 'fr', 'ACE-Step 1.5 Génération de Paroles et de Chansons par IA', 'Saisissez un style musical et des paroles facultatives. Générez une chanson complète avec des paroles et un audio créés par IA.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_llm', 'ru', 'ACE-Step 1.5 Генерация текстов и песен с помощью ИИ', 'Введите музыкальный стиль и необязательный текст. Создайте полную песню с текстом и аудио, созданными ИИ.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_llm', 'tr', 'ACE-Step 1.5 AI Şarkı Sözü ve Şarkı Oluşturma', 'Bir müzik tarzı ve isteğe bağlı şarkı sözleri girin. AI tarafından oluşturulan şarkı sözleri ve sesle tam bir şarkı oluşturun.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_llm', 'ar', 'ACE-Step 1.5 توليد كلمات الأغاني والأغاني بالذكاء الاصطناعي', 'أدخل نمط موسيقي وكلمات اختيارية. قم بإنشاء أغنية كاملة مع كلمات وصوت منشأ بواسطة الذكاء الاصطناعي.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_llm', 'pt-BR', 'ACE-Step 1.5 Geração de Letras e Músicas por IA', 'Insira um estilo musical e letras opcionais. Gere uma música completa com letras e áudio criados por IA.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (347, 'audio_ace_step_1_5_split_4b', 4, 13, 'ACE-Step 1.5 Music Generation (4B LLM )', 'Input a text prompt to generate music. This 4B model version offers stronger audio understanding and composition capabilities compared to smaller variants.', 'audio', 'mp3', NULL, '[]', '["Audio","Music","Text to Audio"]', '["ACE-Step"]', '[]', '[]', '[]', NULL, NULL, NULL, '2026-02-05', 1, 'active', 14710262989, 14710262989, 1458, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_4b', 'en', 'ACE-Step 1.5 Music Generation (4B LLM )', 'Input a text prompt to generate music. This 4B model version offers stronger audio understanding and composition capabilities compared to smaller variants.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_4b', 'zh', 'ACE-Step 1.5 音乐生成（4B LLM）', '输入文本提示以生成音乐。与较小版本相比，此4B模型版本具备更强的音频理解和作曲能力。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_4b', 'zh-TW', 'ACE-Step 1.5 音樂生成（4B LLM）', '輸入文字提示以生成音樂。與較小版本相比，此4B模型版本具備更強的音频理解和作曲能力。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_4b', 'ja', 'ACE-Step 1.5 音楽生成（4B LLM）', 'テキストプロンプトを入力して音楽を生成します。この4Bモデルバージョンは、より小さいバリアントと比較して、より強力なオーディオ理解と作曲能力を提供します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_4b', 'ko', 'ACE-Step 1.5 음악 생성 (4B LLM)', '음악을 생성하려면 텍스트 프롬프트를 입력하세요. 이 4B 모델 버전은 더 작은 변형에 비해 더 강력한 오디오 이해 및 작곡 능력을 제공합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_4b', 'es', 'ACE-Step 1.5 Generación de Música (4B LLM)', 'Introduce un texto para generar música. Esta versión del modelo 4B ofrece capacidades de comprensión de audio y composición más sólidas en comparación con variantes más pequeñas.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_4b', 'fr', 'ACE-Step 1.5 Génération de Musique (4B LLM)', 'Saisissez une invite textuelle pour générer de la musique. Cette version du modèle 4B offre des capacités de compréhension audio et de composition plus robustes que les variantes plus petites.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_4b', 'ru', 'ACE-Step 1.5 Генерация музыки (4B LLM)', 'Введите текстовый запрос для создания музыки. Эта версия модели 4B предлагает более сильные возможности понимания аудио и композиции по сравнению с меньшими вариантами.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_4b', 'tr', 'ACE-Step 1.5 Müzik Üretimi (4B LLM)', 'Müzik oluşturmak için bir metin istemi girin. Bu 4B model sürümü, daha küçük varyantlara kıyasla daha güçlü ses anlama ve beste oluşturma yetenekleri sunar.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_4b', 'ar', 'ACE-Step 1.5 توليد الموسيقى (4B LLM)', 'أدخل نصًا لإنشاء الموسيقى. تقدم نسخة النموذج 4B هذه قدرات أقوى في فهم الصوت والتأليف مقارنة بالإصدارات الأصغر.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split_4b', 'pt-BR', 'ACE-Step 1.5 Geração de Música (4B LLM)', 'Insira um prompt de texto para gerar música. Esta versão do modelo 4B oferece capacidades mais robustas de compreensão de áudio e composição em comparação com variantes menores.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (348, 'audio_ace_step_1_5_split', 4, 14, 'ACE-Step 1.5 Music Generation Workflow', 'Input a text prompt describing the music style and optional lyrics. Generate a full, high-quality audio song in under 10 seconds on consumer hardware.', 'audio', 'mp3', NULL, '[]', '["Audio","Text to Audio","Music"]', '["ACE-Step"]', '[]', '[]', '[]', NULL, NULL, NULL, '2026-02-02', 1, 'active', 10737418240, 2147483648, 541, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split', 'en', 'ACE-Step 1.5 Music Generation Workflow', 'Input a text prompt describing the music style and optional lyrics. Generate a full, high-quality audio song in under 10 seconds on consumer hardware.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split', 'zh', 'ACE-Step 1.5 音乐生成工作流程', '输入描述音乐风格和可选歌词的文本提示。在消费级硬件上10秒内生成完整的高质量音频歌曲。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split', 'zh-TW', 'ACE-Step 1.5 音樂生成工作流程', '輸入描述音樂風格和可選歌詞的文本提示。在消費級硬體上10秒內生成完整的高品質音訊歌曲。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split', 'ja', 'ACE-Step 1.5 音楽生成ワークフロー', '音楽スタイルとオプションの歌詞を説明するテキストプロンプトを入力してください。コンシューマーハードウェアで10秒以内に完全な高品質オーディオ曲を生成します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split', 'ko', 'ACE-Step 1.5 음악 생성 워크플로우', '음악 스타일과 선택적 가사를 설명하는 텍스트 프롬프트를 입력하세요. 소비자용 하드웨어에서 10초 이내에 완전한 고품질 오디오 곡을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split', 'es', 'Flujo de trabajo de generación musical ACE-Step 1.5', 'Introduce un texto que describa el estilo musical y, opcionalmente, la letra. Genera una canción de audio completa y de alta calidad en menos de 10 segundos en hardware de consumo.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split', 'fr', 'Flux de travail de génération musicale ACE-Step 1.5', 'Saisissez une consigne textuelle décrivant le style musical et, éventuellement, les paroles. Générez une chanson audio complète et de haute qualité en moins de 10 secondes sur du matériel grand public.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split', 'ru', 'Рабочий процесс генерации музыки ACE-Step 1.5', 'Введите текстовый запрос, описывающий музыкальный стиль и, по желанию, текст песни. Сгенерируйте полную высококачественную аудиопесню менее чем за 10 секунд на потребительском оборудовании.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split', 'tr', 'ACE-Step 1.5 Müzik Üretimi İş Akışı', 'Müzik tarzını ve isteğe bağlı sözleri açıklayan bir metin istemi girin. Tüketici donanımında 10 saniyeden kısa sürede tam, yüksek kaliteli bir ses şarkısı oluşturun.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split', 'ar', 'سير عمل توليد الموسيقى ACE-Step 1.5', 'أدخل نصًا يصف نمط الموسيقى والكلمات الاختيارية. قم بإنشاء أغنية صوتية كاملة وعالية الجودة في أقل من 10 ثوانٍ على أجهزة المستهلك.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_split', 'pt-BR', 'Fluxo de trabalho de geração musical ACE-Step 1.5', 'Insira um prompt de texto descrevendo o estilo musical e letras opcionais. Gere uma música de áudio completa e de alta qualidade em menos de 10 segundos em hardware de consumo.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (349, 'audio_ace_step_1_5_checkpoint', 4, 15, 'ACE-Step 1.5 Music Generation AIO', 'Input style tags and lyrics to generate a full song. The workflow uses the ACE-Step 1.5 model to produce commercial-grade music in under 10 seconds on consumer hardware.', 'audio', 'mp3', NULL, '[]', '["Audio","Music","Text to Audio"]', '["ACE-Step"]', '[]', '[]', '[]', NULL, NULL, NULL, '2026-02-03', 1, 'active', 10737418240, 5368709120, 414, 0, 'ComfyUI', 1, 1, datetime('now'));
