INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_checkpoint', 'zh', 'ACE-Step 1.5 音乐生成 AIO', '输入风格标签和歌词以生成完整歌曲。该工作流程使用ACE-Step 1.5模型，在消费级硬件上10秒内生成商业级音乐。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_checkpoint', 'zh-TW', 'ACE-Step 1.5 音樂生成 AIO', '輸入風格標籤和歌詞以生成完整歌曲。該工作流程使用ACE-Step 1.5模型，在消費級硬體上10秒內生成商業級音樂。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_checkpoint', 'ja', 'ACE-Step 1.5 音楽生成 AIO', 'スタイルタグと歌詞を入力して完全な曲を生成します。このワークフローはACE-Step 1.5モデルを使用し、コンシューマーハードウェア上で10秒以内に商用レベルの音楽を生成します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_checkpoint', 'ko', 'ACE-Step 1.5 음악 생성 AIO', '스타일 태그와 가사를 입력하여 완전한 노래를 생성합니다. 이 워크플로우는 ACE-Step 1.5 모델을 사용하여 소비자용 하드웨어에서 10초 이내에 상업용 등급의 음악을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_checkpoint', 'es', 'ACE-Step 1.5 Generación de Música AIO', 'Ingresa etiquetas de estilo y letras para generar una canción completa. El flujo de trabajo utiliza el modelo ACE-Step 1.5 para producir música de grado comercial en menos de 10 segundos en hardware de consumo.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_checkpoint', 'fr', 'ACE-Step 1.5 Génération de Musique AIO', 'Saisissez des étiquettes de style et des paroles pour générer une chanson complète. Le flux de travail utilise le modèle ACE-Step 1.5 pour produire de la musique de qualité commerciale en moins de 10 secondes sur du matériel grand public.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_checkpoint', 'ru', 'ACE-Step 1.5 Генерация музыки AIO', 'Введите стилевые теги и текст песни, чтобы сгенерировать полную композицию. Рабочий процесс использует модель ACE-Step 1.5 для создания музыки коммерческого уровня менее чем за 10 секунд на потребительском оборудовании.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_checkpoint', 'tr', 'ACE-Step 1.5 Müzik Üretimi AIO', 'Tam bir şarkı oluşturmak için stil etiketleri ve şarkı sözleri girin. İş akışı, tüketici donanımında 10 saniyeden kısa sürede ticari sınıf müzik üretmek için ACE-Step 1.5 modelini kullanır.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_checkpoint', 'ar', 'ACE-Step 1.5 توليد الموسيقى AIO', 'أدخل علامات النمط وكلمات الأغاني لتوليد أغنية كاملة. يستخدم سير العمل نموذج ACE-Step 1.5 لإنتاج موسيقى ذات جودة تجارية في أقل من 10 ثوانٍ على أجهزة المستهلك.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio_ace_step_1_5_checkpoint', 'pt-BR', 'ACE-Step 1.5 Geração de Música AIO', 'Insira tags de estilo e letras para gerar uma música completa. O fluxo de trabalho usa o modelo ACE-Step 1.5 para produzir música de nível comercial em menos de 10 segundos em hardware de consumo.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (350, 'audio-chatterbox_tts_multilingual', 4, 16, 'Chatter Box: Multilingual Text-to-Speech with Voice Cloning', 'Upload a short voice sample and input your text prompt. Select a target language to generate spoken audio in multiple languages using the cloned reference voice.', 'audio', 'mp3', NULL, '[]', '["Audio","Text to Audio","Voice Cloning"]', '["Chatter Box"]', '[]', '["comfyui_fill-chatterbox"]', '[]', '{"inputs":[{"nodeId":2,"nodeType":"LoadAudio","file":"chatterbox_input_target_voice.mp3","mediaType":"audio"}]}', NULL, NULL, '2026-01-22', 1, 'active', 0, 0, 1318, 0, 'PurzBeats', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_multilingual', 'en', 'Chatter Box: Multilingual Text-to-Speech with Voice Cloning', 'Upload a short voice sample and input your text prompt. Select a target language to generate spoken audio in multiple languages using the cloned reference voice.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_multilingual', 'zh', 'Chatter Box：支持语音克隆的多语言文本转语音', '上传一段简短的语音样本并输入您的文本提示。选择目标语言，使用克隆的参考语音生成多种语言的语音音频。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_multilingual', 'zh-TW', 'Chatter Box：支援語音克隆的多語言文字轉語音', '上傳一段簡短的語音樣本並輸入您的文字提示。選擇目標語言，使用克隆的參考語音生成多種語音的語音音訊。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_multilingual', 'ja', 'Chatter Box：音声クローニング対応の多言語テキスト読み上げ', '短い音声サンプルをアップロードし、テキストプロンプトを入力してください。ターゲット言語を選択して、複製された参照音声を使用して複数の言語で音声オーディオを生成します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_multilingual', 'ko', 'Chatter Box: 음성 복제 지원 다국어 텍스트 음성 변환', '짧은 음성 샘플을 업로드하고 텍스트 프롬프트를 입력하세요. 대상 언어를 선택하여 복제된 참조 음성을 사용하여 여러 언어로 음성 오디오를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_multilingual', 'es', 'Chatter Box: Texto a voz multilingüe con clonación de voz', 'Sube una muestra de voz corta e ingresa tu indicación de texto. Selecciona un idioma objetivo para generar audio hablado en múltiples idiomas utilizando la voz de referencia clonada.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_multilingual', 'fr', 'Chatter Box : Synthèse vocale multilingue avec clonage vocal', 'Téléchargez un court échantillon vocal et saisissez votre invite de texte. Sélectionnez une langue cible pour générer un audio parlé en plusieurs langues en utilisant la voix de référence clonée.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_multilingual', 'ru', 'Chatter Box: Многоязыковое преобразование текста в речь с клонированием голоса', 'Загрузите короткий голосовой образец и введите свой текстовый запрос. Выберите целевой язык для создания озвученного аудио на нескольких языках с использованием клонированного эталонного голоса.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_multilingual', 'tr', 'Chatter Box: Ses Klonlama Özellikli Çok Dilli Metinden Sese', 'Kısa bir ses örneği yükleyin ve metin isteminizi girin. Klonlanmış referans sesi kullanarak birden fazla dilde konuşma sesi oluşturmak için bir hedef dil seçin.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_multilingual', 'ar', 'Chatter Box: تحويل النص إلى كلام متعدد اللغات مع استنساخ الصوت', 'قم بتحميل عينة صوتية قصيرة وأدخل نصك المطلوب. اختر لغة الهدف لتوليد صوت منطوق بلغات متعددة باستخدام الصوت المرجعي المستنسخ.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_multilingual', 'pt-BR', 'Chatter Box: Conversão de texto em voz multilíngue com clonagem de voz', 'Faça upload de uma amostra de voz curta e insira seu prompt de texto. Selecione um idioma de destino para gerar áudio falado em vários idiomas usando a voz de referência clonada.', 0, NULL, '2026-04-19T13:33:43.921Z');
