INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts', 'ko', 'Chatter Box: TTS를 이용한 음성 복제', '짧은 음성 클립을 업로드하고 텍스트를 입력하여 복제된 목소리로 새로운 음성을 생성하세요.', 0, NULL, '2026-04-19T13:33:43.921Z');
