INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_dialog', 'ko', 'Chatter Box: 복제된 음성으로 다중 화자 대화하기', '음성 샘플을 업로드하고 다중 화자 대화 스크립트를 입력하세요. 각 화자에 대해 복제된 음성으로 대화 오디오 파일을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_dialog', 'es', 'Chatter Box: Conversación con múltiples interlocutores y voces clonadas', 'Sube muestras de voz e introduce un guion de diálogo con múltiples hablantes. Genera un archivo de audio de conversación con voces clonadas para cada hablante.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_dialog', 'fr', 'Chatter Box : Conversation multi-interlocuteurs avec des voix clonées', 'Téléchargez des échantillons vocaux et saisissez un script de dialogue multi-interlocuteurs. Générez un fichier audio de conversation avec des voix clonées pour chaque interlocuteur.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_dialog', 'ru', 'Chatter Box: Многопользовательский разговор с клонированными голосами', 'Загрузите голосовые образцы и введите сценарий диалога с несколькими говорящими. Создайте аудиофайл разговора с клонированными голосами для каждого говорящего.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_dialog', 'tr', 'Chatter Box: Kopyalanmış Seslerle Çoklu Konuşmacılı Sohbet', 'Ses örneklerini yükleyin ve çok konuşmacılı bir diyalog senaryosu girin. Her konuşmacı için klonlanmış seslerle bir konuşma ses dosyası oluşturun.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_tts_dialog', 'ar', 'Chatter Box: محادثة متعددة المتحدثين بأصوات مستنسخة', 'قم بتحميل عينات صوتية وأدخل نص حوار متعدد المتحدثين. قم بإنشاء ملف صوتي للمحادثة بأصوات مستنسخة لكل متحدث.', 0, NULL, '2026-04-19T13:33:43.921Z');
