INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('audio-chatterbox_vc', 'es', 'Chatter Box: Conversión de audio por clonación de voz', 'Sube un clip de audio y una breve referencia de voz para generar una salida de audio convertida que clona la voz objetivo mientras conserva el tiempo y la interpretación original.', 0, NULL, '2026-04-19T13:33:43.921Z');
