INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_smart_topology', 'ar', 'هونيوان 3D: طوبولوجيا ذكية', 'قم بتحميل ملف نموذج ثلاثي الأبعاد عالي المضلعات. قم بإنشاء نموذج ثلاثي الأبعاد منخفض المضلعات ومحسن طوبولوجيًا بمستوى تقليل محدد.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_smart_topology', 'pt-BR', 'Hunyuan3D: Topologia Inteligente', 'Faça upload de um arquivo de modelo 3D de alta poligonização. Gere um modelo 3D de baixa poligonização e topologicamente otimizado com um nível de redução especificado.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (365, 'api_meshy_multi_image_to_model', 5, 4, 'Meshy 6: Multi-Image to Model', 'Create high-quality 3D models from multiple images using Meshy 6. More photos mean better detail capture, accurate proportions, and cleaner mesh structure.', 'image', 'webp', NULL, '[]', '["3D","API"]', '["Meshy"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":8,"nodeType":"LoadImage","file":"joker_front.jpg","mediaType":"image"},{"nodeId":12,"nodeType":"LoadImage","file":"joker_back.jpg","mediaType":"image"},{"nodeId":13,"nodeType":"LoadImage","file":"joker_side.jpg","mediaType":"image"}],"outputs":[{"nodeId":6,"nodeType":"Preview3D","file":"","mediaType":"3d"}]}', NULL, NULL, '2026-01-19', 0, 'active', 0, 0, 119, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_multi_image_to_model', 'en', 'Meshy 6: Multi-Image to Model', 'Create high-quality 3D models from multiple images using Meshy 6. More photos mean better detail capture, accurate proportions, and cleaner mesh structure.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_multi_image_to_model', 'zh', 'Meshy 6：多图像生成模型', '使用 Meshy 6 从多张图像创建高质量 3D 模型。照片越多，细节捕捉越精细，比例越准确，网格结构越清晰。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_multi_image_to_model', 'zh-TW', 'Meshy 6：多圖像生成模型', '使用 Meshy 6 從多張圖像創建高品質 3D 模型。照片越多，細節捕捉越精細，比例越準確，網格結構越清晰。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_multi_image_to_model', 'ja', 'Meshy 6：複数画像からモデル生成', 'Meshy 6 を使用して複数の画像から高品質な 3D モデルを作成します。写真が多いほど、詳細なキャプチャ、正確なプロポーション、クリーンなメッシュ構造が実現します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_multi_image_to_model', 'ko', 'Meshy 6: 다중 이미지에서 모델 생성', 'Meshy 6를 사용하여 여러 이미지에서 고품질 3D 모델을 생성하세요. 사진이 많을수록 세부 캡처가 더 정확해지고, 비율이 정밀해지며, 메쉬 구조가 더 깔끔해집니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_multi_image_to_model', 'es', 'Meshy 6: De múltiples imágenes a modelo', 'Cree modelos 3D de alta calidad a partir de múltiples imágenes usando Meshy 6. Más fotos significan una mejor captura de detalles, proporciones precisas y una estructura de malla más limpia.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_multi_image_to_model', 'fr', 'Meshy 6 : Multi-image vers modèle', 'Créez des modèles 3D de haute qualité à partir de plusieurs images en utilisant Meshy 6. Plus de photos signifie une meilleure capture des détails, des proportions précises et une structure de maillage plus propre.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_multi_image_to_model', 'ru', 'Meshy 6: Из нескольких изображений в модель', 'Создавайте высококачественные 3D-модели из нескольких изображений с помощью Meshy 6. Чем больше фотографий, тем лучше захват деталей, точные пропорции и более чистая структура сетки.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_multi_image_to_model', 'tr', 'Meshy 6: Çoklu Görüntüden Modele', 'Meshy 6 kullanarak birden fazla görselden yüksek kaliteli 3D modeller oluşturun. Daha fazla fotoğraf, daha iyi detay yakalama, doğru oranlar ve daha temiz bir ağ yapısı anlamına gelir.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_multi_image_to_model', 'ar', 'Meshy 6: من صور متعددة إلى نموذج', 'أنشئ نماذج ثلاثية الأبعاد عالية الجودة من صور متعددة باستخدام Meshy 6. المزيد من الصور يعني التقاط تفاصيل أفضل ونسب دقيقة وبنية شبكية أنظف.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_multi_image_to_model', 'pt-BR', 'Meshy 6: De Múltiplas Imagens para Modelo', 'Crie modelos 3D de alta qualidade a partir de várias imagens usando o Meshy 6. Mais fotos significam melhor captura de detalhes, proporções precisas e estrutura de malha mais limpa.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (366, 'api_meshy_image_to_model', 5, 5, 'Meshy 6: Image to Model', 'Upload an image and generate a 3D model with Meshy 6. Create characters, objects, or mechanical parts with production-quality geometry and clean topology.', 'image', 'webp', NULL, '[]', '["3D","Image to Model","API"]', '["Meshy"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":8,"nodeType":"LoadImage","file":"robot-warrior.png","mediaType":"image"}],"outputs":[{"nodeId":6,"nodeType":"Preview3D","file":"","mediaType":"3d"}]}', NULL, NULL, '2026-01-19', 0, 'active', 0, 0, 173, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_image_to_model', 'en', 'Meshy 6: Image to Model', 'Upload an image and generate a 3D model with Meshy 6. Create characters, objects, or mechanical parts with production-quality geometry and clean topology.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_image_to_model', 'zh', 'Meshy 6：图像转模型', '上传图像并使用 Meshy 6 生成 3D 模型。创建具有生产质量几何结构和干净拓扑的角色、物体或机械部件。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_image_to_model', 'zh-TW', 'Meshy 6：圖像轉模型', '上傳圖像並使用 Meshy 6 生成 3D 模型。創建具有生產品質幾何結構和乾淨拓撲的角色、物體或機械部件。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_image_to_model', 'ja', 'Meshy 6：画像からモデルへ', '画像をアップロードし、Meshy 6 で 3D モデルを生成します。プロダクション品質のジオメトリとクリーンなトポロジーでキャラクター、オブジェクト、または機械部品を作成します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_image_to_model', 'ko', 'Meshy 6: 이미지에서 모델로', '이미지를 업로드하고 Meshy 6로 3D 모델을 생성하세요. 프로덕션 품질의 지오메트리와 깔끔한 토폴로지로 캐릭터, 오브젝트 또는 기계 부품을 제작하세요.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_image_to_model', 'es', 'Meshy 6: De imagen a modelo', 'Sube una imagen y genera un modelo 3D con Meshy 6. Crea personajes, objetos o piezas mecánicas con geometría de calidad de producción y topología limpia.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_image_to_model', 'fr', 'Meshy 6 : De l''image au modèle', 'Téléchargez une image et générez un modèle 3D avec Meshy 6. Créez des personnages, des objets ou des pièces mécaniques avec une géométrie de qualité production et une topologie propre.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_image_to_model', 'ru', 'Meshy 6: Изображение в модель', 'Загрузите изображение и создайте 3D-модель с помощью Meshy 6. Создавайте персонажей, объекты или механические детали с геометрией производственного качества и чистой топологией.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_image_to_model', 'tr', 'Meshy 6: Görüntüden Modele', 'Bir görsel yükleyin ve Meshy 6 ile 3D model oluşturun. Üretim kalitesinde geometri ve temiz topoloji ile karakterler, nesneler veya mekanik parçalar oluşturun.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_image_to_model', 'ar', 'Meshy 6: من الصورة إلى النموذج', 'قم بتحميل صورة وأنشئ نموذجًا ثلاثي الأبعاد باستخدام Meshy 6. أنشئ شخصيات أو كائنات أو أجزاء ميكانيكية بهندسة عالية الجودة وطوبولوجيا نظيفة.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_image_to_model', 'pt-BR', 'Meshy 6: Imagem para Modelo', 'Faça upload de uma imagem e gere um modelo 3D com o Meshy 6. Crie personagens, objetos ou peças mecânicas com geometria de qualidade de produção e topologia limpa.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (367, 'templates_mjm_image_to_3d', 5, 6, 'Generate 3D Model From Single Image', 'Input a single image to automatically generate three orthographic views. Use these multiviews with Meshy to create a textured 3D model.', 'image', 'webp', 'compareSlider', '["thumbnail/templates_mjm_image_to_3d-1.png","thumbnail/templates_mjm_image_to_3d-2.png"]', '["3D Model","Image to 3D"]', '["Meshy","Nano Banana 2"]', '[{"provider":["Google","Meshy"]}]', '[]', '[]', '{"inputs":[{"nodeId":1,"nodeType":"LoadImage","file":"templates_mjm_image_to_3d.png","mediaType":"image"}],"outputs":[{"nodeId":25,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":26,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":27,"nodeType":"SaveImage","file":"","mediaType":"image"},{"nodeId":24,"nodeType":"Preview3D","file":"","mediaType":"3d"}]}', NULL, NULL, '2026-03-19', 0, 'active', 0, 0, 0, 0, 'Julien | MJM', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_image_to_3d', 'en', 'Generate 3D Model From Single Image', 'Input a single image to automatically generate three orthographic views. Use these multiviews with Meshy to create a textured 3D model.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_image_to_3d', 'zh', '从单张图像生成3D模型', '输入单张图像，自动生成三视图。使用这些多视图与Meshy创建带纹理的3D模型。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_image_to_3d', 'zh-TW', '從單張圖像生成3D模型', '輸入單張圖像，自動生成三視圖。使用這些多視圖與Meshy建立帶紋理的3D模型。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_image_to_3d', 'ja', '単一画像から3Dモデルを生成', '単一画像を入力して自動的に三面図を生成。これらの多面図をMeshyで使用し、テクスチャ付き3Dモデルを作成します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_image_to_3d', 'ko', '단일 이미지에서 3D 모델 생성', '단일 이미지를 입력하여 자동으로 삼면도를 생성합니다. Meshy와 함께 이 다면도를 사용하여 텍스처가 적용된 3D 모델을 만드세요.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_image_to_3d', 'es', 'Generar modelo 3D a partir de una sola imagen', 'Introduce una sola imagen para generar automáticamente tres vistas ortográficas. Utiliza estas multivistas con Meshy para crear un modelo 3D texturizado.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_image_to_3d', 'fr', 'Générer un modèle 3D à partir d''une seule image', 'Saisissez une seule image pour générer automatiquement trois vues orthographiques. Utilisez ces multivues avec Meshy pour créer un modèle 3D texturé.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_image_to_3d', 'ru', 'Создать 3D-модель из одного изображения', 'Введите одно изображение для автоматического создания трех ортогональных видов. Используйте эти многовидовые изображения с Meshy для создания текстурированной 3D-модели.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_image_to_3d', 'tr', 'Tek Bir Görüntüden 3D Model Oluştur', 'Üç ortografik görünümü otomatik oluşturmak için tek bir görsel girin. Bu çoklu görünümleri Meshy ile kullanarak dokulu bir 3D model oluşturun.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_image_to_3d', 'ar', 'إنشاء نموذج ثلاثي الأبعاد من صورة واحدة', 'أدخل صورة واحدة لإنشاء ثلاثة مناظر إسقاطية تلقائيًا. استخدم هذه المناظر المتعددة مع Meshy لإنشاء نموذج ثلاثي الأبعاد مُنقّش.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_mjm_image_to_3d', 'pt-BR', 'Gerar Modelo 3D a Partir de uma Única Imagem', 'Insira uma única imagem para gerar automaticamente três vistas ortográficas. Use essas multivistas com o Meshy para criar um modelo 3D texturizado.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (368, 'api_meshy_text_to_model', 5, 7, 'Meshy 6: Text to Model', 'Generate high-quality 3D models from text prompts using Meshy 6. Create characters with refined geometry, mechanical objects with sharp edges, or game-ready low-poly assets.', 'image', 'webp', NULL, '[]', '["3D","Text to Model","API"]', '["Meshy"]', '[]', '[]', '[]', '{"outputs":[{"nodeId":6,"nodeType":"Preview3D","file":"","mediaType":"3d"}]}', NULL, NULL, '2026-01-19', 0, 'active', 0, 0, 24, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_text_to_model', 'en', 'Meshy 6: Text to Model', 'Generate high-quality 3D models from text prompts using Meshy 6. Create characters with refined geometry, mechanical objects with sharp edges, or game-ready low-poly assets.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_text_to_model', 'zh', 'Meshy 6：文生模型', '使用 Meshy 6 从文本提示生成高质量 3D 模型。创建具有精细几何结构的角色、带有锐利边缘的机械物体，或游戏就绪的低多边形资源。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_text_to_model', 'zh-TW', 'Meshy 6：文字到模型', '使用 Meshy 6 從文字提示生成高品質 3D 模型。創建具有精細幾何結構的角色、帶有銳利邊緣的機械物體，或遊戲就緒的低多邊形資源。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_text_to_model', 'ja', 'Meshy 6：テキストからモデルへ', 'Meshy 6 を使用して、テキストプロンプトから高品質な 3D モデルを生成します。洗練されたジオメトリを持つキャラクター、鋭いエッジを持つ機械的オブジェクト、またはゲーム対応の低ポリゴンアセットを作成できます。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_text_to_model', 'ko', 'Meshy 6: 텍스트에서 모델로', 'Meshy 6를 사용하여 텍스트 프롬프트로 고품질 3D 모델을 생성하세요. 정교한 지오메트리를 가진 캐릭터, 날카로운 가장자리를 가진 기계적 오브젝트 또는 게임 준비가 완료된 로우폴리 에셋을 제작할 수 있습니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_text_to_model', 'es', 'Meshy 6: De texto a modelo', 'Genera modelos 3D de alta calidad a partir de indicaciones de texto usando Meshy 6. Crea personajes con geometría refinada, objetos mecánicos con bordes afilados o activos de baja poligonización listos para juegos.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_text_to_model', 'fr', 'Meshy 6 : Du texte au modèle', 'Générez des modèles 3D de haute qualité à partir de prompts textuels avec Meshy 6. Créez des personnages avec une géométrie raffinée, des objets mécaniques aux arêtes vives ou des assets low-poly prêts pour le jeu.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_text_to_model', 'ru', 'Meshy 6: Текст в модель', 'Создавайте высококачественные 3D-модели из текстовых запросов с помощью Meshy 6. Создавайте персонажей с утонченной геометрией, механические объекты с острыми краями или низкополигональные ассеты, готовые для игр.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_text_to_model', 'tr', 'Meshy 6: Metinden Modele', 'Meshy 6 kullanarak metin istemlerinden yüksek kaliteli 3D modeller oluşturun. İnce geometriye sahip karakterler, keskin kenarlı mekanik nesneler veya oyun için hazır düşük poligonlu varlıklar oluşturun.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_text_to_model', 'ar', 'Meshy 6: من النص إلى النموذج', 'قم بإنشاء نماذج ثلاثية الأبعاد عالية الجودة من نصوص باستخدام Meshy 6. أنشئ شخصيات بهندسة دقيقة، أو كائنات ميكانيكية ذات حواف حادة، أو أصول منخفضة المضلعات جاهزة للألعاب.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_meshy_text_to_model', 'pt-BR', 'Meshy 6: Texto para Modelo', 'Gere modelos 3D de alta qualidade a partir de prompts de texto usando o Meshy 6. Crie personagens com geometria refinada, objetos mecânicos com bordas afiadas ou assets de baixo polígono prontos para jogos.', 0, NULL, '2026-04-19T13:33:43.921Z');
