INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_retopo_uv', 'en', 'Huyuan3D: Model Retopology and UV Unwrapping', 'Input a dense mesh (from AI generation or photogrammetry scans) and create a light weight model with good topology and unwrapped UV. Great for 3D game assets optimization.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_retopo_uv', 'zh', '混元3D：模型重拓扑与UV展开', '输入密集网格（来自AI生成或摄影测量扫描），创建具有良好拓扑结构和展开UV的轻量模型。非常适合3D游戏资产优化。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_retopo_uv', 'zh-TW', 'Huyuan3D：模型重拓撲與UV展開', '輸入密集網格（來自AI生成或攝影測量掃描），創建具有良好拓撲結構和展開UV的輕量模型。非常適合3D遊戲資產優化。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_retopo_uv', 'ja', 'Huyuan3D：モデルリトポロジーとUV展開', '高密度メッシュ（AI生成またはフォトグラメトリースキャンから）を入力し、良好なトポロジーと展開済みUVを持つ軽量モデルを作成します。3Dゲームアセットの最適化に最適です。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_retopo_uv', 'ko', 'Huyuan3D: 모델 리토폴로지 및 UV 전개', '고밀도 메시(AI 생성 또는 포토그래메트리 스캔에서)를 입력하고, 좋은 토폴로지와 전개된 UV를 가진 경량 모델을 생성합니다. 3D 게임 에셋 최적화에 매우 적합합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_retopo_uv', 'es', 'Huyuan3D: Retopología de Modelos y Despliegue UV', 'Introduce una malla densa (de generación por IA o escaneos de fotogrametría) y crea un modelo ligero con buena topología y UV desplegados. Ideal para la optimización de activos de juegos 3D.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_retopo_uv', 'fr', 'Huyuan3D : Rétopologie de Modèles et Dépliage UV', 'Saisissez un maillage dense (issu d''une génération IA ou de scans de photogrammétrie) et créez un modèle léger avec une bonne topologie et des UV dépliés. Idéal pour l''optimisation d''assets de jeux 3D.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_retopo_uv', 'ru', 'Huyuan3D: Ретопология моделей и UV-развертка', 'Введите плотную сетку (из AI-генерации или фотограмметрических сканов) и создайте легковесную модель с хорошей топологией и развернутыми UV. Отлично подходит для оптимизации 3D-ассетов игр.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_retopo_uv', 'tr', 'Huyuan3D: Model Retopolojisi ve UV Açma', 'Yoğun bir ağ (AI üretimi veya fotogrametri taramalarından) girin ve iyi topoloji ve açılmış UV''ye sahip hafif bir model oluşturun. 3D oyun varlıklarını optimize etmek için mükemmeldir.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_retopo_uv', 'ar', 'Huyuan3D: إعادة طوبولوجيا النماذج وفك UV', 'أدخل شبكة كثيفة (من توليد الذكاء الاصطناعي أو مسحات التصوير الضوئي) وأنشئ نموذجًا خفيف الوزن بطوبولوجيا جيدة وUV مفكوك. ممتاز لتحسين أصول ألعاب 3D.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_hunyuan3d_retopo_uv', 'pt-BR', 'Huyuan3D: Retopologia de Modelos e Desdobramento UV', 'Insira uma malha densa (de geração por IA ou varreduras de fotogrametria) e crie um modelo leve com boa topologia e UV desdobrado. Ótimo para otimização de assets de jogos 3D.', 0, NULL, '2026-04-19T13:33:43.921Z');
