INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (383, 'llm_qwen3_5_text_gen', 6, 0, 'Qwen3.5: Text Generation', 'Use the Qwen3.5 model to analyze an input image and generate descriptive text prompts. This workflow performs image captioning and reverse prompt engineering.', 'image', 'webp', NULL, '["thumbnail/llm_qwen3_5_text_gen.png"]', '["Text Generation"]', '["Qwen3.5"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":2,"nodeType":"LoadImage","file":"man_with_red_hat.png","mediaType":"image"}]}', NULL, NULL, '2026-03-27', 1, 'active', 9341553869, 9341553869, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('llm_qwen3_5_text_gen', 'en', 'Qwen3.5: Text Generation', 'Use the Qwen3.5 model to analyze an input image and generate descriptive text prompts. This workflow performs image captioning and reverse prompt engineering.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('llm_qwen3_5_text_gen', 'zh', 'Qwen3.5：文本生成', '使用Qwen3.5模型分析输入图像并生成描述性文本提示。此工作流程执行图像描述和反向提示工程。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('llm_qwen3_5_text_gen', 'zh-TW', 'Qwen3.5：文本生成', '使用Qwen3.5模型分析輸入圖像並生成描述性文字提示。此工作流程執行圖像描述和反向提示工程。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('llm_qwen3_5_text_gen', 'ja', 'Qwen3.5：テキスト生成', 'Qwen3.5モデルを使用して入力画像を分析し、記述的なテキストプロンプトを生成します。このワークフローは画像キャプション生成と逆プロンプトエンジニアリングを実行します。', 0, NULL, '2026-04-19T13:33:43.921Z');
