INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('llm_qwen3_5_text_gen', 'es', 'Qwen3.5: Generación de texto', 'Utilice el modelo Qwen3.5 para analizar una imagen de entrada y generar indicaciones de texto descriptivas. Este flujo de trabajo realiza subtitulado de imágenes e ingeniería inversa de indicaciones.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('llm_qwen3_5_text_gen', 'fr', 'Qwen3.5 : Génération de texte', 'Utilisez le modèle Qwen3.5 pour analyser une image d''entrée et générer des invites de texte descriptives. Ce flux de travail effectue la légende d''images et l''ingénierie inverse d''invites.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('llm_qwen3_5_text_gen', 'ru', 'Qwen3.5: Генерация текста', 'Используйте модель Qwen3.5 для анализа входного изображения и создания описательных текстовых подсказок. Этот рабочий процесс выполняет подписи к изображениям и обратное проектирование подсказок.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('llm_qwen3_5_text_gen', 'tr', 'Qwen3.5: Metin Üretimi', 'Giriş görselini analiz etmek ve betimleyici metin istemleri oluşturmak için Qwen3.5 modelini kullanın. Bu iş akışı, görsel altyazı oluşturma ve ters istem mühendisliği gerçekleştirir.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('llm_qwen3_5_text_gen', 'ar', 'Qwen3.5: توليد النص', 'استخدم نموذج Qwen3.5 لتحليل صورة الإدخال وإنشاء نصوص وصفية توجيهية. يقوم سير العمل هذا بإنشاء تعليقات توضيحية للصور وهندسة عكسية للنصوص التوجيهية.', 0, NULL, '2026-04-19T13:33:43.921Z');
