INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_seedvr2_video_upscale', 'zh', 'SeedVR2：视频超分辨率', '上传视频，使用SeedVR2模型进行超分辨率处理，提升画质以获得高清输出。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_seedvr2_video_upscale', 'zh-TW', 'SeedVR2：影片超解析度', '上傳影片，使用SeedVR2模型進行超解析度處理，提升畫質以獲得高清輸出。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_seedvr2_video_upscale', 'ja', 'SeedVR2：ビデオアップスケーリング', 'SeedVR2モデルを使用して動画をアップロードし、解像度をアップスケールして高画質出力を実現します。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_seedvr2_video_upscale', 'ko', 'SeedVR2: 비디오 업스케일링', 'SeedVR2 모델을 사용하여 비디오를 업로드하고 해상도를 업스케일하여 고화질 출력을 얻으세요.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_seedvr2_video_upscale', 'es', 'SeedVR2: Mejora de calidad de video', 'Sube un video para mejorar y aumentar su resolución utilizando el modelo SeedVR2 para una salida de alta definición.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_seedvr2_video_upscale', 'fr', 'SeedVR2 : Suréchantillonnage vidéo', 'Téléchargez une vidéo pour améliorer et augmenter sa résolution en utilisant le modèle SeedVR2 pour une sortie haute définition.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_seedvr2_video_upscale', 'ru', 'SeedVR2: Улучшение качества видео', 'Загрузите видео для повышения и улучшения его разрешения с использованием модели SeedVR2 для получения высококачественного вывода.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_seedvr2_video_upscale', 'tr', 'SeedVR2: Video Yükseltme', 'Yüksek çözünürlüklü çıktı için SeedVR2 modelini kullanarak çözünürlüğünü yükseltmek ve geliştirmek için bir video yükleyin.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_seedvr2_video_upscale', 'ar', 'SeedVR2: تحسين جودة الفيديو', 'قم بتحميل مقطع فيديو لتحسين ودقة وضوحه باستخدام نموذج SeedVR2 للحصول على إخراج عالي الدقة.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_seedvr2_video_upscale', 'pt-BR', 'SeedVR2: Aprimoramento de Vídeo', 'Faça upload de um vídeo para aprimorar e aumentar sua resolução usando o modelo SeedVR2 para saída em alta definição.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (389, 'utility_sdpose_ood_video_to_pose_map', 7, 2, 'SDPose-OOD: Video to Pose Map', 'Upload a video to extract pose keypoints and generate a pose map. The workflow supports multiple person detection and uses an enhanced SDPose model for accurate whole-body feature extraction.', 'image', 'webp', 'compareSlider', '["input/man_in_the_rain.mp4","output/utility_sdpose_ood_video_to_pose_map.mp4"]', '["Pose Map"]', '["SDPose-OOD"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":679,"nodeType":"LoadVideo","file":"man_in_the_rain.mp4","mediaType":"video"}],"outputs":[{"nodeId":680,"nodeType":"SaveVideo","file":"utility_sdpose_ood_video_to_pose_map.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-02', 1, 'active', 1932735283, 1932735283, 36, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_video_to_pose_map', 'en', 'SDPose-OOD: Video to Pose Map', 'Upload a video to extract pose keypoints and generate a pose map. The workflow supports multiple person detection and uses an enhanced SDPose model for accurate whole-body feature extraction.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_video_to_pose_map', 'zh', 'SDPose-OOD：视频到姿态映射', '上传视频以提取姿态关键点并生成姿态图。该工作流程支持多人检测，并使用增强的SDPose模型进行精确的全身特征提取。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_video_to_pose_map', 'zh-TW', 'SDPose-OOD：影片到姿態映射', '上傳影片以提取姿態關鍵點並生成姿態圖。該工作流程支援多人檢測，並使用增強的SDPose模型進行精確的全身特徵提取。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_video_to_pose_map', 'ja', 'SDPose-OOD：ビデオからポーズへのマッピング', '動画をアップロードして姿勢キーポイントを抽出し、姿勢マップを生成します。このワークフローは複数人物の検出をサポートし、強化されたSDPoseモデルを使用して正確な全身特徴抽出を行います。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_video_to_pose_map', 'ko', 'SDPose-OOD: 비디오에서 포즈로의 매핑', '포즈 키포인트를 추출하고 포즈 맵을 생성하려면 동영상을 업로드하세요. 이 워크플로우는 다중 인물 감지를 지원하며 향상된 SDPose 모델을 사용하여 정확한 전신 특징 추출을 수행합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_video_to_pose_map', 'es', 'SDPose-OOD: Mapeo de video a pose', 'Sube un video para extraer puntos clave de postura y generar un mapa de postura. El flujo de trabajo admite la detección de múltiples personas y utiliza un modelo SDPose mejorado para una extracción precisa de características de todo el cuerpo.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_video_to_pose_map', 'fr', 'SDPose-OOD : Cartographie vidéo vers pose', 'Téléchargez une vidéo pour extraire les points clés de posture et générer une carte de posture. Le flux de travail prend en charge la détection de plusieurs personnes et utilise un modèle SDPose amélioré pour une extraction précise des caractéristiques du corps entier.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_video_to_pose_map', 'ru', 'SDPose-OOD: Отображение видео в позу', 'Загрузите видео для извлечения ключевых точек позы и создания карты позы. Рабочий процесс поддерживает обнаружение нескольких людей и использует улучшенную модель SDPose для точного извлечения признаков всего тела.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_video_to_pose_map', 'tr', 'SDPose-OOD: Videodan poza eşleme', 'Poz anahtar noktalarını çıkarmak ve bir poz haritası oluşturmak için bir video yükleyin. İş akışı, çoklu kişi tespitini destekler ve doğru tüm vücut özellik çıkarımı için geliştirilmiş bir SDPose modeli kullanır.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_video_to_pose_map', 'ar', 'SDPose-OOD: تعيين الفيديو إلى الوضعية', 'قم بتحميل مقطع فيديو لاستخراج نقاط الوضع الرئيسية وإنشاء خريطة وضع. يدعم سير العمل الكشف عن عدة أشخاص ويستخدم نموذج SDPose المحسن لاستخراج ميزات دقيقة لكامل الجسم.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_video_to_pose_map', 'pt-BR', 'SDPose-OOD: Mapeamento de vídeo para pose', 'Faça upload de um vídeo para extrair pontos-chave de pose e gerar um mapa de pose. O fluxo de trabalho suporta detecção de múltiplas pessoas e usa um modelo SDPose aprimorado para extração precisa de características de todo o corpo.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (390, 'utility_sdpose_multi_person_video', 7, 3, 'SDPose: Video Multi-Person Detection', 'Upload a video to detect human poses. Supports detection for both single individuals and multiple people within the same scene', 'image', 'webp', NULL, '[]', '["Pose Map"]', '["SDPose-OOD"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":694,"nodeType":"LoadVideo","file":"man_palying_violin.mp4","mediaType":"video"}],"outputs":[{"nodeId":697,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-03-31', 1, 'active', 2040109466, 2040109466, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person_video', 'en', 'SDPose: Video Multi-Person Detection', 'Upload a video to detect human poses. Supports detection for both single individuals and multiple people within the same scene', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person_video', 'zh', 'SDPose：视频多人检测', '上传视频以检测人体姿态。支持在同一场景中检测单人和多人。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person_video', 'zh-TW', 'SDPose：影片多人偵測', '上傳影片以偵測人體姿態。支援在同一場景中偵測單人與多人。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person_video', 'ja', 'SDPose：動画における複数人物検出', '動画をアップロードして人体のポーズを検出します。同一シーン内での単独人物と複数人物の両方の検出に対応しています。', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person_video', 'ko', 'SDPose: 비디오 다중 인물 감지', '동영상을 업로드하여 인체 포즈를 감지합니다. 동일 장면 내 단일 인물 및 다중 인물 감지를 모두 지원합니다.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person_video', 'es', 'SDPose: Detección de múltiples personas en video', 'Sube un video para detectar poses humanas. Admite la detección tanto de individuos únicos como de múltiples personas en la misma escena.', 0, NULL, '2026-04-19T13:33:43.921Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person_video', 'fr', 'SDPose : Détection multi-personnes en vidéo', 'Téléchargez une vidéo pour détecter les poses humaines. Prend en charge la détection d''individus uniques et de plusieurs personnes dans la même scène.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person_video', 'ru', 'SDPose: Обнаружение нескольких людей на видео', 'Загрузите видео для обнаружения поз человека. Поддерживает обнаружение как отдельных людей, так и нескольких человек в одной сцене.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person_video', 'tr', 'SDPose: Video Çoklu Kişi Tespiti', 'İnsan pozlarını tespit etmek için bir video yükleyin. Aynı sahnede hem tek kişiler hem de birden fazla kişi için tespiti destekler.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person_video', 'ar', 'SDPose: كشف أشخاص متعددين في الفيديو', 'قم بتحميل مقطع فيديو للكشف عن أوضاع الجسم البشرية. يدعم الكشف عن الأفراد المنفردين وأيضًا عدة أشخاص في نفس المشهد.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person_video', 'pt-BR', 'SDPose: Detecção de Múltiplas Pessoas em Vídeo', 'Faça upload de um vídeo para detectar poses humanas. Suporta detecção tanto para indivíduos únicos quanto para várias pessoas na mesma cena.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (391, 'utility_sdpose_multi_person', 7, 4, 'SDPose: Image Multi-Person Detection', 'Upload an image to detect human poses. Supports detection for both single individuals and multiple people within the same scene.', 'image', 'webp', NULL, '["thumbnail/utility_sdpose_multi_person.mp4"]', '["Pose Map"]', '["SDPose-OOD"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":679,"nodeType":"LoadImage","file":"group_photo.png","mediaType":"image"}],"outputs":[{"nodeId":680,"nodeType":"SaveImage","file":"","mediaType":"image"}]}', NULL, NULL, '2026-03-31', 1, 'active', 2040109466, 2040109466, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person', 'en', 'SDPose: Image Multi-Person Detection', 'Upload an image to detect human poses. Supports detection for both single individuals and multiple people within the same scene.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person', 'zh', 'SDPose：图像多人检测', '上传图像以检测人体姿态。支持检测单个人物以及同一场景中的多个人物。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person', 'zh-TW', 'SDPose：圖像多人檢測', '上傳圖像以檢測人體姿態。支援檢測單個人物以及同一場景中的多個人物。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person', 'ja', 'SDPose：画像の複数人物検出', '画像をアップロードして人体ポーズを検出します。単一人物と同一シーン内の複数人物の両方の検出をサポートします。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person', 'ko', 'SDPose: 이미지 다중 인물 감지', '이미지를 업로드하여 인체 포즈를 감지합니다. 단일 개인 및 동일 장면 내 여러 사람에 대한 감지를 지원합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person', 'es', 'SDPose: Detección de múltiples personas en imágenes', 'Sube una imagen para detectar posturas humanas. Admite la detección tanto de individuos únicos como de múltiples personas en la misma escena.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person', 'fr', 'SDPose : Détection multi-personnes dans les images', 'Téléchargez une image pour détecter les poses humaines. Prend en charge la détection d''individus uniques et de plusieurs personnes dans la même scène.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person', 'ru', 'SDPose: Обнаружение нескольких людей на изображении', 'Загрузите изображение для определения поз человека. Поддерживает определение как отдельных людей, так и нескольких человек в одной сцене.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person', 'tr', 'SDPose: Görüntüde Çoklu Kişi Tespiti', 'İnsan pozlarını tespit etmek için bir görsel yükleyin. Tek bireyler ve aynı sahnedeki birden fazla kişi için tespiti destekler.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person', 'ar', 'SDPose: كشف أشخاص متعددين في الصورة', 'قم بتحميل صورة للكشف عن أوضاع الجسم البشرية. يدعم الكشف لكل من الأفراد المنفردين والأشخاص المتعددين داخل المشهد نفسه.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_multi_person', 'pt-BR', 'SDPose: Detecção de Múltiplas Pessoas em Imagens', 'Faça upload de uma imagem para detectar poses humanas. Suporta detecção tanto para indivíduos únicos quanto para várias pessoas na mesma cena.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (392, 'utility_sdpose_ood_image_to_pose', 7, 5, 'SDPose-OOD: Image to Pose Map', 'Upload an image to extract pose keypoints and generate a corresponding pose map using the SDPose-OOD model.', 'image', 'webp', 'compareSlider', '["input/dancer.png","output/utility_sdpose_ood_image_to_pose.png"]', '["Pose Map"]', '["SDPose-OOD"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":667,"nodeType":"LoadImage","file":"dancer.png","mediaType":"image"}],"outputs":[{"nodeId":669,"nodeType":"SaveImage","file":"utility_sdpose_ood_image_to_pose.png","mediaType":"image"}]}', NULL, NULL, '2026-03-02', 1, 'active', 1932735283, 1932735283, 113, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_image_to_pose', 'en', 'SDPose-OOD: Image to Pose Map', 'Upload an image to extract pose keypoints and generate a corresponding pose map using the SDPose-OOD model.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_image_to_pose', 'zh', 'SDPose-OOD：图像到姿态映射', '上传图像以提取姿态关键点，并使用SDPose-OOD模型生成相应的姿态图。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_image_to_pose', 'zh-TW', 'SDPose-OOD：圖像到姿態映射', '上傳圖像以提取姿態關鍵點，並使用SDPose-OOD模型生成相應的姿態圖。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_image_to_pose', 'ja', 'SDPose-OOD：画像からポーズマップへ', '画像をアップロードして姿勢キーポイントを抽出し、SDPose-OODモデルを使用して対応する姿勢マップを生成します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_image_to_pose', 'ko', 'SDPose-OOD: 이미지에서 포즈 맵으로', '이미지를 업로드하여 포즈 키포인트를 추출하고 SDPose-OOD 모델을 사용하여 해당 포즈 맵을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_image_to_pose', 'es', 'SDPose-OOD: Imagen a mapa de poses', 'Sube una imagen para extraer puntos clave de pose y generar un mapa de pose correspondiente utilizando el modelo SDPose-OOD.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_image_to_pose', 'fr', 'SDPose-OOD : Image vers carte de poses', 'Téléchargez une image pour extraire les points clés de pose et générer une carte de pose correspondante à l''aide du modèle SDPose-OOD.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_image_to_pose', 'ru', 'SDPose-OOD: Изображение в карту поз', 'Загрузите изображение для извлечения ключевых точек позы и создания соответствующей карты позы с использованием модели SDPose-OOD.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_image_to_pose', 'tr', 'SDPose-OOD: Görüntüden Poz Haritasına', 'SDPose-OOD modelini kullanarak poz anahtar noktalarını çıkarmak ve karşılık gelen bir poz haritası oluşturmak için bir görsel yükleyin.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_image_to_pose', 'ar', 'SDPose-OOD: من الصورة إلى خريطة الوضعية', 'قم بتحميل صورة لاستخراج النقاط الرئيسية للوضعية وإنشاء خريطة وضعية مقابلة باستخدام نموذج SDPose-OOD.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sdpose_ood_image_to_pose', 'pt-BR', 'SDPose-OOD: Imagem para Mapa de Pose', 'Faça upload de uma imagem para extrair pontos-chave de pose e gerar um mapa de pose correspondente usando o modelo SDPose-OOD.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (393, 'api_magnific_image_upscale_creative', 7, 6, 'Magnific: Creative Image Upscale', 'Upload an image and set the magnification level. Generate an upscaled version of your image with support for up to 16x enlargement.', 'image', 'webp', 'compareSlider', '["input/1950_new_york.png","output/ComfyUI_00915_.png"]', '["API","Image Upscale"]', '["Magnific"]', '[{"provider":"Magnific"}]', '[]', '[]', '{"inputs":[{"nodeId":2,"nodeType":"LoadImage","file":"1950_new_york.png","mediaType":"image"}],"outputs":[{"nodeId":3,"nodeType":"SaveImage","file":"ComfyUI_00915_.png","mediaType":"image"}]}', NULL, NULL, '2026-02-13', 0, 'active', 0, 0, 254, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_upscale_creative', 'en', 'Magnific: Creative Image Upscale', 'Upload an image and set the magnification level. Generate an upscaled version of your image with support for up to 16x enlargement.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_upscale_creative', 'zh', 'Magnific：创意图像放大', '上传图片并设置放大级别。生成支持高达16倍放大的图像高清版本。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_upscale_creative', 'zh-TW', 'Magnific：創意影像放大', '上傳圖片並設定放大級別。生成支援高達16倍放大的圖像高清版本。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_upscale_creative', 'ja', 'Magnific：クリエイティブ画像アップスケール', '画像をアップロードして拡大レベルを設定します。最大16倍の拡大に対応した高解像度バージョンを生成します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_upscale_creative', 'ko', 'Magnific: 창의적 이미지 업스케일', '이미지를 업로드하고 확대 수준을 설정하세요. 최대 16배 확대를 지원하는 고해상도 버전을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_upscale_creative', 'es', 'Magnific: Escalado Creativo de Imágenes', 'Sube una imagen y establece el nivel de ampliación. Genera una versión de alta resolución de tu imagen con soporte para ampliaciones de hasta 16x.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_upscale_creative', 'fr', 'Magnific : Suréchantillonnage Créatif d''Image', 'Téléchargez une image et définissez le niveau d''agrandissement. Générez une version haute résolution de votre image avec prise en charge d''un agrandissement jusqu''à 16x.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_upscale_creative', 'ru', 'Magnific: Креативное Увеличение Изображений', 'Загрузите изображение и установите уровень увеличения. Создайте улучшенную версию изображения с поддержкой увеличения до 16 раз.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_upscale_creative', 'tr', 'Magnific: Yaratıcı Görüntü Büyütme', 'Bir görsel yükleyin ve büyütme seviyesini ayarlayın. 16 kata kadar büyütme desteği ile görselinizin yüksek çözünürlüklü bir versiyonunu oluşturun.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_upscale_creative', 'ar', 'Magnific: تكبير الصور الإبداعي', 'قم بتحميل صورة وضبط مستوى التكبير. قم بإنشاء نسخة عالية الدقة من صورتك مع دعم التكبير حتى 16 ضعفًا.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_upscale_creative', 'pt-BR', 'Magnific: Aumento Criativo de Imagem', 'Faça upload de uma imagem e defina o nível de ampliação. Gere uma versão de alta resolução da sua imagem com suporte para ampliação de até 16x.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (394, 'api_topaz_starlight_precise25', 7, 7, 'Video Upscale: Topaz Starlight Precise 2.5', 'Upload a video to enhance its resolution using the Topaz Starlight Precise 2.5 model. This workflow produces sharper 4K output with reduced artifacts compared to previous versions.', 'image', 'webp', NULL, '["thumbnail/api_topaz_starlight_precise25.mp4"]', '["Video Upscale","API"]', '["Topaz"]', '[{"provider":"Topaz"}]', '[]', '[]', '{"inputs":[{"nodeId":3,"nodeType":"LoadVideo","file":"running_horse.mp4","mediaType":"video"}],"outputs":[{"nodeId":4,"nodeType":"SaveVideo","file":"running_horse.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-26', 0, 'active', 0, 0, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_starlight_precise25', 'en', 'Video Upscale: Topaz Starlight Precise 2.5', 'Upload a video to enhance its resolution using the Topaz Starlight Precise 2.5 model. This workflow produces sharper 4K output with reduced artifacts compared to previous versions.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_starlight_precise25', 'zh', '视频放大：Topaz Starlight Precise 2.5', '上传视频，使用Topaz Starlight Precise 2.5模型提升其分辨率。此工作流程相比先前版本能生成更清晰、伪影更少的4K输出。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_starlight_precise25', 'zh-TW', '影片放大：Topaz Starlight Precise 2.5', '上傳影片，使用Topaz Starlight Precise 2.5模型提升其解析度。此工作流程相比先前版本能生成更清晰、雜訊更少的4K輸出。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_starlight_precise25', 'ja', 'ビデオアップスケール：Topaz Starlight Precise 2.5', 'Topaz Starlight Precise 2.5モデルを使用して解像度を向上させるために動画をアップロードしてください。このワークフローは、以前のバージョンと比較して、より鮮明でアーティファクトの少ない4K出力を生成します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_starlight_precise25', 'ko', '비디오 업스케일: Topaz Starlight Precise 2.5', 'Topaz Starlight Precise 2.5 모델을 사용하여 해상도를 향상시키려면 동영상을 업로드하세요. 이 워크플로우는 이전 버전에 비해 더 선명하고 아티팩트가 감소된 4K 출력을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_starlight_precise25', 'es', 'Mejora de video: Topaz Starlight Precise 2.5', 'Sube un vídeo para mejorar su resolución utilizando el modelo Topaz Starlight Precise 2.5. Este flujo de trabajo produce una salida 4K más nítida con menos artefactos en comparación con versiones anteriores.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_starlight_precise25', 'fr', 'Amélioration vidéo : Topaz Starlight Precise 2.5', 'Téléchargez une vidéo pour améliorer sa résolution en utilisant le modèle Topaz Starlight Precise 2.5. Ce flux de travail produit une sortie 4K plus nette avec moins d''artefacts par rapport aux versions précédentes.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_starlight_precise25', 'ru', 'Улучшение видео: Topaz Starlight Precise 2.5', 'Загрузите видео, чтобы улучшить его разрешение с помощью модели Topaz Starlight Precise 2.5. Этот рабочий процесс обеспечивает более четкий вывод в 4K с уменьшенными артефактами по сравнению с предыдущими версиями.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_starlight_precise25', 'tr', 'Video Yükseltme: Topaz Starlight Precise 2.5', 'Topaz Starlight Precise 2.5 modelini kullanarak çözünürlüğünü artırmak için bir video yükleyin. Bu iş akışı, önceki sürümlere kıyasla daha keskin ve daha az artefakt içeren 4K çıktı üretir.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_starlight_precise25', 'ar', 'تحسين جودة الفيديو: Topaz Starlight Precise 2.5', 'قم بتحميل مقطع فيديو لتعزيز دقته باستخدام نموذج Topaz Starlight Precise 2.5. ينتج سير العمل هذا مخرجات 4K أكثر وضوحًا مع تقليل التشوهات مقارنة بالإصدارات السابقة.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_starlight_precise25', 'pt-BR', 'Melhoria de Vídeo: Topaz Starlight Precise 2.5', 'Faça upload de um vídeo para aprimorar sua resolução usando o modelo Topaz Starlight Precise 2.5. Este fluxo de trabalho produz uma saída 4K mais nítida com artefatos reduzidos em comparação com versões anteriores.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (395, 'utility_gimm_frame_interpolation', 7, 8, 'GIMM Frame Interpolation', 'Generate intermediate frames between existing video frames to create smoother motion. Input a video and receive a fluid, higher-frame-rate output without changing the total duration.', 'image', 'webp', 'compareSlider', '[]', '["Frame Interpolation","Video"]', '["none"]', '[]', '["comfyui-gimm-vfi","comfyui-videohelpersuite"]', '[]', '{"inputs":[{"nodeId":8,"nodeType":"VHS_LoadVideo","file":"gimm-input.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-30', 1, 'active', 10737418240, 10737418240, 0, 0, 'PurzBeats', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_gimm_frame_interpolation', 'en', 'GIMM Frame Interpolation', 'Generate intermediate frames between existing video frames to create smoother motion. Input a video and receive a fluid, higher-frame-rate output without changing the total duration.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_gimm_frame_interpolation', 'zh', 'GIMM 帧插值', '在现有视频帧之间生成中间帧，以创建更流畅的运动。输入视频并获得流畅、更高帧率的输出，而无需改变总时长。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_gimm_frame_interpolation', 'zh-TW', 'GIMM 影格插值', '在現有影片影格之間生成中間影格，以創建更流暢的運動。輸入影片並獲得流暢、更高影格率的輸出，而無需改變總時長。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_gimm_frame_interpolation', 'ja', 'GIMM フレーム補間', '既存のビデオフレームの中間に中間フレームを生成し、より滑らかな動きを作成します。ビデオを入力すると、総時間を変えずに、流動的でより高いフレームレートの出力を得られます。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_gimm_frame_interpolation', 'ko', 'GIMM 프레임 보간', '기존 비디오 프레임 사이에 중간 프레임을 생성하여 더 부드러운 동작을 만듭니다. 비디오를 입력하면 총 지속 시간을 변경하지 않고 유동적이고 더 높은 프레임 속도의 출력을 받습니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_gimm_frame_interpolation', 'es', 'Interpolación de fotogramas GIMM', 'Genera fotogramas intermedios entre los fotogramas existentes del video para crear un movimiento más suave. Introduce un video y recibe una salida fluida con una tasa de fotogramas más alta sin cambiar la duración total.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_gimm_frame_interpolation', 'fr', 'Interpolation d''images GIMM', 'Générez des images intermédiaires entre les images vidéo existantes pour créer un mouvement plus fluide. Saisissez une vidéo et recevez une sortie fluide avec un taux de rafraîchissement plus élevé sans modifier la durée totale.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_gimm_frame_interpolation', 'ru', 'GIMM Интерполяция кадров', 'Создавайте промежуточные кадры между существующими кадрами видео для более плавного движения. Введите видео и получите плавный вывод с более высокой частотой кадров без изменения общей продолжительности.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_gimm_frame_interpolation', 'tr', 'GIMM Kare Ara Değerleme', 'Daha akıcı hareket oluşturmak için mevcut video kareleri arasında ara kareler oluşturun. Bir video girin ve toplam süreyi değiştirmeden akıcı, daha yüksek kare hızında bir çıktı alın.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_gimm_frame_interpolation', 'ar', 'GIMM استيفاء الإطار', 'قم بإنشاء إطارات وسيطة بين إطارات الفيديو الحالية لإنشاء حركة أكثر سلاسة. أدخل مقطع فيديو واحصل على إخراج سلس بمعدل إطارات أعلى دون تغيير المدة الإجمالية.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_gimm_frame_interpolation', 'pt-BR', 'Interpolação de Quadros GIMM', 'Gere quadros intermediários entre os quadros existentes do vídeo para criar um movimento mais suave. Insira um vídeo e receba uma saída fluida com taxa de quadros mais alta sem alterar a duração total.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (396, 'utility_z_image_turbo_2k_upscaler.app', 7, 9, 'Image Upscale: Z-Image-Turbo 2K', 'Upload an image to upscale it to 2K resolution using the Z-Image-Turbo model.', 'image', 'webp', 'compareSlider', '["input/fighter_jet.png","output/utility_z_image_turbo_2k_upscaler.png"]', '["Image Upscale"]', '["Z-Image-Turbo"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":77,"nodeType":"LoadImage","file":"fighter_jet.png","mediaType":"image"}],"outputs":[{"nodeId":9,"nodeType":"SaveImage","file":"utility_z_image_turbo_2k_upscaler.png","mediaType":"image"}]}', NULL, NULL, '2026-02-19', 1, 'active', 20723217203, 20723217203, 2, 0, 'hellorob', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_z_image_turbo_2k_upscaler.app', 'en', 'Image Upscale: Z-Image-Turbo 2K', 'Upload an image to upscale it to 2K resolution using the Z-Image-Turbo model.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_z_image_turbo_2k_upscaler.app', 'zh', '图像放大：Z-Image-Turbo 2K', '上传图片，使用Z-Image-Turbo模型将其提升至2K分辨率。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_z_image_turbo_2k_upscaler.app', 'zh-TW', '圖像放大：Z-Image-Turbo 2K', '上傳圖片，使用Z-Image-Turbo模型將其提升至2K解析度。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_z_image_turbo_2k_upscaler.app', 'ja', '画像アップスケール：Z-Image-Turbo 2K', '画像をアップロードして、Z-Image-Turboモデルを使用して2K解像度にアップスケールします。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_z_image_turbo_2k_upscaler.app', 'ko', '이미지 업스케일: Z-Image-Turbo 2K', '이미지를 업로드하여 Z-Image-Turbo 모델을 사용해 2K 해상도로 업스케일하세요.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_z_image_turbo_2k_upscaler.app', 'es', 'Mejora de imagen: Z-Image-Turbo 2K', 'Sube una imagen para mejorarla a resolución 2K usando el modelo Z-Image-Turbo.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_z_image_turbo_2k_upscaler.app', 'fr', 'Amélioration d''image : Z-Image-Turbo 2K', 'Téléchargez une image pour l''améliorer en résolution 2K à l''aide du modèle Z-Image-Turbo.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_z_image_turbo_2k_upscaler.app', 'ru', 'Увеличение изображения: Z-Image-Turbo 2K', 'Загрузите изображение, чтобы повысить его разрешение до 2K с помощью модели Z-Image-Turbo.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_z_image_turbo_2k_upscaler.app', 'tr', 'Görüntü Büyütme: Z-Image-Turbo 2K', 'Z-Image-Turbo modelini kullanarak bir görseli yükleyin ve 2K çözünürlüğe yükseltin.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_z_image_turbo_2k_upscaler.app', 'ar', 'تحسين جودة الصورة: Z-Image-Turbo 2K', 'قم بتحميل صورة لتحسين دقتها إلى 2K باستخدام نموذج Z-Image-Turbo.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_z_image_turbo_2k_upscaler.app', 'pt-BR', 'Aprimoramento de Imagem: Z-Image-Turbo 2K', 'Faça upload de uma imagem para aprimorá-la para resolução 2K usando o modelo Z-Image-Turbo.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (397, 'utility_bria_remove_image_background', 7, 10, 'Bira: Remove Image Background', 'Upload an image to automatically remove its background using the Bria API. The workflow processes the request asynchronously and returns the edited image with a transparent background.', 'image', 'webp', 'compareSlider', '["input/denim_girl.png","output/utility_bria_remove_image_background.png"]', '["Remove Background","Image"]', '["BRIA"]', '[{"provider":"BRIA"}]', '[]', '[]', '{"inputs":[{"nodeId":26,"nodeType":"LoadImage","file":"denim_girl.png","mediaType":"image"}],"outputs":[{"nodeId":27,"nodeType":"SaveImage","file":"utility_bria_remove_image_background.png","mediaType":"image"}]}', NULL, NULL, '2026-02-16', 0, 'active', 0, 0, 152, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_bria_remove_image_background', 'en', 'Bira: Remove Image Background', 'Upload an image to automatically remove its background using the Bria API. The workflow processes the request asynchronously and returns the edited image with a transparent background.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_bria_remove_image_background', 'zh', 'Bira：移除图片背景', '上传图片，使用Bria API自动移除背景。工作流程异步处理请求，并返回带有透明背景的编辑后图片。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_bria_remove_image_background', 'zh-TW', 'Bira：移除圖片背景', '上傳圖片，使用Bria API自動移除背景。工作流程非同步處理請求，並返回帶有透明背景的編輯後圖片。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_bria_remove_image_background', 'ja', 'Bira：画像の背景を削除', '画像をアップロードすると、Bria APIを使用して自動的に背景が削除されます。ワークフローはリクエストを非同期で処理し、透明な背景を持つ編集済み画像を返します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_bria_remove_image_background', 'ko', 'Bira：이미지 배경 제거', '이미지를 업로드하여 Bria API를 사용해 자동으로 배경을 제거하세요. 워크플로우는 요청을 비동기적으로 처리하고 투명 배경이 적용된 편집된 이미지를 반환합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_bria_remove_image_background', 'es', 'Bira: Eliminar fondo de imagen', 'Sube una imagen para eliminar automáticamente su fondo mediante la API de Bria. El flujo de trabajo procesa la solicitud de forma asíncrona y devuelve la imagen editada con un fondo transparente.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_bria_remove_image_background', 'fr', 'Bira : Supprimer l''arrière-plan de l''image', 'Téléchargez une image pour supprimer automatiquement son arrière-plan à l''aide de l''API Bria. Le flux de travail traite la requête de manière asynchrone et renvoie l''image modifiée avec un arrière-plan transparent.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_bria_remove_image_background', 'ru', 'Bira: Удалить фон изображения', 'Загрузите изображение, чтобы автоматически удалить фон с помощью API Bria. Рабочий процесс обрабатывает запрос асинхронно и возвращает отредактированное изображение с прозрачным фоном.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_bria_remove_image_background', 'tr', 'Bira: Görsel Arka Planını Kaldır', 'Bria API kullanarak arka planını otomatik olarak kaldırmak için bir görsel yükleyin. İş akışı isteği eşzamansız olarak işler ve şeffaf arka plana sahip düzenlenmiş görseli döndürür.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_bria_remove_image_background', 'ar', 'Bira: إزالة خلفية الصورة', 'قم بتحميل صورة لإزالة خلفيتها تلقائيًا باستخدام واجهة برمجة تطبيقات Bria. تعالج سير العمل الطلب بشكل غير متزامن وتعيد الصورة المحررة بخلفية شفافة.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_bria_remove_image_background', 'pt-BR', 'Bira: Remover Fundo da Imagem', 'Faça upload de uma imagem para remover automaticamente seu plano de fundo usando a API Bria. O fluxo de trabalho processa a solicitação de forma assíncrona e retorna a imagem editada com um plano de fundo transparente.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (398, 'templates_purz_crossfade', 7, 11, 'Blend Video Sequences With Crossfade Transition', 'Smoothly blend two video sequences using a crossfade effect. Input two image sequences and define the transition length and blend mode. Outputs a single, merged video sequence.', 'image', 'webp', NULL, '["output/templates_purz_crossfade.mp4"]', '["Video"]', '["None"]', '[]', '["comfyui-videohelpersuite","comfyui_fill-nodes"]', '[]', '{"inputs":[{"nodeId":3,"nodeType":"VHS_LoadVideo","file":"crossfade_clip_1.mp4","mediaType":"video"},{"nodeId":4,"nodeType":"VHS_LoadVideo","file":"crossfade_clip_2.mp4","mediaType":"video"}]}', NULL, NULL, '2026-03-19', 1, 'active', 0, 0, 0, 0, 'PurzBeats', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_crossfade', 'en', 'Blend Video Sequences With Crossfade Transition', 'Smoothly blend two video sequences using a crossfade effect. Input two image sequences and define the transition length and blend mode. Outputs a single, merged video sequence.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_crossfade', 'zh', '使用交叉淡入淡出过渡混合视频序列', '使用交叉淡入淡出效果平滑融合两个视频序列。输入两个图像序列并定义过渡长度和混合模式。输出一个合并后的单一视频序列。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_crossfade', 'zh-TW', '使用交叉淡入淡出過渡混合影片序列', '使用交叉淡入淡出效果平滑融合兩個影片序列。輸入兩個影像序列並定義過渡長度和混合模式。輸出一個合併後的單一影片序列。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_crossfade', 'ja', 'クロスフェードトランジションでビデオシーケンスをブレンド', 'クロスフェード効果を使用して2つのビデオシーケンスを滑らかにブレンドします。2つの画像シーケンスを入力し、トランジションの長さとブレンドモードを定義します。単一の統合されたビデオシーケンスを出力します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_crossfade', 'ko', '크로스페이드 전환으로 비디오 시퀀스 블렌딩', '크로스페이드 효과를 사용하여 두 비디오 시퀀스를 부드럽게 블렌딩합니다. 두 이미지 시퀀스를 입력하고 전환 길이와 블렌드 모드를 정의합니다. 단일 통합 비디오 시퀀스를 출력합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_crossfade', 'es', 'Mezclar secuencias de video con transición de fundido cruzado', 'Mezcla suavemente dos secuencias de video utilizando un efecto de fundido cruzado. Ingresa dos secuencias de imágenes y define la duración de la transición y el modo de fusión. Genera una única secuencia de video fusionada.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_crossfade', 'fr', 'Fusionner des séquences vidéo avec une transition de fondu enchaîné', 'Fusionnez en douceur deux séquences vidéo à l''aide d''un effet de fondu enchaîné. Saisissez deux séquences d''images et définissez la durée de transition et le mode de fusion. Produit une seule séquence vidéo fusionnée.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_crossfade', 'ru', 'Смешивание видеопоследовательностей с переходом кроссфейд', 'Плавно смешайте две видеопоследовательности с помощью эффекта перекрестного растворения. Введите две последовательности изображений и определите длительность перехода и режим смешивания. Выводит единую объединенную видеопоследовательность.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_crossfade', 'tr', 'Çapraz Geçiş Efekti ile Video Dizilerini Harmanlama', 'Bir çapraz geçiş efekti kullanarak iki video dizisini sorunsuzca harmanlayın. İki görüntü dizisi girin ve geçiş uzunluğu ile harmanlama modunu tanımlayın. Tek bir birleştirilmiş video dizisi çıktısı verir.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_crossfade', 'ar', 'مزج تسلسلات الفيديو باستخدام انتقال التلاشي المتقاطع', 'امزج تسلسلين فيديو بسلاسة باستخدام تأثير التلاشي المتقاطع. أدخل تسلسلي صور وحدد طول الانتقال ووضع المزج. يُخرج تسلسل فيديو واحدًا مدمجًا.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_crossfade', 'pt-BR', 'Misturar sequências de vídeo com transição de crossfade', 'Misture suavemente duas sequências de vídeo usando um efeito de fusão cruzada. Insira duas sequências de imagens e defina a duração da transição e o modo de mesclagem. Gera uma única sequência de vídeo mesclada.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (399, 'templates_doc_workbox_klein_9b_image_extend', 7, 12, 'Flux.2 Klein 9B: Image Extend', 'Use the FLUX.2 Klein 9B model to intelligently extend and expand image content. Input an image to generate seamless outpainting and extended compositions.', 'image', 'webp', 'compareSlider', '["thumbnail/templates_doc_workbox_klein_9b_image_extend-1.png","thumbnail/templates_doc_workbox_klein_9b_image_extend-2.png"]', '["Image","Outpainting"]', '["Flux.2 Klein"]', '[]', '["ComfyUI-Color-Matcher","ComfyUI_Swwan","comfyui-kjnodes"]', '[]', '{"inputs":[{"nodeId":159,"nodeType":"LoadImage","file":"red_panda.png","mediaType":"image"}],"outputs":[{"nodeId":142,"nodeType":"SaveImage","file":"templates_doc_workbox_klein_9b_image_extend.png","mediaType":"image"}]}', NULL, NULL, '2026-03-19', 1, 'active', 16750372454, 16750372454, 0, 0, 'Doc_workBox', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_klein_9b_image_extend', 'en', 'Flux.2 Klein 9B: Image Extend', 'Use the FLUX.2 Klein 9B model to intelligently extend and expand image content. Input an image to generate seamless outpainting and extended compositions.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_klein_9b_image_extend', 'zh', 'Flux.2 Klein 9B：图像扩展', '使用FLUX.2 Klein 9B模型智能扩展和扩充图像内容。输入图像以生成无缝外绘和扩展构图。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_klein_9b_image_extend', 'zh-TW', 'Flux.2 Klein 9B：圖像擴展', '使用FLUX.2 Klein 9B模型智慧擴展和擴充影像內容。輸入影像以生成無縫外繪和擴展構圖。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_klein_9b_image_extend', 'ja', 'Flux.2 Klein 9B：画像拡張', 'FLUX.2 Klein 9Bモデルを使用して、画像コンテンツをインテリジェントに拡張および拡大します。画像を入力して、シームレスなアウトペインティングと拡張構図を生成します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_klein_9b_image_extend', 'ko', 'Flux.2 Klein 9B: 이미지 확장', 'FLUX.2 Klein 9B 모델을 사용하여 이미지 콘텐츠를 지능적으로 확장 및 확대합니다. 이미지를 입력하여 매끄러운 아웃페인팅과 확장 구도를 생성하세요.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_klein_9b_image_extend', 'es', 'Flux.2 Klein 9B: Extensión de Imagen', 'Utilice el modelo FLUX.2 Klein 9B para extender y expandir inteligentemente el contenido de la imagen. Ingrese una imagen para generar pintura exterior sin costuras y composiciones extendidas.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_klein_9b_image_extend', 'fr', 'Flux.2 Klein 9B : Extension d''Image', 'Utilisez le modèle FLUX.2 Klein 9B pour étendre et développer intelligemment le contenu de l''image. Saisissez une image pour générer une peinture extérieure sans couture et des compositions étendues.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_klein_9b_image_extend', 'ru', 'Flux.2 Klein 9B: Расширение Изображения', 'Используйте модель FLUX.2 Klein 9B для интеллектуального расширения и дополнения содержимого изображения. Введите изображение для создания бесшовного аутпейнтинга и расширенных композиций.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_klein_9b_image_extend', 'tr', 'Flux.2 Klein 9B: Görüntü Uzatma', 'Görsel içeriğini akıllıca genişletmek ve büyütmek için FLUX.2 Klein 9B modelini kullanın. Sorunsuz dış boyama ve genişletilmiş kompozisyonlar oluşturmak için bir görsel girin.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_klein_9b_image_extend', 'ar', 'Flux.2 Klein 9B: توسيع الصورة', 'استخدم نموذج FLUX.2 Klein 9B لتوسيع محتوى الصورة وتوسيعه بذكاء. أدخل صورة لإنشاء رسم خارجي سلس وتكوينات موسعة.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_doc_workbox_klein_9b_image_extend', 'pt-BR', 'Flux.2 Klein 9B: Extensão de Imagem', 'Use o modelo FLUX.2 Klein 9B para estender e expandir inteligentemente o conteúdo da imagem. Insira uma imagem para gerar pintura externa perfeita e composições estendidas.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (400, 'utility-bria_remove_video_backgroud', 7, 13, 'Bria: Remove Video Background', 'Upload a video to remove the background. Generate a new video with a transparent or solid color background.', 'image', 'webp', 'compareSlider', '["input/prince_and_phoenix.mp4","output/utility-bria_remove_video_backgroud.mp4"]', '["Remove Background"]', '["BRIA"]', '[{"provider":"BRIA"}]', '[]', '[]', '{"inputs":[{"nodeId":123,"nodeType":"LoadVideo","file":"prince_and_phoenix.mp4","mediaType":"video"}],"outputs":[{"nodeId":124,"nodeType":"SaveVideo","file":"utility-bria_remove_video_backgroud.mp4","mediaType":"video"}]}', NULL, NULL, '2026-02-16', 0, 'active', 0, 0, 39, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-bria_remove_video_backgroud', 'en', 'Bria: Remove Video Background', 'Upload a video to remove the background. Generate a new video with a transparent or solid color background.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-bria_remove_video_backgroud', 'zh', 'Bria：移除视频背景', '上传视频以移除背景。生成具有透明或纯色背景的新视频。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-bria_remove_video_backgroud', 'zh-TW', 'Bria：移除影片背景', '上傳影片以移除背景。生成具有透明或純色背景的新影片。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-bria_remove_video_backgroud', 'ja', 'Bria：ビデオ背景を削除', '背景を削除するために動画をアップロードしてください。透明または単色の背景を持つ新しい動画を生成します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-bria_remove_video_backgroud', 'ko', 'Bria: 비디오 배경 제거', '배경을 제거하려면 동영상을 업로드하세요. 투명하거나 단색 배경의 새 동영상을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-bria_remove_video_backgroud', 'es', 'Bria: Eliminar fondo de video', 'Sube un vídeo para eliminar el fondo. Genera un nuevo vídeo con un fondo transparente o de color sólido.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-bria_remove_video_backgroud', 'fr', 'Bria : Supprimer l''arrière-plan vidéo', 'Téléchargez une vidéo pour supprimer l''arrière-plan. Générez une nouvelle vidéo avec un arrière-plan transparent ou de couleur unie.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-bria_remove_video_backgroud', 'ru', 'Bria: Удалить фон видео', 'Загрузите видео, чтобы удалить фон. Создайте новое видео с прозрачным или однотонным фоном.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-bria_remove_video_backgroud', 'tr', 'Bria: Video Arka Planını Kaldır', 'Arka planı kaldırmak için bir video yükleyin. Şeffaf veya düz renkli arka plana sahip yeni bir video oluşturun.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-bria_remove_video_backgroud', 'ar', 'Bria: إزالة خلفية الفيديو', 'قم بتحميل مقطع فيديو لإزالة الخلفية. قم بإنشاء مقطع فيديو جديد بخلفية شفافة أو بلون صلب.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-bria_remove_video_backgroud', 'pt-BR', 'Bria: Remover Fundo de Vídeo', 'Faça upload de um vídeo para remover o plano de fundo. Gere um novo vídeo com um plano de fundo transparente ou de cor sólida.', 0, NULL, '2026-04-19T13:33:43.922Z');
