INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_video_upscale', 'zh-TW', '創意影片升級至4K - Wan2.2', '上傳影片並使用Wan 2.2將其提升至更高解析度', 0, NULL, '2026-04-19T13:33:43.922Z');
