INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_video_upscale', 'ko', '크리에이티브 비디오 4K 업스케일 - Wan2.2', '동영상을 업로드하고 Wan 2.2로 더 높은 해상도로 업스케일', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_video_upscale', 'es', 'Mejora creativa de video a 4K - Wan2.2', 'Sube un video y mejóralo a una resolución más alta con Wan 2.2', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_video_upscale', 'fr', 'Amélioration créative de vidéo en 4K - Wan2.2', 'Téléchargez une vidéo et améliorez-la en haute résolution avec Wan 2.2', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_video_upscale', 'ru', 'Креативное улучшение видео до 4K - Wan2.2', 'Загрузите видео и повысьте его разрешение с помощью Wan 2.2', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_video_upscale', 'tr', 'Yaratıcı Video 4K Yükseltme - Wan2.2', 'Bir video yükleyin ve Wan 2.2 ile daha yüksek çözünürlüğe yükseltin', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_video_upscale', 'ar', 'ترقية الفيديو الإبداعي إلى 4K - Wan2.2', 'قم بتحميل مقطع فيديو وارفع دقته إلى دقة أعلى باستخدام Wan 2.2', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_video_upscale', 'pt-BR', 'Aprimoramento Criativo de Vídeo para 4K - Wan2.2', 'Faça upload de um vídeo e melhore sua resolução com o Wan 2.2', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (402, 'utility_sirolim_image_controlled_upscale', 7, 15, 'Wan2.2: Two-Stage Image Upscaler', 'Upload an image and set a resize factor. Generate an AI prompt from your image and upscale it in two controlled stages to enhance detail and fidelity.', 'image', 'webp', 'compareSlider', '["input/playful_portrait.png","output/utility_sirolim_image_controlled_upscale-2.png"]', '["Image Upscale"]', '["Wan2.2"]', '[]', '["ComfyUI-WanVideoWrapper","comfyui-wanvideowrapper"]', '[]', '{"inputs":[{"nodeId":664,"nodeType":"LoadImage","file":"playful_portrait.png","mediaType":"image"}],"outputs":[{"nodeId":733,"nodeType":"SaveImage","file":"utility_sirolim_image_controlled_upscale-1.png","mediaType":"image"},{"nodeId":670,"nodeType":"SaveImage","file":"utility_sirolim_image_controlled_upscale-2.png","mediaType":"image"}]}', NULL, NULL, '2026-03-12', 1, 'active', 21474836480, 21474836480, 350, 0, 'sirolim', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sirolim_image_controlled_upscale', 'en', 'Wan2.2: Two-Stage Image Upscaler', 'Upload an image and set a resize factor. Generate an AI prompt from your image and upscale it in two controlled stages to enhance detail and fidelity.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sirolim_image_controlled_upscale', 'zh', 'Wan2.2：两阶段图像超分辨率', '上传一张图片并设置缩放系数。根据您的图片生成AI提示，并通过两个受控阶段进行放大，以增强细节和保真度。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sirolim_image_controlled_upscale', 'zh-TW', 'Wan2.2：兩階段圖像超解析度', '上傳一張圖片並設定縮放係數。根據您的圖片生成AI提示，並透過兩個受控階段進行放大，以增強細節和保真度。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sirolim_image_controlled_upscale', 'ja', 'Wan2.2：2段階画像超解像', '画像をアップロードし、リサイズ係数を設定します。画像からAIプロンプトを生成し、詳細と忠実度を高めるために2段階の制御された方法で拡大します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sirolim_image_controlled_upscale', 'ko', 'Wan2.2: 2단계 이미지 업스케일러', '이미지를 업로드하고 리사이즈 비율을 설정하세요. 이미지에서 AI 프롬프트를 생성하고, 세부 사항과 정확도를 향상시키기 위해 두 단계의 제어된 방식으로 업스케일합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sirolim_image_controlled_upscale', 'es', 'Wan2.2: Escalador de imagen en dos etapas', 'Sube una imagen y establece un factor de redimensionamiento. Genera un prompt de IA a partir de tu imagen y amplíala en dos etapas controladas para mejorar el detalle y la fidelidad.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sirolim_image_controlled_upscale', 'fr', 'Wan2.2 : Suréchantillonneur d''image en deux étapes', 'Téléchargez une image et définissez un facteur de redimensionnement. Générez une invite IA à partir de votre image et augmentez sa résolution en deux étapes contrôlées pour améliorer les détails et la fidélité.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sirolim_image_controlled_upscale', 'ru', 'Wan2.2: Двухэтапный апскейлер изображений', 'Загрузите изображение и задайте коэффициент изменения размера. Сгенерируйте AI-запрос на основе вашего изображения и увеличьте его в два контролируемых этапа для улучшения детализации и точности.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sirolim_image_controlled_upscale', 'tr', 'Wan2.2: İki Aşamalı Görüntü Büyütücü', 'Bir görsel yükleyin ve yeniden boyutlandırma faktörü belirleyin. Görselinizden bir AI istemi oluşturun ve detay ile doğruluğu artırmak için iki kontrollü aşamada yükseltin.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sirolim_image_controlled_upscale', 'ar', 'Wan2.2: مُرتفع جودة الصورة ثنائي المراحل', 'قم بتحميل صورة وحدد عامل تغيير الحجم. أنشئ مطالبة ذكاء اصطناعي من صورتك وقم بتكبيرها في مرحلتين مضبوطتين لتعزيز التفاصيل والدقة.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_sirolim_image_controlled_upscale', 'pt-BR', 'Wan2.2: Upscaler de Imagem em Dois Estágios', 'Faça upload de uma imagem e defina um fator de redimensionamento. Gere um prompt de IA a partir da sua imagem e aumente a resolução em dois estágios controlados para aprimorar detalhes e fidelidade.', 0, NULL, '2026-04-19T13:33:43.922Z');
