INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_ai_image_fix', 'es', 'Upscale: Mejora de imágenes con IA mediante Nano Banana Pro', 'Sube una imagen generada por IA para aumentar la resolución y mejorar los detalles. Genera una salida 4K con mayor nitidez y coherencia usando Nano Banana Pro.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_ai_image_fix', 'fr', 'Upscale : Amélioration d''images par IA avec Nano Banana Pro', 'Téléchargez une image générée par IA pour l''agrandir et améliorer les détails. Générez une sortie 4K avec une netteté et une cohérence améliorées grâce à Nano Banana Pro.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_ai_image_fix', 'ru', 'Upscale: Улучшение изображений с помощью ИИ и Nano Banana Pro', 'Загрузите изображение, созданное ИИ, для увеличения разрешения и улучшения деталей. Создайте 4K-вывод с улучшенной резкостью и согласованностью с помощью Nano Banana Pro.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_ai_image_fix', 'tr', 'Upscale: Nano Banana Pro ile AI Görüntü İyileştirme', 'Detayları büyütmek ve geliştirmek için bir AI tarafından oluşturulmuş görsel yükleyin. Nano Banana Pro kullanarak keskinliği ve tutarlılığı geliştirilmiş bir 4K çıktı oluşturun.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_ai_image_fix', 'ar', 'Upscale: تحسين الصور بالذكاء الاصطناعي باستخدام Nano Banana Pro', 'قم بتحميل صورة تم إنشاؤها بواسطة الذكاء الاصطناعي لزيادة الدقة وتحسين التفاصيل. أنشئ إخراج 4K بحدة وتماسك محسّنين باستخدام Nano Banana Pro.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_ai_image_fix', 'pt-BR', 'Upscale: Aprimoramento de Imagem com IA usando Nano Banana Pro', 'Faça upload de uma imagem gerada por IA para aumentar a resolução e aprimorar os detalhes. Gere uma saída 4K com nitidez e coerência aprimoradas usando o Nano Banana Pro.', 0, NULL, '2026-04-19T13:33:43.922Z');
