INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_video_enhance', 'en', 'Topaz Astra: Video Creative Upscale', 'Enhance videos with Topaz AI. Supports resolution upscaling using Starlight (Astra) Fast model and frame interpolation with apo-8 model.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_video_enhance', 'zh', 'Topaz Astra：视频创意增强', '使用 Topaz AI 增强视频。支持通过 Starlight（Astra）Fast 模型进行分辨率放大，并支持通过 apo-8 模型进行画面插帧。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_video_enhance', 'zh-TW', 'Topaz Astra：影片創意升級', '使用 Topaz AI 加強影片。支援以 Starlight（Astra）Fast 模型提升解析度，並以 apo-8 模型進行畫面插補。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_video_enhance', 'ja', 'Topaz Astra：クリエイティブ動画アップスケール', 'Topaz： AI で動画を高画質化。Starlight（Astra）Fastモデルによる解像度アップスケーリングと、apo-8モデルによるフレーム補間をサポートします。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_video_enhance', 'ko', 'Topaz Astra：창의적 비디오 업스케일', 'Topaz： AI로 비디오를 향상하세요. Starlight(Astra) Fast 모델을 통한 해상도 업스케일링과 apo-8 모델을 활용한 프레임 보간을 지원합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_video_enhance', 'es', 'Mejora Creativa de Video - Topaz Astra', 'Mejora vídeos con Topaz AI. Permite aumentar la resolución usando el modelo Starlight (Astra) Fast e interpolar fotogramas con el modelo apo-8.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_video_enhance', 'fr', 'Upscale Créatif Vidéo - Topaz Astra', 'Améliorez les vidéos avec Topaz AI. Prend en charge l’upscaling de résolution avec le modèle Starlight (Astra) Fast et l’interpolation d’images avec le modèle apo-8.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_video_enhance', 'ru', 'Креативное Улучшение Видео — Topaz Astra', 'Улучшайте видео с помощью Topaz AI. Поддерживает увеличение разрешения через модель Starlight (Astra) Fast и интерполяцию кадров с моделью apo-8.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_video_enhance', 'tr', 'Topaz Astra：Yaratıcı Video İyileştirme', 'Videoları Topaz AI ile iyileştirin. Çözünürlük yükseltme için Starlight (Astra) Fast modeli ve kare enterpolasyonu için apo-8 modeli desteklenir.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_video_enhance', 'ar', 'الارتقاء الإبداعي للفيديو - Topaz Astra', 'عزّز مقاطع الفيديو باستخدام Topaz AI. يدعم ترقية الدقة باستخدام نموذج Starlight (Astra) Fast واستكمال الإطارات بنموذج apo-8.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_topaz_video_enhance', 'pt-BR', 'Upscale Criativo de Vídeo - Topaz Astra', 'Aprimore vídeos com Topaz AI. Suporta upscale de resolução usando o modelo Starlight (Astra) Fast e interpolação de quadros com o modelo apo-8.', 0, NULL, '2026-04-19T13:33:43.922Z');
