INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_topaz_illustration_upscale', 'zh', '放大：使用 Topaz 进行插画放大', '上传插图以使用Topaz进行放大。生成平滑、风格化的图像，色彩准确，但可能会出现一些伪影。', 0, NULL, '2026-04-19T13:33:43.922Z');
