INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_topaz_illustration_upscale', 'ja', 'アップスケール：Topaz によるイラストのアップスケール', 'Topazを使用して拡大するイラストをアップロードしてください。正確な色合いで滑らかでスタイリッシュな画像を生成しますが、一部のアーティファクトが現れる場合があります。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_topaz_illustration_upscale', 'ko', '업스케일: Topaz를 사용한 일러스트 업스케일', 'Topaz를 사용하여 업스케일할 일러스트를 업로드하세요. 정확한 색상으로 부드럽고 스타일화된 이미지를 생성하지만 일부 아티팩트가 나타날 수 있습니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_topaz_illustration_upscale', 'es', 'Mejora de resolución: Mejora de ilustraciones con Topaz', 'Sube una ilustración para mejorar su resolución con Topaz. Genera una imagen suave y estilizada con colores precisos, aunque pueden aparecer algunos artefactos.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_topaz_illustration_upscale', 'fr', 'Amélioration d''échelle : Amélioration d''illustration avec Topaz', 'Téléchargez une illustration pour l''améliorer avec Topaz. Générez une image lisse et stylisée avec des couleurs précises, bien que certains artefacts puissent apparaître.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_topaz_illustration_upscale', 'ru', 'Увеличение масштаба: Увеличение иллюстрации с помощью Topaz', 'Загрузите иллюстрацию для увеличения разрешения с помощью Topaz. Создайте гладкое стилизованное изображение с точными цветами, хотя могут появиться некоторые артефакты.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_topaz_illustration_upscale', 'tr', 'Ölçek Büyütme: Topaz ile İllüstrasyon Ölçek Büyütme', 'Topaz kullanarak yükseltmek için bir illüstrasyon yükleyin. Doğru renklerle düzgün, stilize edilmiş bir görüntü oluşturun, ancak bazı artefaktlar görünebilir.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_topaz_illustration_upscale', 'ar', 'التحسين: تحسين الرسوم التوضيحية باستخدام Topaz', 'قم بتحميل رسم توضيحي لتحسين دقته باستخدام Topaz. أنشئ صورة ناعمة ومصممة بألوان دقيقة، على الرغم من أن بعض التشوهات قد تظهر.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_topaz_illustration_upscale', 'pt-BR', 'Aprimoramento: Aprimoramento de Ilustração com Topaz', 'Faça upload de uma ilustração para aprimorar usando o Topaz. Gere uma imagem suave e estilizada com cores precisas, embora alguns artefatos possam aparecer.', 0, NULL, '2026-04-19T13:33:43.922Z');
