INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_stability_upscale_fast', 'fr', 'Stability AI : Agrandissement rapide d''images', 'Téléchargez une image pour la suréchantillonner rapidement 4x via l''API Stability AI, idéal pour améliorer les images de faible qualité ou compressées.', 0, NULL, '2026-04-19T13:33:43.922Z');
