INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_illustration_upscale', 'zh', 'Upscale：使用Nano Banana Pro进行风格化艺术创意放大', '上传风格化艺术或插图。使用Nano Banana Pro模型生成创意升级的4K图像，增强细节，适合营销或游戏素材。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_illustration_upscale', 'zh-TW', 'Upscale：使用Nano Banana Pro進行風格化藝術創意放大', '上傳風格化藝術或插圖。使用Nano Banana Pro模型生成創意升級的4K圖像，增強細節，適合行銷或遊戲素材。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_illustration_upscale', 'ja', 'Upscale：Nano Banana Proによるスタイライズされたアートクリエイティブなアップスケール', 'スタイライズされたアートまたはイラストをアップロードしてください。Nano Banana Proモデルを使用して、詳細が強化された創造的にアップスケールされた4K画像を生成し、マーケティングやゲームアセットに最適です。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_illustration_upscale', 'ko', 'Upscale: Nano Banana Pro로 스타일화된 아트 크리에이티브 업스케일', '스타일화된 아트 또는 일러스트를 업로드하세요. Nano Banana Pro 모델을 사용하여 세부 사항이 향상된 창의적으로 업스케일된 4K 이미지를 생성하며, 마케팅 또는 게임 자산에 이상적입니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_illustration_upscale', 'es', 'Upscale: Arte estilizado, ampliación creativa con Nano Banana Pro', 'Sube un arte o ilustración estilizada. Genera una imagen 4K creativamente mejorada con detalles realzados usando el modelo Nano Banana Pro, ideal para recursos de marketing o videojuegos.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_illustration_upscale', 'fr', 'Upscale : Art stylisé, upscale créatif avec Nano Banana Pro', 'Téléchargez un art ou une illustration stylisée. Générez une image 4K créativement améliorée avec des détails renforcés en utilisant le modèle Nano Banana Pro, idéale pour les ressources marketing ou de jeu.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_illustration_upscale', 'ru', 'Upscale: Стилизованное искусство, творческое увеличение с Nano Banana Pro', 'Загрузите стилизованное искусство или иллюстрацию. Сгенерируйте творчески улучшенное 4K-изображение с усиленной детализацией с помощью модели Nano Banana Pro, идеально подходящее для маркетинговых или игровых активов.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_illustration_upscale', 'tr', 'Upscale: Nano Banana Pro ile Stilize Sanat Yaratıcı Büyütme', 'Stilize bir sanat veya illüstrasyon yükleyin. Nano Banana Pro modelini kullanarak gelişmiş detaylarla yaratıcı şekilde yükseltilmiş bir 4K görüntü oluşturun, pazarlama veya oyun varlıkları için idealdir.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_illustration_upscale', 'ar', 'Upscale: فن مُنمّق، تكبير إبداعي باستخدام Nano Banana Pro', 'قم بتحميل فن أو رسم توضيحي مُصمم. أنشئ صورة 4K مُحسنة بشكل إبداعي مع تفاصيل محسنة باستخدام نموذج Nano Banana Pro، مثالية لأصول التسويق أو الألعاب.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_illustration_upscale', 'pt-BR', 'Upscale: Arte estilizada, upscale criativo com Nano Banana Pro', 'Faça upload de uma arte ou ilustração estilizada. Gere uma imagem 4K criativamente aprimorada com detalhes realçados usando o modelo Nano Banana Pro, ideal para recursos de marketing ou jogos.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (411, 'utility_nanobanana_pro_product_upscale', 7, 24, 'Nano Banana Pro: Product Detail Enhancement', 'Upload a product image to enhance its detail and sharpness. Generate an upscaled, high-quality output with improved typography and realistic coherence using the Nano Banana Pro model.', 'image', 'webp', 'compareSlider', '[]', '["Image Upscale","Product"]', '["Nano Banana Pro"]', '[{"provider":"Google"}]', '[]', '[]', '{"inputs":[{"nodeId":2,"nodeType":"LoadImage","file":"orange_beauty_trio.png","mediaType":"image"}],"outputs":[{"nodeId":5,"nodeType":"SaveImage","file":"","mediaType":"image"}]}', NULL, NULL, '2026-02-02', 0, 'active', 0, 0, 153, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_product_upscale', 'en', 'Nano Banana Pro: Product Detail Enhancement', 'Upload a product image to enhance its detail and sharpness. Generate an upscaled, high-quality output with improved typography and realistic coherence using the Nano Banana Pro model.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_product_upscale', 'zh', '画质提升：使用Nano Banana Pro增强产品细节', '上传产品图片以增强其细节和清晰度。使用Nano Banana Pro模型生成放大、高质量的输出，具有改进的排版和逼真的连贯性。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_product_upscale', 'zh-TW', '畫質提升：使用Nano Banana Pro增強產品細節', '上傳產品圖片以增強其細節和清晰度。使用Nano Banana Pro模型生成放大、高品質的輸出，具有改進的排版和逼真的連貫性。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_product_upscale', 'ja', '画質向上：Nano Banana Proによる製品詳細の強化', '製品画像をアップロードして、その詳細と鮮明さを向上させます。Nano Banana Proモデルを使用して、改善されたタイポグラフィと現実的な一貫性を持つ、アップスケールされた高品質の出力を生成します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_product_upscale', 'ko', '화질 향상: Nano Banana Pro를 통한 제품 세부 사항 강화', '제품 이미지를 업로드하여 세부 사항과 선명도를 향상시킵니다. Nano Banana Pro 모델을 사용하여 개선된 타이포그래피와 현실적인 일관성을 가진 업스케일된 고품질 출력을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_product_upscale', 'es', 'Mejora de calidad: Potenciación de detalles del producto con Nano Banana Pro', 'Sube una imagen del producto para mejorar su detalle y nitidez. Genera una salida de alta calidad y ampliada con tipografía mejorada y coherencia realista utilizando el modelo Nano Banana Pro.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_product_upscale', 'fr', 'Amélioration de qualité : Renforcement des détails produit avec Nano Banana Pro', 'Téléchargez une image de produit pour améliorer ses détails et sa netteté. Générez une sortie de haute qualité et agrandie avec une typographie améliorée et une cohérence réaliste en utilisant le modèle Nano Banana Pro.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_product_upscale', 'ru', 'Повышение качества: Улучшение деталей продукта с Nano Banana Pro', 'Загрузите изображение продукта, чтобы улучшить его детализацию и четкость. Сгенерируйте увеличенный, высококачественный результат с улучшенной типографикой и реалистичной согласованностью с помощью модели Nano Banana Pro.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_product_upscale', 'tr', 'Kalite Yükseltme: Nano Banana Pro ile Ürün Detay Geliştirme', 'Ürün görselini detay ve keskinliğini artırmak için yükleyin. Nano Banana Pro modelini kullanarak geliştirilmiş tipografi ve gerçekçi tutarlılıkla yüksek kaliteli, ölçeklendirilmiş bir çıktı oluşturun.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_product_upscale', 'ar', 'تحسين الجودة: تعزيز تفاصيل المنتج باستخدام Nano Banana Pro', 'قم بتحميل صورة المنتج لتعزيز تفاصيلها ووضوحها. قم بإنشاء مخرجات عالية الجودة ومكبرة مع تحسين الطباعة والتماسك الواقعي باستخدام نموذج Nano Banana Pro.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_nanobanana_pro_product_upscale', 'pt-BR', 'Aprimoramento de qualidade: Melhoria de detalhes do produto com Nano Banana Pro', 'Faça upload de uma imagem do produto para aprimorar seus detalhes e nitidez. Gere uma saída de alta qualidade e ampliada com tipografia aprimorada e coerência realista usando o modelo Nano Banana Pro.', 0, NULL, '2026-04-19T13:33:43.922Z');
