INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_video_enhance', 'en', 'HitPaw: Video Enhancement and Upscaling', 'Upload a video to enhance and upscale. Generate a restored output with improved clarity, temporal stability, and optional portrait enhancement.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_video_enhance', 'zh', 'HitPaw 视频增强与放大', '上传视频以增强和提升画质。生成修复后的输出，具有更高的清晰度、时间稳定性以及可选的人像增强功能。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_video_enhance', 'zh-TW', 'HitPaw 影片增強與放大', '上傳影片以增強和提升畫質。生成修復後的輸出，具有更高的清晰度、時間穩定性以及可選的人像增強功能。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_video_enhance', 'ja', 'HitPaw ビデオエンハンスメントとアップスケーリング', '動画をアップロードして画質を向上・アップスケールします。鮮明さ、時間的安定性、オプションのポートレート強化を備えた修復済み出力を生成します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_video_enhance', 'ko', 'HitPaw 비디오 향상 및 업스케일링', '비디오를 업로드하여 화질을 향상하고 업스케일하세요. 선명도, 시간적 안정성 및 선택적 인물 향상 기능이 적용된 복원된 출력을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_video_enhance', 'es', 'HitPaw Mejora y Escalado de Video', 'Sube un video para mejorarlo y escalarlo. Genera una salida restaurada con mayor claridad, estabilidad temporal y mejora opcional de retratos.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_video_enhance', 'fr', 'HitPaw Amélioration et Suréchantillonnage Vidéo', 'Téléchargez une vidéo pour l''améliorer et l''upscaler. Générez une sortie restaurée avec une meilleure clarté, une stabilité temporelle et une amélioration optionnelle des portraits.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_video_enhance', 'ru', 'HitPaw Улучшение и Масштабирование Видео', 'Загрузите видео для улучшения и повышения качества. Создайте восстановленный результат с улучшенной четкостью, временной стабильностью и опциональным улучшением портретов.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_video_enhance', 'tr', 'HitPaw Video İyileştirme ve Ölçeklendirme', 'Bir videoyu geliştirmek ve yükseltmek için yükleyin. Gelişmiş netlik, zamansal kararlılık ve isteğe bağlı portre iyileştirmesi ile restore edilmiş bir çıktı oluşturun.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_video_enhance', 'ar', 'HitPaw تحسين وتكبير الفيديو', 'قم بتحميل مقطع فيديو لتحسينه ورفع جودته. أنشئ مخرجات مستعادة مع وضوح محسن، واستقرار زمني، وتحسين اختياري للصور الشخصية.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_video_enhance', 'pt-BR', 'HitPaw Aprimoramento e Aumento de Vídeo', 'Faça upload de um vídeo para aprimorar e aumentar a qualidade. Gere uma saída restaurada com melhor clareza, estabilidade temporal e aprimoramento opcional de retratos.', 0, NULL, '2026-04-19T13:33:43.922Z');
