INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_general_image_enhance', 'en', 'HitPaw: Portrait Diffusion Upscaler', 'Upload a low-quality portrait image and adjust the upscaling factor. Generate a high-fidelity, detailed portrait with enhanced skin textures and facial features.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_general_image_enhance', 'zh', 'HitPaw 肖像扩散放大工具', '上传一张低质量人像图片并调整放大倍数。生成一张高保真、细节丰富的人像，增强皮肤纹理和面部特征。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_general_image_enhance', 'zh-TW', 'HitPaw 肖像擴散放大工具', '上傳一張低品質人像圖片並調整放大倍數。生成一張高保真、細節豐富的人像，增強皮膚紋理和面部特徵。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_general_image_enhance', 'ja', 'HitPaw ポートレート拡散アップスケーラー', '低品質のポートレート画像をアップロードし、アップスケーリング係数を調整します。皮膚の質感や顔の特徴が強化された、高精細で詳細なポートレートを生成します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_general_image_enhance', 'ko', 'HitPaw 초상화 확산 업스케일러', '저화질 초상화 이미지를 업로드하고 업스케일링 배율을 조정하세요. 향상된 피부 질감과 얼굴 특징을 가진 고화질의 디테일한 초상화를 생성합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_general_image_enhance', 'es', 'HitPaw Escalador de Difusión de Retratos', 'Sube una imagen de retrato de baja calidad y ajusta el factor de ampliación. Genera un retrato de alta fidelidad y detallado con texturas de piel y rasgos faciales mejorados.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_general_image_enhance', 'fr', 'HitPaw Suréchantillonneur par Diffusion de Portraits', 'Téléchargez une image portrait de faible qualité et ajustez le facteur de suréchantillonnage. Générez un portrait haute fidélité et détaillé avec des textures de peau et des traits du visage améliorés.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_general_image_enhance', 'ru', 'HitPaw Портретный диффузионный апскейлер', 'Загрузите некачественное портретное изображение и отрегулируйте коэффициент увеличения. Создайте высокодетализированный портрет с улучшенной текстурой кожи и чертами лица.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_general_image_enhance', 'tr', 'HitPaw Portre Difüzyon Yükseltici', 'Düşük kaliteli bir portre görseli yükleyin ve yükseltme faktörünü ayarlayın. Geliştirilmiş cilt dokuları ve yüz özellikleriyle yüksek kaliteli, detaylı bir portre oluşturun.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_general_image_enhance', 'ar', 'HitPaw مُحسّن الانتشار للصور الشخصية', 'قم بتحميل صورة بورتريه منخفضة الجودة واضبط عامل التكبير. أنشئ بورتريه عالي الدقة ومفصل مع تحسين نسيج البشرة وميزات الوجه.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('ultility_hitpaw_general_image_enhance', 'pt-BR', 'HitPaw Ampliador de Difusão de Retratos', 'Faça upload de uma imagem de retrato de baixa qualidade e ajuste o fator de ampliação. Gere um retrato de alta fidelidade e detalhado com texturas de pele e características faciais aprimoradas.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (414, 'utility_recraft_creative_image_upscale', 7, 27, 'Recraft: Creative Image Enhancement Upscaler', 'Upload an image to enhance and upscale it. Recraft''s AI reconstructs details and improves textures, outputting a higher-quality image with a natural appearance.', 'image', 'webp', 'compareSlider', '["input/butterfly_girl.png","output/utility_recraft_creative_image_upscale.png"]', '["API","Image Upscale"]', '["Recraft"]', '[{"provider":"Recraft"}]', '[]', '[]', '{"inputs":[{"nodeId":2,"nodeType":"LoadImage","file":"butterfly_girl.png","mediaType":"image"}],"outputs":[{"nodeId":3,"nodeType":"SaveImage","file":"utility_recraft_creative_image_upscale.png","mediaType":"image"}]}', NULL, NULL, '2026-02-02', 0, 'active', 0, 0, 26, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_creative_image_upscale', 'en', 'Recraft: Creative Image Enhancement Upscaler', 'Upload an image to enhance and upscale it. Recraft''s AI reconstructs details and improves textures, outputting a higher-quality image with a natural appearance.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_creative_image_upscale', 'zh', 'Recraft：创意图像增强放大工具', '上传图像以增强和放大。Recraft的AI重建细节并改善纹理，输出具有自然外观的更高质量图像。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_creative_image_upscale', 'zh-TW', 'Recraft：創意圖像增強放大工具', '上傳圖像以增強和放大。Recraft的AI重建細節並改善紋理，輸出具有自然外觀的更高品質圖像。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_creative_image_upscale', 'ja', 'Recraft：クリエイティブ画像エンハンスメントアップスケーラー', '画像をアップロードして強化・拡大します。RecraftのAIが詳細を再構築しテクスチャを改善し、自然な外観の高品質な画像を出力します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_creative_image_upscale', 'ko', 'Recraft: 창의적 이미지 향상 업스케일러', '이미지를 업로드하여 향상 및 업스케일하세요. Recraft의 AI가 세부 사항을 재구성하고 질감을 개선하여 자연스러운 외관의 고품질 이미지를 출력합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_creative_image_upscale', 'es', 'Recraft: Mejorador creativo de imágenes y escalador', 'Sube una imagen para mejorarla y ampliarla. La IA de Recraft reconstruye detalles y mejora texturas, generando una imagen de mayor calidad con apariencia natural.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_creative_image_upscale', 'fr', 'Recraft : Améliorateur créatif d''images et suréchantillonneur', 'Téléchargez une image pour l''améliorer et l''agrandir. L''IA de Recraft reconstruit les détails et améliore les textures, produisant une image de qualité supérieure avec un aspect naturel.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_creative_image_upscale', 'ru', 'Recraft: Креативный усилитель и апскейлер изображений', 'Загрузите изображение для улучшения и увеличения. ИИ Recraft восстанавливает детали и улучшает текстуры, выводя изображение более высокого качества с естественным видом.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_creative_image_upscale', 'tr', 'Recraft: Yaratıcı Görüntü İyileştirme ve Büyütücü', 'Bir görseli geliştirmek ve büyütmek için yükleyin. Recraft''ın AI''sı detayları yeniden oluşturur ve dokuları iyileştirir, doğal görünümlü daha yüksek kaliteli bir görsel çıktılar.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_creative_image_upscale', 'ar', 'Recraft: مُحسّن الصور الإبداعي ومُكبّر الدقة', 'قم بتحميل صورة لتحسينها وتكبيرها. الذكاء الاصطناعي من Recraft يعيد بناء التفاصيل ويحسن القوام، لينتج صورة عالية الجودة بمظهر طبيعي.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_creative_image_upscale', 'pt-BR', 'Recraft: Aprimorador Criativo de Imagens e Upscaler', 'Faça upload de uma imagem para aprimorá-la e ampliá-la. A IA do Recraft reconstrói detalhes e melhora texturas, gerando uma imagem de qualidade superior com aparência natural.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (415, 'utility_recraft_crisp_image_upscale', 7, 28, 'Recraft: Crisp Upscale Image Restoration', 'Upload a low-resolution or noisy image to restore and upscale. Generate a high-resolution output with enhanced details, reduced artifacts, and preserved natural look.', 'image', 'webp', 'compareSlider', '["input/man_with_rose.png","output/utility_recraft_crisp_image_upscale.png"]', '["API","Image Upscale"]', '["Recraft"]', '[{"provider":"Recraft"}]', '[]', '[]', '{"inputs":[{"nodeId":2,"nodeType":"LoadImage","file":"man_with_rose.png","mediaType":"image"}],"outputs":[{"nodeId":3,"nodeType":"SaveImage","file":"utility_recraft_crisp_image_upscale.png","mediaType":"image"}]}', NULL, NULL, '2026-02-02', 0, 'active', 0, 0, 44, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_crisp_image_upscale', 'en', 'Recraft: Crisp Upscale Image Restoration', 'Upload a low-resolution or noisy image to restore and upscale. Generate a high-resolution output with enhanced details, reduced artifacts, and preserved natural look.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_crisp_image_upscale', 'zh', 'Recraft：清晰图像超分辨率修复', '上传低分辨率或噪点图像进行修复和放大。生成高分辨率输出，增强细节，减少伪影，保持自然外观。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_crisp_image_upscale', 'zh-TW', 'Recraft：清晰圖像超解析度修復', '上傳低解析度或噪點影像進行修復和放大。生成高解析度輸出，增強細節，減少偽影，保持自然外觀。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_crisp_image_upscale', 'ja', 'Recraft：鮮明な高解像度画像修復', '低解像度またはノイズの多い画像をアップロードして修復およびアップスケールします。高解像度の出力を生成し、詳細を強化、アーティファクトを低減、自然な見た目を維持します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_crisp_image_upscale', 'ko', 'Recraft：선명한 고해상도 이미지 복원', '저해상도 또는 노이즈가 있는 이미지를 업로드하여 복원 및 업스케일합니다. 향상된 디테일, 감소된 아티팩트, 자연스러운 외관을 유지한 고해상도 출력을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_crisp_image_upscale', 'es', 'Recraft: Restauración de imágenes nítidas en alta resolución', 'Sube una imagen de baja resolución o con ruido para restaurarla y ampliarla. Genera una salida de alta resolución con detalles mejorados, artefactos reducidos y apariencia natural preservada.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_crisp_image_upscale', 'fr', 'Recraft : Restauration nette d''images en haute résolution', 'Téléchargez une image basse résolution ou bruitée pour la restaurer et l''agrandir. Générez une sortie haute résolution avec des détails améliorés, des artefacts réduits et un aspect naturel préservé.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_crisp_image_upscale', 'ru', 'Recraft: Четкое восстановление изображений с повышением разрешения', 'Загрузите изображение низкого разрешения или с шумами для восстановления и увеличения. Создайте высококачественный результат с улучшенными деталями, уменьшенными артефактами и сохраненным естественным видом.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_crisp_image_upscale', 'tr', 'Recraft: Net Yüksek Çözünürlüklü Görüntü Restorasyonu', 'Düşük çözünürlüklü veya gürültülü bir görüntüyü yükleyerek onarın ve büyütün. Geliştirilmiş detaylar, azaltılmış artefaktlar ve korunmuş doğal görünüm ile yüksek çözünürlüklü bir çıktı oluşturun.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_crisp_image_upscale', 'ar', 'Recraft: استعادة الصور بدقة عالية ووضوح', 'قم بتحميل صورة منخفضة الدقة أو مليئة بالضوضاء لاستعادتها وتكبيرها. أنشئ مخرجات عالية الدقة مع تفاصيل محسنة، وقطع أثرية مخفضة، ومظهر طبيعي محفوظ.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_recraft_crisp_image_upscale', 'pt-BR', 'Recraft: Restauração de Imagens Nítidas em Alta Resolução', 'Faça upload de uma imagem de baixa resolução ou com ruído para restaurar e ampliar. Gere uma saída de alta resolução com detalhes aprimorados, artefatos reduzidos e aparência natural preservada.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (416, 'api_wavespped_seedvr2_ai_image_fix', 7, 29, 'WaveSpeed: AI Image Restoration with SeedVR2', 'Upload an AI-generated image to restore details and upscale. The workflow preserves colors and sharpness while minimizing artifacts. Output is a high-quality, enlarged version of your input.', 'image', 'webp', 'compareSlider', '["input/midnight_coasta.png","output/api_wavespped_seedvr2_ai_image_fix.png"]', '["API","Image Upscale"]', '["SeedVR2","WaveSpeed"]', '[{"provider":"WaveSpeed"}]', '[]', '[]', '{"inputs":[{"nodeId":9,"nodeType":"LoadImage","file":"midnight_coasta.png","mediaType":"image"}],"outputs":[{"nodeId":3,"nodeType":"SaveImage","file":"api_wavespped_seedvr2_ai_image_fix.png","mediaType":"image"}]}', NULL, NULL, '2026-02-02', 0, 'active', 0, 0, 150, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_seedvr2_ai_image_fix', 'en', 'WaveSpeed: AI Image Restoration with SeedVR2', 'Upload an AI-generated image to restore details and upscale. The workflow preserves colors and sharpness while minimizing artifacts. Output is a high-quality, enlarged version of your input.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_seedvr2_ai_image_fix', 'zh', 'Upscale：使用 WaveSpeed SeedVR2 进行 AI 图像修复', '上传AI生成的图像以恢复细节并放大。工作流程在保留颜色和锐度的同时最小化伪影。输出为高质量、放大后的输入版本。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_seedvr2_ai_image_fix', 'zh-TW', 'Upscale：使用 WaveSpeed SeedVR2 進行 AI 影像修復', '上傳AI生成的圖像以恢復細節並放大。工作流程在保留顏色和銳度的同時最小化偽影。輸出為高品質、放大後的輸入版本。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_seedvr2_ai_image_fix', 'ja', 'Upscale：WaveSpeed SeedVR2 による AI 画像修復', 'AI生成画像をアップロードして詳細を復元し、アップスケールします。ワークフローは色とシャープネスを維持しながらアーティファクトを最小限に抑えます。出力は高品質で拡大された入力画像です。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_seedvr2_ai_image_fix', 'ko', 'Upscale：WaveSpeed SeedVR2를 이용한 AI 이미지 복원', 'AI 생성 이미지를 업로드하여 세부 사항을 복원하고 업스케일하세요. 워크플로우는 색상과 선명도를 보존하면서 아티팩트를 최소화합니다. 출력은 입력된 이미지의 고품질 확대 버전입니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_seedvr2_ai_image_fix', 'es', 'Upscale: Restauración de imágenes con IA mediante WaveSpeed SeedVR2', 'Sube una imagen generada por IA para restaurar detalles y aumentar la resolución. El flujo de trabajo preserva colores y nitidez mientras minimiza artefactos. La salida es una versión ampliada y de alta calidad de tu entrada.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_seedvr2_ai_image_fix', 'fr', 'Upscale : Restauration d''images par IA avec WaveSpeed SeedVR2', 'Téléchargez une image générée par IA pour restaurer les détails et augmenter la résolution. Le flux de travail préserve les couleurs et la netteté tout en minimisant les artefacts. Le résultat est une version agrandie et de haute qualité de votre image d''entrée.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_seedvr2_ai_image_fix', 'ru', 'Upscale: Восстановление изображений с помощью ИИ и WaveSpeed SeedVR2', 'Загрузите изображение, созданное ИИ, для восстановления деталей и увеличения масштаба. Рабочий процесс сохраняет цвета и резкость, сводя к минимуму артефакты. Результат — высококачественная увеличенная версия вашего исходного изображения.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_seedvr2_ai_image_fix', 'tr', 'Upscale: WaveSpeed SeedVR2 ile AI Görüntü Restorasyonu', 'Detayları geri yüklemek ve ölçeği büyütmek için bir AI tarafından oluşturulmuş görsel yükleyin. İş akışı, renkleri ve keskinliği korurken artefaktları en aza indirir. Çıktı, girdinizin yüksek kaliteli, büyütülmüş bir versiyonudur.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_seedvr2_ai_image_fix', 'ar', 'Upscale: استعادة الصور بالذكاء الاصطناعي باستخدام WaveSpeed SeedVR2', 'قم بتحميل صورة تم إنشاؤها بواسطة الذكاء الاصطناعي لاستعادة التفاصيل وزيادة الدقة. يحافظ سير العمل على الألوان والوضوح مع تقليل التشوهات إلى الحد الأدنى. الناتج هو نسخة عالية الجودة ومكبرة من المدخلات الخاصة بك.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_seedvr2_ai_image_fix', 'pt-BR', 'Upscale: Restauração de Imagens com IA usando WaveSpeed SeedVR2', 'Faça upload de uma imagem gerada por IA para restaurar detalhes e aumentar a escala. O fluxo de trabalho preserva cores e nitidez enquanto minimiza artefatos. A saída é uma versão ampliada e de alta qualidade da sua entrada.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (417, 'api_wavespped_image_upscale', 7, 30, 'WaveSpeed: Image Upscale', 'Upload an image to upscale its resolution. Generate an enhanced 2K, 4K, or 8K output that preserves details and reduces artifacts in JPEG, PNG, or WEBP format.', 'image', 'webp', 'compareSlider', '["input/woman_behind_veil.png","output/api_wavespped_image_upscale.png"]', '["API","Image Upscale"]', '["WaveSpeed"]', '[{"provider":"WaveSpeed"}]', '[]', '[]', '{"inputs":[{"nodeId":9,"nodeType":"LoadImage","file":"woman_behind_veil.png","mediaType":"image"}],"outputs":[{"nodeId":3,"nodeType":"SaveImage","file":"api_wavespped_image_upscale.png","mediaType":"image"}]}', NULL, NULL, '2026-01-23', 0, 'active', 0, 0, 206, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_image_upscale', 'en', 'WaveSpeed: Image Upscale', 'Upload an image to upscale its resolution. Generate an enhanced 2K, 4K, or 8K output that preserves details and reduces artifacts in JPEG, PNG, or WEBP format.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_image_upscale', 'zh', 'WaveSpeed：图像放大', '上传图像以提升其分辨率。生成增强的2K、4K或8K输出，保留细节并减少JPEG、PNG或WEBP格式的伪影。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_image_upscale', 'zh-TW', 'WaveSpeed：影像放大', '上傳圖像以提升其解析度。生成增強的2K、4K或8K輸出，保留細節並減少JPEG、PNG或WEBP格式的偽影。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_image_upscale', 'ja', 'WaveSpeed：画像アップスケール', '画像をアップロードして解像度をアップスケールします。詳細を保持し、JPEG、PNG、またはWEBP形式でのアーティファクトを軽減した、強化された2K、4K、または8Kの出力を生成します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_image_upscale', 'ko', 'WaveSpeed：이미지 업스케일', '이미지를 업로드하여 해상도를 향상시키세요. 세부 사항을 보존하고 JPEG, PNG 또는 WEBP 형식의 아티팩트를 줄인 향상된 2K, 4K 또는 8K 출력을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_image_upscale', 'es', 'WaveSpeed: Escalado de imagen', 'Sube una imagen para mejorar su resolución. Genera una salida mejorada de 2K, 4K u 8K que preserve los detalles y reduzca los artefactos en formato JPEG, PNG o WEBP.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_image_upscale', 'fr', 'WaveSpeed : Agrandissement d''image', 'Téléchargez une image pour améliorer sa résolution. Générez une sortie améliorée en 2K, 4K ou 8K qui préserve les détails et réduit les artefacts aux formats JPEG, PNG ou WEBP.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_image_upscale', 'ru', 'WaveSpeed: Увеличение изображения', 'Загрузите изображение для повышения его разрешения. Создайте улучшенный вывод 2K, 4K или 8K, который сохраняет детали и уменьшает артефакты в форматах JPEG, PNG или WEBP.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_image_upscale', 'tr', 'WaveSpeed: Görüntü Büyütme', 'Çözünürlüğünü artırmak için bir görsel yükleyin. JPEG, PNG veya WEBP formatında detayları koruyan ve yapaylıkları azaltan geliştirilmiş 2K, 4K veya 8K çıktı oluşturun.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_image_upscale', 'ar', 'WaveSpeed: تكبير الصورة', 'قم بتحميل صورة لتحسين دقتها. أنتج مخرجات محسّنة بدقة 2K أو 4K أو 8K تحافظ على التفاصيل وتقلل من التشوهات بصيغة JPEG أو PNG أو WEBP.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespped_image_upscale', 'pt-BR', 'WaveSpeed: Aumento de Imagem', 'Faça upload de uma imagem para aprimorar sua resolução. Gere uma saída aprimorada em 2K, 4K ou 8K que preserve os detalhes e reduza artefatos nos formatos JPEG, PNG ou WEBP.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (418, 'api_wavespeed_flshvsr_video_upscale', 7, 31, 'WaveSpeed: FlashVSR Video Upscale', 'Upload a video to upscale it to 720p, 1080p, 2K, or 4K. The workflow enhances detail, reduces artifacts, and ensures consistent motion for a high-quality, natural-looking output.', 'image', 'webp', 'compareSlider', '[]', '["API","Video Upscale"]', '["FlashVSR","WaveSpeed"]', '[{"provider":"WaveSpeed"}]', '[]', '[]', '{"inputs":[{"nodeId":4,"nodeType":"LoadVideo","file":"lighter.mp4","mediaType":"video"}],"outputs":[{"nodeId":3,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-01-23', 0, 'active', 0, 0, 74, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespeed_flshvsr_video_upscale', 'en', 'WaveSpeed: FlashVSR Video Upscale', 'Upload a video to upscale it to 720p, 1080p, 2K, or 4K. The workflow enhances detail, reduces artifacts, and ensures consistent motion for a high-quality, natural-looking output.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespeed_flshvsr_video_upscale', 'zh', 'WaveSpeed：FlashVSR 视频超分辨率', '上传视频以将其升级至720p、1080p、2K或4K。该工作流程可增强细节、减少伪影并确保运动一致，从而获得高质量、自然观感的输出。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespeed_flshvsr_video_upscale', 'zh-TW', 'WaveSpeed：FlashVSR 影片超解析度', '上傳影片以將其升級至720p、1080p、2K或4K。該工作流程可增強細節、減少偽影並確保運動一致，從而獲得高品質、自然觀感的輸出。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespeed_flshvsr_video_upscale', 'ja', 'WaveSpeed：FlashVSR ビデオアップスケール', '動画をアップロードして720p、1080p、2K、または4Kにアップスケールできます。このワークフローは詳細を強化、アーティファクトを低減し、動きの一貫性を確保することで、高品質で自然な見た目の出力を実現します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespeed_flshvsr_video_upscale', 'ko', 'WaveSpeed: FlashVSR 비디오 업스케일', '동영상을 업로드하여 720p, 1080p, 2K 또는 4K로 업스케일하세요. 이 워크플로우는 디테일을 향상시키고 아티팩트를 줄이며 일관된 모션을 보장하여 고품질의 자연스러운 출력물을 제공합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespeed_flshvsr_video_upscale', 'es', 'WaveSpeed: Superresolución de video FlashVSR', 'Sube un vídeo para escalarlo a 720p, 1080p, 2K o 4K. El flujo de trabajo mejora el detalle, reduce artefactos y garantiza un movimiento consistente para una salida de alta calidad y apariencia natural.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespeed_flshvsr_video_upscale', 'fr', 'WaveSpeed : Suréchantillonnage vidéo FlashVSR', 'Téléversez une vidéo pour la convertir en 720p, 1080p, 2K ou 4K. Le flux de travail améliore les détails, réduit les artefacts et assure un mouvement cohérent pour un résultat de haute qualité et d''apparence naturelle.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespeed_flshvsr_video_upscale', 'ru', 'WaveSpeed: Увеличение разрешения видео FlashVSR', 'Загрузите видео, чтобы повысить его качество до 720p, 1080p, 2K или 4K. Рабочий процесс улучшает детализацию, снижает артефакты и обеспечивает плавность движения для получения высококачественного, естественно выглядящего результата.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespeed_flshvsr_video_upscale', 'tr', 'WaveSpeed: FlashVSR Video Yükseltme', 'Bir videoyu 720p, 1080p, 2K veya 4K''ya yükseltmek için yükleyin. İş akışı, yüksek kaliteli ve doğal görünümlü bir çıktı için detayları geliştirir, artefaktları azaltır ve tutarlı hareket sağlar.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespeed_flshvsr_video_upscale', 'ar', 'WaveSpeed: رفع دقة فيديو FlashVSR', 'قم بتحميل مقطع فيديو لرفع دقته إلى 720p أو 1080p أو 2K أو 4K. تدفق العمل يعزز التفاصيل، ويقلل من التشوهات، ويضمن حركة متناسقة للحصول على مخرج عالي الجودة وذو مظهر طبيعي.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_wavespeed_flshvsr_video_upscale', 'pt-BR', 'WaveSpeed: Superamostragem de Vídeo FlashVSR', 'Faça upload de um vídeo para aprimorá-lo para 720p, 1080p, 2K ou 4K. O fluxo de trabalho aprimora os detalhes, reduz artefatos e garante movimento consistente para uma saída de alta qualidade e aparência natural.', 0, NULL, '2026-04-19T13:33:43.922Z');
