INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_vidu_video_extension', 'tr', 'Vidu: Video Uzantısı', 'Bir video yükleyin ve Vidu Q2 modelini kullanarak 7 saniyeye kadar uzatın ve çözünürlüğü 1080p''ye yükseltin.', 0, NULL, '2026-04-19T13:33:43.922Z');
