INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_relight', 'en', 'Magnific: Image Relight', 'Upload a source image and a reference lighting image. Generate a relit version of your source image, applying the lighting conditions from the reference.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_relight', 'zh', 'Magnific：图像重光', '上传源图像和参考光照图像。根据参考图像的光照条件，生成源图像的重新光照版本。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_relight', 'zh-TW', 'Magnific：圖像重光', '上傳源圖像和參考光照圖像。根據參考圖像的光照條件，生成源圖像的重新光照版本。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_relight', 'ja', 'Magnific：画像リライト', 'ソース画像と参照照明画像をアップロードします。参照画像の照明条件を適用して、ソース画像の再照明バージョンを生成します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_relight', 'ko', 'Magnific：이미지 재조명', '소스 이미지와 참조 조명 이미지를 업로드하세요. 참조 이미지의 조명 조건을 적용하여 소스 이미지의 재조명 버전을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_relight', 'es', 'Magnific: Reiluminación de Imágenes', 'Sube una imagen fuente y una imagen de iluminación de referencia. Genera una versión reiluminada de tu imagen fuente, aplicando las condiciones de iluminación de la referencia.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_relight', 'fr', 'Magnific : Rééclairage d''Image', 'Téléchargez une image source et une image d''éclairage de référence. Générez une version rééclairée de votre image source en appliquant les conditions d''éclairage de la référence.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_relight', 'ru', 'Magnific: Переосвещение Изображений', 'Загрузите исходное изображение и эталонное изображение освещения. Сгенерируйте переосвещенную версию вашего исходного изображения, применяя условия освещения из эталона.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_relight', 'tr', 'Magnific: Görsel Yeniden Aydınlatma', 'Bir kaynak görsel ve bir referans aydınlatma görseli yükleyin. Referanstaki aydınlatma koşullarını uygulayarak kaynak görselinizin yeniden aydınlatılmış bir versiyonunu oluşturun.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_relight', 'ar', 'Magnific: إعادة إضاءة الصورة', 'قم بتحميل صورة مصدر وصورة إضاءة مرجعية. قم بإنشاء نسخة معاد إضاءتها من صورتك المصدر، مع تطبيق ظروف الإضاءة من المرجع.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_image_relight', 'pt-BR', 'Magnific: Reiluminação de Imagem', 'Faça upload de uma imagem de origem e uma imagem de iluminação de referência. Gere uma versão com iluminação ajustada da sua imagem de origem, aplicando as condições de iluminação da referência.', 0, NULL, '2026-04-19T13:33:43.922Z');
