INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_skin_enhancer', 'en', 'Magnific: Skin Enhancer', 'Enhance skin and overall image quality by uploading your image and selecting a preset to adjust lighting, color grading, and realism.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_skin_enhancer', 'zh', 'Magnific：皮肤增强', '通过上传您的图像并选择预设来调整光照、色彩分级和真实感，从而提升皮肤和整体图像质量。', 0, NULL, '2026-04-19T13:33:43.922Z');
