INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_magnific_skin_enhancer', 'ja', 'Magnific：スキンエンハンサー', '画像をアップロードし、プリセットを選択して照明、カラーグレーディング、リアリズムを調整することで、肌と全体の画質を向上させます。', 0, NULL, '2026-04-19T13:33:43.922Z');
