INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux1_expand_image', 'ru', 'Flux.1: Расширение изображения', 'Загрузите изображение, чтобы расширить его холст с помощью Flux.1. Сгенерируйте изображение с внешней отрисовкой и расширенным содержимым.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux1_expand_image', 'tr', 'Flux.1: Görüntü Genişletme', 'Flux.1 kullanarak tuvalini genişletmek için bir görsel yükleyin. Genişletilmiş içerikle dış boyama görseli oluşturun.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux1_expand_image', 'ar', 'Flux.1: توسيع الصورة', 'قم بتحميل صورة لتوسيع لوحتها باستخدام Flux.1. قم بإنشاء صورة مرسومة خارجيًا بمحتوى موسع.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('api_bfl_flux1_expand_image', 'pt-BR', 'Flux.1: Extensão de Imagem', 'Faça upload de uma imagem para expandir sua tela usando o Flux.1. Gere uma imagem com pintura externa com conteúdo estendido.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (426, 'utility-gan_upscaler', 7, 39, 'Fast GAN Video Upscaler', 'Upload a video to upscale it using a fast GAN model. The output resolution is determined by your chosen model (e.g., 2x or 4x). For best results, upscale first, then resize to your target resolution.', 'image', 'webp', 'compareSlider', '[]', '["Video Upscale","API"]', '["Real-ESRGAN"]', '[]', '[]', '[]', '{"inputs":[{"nodeId":9,"nodeType":"LoadVideo","file":"gan_input.mp4","mediaType":"video"}],"outputs":[{"nodeId":12,"nodeType":"SaveVideo","file":"","mediaType":"video"}]}', NULL, NULL, '2026-01-26', 1, 'active', 0, 0, 143, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-gan_upscaler', 'en', 'Fast GAN Video Upscaler', 'Upload a video to upscale it using a fast GAN model. The output resolution is determined by your chosen model (e.g., 2x or 4x). For best results, upscale first, then resize to your target resolution.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-gan_upscaler', 'zh', '快速GAN视频增强器', '上传视频以使用快速GAN模型进行超分辨率处理。输出分辨率由您选择的模型决定（例如2倍或4倍）。为获得最佳效果，请先进行超分辨率处理，然后调整至目标分辨率。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-gan_upscaler', 'zh-TW', '快速GAN影片增強器', '上傳影片以使用快速GAN模型進行超解析度處理。輸出解析度由您選擇的模型決定（例如2倍或4倍）。為獲得最佳效果，請先進行超解析度處理，然後調整至目標解析度。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-gan_upscaler', 'ja', '高速GAN動画アップスケーラー', '高速GANモデルを使用して動画をアップスケールするには、動画をアップロードしてください。出力解像度は選択したモデル（例：2倍または4倍）によって決まります。最良の結果を得るには、まずアップスケールを行い、その後目標解像度にリサイズしてください。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-gan_upscaler', 'ko', '빠른 GAN 비디오 업스케일러', '빠른 GAN 모델을 사용하여 비디오를 업스케일하려면 비디오를 업로드하세요. 출력 해상도는 선택한 모델(예: 2배 또는 4배)에 따라 결정됩니다. 최상의 결과를 얻으려면 먼저 업스케일한 후 목표 해상도로 크기를 조정하세요.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-gan_upscaler', 'es', 'Mejorador de video GAN rápido', 'Sube un vídeo para mejorarlo usando un modelo GAN rápido. La resolución de salida la determina el modelo que elijas (por ejemplo, 2x o 4x). Para obtener los mejores resultados, mejora primero la resolución y luego redimensiona a la resolución objetivo.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-gan_upscaler', 'fr', 'Améliorateur vidéo GAN rapide', 'Téléchargez une vidéo pour l''améliorer à l''aide d''un modèle GAN rapide. La résolution de sortie est déterminée par le modèle choisi (par exemple, 2x ou 4x). Pour de meilleurs résultats, améliorez d''abord la résolution, puis redimensionnez à la résolution cible.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-gan_upscaler', 'ru', 'Быстрый апскейлер видео на GAN', 'Загрузите видео для повышения его качества с помощью быстрой GAN-модели. Выходное разрешение определяется выбранной моделью (например, 2x или 4x). Для наилучших результатов сначала повысьте разрешение, а затем измените размер до целевого разрешения.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-gan_upscaler', 'tr', 'Hızlı GAN Video Yükseltici', 'Hızlı bir GAN modeli kullanarak bir videoyu yükseltmek için videoyu yükleyin. Çıktı çözünürlüğü seçtiğiniz modele (örneğin 2x veya 4x) göre belirlenir. En iyi sonuçlar için önce yükseltme yapın, ardından hedef çözünürlüğe yeniden boyutlandırın.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-gan_upscaler', 'ar', 'محسن فيديو GAN السريع', 'قم بتحميل مقطع فيديو لتحسين دقته باستخدام نموذج GAN سريع. يتم تحديد دقة الإخراج بواسطة النموذج الذي تختاره (مثل 2x أو 4x). للحصول على أفضل النتائج، قم بتحسين الدقة أولاً، ثم غيّر الحجم إلى الدقة المستهدفة.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility-gan_upscaler', 'pt-BR', 'Melhorador de Vídeo GAN Rápido', 'Faça upload de um vídeo para aprimorá-lo usando um modelo GAN rápido. A resolução de saída é determinada pelo modelo escolhido (por exemplo, 2x ou 4x). Para obter os melhores resultados, aprimore primeiro a resolução e depois redimensione para a resolução desejada.', 0, NULL, '2026-04-19T13:33:43.922Z');
