INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_interpolation_image_upscale', 'en', 'Image Upscale: Traditional Interpolation', 'Upload an image and select an interpolation method. Upscale the image using traditional algorithms for faster processing with minimal detail changes.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_interpolation_image_upscale', 'zh', '图像放大：传统插值', '上传图像并选择插值方法。使用传统算法放大图像，以实现更快的处理速度，同时保持细节变化最小。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_interpolation_image_upscale', 'zh-TW', '影像放大：傳統插值', '上傳圖像並選擇插值方法。使用傳統算法放大圖像，以實現更快的處理速度，同時保持細節變化最小。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_interpolation_image_upscale', 'ja', '画像アップスケール：従来の補間', '画像をアップロードし、補間方法を選択してください。従来のアルゴリズムを使用して画像を拡大し、詳細の変更を最小限に抑えながら処理を高速化します。', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_interpolation_image_upscale', 'ko', '이미지 업스케일: 전통적인 보간', '이미지를 업로드하고 보간 방법을 선택하세요. 기존 알고리즘을 사용하여 이미지를 확대하면 세부 사항 변경을 최소화하면서 더 빠른 처리가 가능합니다.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_interpolation_image_upscale', 'es', 'Mejora de imagen: Interpolación tradicional', 'Sube una imagen y selecciona un método de interpolación. Escala la imagen usando algoritmos tradicionales para un procesamiento más rápido con cambios mínimos en los detalles.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_interpolation_image_upscale', 'fr', 'Suréchantillonnage d''image : Interpolation traditionnelle', 'Téléchargez une image et sélectionnez une méthode d''interpolation. Agrandissez l''image à l''aide d''algorithmes traditionnels pour un traitement plus rapide avec des changements de détails minimes.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_interpolation_image_upscale', 'ru', 'Увеличение изображения: Традиционная интерполяция', 'Загрузите изображение и выберите метод интерполяции. Увеличьте изображение с помощью традиционных алгоритмов для более быстрой обработки с минимальными изменениями деталей.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_interpolation_image_upscale', 'tr', 'Görüntü Büyütme: Geleneksel Enterpolasyon', 'Bir görsel yükleyin ve bir enterpolasyon yöntemi seçin. Görseli, geleneksel algoritmalar kullanarak büyütün; böylece detay değişiklikleri en aza indirilerek daha hızlı işlem yapılır.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_interpolation_image_upscale', 'ar', 'تكبير الصورة: الاستيفاء التقليدي', 'قم بتحميل صورة واختر طريقة الاستيفاء. قم بتكبير الصورة باستخدام الخوارزميات التقليدية لمعالجة أسرع مع تغييرات طفيفة في التفاصيل.', 0, NULL, '2026-04-19T13:33:43.922Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_interpolation_image_upscale', 'pt-BR', 'Aumento de Imagem: Interpolação Tradicional', 'Faça upload de uma imagem e selecione um método de interpolação. Aumente a escala da imagem usando algoritmos tradicionais para processamento mais rápido com alterações mínimas nos detalhes.', 0, NULL, '2026-04-19T13:33:43.922Z');
