INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_image_stitch', 'ru', 'Сшивание изображений Сетка 2x2', 'Объедините четыре входных изображения в сетку 2x2. Автоматически изменяет размер несоответствующих изображений и выводит одно изображение размером 2048x2048.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_image_stitch', 'tr', 'Görsel Birleştirme 2x2 Izgara', 'Dört giriş görüntüsünü 2x2 ızgarada birleştirin. Uyumsuz görüntüleri otomatik olarak yeniden boyutlandırır ve tek bir 2048x2048 görüntü çıktısı verir.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_image_stitch', 'ar', 'دمج الصور شبكة 2x2', 'اجمع أربع صور مدخلة في شبكة 2x2. يعيد تلقائيًا تغيير حجم الصور غير المتطابقة ويخرج صورة واحدة بحجم 2048x2048.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_image_stitch', 'pt-BR', 'Costura de Imagem Grade 2x2', 'Combine quatro imagens de entrada em uma grade 2x2. Redimensiona automaticamente imagens incompatíveis e gera uma única imagem de 2048x2048.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (454, 'utility_text_lists_select_prompt', 9, 2, 'Batch Process Text Prompts From List', 'Loads and executes a workflow sequentially using prompts from a text list. Iterates through each entry to generate multiple outputs from a single batch operation.', 'image', 'webp', NULL, '["thumbnail/utility_text_lists_select_prompt.mp4"]', '["Batch Generation"]', '["Z-Image-Turbo"]', '[]', '["FL_PromptSelectorBasic"]', '[]', '{"outputs":[{"nodeId":36,"nodeType":"SaveImage","file":"","mediaType":"image"}]}', NULL, NULL, '2026-03-30', 1, 'active', 20723217203, 20723217203, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_text_lists_select_prompt', 'en', 'Batch Process Text Prompts From List', 'Loads and executes a workflow sequentially using prompts from a text list. Iterates through each entry to generate multiple outputs from a single batch operation.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_text_lists_select_prompt', 'zh', '从列表批量处理文本提示', '使用文本列表中的提示顺序加载并执行工作流。遍历每个条目以从单个批处理操作生成多个输出。', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_text_lists_select_prompt', 'zh-TW', '從列表批次處理文字提示', '使用文字清單中的提示順序載入並執行工作流程。遍歷每個條目以從單一批次操作生成多個輸出。', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_text_lists_select_prompt', 'ja', 'リストからテキストプロンプトを一括処理', 'テキストリストのプロンプトを使用してワークフローを順次読み込み、実行します。各エントリを反復処理し、単一のバッチ操作から複数の出力を生成します。', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_text_lists_select_prompt', 'ko', '목록에서 텍스트 프롬프트 일괄 처리', '텍스트 목록의 프롬프트를 사용하여 워크플로우를 순차적으로 로드하고 실행합니다. 각 항목을 반복하여 단일 배치 작업에서 여러 출력을 생성합니다.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_text_lists_select_prompt', 'es', 'Procesar por lotes indicaciones de texto desde la lista', 'Carga y ejecuta un flujo de trabajo secuencialmente utilizando indicaciones de una lista de texto. Itera a través de cada entrada para generar múltiples salidas desde una única operación por lotes.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_text_lists_select_prompt', 'fr', 'Traiter par lots les invites de texte à partir de la liste', 'Charge et exécute un flux de travail séquentiellement en utilisant les invites d''une liste de texte. Itère à travers chaque entrée pour générer plusieurs sorties à partir d''une seule opération par lots.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_text_lists_select_prompt', 'ru', 'Пакетная обработка текстовых подсказок из списка', 'Загружает и выполняет рабочий процесс последовательно, используя подсказки из текстового списка. Перебирает каждую запись для генерации нескольких выходных данных из одной пакетной операции.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_text_lists_select_prompt', 'tr', 'Listeden Toplu Metin İstemleri İşle', 'Bir metin listesindeki istemleri kullanarak bir iş akışını sırayla yükler ve çalıştırır. Tek bir toplu işlemden birden fazla çıktı oluşturmak için her girdiyi yineler.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_text_lists_select_prompt', 'ar', 'معالجة نصوص المطالبات دفعة واحدة من القائمة', 'يحمل وينفذ سير عمل بشكل تسلسلي باستخدام مطالبات من قائمة نصية. يتكرر عبر كل إدخال لتوليد مخرجات متعددة من عملية دفعة واحدة.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('utility_text_lists_select_prompt', 'pt-BR', 'Processar em Lote Prompts de Texto da Lista', 'Carrega e executa um fluxo de trabalho sequencialmente usando prompts de uma lista de texto. Itera por cada entrada para gerar múltiplas saídas de uma única operação em lote.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO templates (id, name, category_id, sort_order, title, description, media_type, media_subtype, thumbnail_variant, thumbnail, tags, models, logos, requires_custom_nodes, include_on_distributions, io, tutorial_url, comfyui_version, date, open_source, status, size, vram, usage, search_rank, username, version, synced_to_github, last_synced_at) VALUES (455, 'templates_purz_batch_generation', 9, 3, 'Prompt Multi Batch Generation', 'Send multiple prompts simultaneously to generate independent outputs in a single queue. Connect to Blueprint or Partner Nodes for batch processing of any modality. Use for prompt variation comparisons and batch generation.', 'image', 'webp', 'zoomHover', '["thumbnail/templates_purz_batch_generation.mp4"]', '["Batch Generation","Image"]', '["Z-Image-Turbo"]', '[]', '["comfyui_fill-nodes"]', '[]', '{"outputs":[{"nodeId":36,"nodeType":"SaveImage","file":"","mediaType":"image"}]}', NULL, NULL, '2026-03-21', 1, 'active', 20723217203, 20723217203, 0, 0, 'ComfyUI', 1, 1, datetime('now'));
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_batch_generation', 'en', 'Prompt Multi Batch Generation', 'Send multiple prompts simultaneously to generate independent outputs in a single queue. Connect to Blueprint or Partner Nodes for batch processing of any modality. Use for prompt variation comparisons and batch generation.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_batch_generation', 'zh', '提示多批次生成', '同时发送多个提示，在单个队列中生成独立输出。连接至蓝图或合作伙伴节点，进行任何模态的批量处理。适用于提示变体比较和批量生成。', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_batch_generation', 'zh-TW', '提示多批次生成', '同時發送多個提示，在單個佇列中生成獨立輸出。連接至藍圖或合作夥伴節點，進行任何模態的批次處理。適用於提示變體比較和批次生成。', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_batch_generation', 'ja', 'プロンプト複数バッチ生成', '複数のプロンプトを同時に送信し、単一のキューで独立した出力を生成します。ブループリントまたはパートナーノードに接続して、あらゆるモダリティのバッチ処理を行います。プロンプトのバリエーション比較やバッチ生成に使用します。', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_batch_generation', 'ko', '프롬프트 다중 배치 생성', '여러 프롬프트를 동시에 전송하여 단일 큐에서 독립적인 출력을 생성합니다. 블루프린트 또는 파트너 노드에 연결하여 모든 모달리티의 일괄 처리를 수행합니다. 프롬프트 변형 비교 및 일괄 생성에 사용합니다.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_batch_generation', 'es', 'Generación por Lotes Múltiples de Prompts', 'Envía múltiples prompts simultáneamente para generar salidas independientes en una sola cola. Conéctate a Nodos Blueprint o de Socios para el procesamiento por lotes de cualquier modalidad. Úsalo para comparaciones de variaciones de prompts y generación por lotes.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_batch_generation', 'fr', 'Génération par Lots Multiples de Prompts', 'Envoyez plusieurs invites simultanément pour générer des sorties indépendantes dans une seule file d''attente. Connectez-vous aux nœuds Blueprint ou Partenaires pour le traitement par lots de toute modalité. Utilisez-le pour les comparaisons de variations d''invites et la génération par lots.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_batch_generation', 'ru', 'Многопакетная генерация промптов', 'Отправляйте несколько промптов одновременно для создания независимых выходных данных в одной очереди. Подключайтесь к узлам Blueprint или Partner для пакетной обработки любой модальности. Используйте для сравнения вариаций промптов и пакетной генерации.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_batch_generation', 'tr', 'Çoklu Toplu İstek Üretimi', 'Tek bir kuyrukta bağımsız çıktılar oluşturmak için birden fazla istemi aynı anda gönderin. Herhangi bir modalite için toplu işlem yapmak üzere Blueprint veya Partner Düğümlerine bağlanın. İstem varyasyon karşılaştırmaları ve toplu oluşturma için kullanın.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_batch_generation', 'ar', 'توليد دفعات متعددة من المطالبات', 'أرسل عدة مطالبات في وقت واحد لتوليد مخرجات مستقلة في قائمة انتظار واحدة. اتصل بعقد Blueprint أو Partner Nodes للمعالجة المجمعة لأي نمط. استخدم لمقارنة اختلافات المطالبات والتوليد المجمع.', 0, NULL, '2026-04-19T13:33:43.923Z');
INSERT INTO translations (template_name, lang, title, description, is_outdated, outdated_fields, last_updated) VALUES ('templates_purz_batch_generation', 'pt-BR', 'Geração em Múltiplos Lotes de Prompts', 'Envie múltiplos prompts simultaneamente para gerar saídas independentes em uma única fila. Conecte-se aos Nós Blueprint ou de Parceiros para processamento em lote de qualquer modalidade. Use para comparações de variações de prompts e geração em lote.', 0, NULL, '2026-04-19T13:33:43.923Z');
